import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

async function main() {
    console.log('Seeding Help Center...');

    // 1. Getting Started
    const gettingStarted = await prisma.helpCollection.upsert({
        where: { slug: 'getting-started' },
        update: {},
        create: {
            title: 'Getting Started',
            slug: 'getting-started',
            description: 'Everything you need to know to get up and running with Overseek.',
            icon: 'Box',
            order: 1,
            articles: {
                create: [
                    {
                        title: 'Welcome to Overseek',
                        slug: 'welcome-to-overseek',
                        content: `# Welcome to Overseek\n\nWelcome to your new command center for WooCommerce. Overseek helps you manage multiple stores, track analytics, and automate your workflow from a single dashboard.\n\n### Key Features\n\n- **Unified Dashboard**: See all your stores in one place.\n- **Real-time Sync**: Orders, products, and customers update instantly.\n- **Marketing Intel**: Track ad performance alongside sales.\n\n### Next Steps\n\n1. Connect your first WooCommerce store.\n2. Invite your team members.\n3. Configure your dashboard widgets.`,
                        excerpt: 'A quick introduction to Overseek and its key features.',
                        order: 1,
                        isPublished: true
                    },
                    {
                        title: 'Connecting Your Store',
                        slug: 'connecting-your-store',
                        content: `# Connecting WooCommerce\n\nTo connect your store, you'll need to generate API keys in WooCommerce.\n\n1. Go to **WooCommerce > Settings > Advanced > REST API**.\n2. Click **Add Key**.\n3. Set permissions to **Read/Write**.\n4. Copy the Consumer Key and Consumer Secret.\n5. Paste them into the Overseek "Connect Store" wizard.`,
                        excerpt: 'Step-by-step guide to connecting your WooCommerce store.',
                        order: 2,
                        isPublished: true
                    }
                ]
            }
        }
    });

    // 2. Analytics & Reporting
    await prisma.helpCollection.upsert({
        where: { slug: 'analytics' },
        update: {},
        create: {
            title: 'Analytics & Reporting',
            slug: 'analytics',
            description: 'Deep dive into your sales, revenue, and customer data.',
            icon: 'TrendingUp',
            order: 2,
            articles: {
                create: [
                    {
                        title: 'Understanding Your Dashboard',
                        slug: 'understanding-dashboard',
                        content: `# Dashboard Metrics\n\nYour main dashboard gives a health check of your business.\n\n- **Total Sales**: Gross revenue including tax and shipping.\n- **Net Sales**: Revenue minus returns and discounts.\n- **Orders**: Total number of orders placed.\n- **AOV (Average Order Value)**: Total Sales / Order Count.\n\n### Customizing Widgets\n\nYou can drag and drop widgets to rearrange your view. Click the "Edit Dashboard" button to add or remove specific metrics.`,
                        excerpt: 'Guide to the metrics and widgets available on your dashboard.',
                        order: 1,
                        isPublished: true
                    }
                ]
            }
        }
    });

    // 3. User Management
    await prisma.helpCollection.upsert({
        where: { slug: 'users' },
        update: {},
        create: {
            title: 'Team & Users',
            slug: 'users',
            description: 'Manage access, roles, and permissions for your team.',
            icon: 'Users',
            order: 3,
            articles: {
                create: [
                    {
                        title: 'Inviting Team Members',
                        slug: 'inviting-team',
                        content: `# Expanding Your Team\n\nYou can invite unlimited team members to your Overseek account.\n\n1. Navigate to **Settings > Team**.\n2. Click **Invite Member**.\n3. Enter their email and select a role.\n\n### Roles\n\n- **Admin**: Full access to all settings and stores.\n- **Manager**: Can manage stores but not billing or account ownership.\n- **Viewer**: Read-only access to dashboards.`,
                        excerpt: 'How to add users and assign roles.',
                        order: 1,
                        isPublished: true
                    }
                ]
            }
        }
    });

    console.log('Seeding completed.');
}

main()
    .catch((e) => {
        console.error(e);
        process.exit(1);
    })
    .finally(async () => {
        await prisma.$disconnect();
    });

import dotenv from 'dotenv';
// Silence dotenv v17+ stdout output to prevent corrupting Pino's JSON log stream
dotenv.config({ quiet: true });

import os from 'os';

import { appPromise, app } from './app';
import { SchedulerService } from './services/scheduler';
import { startWorkers } from './workers';
import { IndexingService } from './services/search/IndexingService';
import { esClient } from './utils/elastic';
import { Logger } from './utils/logger';
import { validateEnvironment } from './utils/env';
import { initGracefulShutdown } from './utils/shutdown';

// Validate environment variables before proceeding
try {
  validateEnvironment();
} catch (error) {
  Logger.error('[STARTUP] Environment validation failed, exiting');
  process.exit(1);
}

const port = process.env.PORT || 3000;

/** Detect the first non-internal IPv4 address for the startup banner */
function getNetworkAddress(): string | null {
  const interfaces = os.networkInterfaces();
  for (const name of Object.keys(interfaces)) {
    for (const iface of interfaces[name] || []) {
      if (iface.family === 'IPv4' && !iface.internal) {
        return iface.address;
      }
    }
  }
  return null;
}

// Global Error Handlers to prevent silent crashes
process.on('uncaughtException', (error) => {
  Logger.error('[CRITICAL] Uncaught Exception', { error });
});

process.on('unhandledRejection', (reason, promise) => {
  // Serialize the reason properly - PrismaClientValidationError and other errors
  // have non-enumerable properties that need explicit extraction
  const serializedReason = reason instanceof Error
    ? { name: reason.name, message: reason.message, stack: reason.stack }
    : reason;
  Logger.error('[CRITICAL] Unhandled Rejection', { reason: serializedReason });
});

// Main startup function
async function start() {
  // Wait for Fastify app to be fully initialized
  await appPromise;

  // Start Internal Workers
  try {
    await startWorkers();
    Logger.info('[Startup] Workers initialized');
  } catch (error) {
    Logger.error('[Startup] Failed to start workers', { error });
  }

  // Start Scheduler
  try {
    await SchedulerService.start();
    Logger.info('[Startup] Scheduler started');

    // Register scheduler worker for graceful shutdown
    const { onShutdown } = await import('./utils/shutdown');
    onShutdown(() => SchedulerService.shutdown());
  } catch (error) {
    Logger.error('[Startup] Failed to start scheduler', { error });
  }

  // Start keyword rank tracking scheduler
  try {
    const { startKeywordRankScheduler } = await import('./services/search-console/keywordRankScheduler');
    startKeywordRankScheduler();
    Logger.info('[Startup] Keyword rank scheduler started');
  } catch (error) {
    Logger.error('[Startup] Failed to start keyword rank scheduler', { error });
  }

  // Start competitor SERP position tracking scheduler
  try {
    const { startCompetitorRankScheduler } = await import('./services/search-console/CompetitorRankScheduler');
    startCompetitorRankScheduler();
    Logger.info('[Startup] Competitor rank scheduler started');
  } catch (error) {
    Logger.error('[Startup] Failed to start competitor rank scheduler', { error });
  }

  // Initialize Elastic Indices
  try {
    await IndexingService.initializeIndices();
    Logger.info('[Startup] Elasticsearch indices initialized');

    // Check if products index is empty (e.g. after mapping reset) and trigger sync
    try {
      const { count } = await esClient.count({ index: 'products' });
      if (count === 0) {
        Logger.info('[Startup] Products index is empty. Triggering initial sync...');
        const { SyncService } = await import('./services/sync');
        const syncService = new SyncService();
        const { prisma } = await import('./utils/prisma');
        const account = await prisma.account.findFirst();
        if (account) {
          // Run in background so server startup isn't blocked too long
          syncService.runSync(account.id, { types: ['products'], incremental: false })
            .catch(err => Logger.error('[Startup] Failed to trigger initial sync', { error: err }));
        }
      }
    } catch (err) {
      Logger.warn('[Startup] Failed to check product index count', { error: err });
    }

  } catch (error) {
    Logger.error('[Startup] Failed to initialize Elasticsearch indices', { error });
  }

  // Start Fastify server
  try {
    await app.listen({ port: Number(port), host: '0.0.0.0' });
    Logger.info(`[Server] Fastify listening on http://0.0.0.0:${port}`);

    // Print human-readable startup banner to console
    const networkAddress = getNetworkAddress();
    console.log('');
    console.log('  ╔══════════════════════════════════════════════╗');
    console.log('  ║           OverSeek API Server Ready          ║');
    console.log('  ╠══════════════════════════════════════════════╣');
    console.log(`  ║  Local:    http://localhost:${port}             ║`);
    if (networkAddress) {
      console.log(`  ║  Network:  http://${networkAddress}:${port}`.padEnd(49) + '║');
    }
    console.log('  ╚══════════════════════════════════════════════╝');
    console.log('');

    // Initialize graceful shutdown after server starts
    initGracefulShutdown(app.server);
  } catch (error) {
    Logger.error('[CRITICAL] Failed to start server', { error });
    process.exit(1);
  }
}

start();

/**
 * Unit tests for OAuth URL helpers.
 *
 * Why: The original inline string-concatenation produced malformed redirect
 * URLs behind proxies (wrong separators, whitespace). These tests lock in
 * correct behaviour for every edge case.
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { getApiBase, buildCallbackUrl, getAppUrl, buildFrontendUrl } from '../oauthHelpers';
import { FastifyRequest } from 'fastify';

/** Minimal mock that satisfies the subset of FastifyRequest we use */
function mockRequest(opts: { protocol?: string; hostname?: string } = {}): FastifyRequest {
    return {
        protocol: opts.protocol ?? 'https',
        hostname: opts.hostname ?? 'myapp.example.com',
    } as unknown as FastifyRequest;
}

describe('getApiBase', () => {
    afterEach(() => { delete process.env.API_URL; });

    it('returns API_URL when set', () => {
        process.env.API_URL = 'https://api.prod.example.com';
        expect(getApiBase(mockRequest())).toBe('https://api.prod.example.com');
    });

    it('strips trailing slashes from API_URL', () => {
        process.env.API_URL = 'https://api.prod.example.com///';
        expect(getApiBase(mockRequest())).toBe('https://api.prod.example.com');
    });

    it('trims whitespace from API_URL', () => {
        process.env.API_URL = '  https://api.prod.example.com  ';
        expect(getApiBase(mockRequest())).toBe('https://api.prod.example.com');
    });

    it('falls back to request origin when API_URL is not set', () => {
        expect(getApiBase(mockRequest({ protocol: 'http', hostname: 'localhost:3000' })))
            .toBe('http://localhost:3000');
    });
});

describe('buildCallbackUrl', () => {
    afterEach(() => { delete process.env.API_URL; });

    it('builds correct URL with API_URL', () => {
        process.env.API_URL = 'https://api.prod.example.com';
        expect(buildCallbackUrl(mockRequest(), 'google/callback'))
            .toBe('https://api.prod.example.com/api/oauth/google/callback');
    });

    it('builds correct URL from request fallback', () => {
        expect(buildCallbackUrl(mockRequest({ protocol: 'https', hostname: 'myapp.example.com' }), 'meta/ads/callback'))
            .toBe('https://myapp.example.com/api/oauth/meta/ads/callback');
    });

    it('trims any whitespace from the result', () => {
        process.env.API_URL = '  https://api.example.com  ';
        const url = buildCallbackUrl(mockRequest(), 'google/callback');
        expect(url).not.toMatch(/\s/);
        expect(url).toBe('https://api.example.com/api/oauth/google/callback');
    });
});

describe('getAppUrl', () => {
    afterEach(() => { delete process.env.APP_URL; });

    it('returns APP_URL when set', () => {
        process.env.APP_URL = 'https://app.example.com';
        expect(getAppUrl()).toBe('https://app.example.com');
    });

    it('strips trailing slashes', () => {
        process.env.APP_URL = 'https://app.example.com/';
        expect(getAppUrl()).toBe('https://app.example.com');
    });

    it('defaults to localhost:5173', () => {
        expect(getAppUrl()).toBe('http://localhost:5173');
    });
});

describe('buildFrontendUrl', () => {
    afterEach(() => { delete process.env.APP_URL; });

    it('appends query params with proper separator (no existing query)', () => {
        process.env.APP_URL = 'https://app.example.com';
        const url = buildFrontendUrl('/marketing', { error: 'oauth_denied' });
        expect(url).toBe('https://app.example.com/marketing?error=oauth_denied');
    });

    it('appends query params with proper separator (existing query)', () => {
        process.env.APP_URL = 'https://app.example.com';
        const url = buildFrontendUrl('/settings?tab=ads', { success: 'connected', id: '123' });
        // URL API preserves existing params and adds new ones
        expect(url).toContain('tab=ads');
        expect(url).toContain('success=connected');
        expect(url).toContain('id=123');
        // No double ? or malformed separators
        expect(url.match(/\?/g)?.length).toBe(1);
    });

    it('encodes special characters in param values', () => {
        process.env.APP_URL = 'https://app.example.com';
        const url = buildFrontendUrl('/error', { message: 'token exchange failed (403)' });
        expect(url).not.toContain(' ');
        expect(url).not.toContain('(');
        expect(url).toContain('message=');
    });

    it('handles absolute path input', () => {
        const url = buildFrontendUrl('https://other.example.com/foo', { bar: 'baz' });
        expect(url).toBe('https://other.example.com/foo?bar=baz');
    });

    it('produces no whitespace in output', () => {
        process.env.APP_URL = '  https://app.example.com  ';
        const url = buildFrontendUrl('/callback', { flowName: 'GeneralOAuthFlow' });
        expect(url).not.toMatch(/\s/);
    });
});

/**
 * Creative Experiment Routes
 * 
 * API endpoints for A/B testing of ad creatives.
 * Part of AI Co-Pilot v2 - Phase 4: Creative A/B Engine.
 */

import { FastifyInstance } from 'fastify';
import { CreativeVariantService, CreateExperimentParams, VariantContent } from '../../services/ads/CreativeVariantService';
import { AdCopyGenerator } from '../../services/tools/AdCopyGenerator';
import { requireAuthFastify } from '../../middleware/auth';
import { prisma } from '../../utils/prisma';

interface CreateExperimentBody {
    name: string;
    platform: 'google' | 'meta';
    adAccountId: string;
    campaignId?: string;
    adGroupId?: string;
    primaryMetric?: 'ctr' | 'conversions' | 'roas';
    minSampleSize?: number;
}

interface AddVariantBody {
    headlines?: string[];
    descriptions?: string[];
    primaryTexts?: string[];
    isControl?: boolean;
}

interface GenerateVariantsBody {
    baseHeadlines: string[];
    baseDescriptions: string[];
    variantCount: number;
    platform?: 'google' | 'meta';
}

interface ConcludeBody {
    winnerId?: string;
}

export default async function experimentsRoutes(fastify: FastifyInstance) {
    // All routes require authentication
    fastify.addHook('preHandler', requireAuthFastify);

    /**
     * GET /api/ads/experiments
     * List all experiments for the account.
     */
    fastify.get<{ Querystring: { status?: string } }>('/', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account selected' });

        const { status } = request.query;
        const experiments = await CreativeVariantService.listExperiments(accountId, status);

        return { experiments };
    });

    /**
     * POST /api/ads/experiments
     * Create a new A/B experiment.
     */
    fastify.post<{ Body: CreateExperimentBody }>('/', {
        schema: {
            body: {
                type: 'object',
                required: ['name', 'platform', 'adAccountId'],
                properties: {
                    name: { type: 'string', minLength: 1 },
                    platform: { type: 'string', enum: ['google', 'meta'] },
                    adAccountId: { type: 'string' },
                    campaignId: { type: 'string' },
                    adGroupId: { type: 'string' },
                    primaryMetric: { type: 'string', enum: ['ctr', 'conversions', 'roas'] },
                    minSampleSize: { type: 'number', minimum: 50 }
                }
            }
        }
    }, async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account selected' });

        const experiment = await CreativeVariantService.createExperiment(
            accountId,
            request.body as CreateExperimentParams
        );

        return { success: true, experiment };
    });

    /**
     * GET /api/ads/experiments/:id
     * Get experiment details with variants.
     */
    fastify.get<{ Params: { id: string } }>('/:id', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account selected' });

        const { id } = request.params;
        const experiment = await CreativeVariantService.getExperiment(id);

        if (!experiment || experiment.accountId !== accountId) {
            return reply.code(404).send({ error: 'Experiment not found' });
        }

        return { experiment };
    });

    /**
     * POST /api/ads/experiments/:id/variants
     * Add a variant to an experiment.
     */
    fastify.post<{ Params: { id: string }; Body: AddVariantBody }>('/:id/variants', {
        schema: {
            body: {
                type: 'object',
                properties: {
                    headlines: { type: 'array', items: { type: 'string' } },
                    descriptions: { type: 'array', items: { type: 'string' } },
                    primaryTexts: { type: 'array', items: { type: 'string' } },
                    isControl: { type: 'boolean' }
                }
            }
        }
    }, async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account selected' });

        const { id } = request.params;

        // Verify experiment belongs to account
        const experiment = await CreativeVariantService.getExperiment(id);
        if (!experiment || experiment.accountId !== accountId) {
            return reply.code(404).send({ error: 'Experiment not found' });
        }

        const variant = await CreativeVariantService.addVariant(id, request.body as VariantContent);

        return { success: true, variant };
    });

    /**
     * POST /api/ads/experiments/:id/generate-variants
     * Generate AI-powered variants for an experiment.
     */
    fastify.post<{ Params: { id: string }; Body: GenerateVariantsBody }>('/:id/generate-variants', {
        schema: {
            body: {
                type: 'object',
                required: ['baseHeadlines', 'baseDescriptions', 'variantCount'],
                properties: {
                    baseHeadlines: { type: 'array', items: { type: 'string' } },
                    baseDescriptions: { type: 'array', items: { type: 'string' } },
                    variantCount: { type: 'number', minimum: 2, maximum: 5 },
                    platform: { type: 'string', enum: ['google', 'meta'] }
                }
            }
        }
    }, async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account selected' });

        const { id } = request.params;
        const { baseHeadlines, baseDescriptions, variantCount, platform } = request.body;

        // Verify experiment belongs to account
        const experiment = await CreativeVariantService.getExperiment(id);
        if (!experiment || experiment.accountId !== accountId) {
            return reply.code(404).send({ error: 'Experiment not found' });
        }

        // Generate variants using AI
        const baseCopy = {
            headlines: baseHeadlines,
            descriptions: baseDescriptions,
            source: 'ai' as const
        };

        const variants = await AdCopyGenerator.generateVariants(
            accountId,
            baseCopy,
            variantCount,
            (platform || experiment.platform) as 'google' | 'meta'
        );

        // Add each variant to the experiment
        const addedVariants = [];
        for (let i = 0; i < variants.length; i++) {
            const variant = await CreativeVariantService.addVariant(id, {
                headlines: variants[i].headlines,
                descriptions: variants[i].descriptions,
                primaryTexts: variants[i].primaryTexts,
                isControl: i === 0
            });
            addedVariants.push(variant);
        }

        return { success: true, variants: addedVariants };
    });

    /**
     * POST /api/ads/experiments/:id/refresh
     * Refresh metrics for an experiment.
     */
    fastify.post<{ Params: { id: string } }>('/:id/refresh', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account selected' });

        const { id } = request.params;

        // Verify experiment belongs to account
        const experiment = await CreativeVariantService.getExperiment(id);
        if (!experiment || experiment.accountId !== accountId) {
            return reply.code(404).send({ error: 'Experiment not found' });
        }

        await CreativeVariantService.refreshExperimentMetrics(id);

        // Return updated experiment
        const updated = await CreativeVariantService.getExperiment(id);

        return { success: true, experiment: updated };
    });

    /**
     * POST /api/ads/experiments/:id/analyze
     * Analyze statistical significance.
     */
    fastify.post<{ Params: { id: string } }>('/:id/analyze', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account selected' });

        const { id } = request.params;

        // Verify experiment belongs to account
        const experiment = await CreativeVariantService.getExperiment(id);
        if (!experiment || experiment.accountId !== accountId) {
            return reply.code(404).send({ error: 'Experiment not found' });
        }

        const analysis = await CreativeVariantService.analyzeSignificance(id);

        return { success: true, analysis };
    });

    /**
     * POST /api/ads/experiments/:id/conclude
     * End experiment and declare winner.
     */
    fastify.post<{ Params: { id: string }; Body: ConcludeBody }>('/:id/conclude', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account selected' });

        const { id } = request.params;
        const { winnerId } = request.body;

        // Verify experiment belongs to account
        const experiment = await CreativeVariantService.getExperiment(id);
        if (!experiment || experiment.accountId !== accountId) {
            return reply.code(404).send({ error: 'Experiment not found' });
        }

        await CreativeVariantService.concludeExperiment(id, winnerId);

        return { success: true, message: 'Experiment concluded' };
    });

    /**
     * POST /api/ads/experiments/:id/pause
     * Pause an experiment.
     */
    fastify.post<{ Params: { id: string } }>('/:id/pause', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account selected' });

        const { id } = request.params;

        // Verify experiment belongs to account
        const experiment = await CreativeVariantService.getExperiment(id);
        if (!experiment || experiment.accountId !== accountId) {
            return reply.code(404).send({ error: 'Experiment not found' });
        }

        await CreativeVariantService.pauseExperiment(id);

        return { success: true, message: 'Experiment paused' };
    });

    /**
     * POST /api/ads/experiments/:id/resume
     * Resume a paused experiment.
     */
    fastify.post<{ Params: { id: string } }>('/:id/resume', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account selected' });

        const { id } = request.params;

        // Verify experiment belongs to account
        const experiment = await CreativeVariantService.getExperiment(id);
        if (!experiment || experiment.accountId !== accountId) {
            return reply.code(404).send({ error: 'Experiment not found' });
        }

        await CreativeVariantService.resumeExperiment(id);

        return { success: true, message: 'Experiment resumed' };
    });
}

/**
 * Auth Route - Fastify Plugin
 * Authentication endpoints with 2FA, sessions, and password reset
 */

import { FastifyPluginAsync } from 'fastify';
import { hashPassword, comparePassword, generateToken } from '../utils/auth';
import { requireAuthFastify } from '../middleware/auth';
import { SecurityService } from '../services/SecurityService';
import { prisma } from '../utils/prisma';
import { Logger } from '../utils/logger';
import { PermissionService } from '../services/PermissionService';
import { z } from 'zod';
import path from 'path';
import fs from 'fs';
import crypto from 'crypto';
import { redisClient } from '../utils/redis';

// Schemas
const registerSchema = z.object({
    email: z.string().email(),
    password: z.string().min(8, 'Password must be at least 8 characters'),
    fullName: z.string().min(2, 'Full name is required')
});

const loginSchema = z.object({
    email: z.string().email(),
    password: z.string(),
    token: z.string().optional() // Optional 2FA token
});

const resetPasswordSchema = z.object({
    email: z.string().email(),
    token: z.string(),
    newPassword: z.string().min(8, 'Password must be at least 8 characters')
});

const changePasswordSchema = z.object({
    currentPassword: z.string().min(1, 'Current password is required'),
    newPassword: z.string()
        .min(8, 'Password must be at least 8 characters')
        .regex(/[a-zA-Z]/, 'Password must contain at least one letter')
        .regex(/[0-9]/, 'Password must contain at least one number'),
    confirmPassword: z.string()
}).refine((data) => data.newPassword === data.confirmPassword, {
    message: 'Passwords do not match',
    path: ['confirmPassword']
});

// Simple in-memory rate limiter (per IP) as fallback if Redis is unavailable.
const loginAttempts = new Map<string, { count: number; firstAttempt: number }>();
const WINDOW_MS = 60 * 60 * 1000; // 1 hour
const MAX_FAILED_ATTEMPTS = 10; // Increased limit - only counts FAILED attempts now
const MAX_MAP_SIZE = 10_000; // Cap to prevent unbounded memory growth
const CLEANUP_INTERVAL_MS = 10 * 60 * 1000; // Cleanup every 10 minutes

/**
 * Periodically clean up expired entries from the in-memory rate limit map.
 * Prevents memory leak when Redis is unavailable for extended periods.
 */
function cleanupExpiredEntries(): void {
    const now = Date.now();
    let cleaned = 0;

    for (const [ip, record] of loginAttempts) {
        if (now - record.firstAttempt > WINDOW_MS) {
            loginAttempts.delete(ip);
            cleaned++;
        }
    }

    if (cleaned > 0) {
        Logger.debug('Rate limit cleanup completed', { entriesRemoved: cleaned, remaining: loginAttempts.size });
    }
}

// Start cleanup interval (runs in background)
const cleanupInterval = setInterval(cleanupExpiredEntries, CLEANUP_INTERVAL_MS);

// Ensure cleanup interval is cleared on process exit (prevents test hangs)
if (typeof process !== 'undefined') {
    process.on('beforeExit', () => clearInterval(cleanupInterval));
}

/**
 * Check if IP is currently rate limited (without incrementing).
 * Returns true if allowed to attempt login, false if blocked.
 */
function isLoginAllowedFallback(ip: string): boolean {
    const now = Date.now();
    const record = loginAttempts.get(ip);

    if (!record) return true; // No record = allowed

    // Window expired, reset
    if (now - record.firstAttempt > WINDOW_MS) {
        loginAttempts.delete(ip);
        return true;
    }

    // Check if at limit
    return record.count < MAX_FAILED_ATTEMPTS;
}

/**
 * Increment failed login counter for IP.
 * Enforces MAX_MAP_SIZE cap to prevent unbounded memory growth.
 */
function incrementFailedLoginFallback(ip: string): void {
    const now = Date.now();
    const record = loginAttempts.get(ip);

    if (!record) {
        // Enforce size cap before adding new entry
        if (loginAttempts.size >= MAX_MAP_SIZE) {
            // Remove oldest entries (first 10% or at least 100)
            const toRemove = Math.max(100, Math.floor(MAX_MAP_SIZE * 0.1));
            let removed = 0;
            for (const key of loginAttempts.keys()) {
                if (removed >= toRemove) break;
                loginAttempts.delete(key);
                removed++;
            }
            Logger.warn('Rate limit map size cap reached, evicted oldest entries', {
                evicted: removed,
                remaining: loginAttempts.size
            });
        }
        loginAttempts.set(ip, { count: 1, firstAttempt: now });
        return;
    }

    // Window expired, reset
    if (now - record.firstAttempt > WINDOW_MS) {
        loginAttempts.set(ip, { count: 1, firstAttempt: now });
        return;
    }

    record.count++;
}

/**
 * Check if IP is allowed to attempt login.
 * Returns true if allowed, false if blocked by rate limit.
 */
async function isLoginAllowed(ip: string): Promise<boolean> {
    const key = `login:failed:${ip}`;

    try {
        const count = await redisClient.get(key);
        if (!count) return true; // No record = allowed
        return parseInt(count, 10) < MAX_FAILED_ATTEMPTS;
    } catch (error) {
        Logger.warn('Rate limit check fallback to memory', { error });
        return isLoginAllowedFallback(ip);
    }
}

/**
 * Increment failed login counter for IP in Redis.
 */
async function incrementFailedLogin(ip: string): Promise<void> {
    const windowSeconds = 60 * 60; // 1 hour
    const key = `login:failed:${ip}`;

    try {
        const count = await redisClient.incr(key);
        if (count === 1) {
            await redisClient.expire(key, windowSeconds);
        }
    } catch (error) {
        Logger.warn('Failed login increment fallback to memory', { error });
        incrementFailedLoginFallback(ip);
    }
}

function detectImageType(buffer: Buffer): { ext: string; mime: string } | null {
    if (buffer.length < 12) return null;

    // JPEG
    if (buffer[0] === 0xff && buffer[1] === 0xd8 && buffer[2] === 0xff) {
        return { ext: '.jpg', mime: 'image/jpeg' };
    }
    // PNG
    if (
        buffer[0] === 0x89 &&
        buffer[1] === 0x50 &&
        buffer[2] === 0x4e &&
        buffer[3] === 0x47
    ) {
        return { ext: '.png', mime: 'image/png' };
    }
    // GIF
    if (
        buffer[0] === 0x47 &&
        buffer[1] === 0x49 &&
        buffer[2] === 0x46 &&
        buffer[3] === 0x38
    ) {
        return { ext: '.gif', mime: 'image/gif' };
    }
    // WEBP (RIFF....WEBP)
    if (
        buffer[0] === 0x52 &&
        buffer[1] === 0x49 &&
        buffer[2] === 0x46 &&
        buffer[3] === 0x46 &&
        buffer[8] === 0x57 &&
        buffer[9] === 0x45 &&
        buffer[10] === 0x42 &&
        buffer[11] === 0x50
    ) {
        return { ext: '.webp', mime: 'image/webp' };
    }

    return null;
}

const authRoutes: FastifyPluginAsync = async (fastify) => {
    // Ensure upload directory exists
    const uploadDir = path.join(__dirname, '../../uploads');
    if (!fs.existsSync(uploadDir)) {
        fs.mkdirSync(uploadDir, { recursive: true });
    }

    // REGISTER
    fastify.post('/register', async (request, reply) => {
        try {
            const parsed = registerSchema.safeParse(request.body);
            if (!parsed.success) {
                return reply.code(400).send({ error: parsed.error.issues[0].message });
            }
            const { email, password, fullName } = parsed.data;

            // Check if this is the first user (superadmin bootstrap - always allowed)
            const userCount = await prisma.user.count();
            const isSuperAdmin = userCount === 0;

            // If not the first user, check if registrations are enabled
            if (!isSuperAdmin) {
                const platformSettings = await prisma.platformSettings.findUnique({
                    where: { key: 'default' }
                });

                // Default to enabled if no settings exist, but check if explicitly disabled
                if (platformSettings && !platformSettings.registrationEnabled) {
                    return reply.code(403).send({ error: 'New registrations are currently disabled' });
                }
            }

            const existingUser = await prisma.user.findUnique({ where: { email } });
            if (existingUser) return reply.code(400).send({ error: 'User already exists' });

            const passwordHash = await hashPassword(password);

            let user;
            try {
                user = await prisma.user.create({
                    data: { email, passwordHash, fullName, isSuperAdmin }
                });
            } catch (createError: any) {
                // Handle race condition: concurrent registration with same email
                if (createError.code === 'P2002') {
                    return reply.code(400).send({ error: 'User already exists' });
                }
                throw createError;
            }

            const { accessToken, refreshToken } = await SecurityService.createSession(
                user.id, request.ip, request.headers['user-agent'] as string
            );
            return { token: accessToken, refreshToken, user: { id: user.id, email: user.email, fullName: user.fullName, avatarUrl: user.avatarUrl, isSuperAdmin: user.isSuperAdmin } };
        } catch (error) {
            Logger.error('Register error', { error });
            return reply.code(500).send({ error: 'Internal server error' });
        }
    });

    // LOGIN
    fastify.post('/login', async (request, reply) => {
        try {
            const ip = request.ip;

            // Check if IP is currently rate limited
            if (!(await isLoginAllowed(ip))) {
                return reply.code(429).send({ error: 'Too many login attempts, please try again later.' });
            }

            const parsed = loginSchema.safeParse(request.body);
            if (!parsed.success) {
                return reply.code(400).send({ error: parsed.error.issues[0].message });
            }
            const { email, password, token: twoFactorToken } = parsed.data;

            const user = await prisma.user.findUnique({ where: { email } });
            if (!user) {
                // Increment failed attempt counter - only on actual failed login
                await incrementFailedLogin(ip);
                return reply.code(401).send({ error: 'Invalid credentials' });
            }

            const isValid = await comparePassword(password, user.passwordHash);
            if (!isValid) {
                // Increment failed attempt counter - only on actual failed login
                await incrementFailedLogin(ip);
                return reply.code(401).send({ error: 'Invalid credentials' });
            }

            // 2FA Check (successful password, check 2FA if enabled)
            if (user.isTwoFactorEnabled) {
                if (!twoFactorToken) {
                    // Why 401 + requireTwoFactor: returning 200 with requireTwoFactor
                    // leaks that the email/password combo is valid, enabling enumeration.
                    return reply.code(401).send({ requireTwoFactor: true });
                }
                const isTokenValid = SecurityService.verifyTwoFactorToken(twoFactorToken, user.twoFactorSecret!);
                if (!isTokenValid) {
                    // Increment failed attempt counter for bad 2FA
                    await incrementFailedLogin(ip);
                    return reply.code(401).send({ error: 'Invalid 2FA code' });
                }
            }

            // Successful login - no rate limit increment!
            const { accessToken, refreshToken } = await SecurityService.createSession(user.id, ip, request.headers['user-agent'] as string);

            return {
                token: accessToken,
                refreshToken,
                user: { id: user.id, email: user.email, fullName: user.fullName, avatarUrl: user.avatarUrl, isSuperAdmin: user.isSuperAdmin }
            };
        } catch (error) {
            Logger.error('Login error', { error });
            return reply.code(500).send({ error: 'Internal server error' });
        }
    });

    // ME (Protected)
    fastify.get('/me', { preHandler: requireAuthFastify }, async (request, reply) => {
        try {
            const userId = request.user!.id;
            const user = await prisma.user.findUnique({
                where: { id: userId },
                include: { accounts: true }
            });
            if (!user) return reply.code(404).send({ error: 'User not found' });
            const { passwordHash, ...safeUser } = user;

            // If valid account context, resolve permissions
            const accountId = request.accountId;
            let permissions = {};
            if (accountId) {
                permissions = await PermissionService.resolvePermissions(userId, accountId);
            }

            return { ...safeUser, permissions };
        } catch (error) {
            Logger.error('GET /me error', { error });
            return reply.code(500).send({ error: 'Internal server error' });
        }
    });

    // UPDATE PROFILE
    fastify.put('/me', { preHandler: requireAuthFastify }, async (request, reply) => {
        try {
            const userId = request.user!.id;
            const { fullName, shiftStart, shiftEnd, emailSignature } = request.body as any;

            // Why: explicit whitelist prevents mass-assignment if new sensitive fields are added to User model
            const data: Record<string, unknown> = {};
            if (fullName !== undefined) data.fullName = fullName;
            if (shiftStart !== undefined) data.shiftStart = shiftStart;
            if (shiftEnd !== undefined) data.shiftEnd = shiftEnd;
            if (emailSignature !== undefined) data.emailSignature = emailSignature;

            const updatedUser = await prisma.user.update({
                where: { id: userId },
                data
            });
            const { passwordHash, ...safeUser } = updatedUser;
            return safeUser;
        } catch (error) {
            Logger.error('Update profile error', { error });
            return reply.code(500).send({ error: 'Failed to update profile' });
        }
    });

    // UPLOAD AVATAR
    // Why max 5MB: avatars are small images; unbounded uploads can OOM the server
    // when toBuffer() loads the entire file into memory.
    const MAX_AVATAR_SIZE = 5 * 1024 * 1024; // 5 MB
    fastify.post('/upload-avatar', { preHandler: requireAuthFastify }, async (request, reply) => {
        try {
            const userId = request.user!.id;
            const data = await request.file({ limits: { fileSize: MAX_AVATAR_SIZE } });
            if (!data) return reply.code(400).send({ error: 'No file uploaded' });

            const fileBuffer = await data.toBuffer();

            // Check if file was truncated (exceeded size limit)
            if ((data as any).file?.truncated) {
                return reply.code(400).send({ error: 'File too large. Maximum avatar size is 5MB.' });
            }

            const detected = detectImageType(fileBuffer);
            if (!detected) {
                return reply.code(400).send({ error: 'Only image files are allowed!' });
            }

            const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
            const filename = 'avatar-' + uniqueSuffix + detected.ext;
            const filePath = path.join(uploadDir, filename);

            await fs.promises.writeFile(filePath, fileBuffer);

            const avatarUrl = `/uploads/${filename}`;
            await prisma.user.update({ where: { id: userId }, data: { avatarUrl } });
            return { avatarUrl };
        } catch (error) {
            Logger.error('Upload error', { error });
            return reply.code(500).send({ error: 'Failed to upload avatar' });
        }
    });

    // FORGOT PASSWORD
    fastify.post('/forgot-password', async (request, reply) => {
        try {
            const { email } = request.body as { email?: string };
            if (!email) return reply.code(400).send({ error: 'Email is required' });

            const user = await prisma.user.findUnique({ where: { email } });
            if (!user) {
                return { message: 'If an account exists, a reset link has been sent.' };
            }

            const resetToken = crypto.randomBytes(32).toString('hex');
            const resetTokenExpiry = new Date(Date.now() + 3600000);

            // Why hash: storing the token in plaintext means a DB leak gives
            // attackers password-reset capability. Hashing prevents this.
            const hashedResetToken = crypto.createHash('sha256').update(resetToken).digest('hex');

            await prisma.user.update({
                where: { id: user.id },
                data: { resetToken: hashedResetToken, resetTokenExpiry }
            });

            // Why no email param: including the email in the URL leaks it into
            // browser history, server logs, and referrer headers.
            const resetLink = `${process.env.CLIENT_URL || 'http://localhost:5173'}/reset-password?token=${resetToken}`;

            if (process.env.SMTP_HOST) {
                const nodemailer = require('nodemailer');
                const transporter = nodemailer.createTransport({
                    host: process.env.SMTP_HOST,
                    port: parseInt(process.env.SMTP_PORT || '587', 10),
                    auth: { user: process.env.SMTP_USER, pass: process.env.SMTP_PASS }
                });

                await transporter.sendMail({
                    from: process.env.SMTP_FROM || `"${process.env.APP_NAME || 'Commerce Platform'} Security" <${process.env.CONTACT_EMAIL || 'no-reply@localhost'}>`,
                    to: email,
                    subject: 'Password Reset Request',
                    html: `<p>You requested a password reset. Click <a href="${resetLink}">here</a> to reset your password.</p>`
                });
                transporter.close();
            } else {
                Logger.debug(`Password Reset Link generated (SMTP not configured, link not sent)`);
            }

            return { message: 'If an account exists, a reset link has been sent.' };
        } catch (error) {
            Logger.error('Forgot password error', { error });
            return reply.code(500).send({ error: 'Internal server error' });
        }
    });

    // RESET PASSWORD
    fastify.post('/reset-password', async (request, reply) => {
        try {
            const parsed = resetPasswordSchema.safeParse(request.body);
            if (!parsed.success) {
                return reply.code(400).send({ error: parsed.error.issues[0].message });
            }
            const { email, token, newPassword } = parsed.data;

            // Hash the incoming token to compare against stored hash
            const hashedToken = crypto.createHash('sha256').update(token).digest('hex');

            const user = await prisma.user.findUnique({ where: { email } });
            if (!user || !user.resetToken || user.resetToken !== hashedToken || !user.resetTokenExpiry || user.resetTokenExpiry < new Date()) {
                return reply.code(400).send({ error: 'Invalid or expired token' });
            }

            const passwordHash = await hashPassword(newPassword);
            await prisma.user.update({
                where: { id: user.id },
                data: { passwordHash, resetToken: null, resetTokenExpiry: null }
            });

            return { message: 'Password has been reset successfully' };
        } catch (error) {
            Logger.error('Reset password error', { error });
            return reply.code(500).send({ error: 'Internal server error' });
        }
    });

    // CHANGE PASSWORD (Authenticated)
    fastify.post('/change-password', { preHandler: requireAuthFastify }, async (request, reply) => {
        try {
            const parsed = changePasswordSchema.safeParse(request.body);
            if (!parsed.success) {
                return reply.code(400).send({ error: parsed.error.issues[0].message });
            }
            const { currentPassword, newPassword } = parsed.data;
            const userId = request.user!.id;

            const user = await prisma.user.findUnique({ where: { id: userId } });
            if (!user) {
                return reply.code(404).send({ error: 'User not found' });
            }

            // Verify current password
            const isCurrentValid = await comparePassword(currentPassword, user.passwordHash);
            if (!isCurrentValid) {
                return reply.code(401).send({ error: 'Current password is incorrect' });
            }

            // Ensure new password is different from current
            const isSamePassword = await comparePassword(newPassword, user.passwordHash);
            if (isSamePassword) {
                return reply.code(400).send({ error: 'New password cannot be the same as current password' });
            }

            // Hash and save new password + revoke sessions atomically
            const newPasswordHash = await hashPassword(newPassword);
            await prisma.$transaction(async (tx) => {
                await tx.user.update({
                    where: { id: userId },
                    data: { passwordHash: newPasswordHash }
                });

                // Why: existing JWTs remain valid until expiry. Revoking all refresh
                // tokens forces re-login, closing any stolen sessions.
                await tx.refreshToken.updateMany({
                    where: { userId, revokedAt: null },
                    data: { revokedAt: new Date() }
                });
            });

            Logger.info('Password changed successfully', { userId });
            return { message: 'Password changed successfully' };
        } catch (error) {
            Logger.error('Change password error', { error });
            return reply.code(500).send({ error: 'Internal server error' });
        }
    });

    // 2FA SETUP
    fastify.post('/2fa/setup', { preHandler: requireAuthFastify }, async (request, reply) => {
        try {
            const user = await prisma.user.findUnique({ where: { id: request.user!.id } });
            if (!user) return reply.code(404).send({ error: 'User not found' });
            const { secret, qrCodeUrl } = await SecurityService.generateTwoFactorSecret(user);
            return { secret, qrCodeUrl };
        } catch (error) {
            Logger.error('2FA setup error', { error });
            return reply.code(500).send({ error: 'Internal server error' });
        }
    });

    // 2FA VERIFY & ENABLE
    fastify.post('/2fa/verify', { preHandler: requireAuthFastify }, async (request, reply) => {
        try {
            const { token, secret } = request.body as { token: string; secret: string };
            const isValid = SecurityService.verifyTwoFactorToken(token, secret);
            if (!isValid) return reply.code(400).send({ error: 'Invalid token' });
            const backupCodes = await SecurityService.enableTwoFactor(request.user!.id, secret);
            return { message: '2FA enabled successfully', backupCodes };
        } catch (error) {
            Logger.error('2FA verify error', { error });
            return reply.code(500).send({ error: 'Internal server error' });
        }
    });

    // REFRESH TOKEN
    fastify.post('/refresh', async (request, reply) => {
        try {
            const { refreshToken } = request.body as { refreshToken?: string };
            if (!refreshToken) return reply.code(400).send({ error: 'Refresh token required' });
            const tokens = await SecurityService.refreshSession(refreshToken, request.ip, request.headers['user-agent'] as string);
            return tokens;
        } catch (error) {
            return reply.code(401).send({ error: 'Invalid or expired refresh token' });
        }
    });

    // REVOKE SESSION (LOGOUT)
    fastify.post('/revoke', { preHandler: requireAuthFastify }, async (request, reply) => {
        try {
            const { refreshToken } = request.body as { refreshToken?: string };
            if (refreshToken) {
                // Why: verify the token belongs to the requesting user to prevent cross-user session revocation
                const hashedToken = crypto.createHash('sha256').update(refreshToken).digest('hex');
                const tokenRecord = await prisma.refreshToken.findUnique({ where: { token: hashedToken } });

                if (!tokenRecord || tokenRecord.userId !== request.user!.id) {
                    return reply.code(403).send({ error: 'Token does not belong to this user' });
                }

                await prisma.refreshToken.update({
                    where: { id: tokenRecord.id },
                    data: { revokedAt: new Date() }
                });
            }
            return { message: 'Logged out successfully' };
        } catch (error) {
            return reply.code(500).send({ error: 'Internal server error' });
        }
    });

    // REVOKE ALL SESSIONS
    fastify.post('/revoke-all', { preHandler: requireAuthFastify }, async (request, reply) => {
        try {
            await SecurityService.revokeUserSessions(request.user!.id);
            return { message: 'All sessions revoked' };
        } catch (error) {
            return reply.code(500).send({ error: 'Internal server error' });
        }
    });
};

export default authRoutes;

/**
 * CAPI Settings Routes — Fastify Plugin
 *
 * Management endpoints for server-side conversion tracking configuration.
 * Handles platform credential storage, test events, and delivery log viewing.
 */

import { FastifyPluginAsync } from 'fastify';
import { prisma } from '../utils/prisma';
import { Logger } from '../utils/logger';
import { ConversionForwarder } from '../services/tracking/ConversionForwarder';
import { getSupportedPlatforms } from '../services/tracking/conversionUtils';
import { requireAuthFastify } from '../middleware/auth';

/** Maps URL platform param → AccountFeature.featureKey */
const PLATFORM_FEATURE_KEY: Record<string, string> = {
    meta: 'META_CAPI',
    tiktok: 'TIKTOK_EVENTS_API',
    google: 'GOOGLE_ENHANCED_CONVERSIONS',
    pinterest: 'PINTEREST_CAPI',
    ga4: 'GA4_MEASUREMENT',
    snapchat: 'SNAPCHAT_CAPI',
    microsoft: 'MICROSOFT_CAPI',
    twitter: 'TWITTER_CAPI',
    _consent: 'CONSENT_MODE',
};

const capiRoutes: FastifyPluginAsync = async (fastify) => {
    /**
     * GET /api/capi/config — Get all CAPI platform configs for account
     */
    fastify.get('/config', { preHandler: requireAuthFastify }, async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'Account context required' });

        const features = await prisma.accountFeature.findMany({
            where: {
                accountId,
                featureKey: { in: Object.values(PLATFORM_FEATURE_KEY) },
            },
            select: {
                featureKey: true,
                isEnabled: true,
                config: true,
                updatedAt: true,
            },
        });

        // Build a map of platform → config for the frontend
        const platforms: Record<string, any> = {};
        let consent: Record<string, any> | null = null;
        for (const [urlKey, featureKey] of Object.entries(PLATFORM_FEATURE_KEY)) {
            const feature = features.find((f) => f.featureKey === featureKey);
            if (urlKey === '_consent') {
                consent = (feature?.config as Record<string, any>) || null;
                continue;
            }
            platforms[urlKey] = {
                enabled: feature?.isEnabled || false,
                config: feature?.config || {},
                updatedAt: feature?.updatedAt || null,
            };
        }

        return { platforms, consent };
    });

    /**
     * PUT /api/capi/config/:platform — Save config for a specific platform
     */
    fastify.put('/config/:platform', { preHandler: requireAuthFastify }, async (request, reply) => {
        const { platform } = request.params as { platform: string };
        const accountId = request.accountId;
        const { enabled, config } = request.body as {
            enabled: boolean;
            config: Record<string, any>;
        };

        if (!accountId) return reply.code(400).send({ error: 'Account context required' });

        const featureKey = PLATFORM_FEATURE_KEY[platform];
        if (!featureKey) {
            return reply.code(400).send({
                error: `Invalid platform: ${platform}. Supported: ${Object.keys(PLATFORM_FEATURE_KEY).join(', ')}`,
            });
        }

        await prisma.accountFeature.upsert({
            where: { accountId_featureKey: { accountId, featureKey } },
            create: {
                accountId,
                featureKey,
                isEnabled: enabled,
                config: config as object,
            },
            update: {
                isEnabled: enabled,
                config: config as object,
            },
        });

        // Invalidate cached config so ConversionForwarder picks up changes immediately
        ConversionForwarder.invalidateCache(accountId);

        Logger.info('[CAPI] Platform config updated', { accountId, platform, enabled });
        return { success: true };
    });

    /**
     * DELETE /api/capi/config/:platform — Disable a platform
     */
    fastify.delete('/config/:platform', { preHandler: requireAuthFastify }, async (request, reply) => {
        const { platform } = request.params as { platform: string };
        const accountId = request.accountId;

        if (!accountId) return reply.code(400).send({ error: 'Account context required' });

        const featureKey = PLATFORM_FEATURE_KEY[platform];
        if (!featureKey) {
            return reply.code(400).send({ error: `Invalid platform: ${platform}` });
        }

        await prisma.accountFeature.updateMany({
            where: { accountId, featureKey },
            data: { isEnabled: false },
        });

        ConversionForwarder.invalidateCache(accountId);

        Logger.info('[CAPI] Platform disabled', { accountId, platform });
        return { success: true };
    });

    /**
     * POST /api/capi/test/:platform — Send a test event to verify connectivity
     */
    fastify.post('/test/:platform', { preHandler: requireAuthFastify }, async (request, reply) => {
        const { platform } = request.params as { platform: string };
        const accountId = request.accountId;

        if (!accountId) return reply.code(400).send({ error: 'Account context required' });

        const featureKey = PLATFORM_FEATURE_KEY[platform];
        if (!featureKey) {
            return reply.code(400).send({ error: `Invalid platform: ${platform}` });
        }

        // Get the platform config
        const feature = await prisma.accountFeature.findUnique({
            where: { accountId_featureKey: { accountId, featureKey } },
        });

        if (!feature?.isEnabled || !feature?.config) {
            return reply.code(400).send({ error: `Platform ${platform} is not configured` });
        }

        // Send a test purchase event through the ConversionForwarder
        const testData = {
            accountId,
            visitorId: 'test-visitor',
            type: 'purchase',
            url: 'https://example.com/test-order',
            eventId: `test-${Date.now()}`,
            payload: {
                orderId: 'TEST-001',
                total: 1.00,
                currency: 'USD',
                email: 'test@example.com',
                items: [{ id: '1', name: 'Test Product', quantity: 1, price: 1.00 }],
            },
        };

        try {
            await ConversionForwarder.forwardIfConversion(testData as any, null);
            return { success: true, message: `Test event sent to ${platform}. Check your platform's event debugger.` };
        } catch (error: any) {
            Logger.error('[CAPI] Test event failed', { platform, error: error.message });
            return reply.code(500).send({ error: `Test event failed: ${error.message}` });
        }
    });

    /**
     * GET /api/capi/deliveries — List recent CAPI delivery logs
     */
    fastify.get('/deliveries', { preHandler: requireAuthFastify }, async (request, reply) => {
        const accountId = request.accountId;
        const { platform, status, limit = '50', page = '1' } = request.query as {
            platform?: string;
            status?: string;
            limit?: string;
            page?: string;
        };

        if (!accountId) return reply.code(400).send({ error: 'Account context required' });

        const take = Math.min(parseInt(limit, 10) || 50, 100);
        const skip = ((parseInt(page, 10) || 1) - 1) * take;

        const where: Record<string, any> = { accountId };
        if (platform) where.platform = platform.toUpperCase();
        if (status) where.status = status.toUpperCase();

        const [deliveries, total] = await Promise.all([
            prisma.conversionDelivery.findMany({
                where,
                orderBy: { createdAt: 'desc' },
                take,
                skip,
                select: {
                    id: true,
                    platform: true,
                    eventName: true,
                    eventId: true,
                    status: true,
                    httpStatus: true,
                    attempts: true,
                    lastError: true,
                    response: true,
                    payload: true,
                    sentAt: true,
                    createdAt: true,
                },
            }),
            prisma.conversionDelivery.count({ where }),
        ]);

        return {
            deliveries,
            total,
            page: parseInt(page, 10) || 1,
            totalPages: Math.ceil(total / take),
        };
    });
    /**
     * GET /api/capi/health — Delivery health dashboard aggregations.
     * Returns per-platform success/failure rates, daily failure trend,
     * event type breakdown, and recent failures in a single request.
     */
    fastify.get('/health', { preHandler: requireAuthFastify }, async (request, reply) => {
        const accountId = request.accountId;
        const { range = '7d' } = request.query as { range?: string };
        if (!accountId) return reply.code(400).send({ error: 'Account context required' });

        const rangeMs: Record<string, number> = {
            '24h': 24 * 60 * 60 * 1000,
            '7d': 7 * 24 * 60 * 60 * 1000,
            '30d': 30 * 24 * 60 * 60 * 1000,
        };
        const ms = rangeMs[range] || rangeMs['7d'];
        const rangeStart = new Date(Date.now() - ms);
        const trendStart = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);

        const [platformSummary, failureTrend, eventBreakdown, recentFailures] = await Promise.all([
            // 1. Per-platform × status counts
            prisma.conversionDelivery.groupBy({
                by: ['platform', 'status'],
                where: { accountId, createdAt: { gte: rangeStart } },
                _count: { _all: true },
            }),

            // 2. Daily failure counts (always 30 days for stable chart)
            prisma.$queryRaw<Array<{ date: string; count: bigint }>>`
                SELECT DATE("createdAt") as date, COUNT(*)::bigint as count
                FROM "ConversionDelivery"
                WHERE "accountId" = ${accountId}
                  AND "status" = 'FAILED'
                  AND "createdAt" >= ${trendStart}
                GROUP BY DATE("createdAt")
                ORDER BY date
            `,

            // 3. Per-platform × event × status counts
            prisma.conversionDelivery.groupBy({
                by: ['platform', 'eventName', 'status'],
                where: { accountId, createdAt: { gte: rangeStart } },
                _count: { _all: true },
            }),

            // 4. Recent failures (most recent 20)
            prisma.conversionDelivery.findMany({
                where: { accountId, status: 'FAILED' },
                orderBy: { createdAt: 'desc' },
                take: 20,
                select: {
                    id: true,
                    platform: true,
                    eventName: true,
                    eventId: true,
                    httpStatus: true,
                    lastError: true,
                    attempts: true,
                    createdAt: true,
                },
            }),
        ]);

        return {
            platformSummary: platformSummary.map(r => ({
                platform: r.platform,
                status: r.status,
                count: r._count._all,
            })),
            failureTrend: failureTrend.map(r => ({
                date: String(r.date),
                count: Number(r.count),
            })),
            eventBreakdown: eventBreakdown.map(r => ({
                platform: r.platform,
                eventName: r.eventName,
                status: r.status,
                count: r._count._all,
            })),
            recentFailures,
            range,
        };
    });

    /**
     * GET /api/capi/pixels/:accountId — Public endpoint for WC plugin.
     *
     * Why public: The WC plugin fetches pixel IDs via wp_remote_get and caches
     * with a transient. Only non-secret fields (pixel IDs, event toggles) are
     * returned — access tokens are never exposed.
     */
    fastify.get('/pixels/:accountId', async (request, reply) => {
        const { accountId } = request.params as { accountId: string };
        if (!accountId) return reply.code(400).send({ error: 'accountId required' });

        const features = await prisma.accountFeature.findMany({
            where: {
                accountId,
                featureKey: { in: Object.values(PLATFORM_FEATURE_KEY) },
            },
            select: { featureKey: true, isEnabled: true, config: true },
        });

        /** Strip access tokens — only return pixel IDs and event toggles */
        const SAFE_FIELDS: Record<string, string[]> = {
            META_CAPI: ['pixelId', 'events', 'advancedMatching', 'contentIdFormat', 'contentIdPrefix', 'contentIdSuffix', 'excludeShipping', 'excludeTax'],
            TIKTOK_EVENTS_API: ['pixelCode', 'events', 'advancedMatching'],
            GA4_MEASUREMENT: ['measurementId', 'events'],
            GOOGLE_ENHANCED_CONVERSIONS: ['conversionId', 'conversionLabel', 'conversionLabelAddToCart', 'conversionLabelBeginCheckout', 'conversionLabelViewItem', 'events'],
            PINTEREST_CAPI: ['tagId', 'events'],
            SNAPCHAT_CAPI: ['pixelId', 'events'],
            MICROSOFT_CAPI: ['tagId', 'events'],
            TWITTER_CAPI: ['pixelId', 'events'],
            CONSENT_MODE: ['autoAccept'],
        };

        const pixels: Record<string, any> = {};
        for (const [urlKey, featureKey] of Object.entries(PLATFORM_FEATURE_KEY)) {
            const feature = features.find(f => f.featureKey === featureKey);

            // Consent config goes under _consent key
            if (urlKey === '_consent') {
                if (feature) {
                    const raw = (feature.config as Record<string, any>) || {};
                    pixels['_consent'] = { autoAccept: !!raw.autoAccept };
                }
                continue;
            }

            if (!feature?.isEnabled) continue;

            const raw = (feature.config as Record<string, any>) || {};
            const allowed = SAFE_FIELDS[featureKey] || [];
            const safeConfig: Record<string, any> = {};
            for (const key of allowed) {
                if (raw[key] !== undefined) safeConfig[key] = raw[key];
            }
            pixels[urlKey] = safeConfig;
        }

        // Long cache header — WC plugin also caches via transient
        reply.header('Cache-Control', 'public, max-age=300');
        return pixels;
    });
};

export default capiRoutes;

/**
 * Chat Routes - Fastify Plugin Factory
 * Requires ChatService injection for Socket.IO integration.
 * 
 * Modular sub-routes extracted for maintainability:
 * - cannedResponses.ts: Canned response templates
 * - macros.ts: Chat macros
 * - blockedContacts.ts: Blocked contact management
 * - bulkActions.ts: Bulk conversation actions
 * - messages.ts: Message CRUD, attachments, reactions
 * - scheduling.ts: Scheduled messages, snooze
 * - notes.ts: Conversation notes and labels
 */

import { FastifyPluginAsync } from 'fastify';
import { prisma } from '../utils/prisma';
import { ChatService } from '../services/ChatService';
import { EmailService } from '../services/EmailService';
import { InboxAIService } from '../services/InboxAIService';
import { requireAuthFastify } from '../middleware/auth';
import { Logger } from '../utils/logger';
import path from 'path';
import fs from 'fs';
import { pipeline } from 'stream/promises';

// Modular sub-routes (extracted for maintainability)
import { cannedResponseRoutes } from './chat/cannedResponses';
import { macroRoutes } from './chat/macros';
import { blockedContactRoutes } from './chat/blockedContacts';
import { createBulkActionRoutes } from './chat/bulkActions';
import { createMessageRoutes } from './chat/messages';
import { schedulingRoutes } from './chat/scheduling';
import { notesRoutes } from './chat/notes';

// Ensure attachments directory exists
const attachmentsDir = path.join(__dirname, '../../uploads/attachments');
if (!fs.existsSync(attachmentsDir)) {
    fs.mkdirSync(attachmentsDir, { recursive: true });
}

export const createChatRoutes = (chatService: ChatService): FastifyPluginAsync => {
    return async (fastify) => {
        fastify.addHook('preHandler', requireAuthFastify);

        // Register modular sub-routes
        await fastify.register(cannedResponseRoutes);
        await fastify.register(macroRoutes);
        await fastify.register(blockedContactRoutes);
        await fastify.register(createBulkActionRoutes(chatService));
        await fastify.register(createMessageRoutes(chatService));
        await fastify.register(schedulingRoutes);
        await fastify.register(notesRoutes, { prefix: '/conversations' });

        // GET /conversations
        fastify.get('/conversations', async (request, reply) => {
            try {
                const query = request.query as { status?: string; assignedTo?: string; limit?: string; cursor?: string };
                const accountId = request.accountId;
                if (!accountId) return reply.code(400).send({ error: 'Account ID required' });

                const limit = Math.min(parseInt(query.limit || '50', 10), 100);
                // Fetch one extra to determine if there are more results
                const conversations = await chatService.listConversations(
                    accountId,
                    query.status,
                    query.assignedTo,
                    limit + 1,
                    query.cursor
                );

                const hasMore = conversations.length > limit;
                const result = hasMore ? conversations.slice(0, limit) : conversations;

                return {
                    conversations: result,
                    hasMore,
                    nextCursor: hasMore ? result[result.length - 1]?.id : null
                };
            } catch (error) {
                Logger.error('Failed to fetch conversations', { error });
                return reply.code(500).send({ error: 'Failed to fetch conversations' });
            }
        });

        // GET /conversations/search - Global search across conversations
        fastify.get('/conversations/search', async (request, reply) => {
            try {
                const { q, limit = '20' } = request.query as { q?: string; limit?: string };
                const accountId = request.accountId;
                if (!accountId) return reply.code(400).send({ error: 'Account ID required' });
                if (!q || q.trim().length < 2) return reply.code(400).send({ error: 'Search query must be at least 2 characters' });

                const searchTerm = q.trim().toLowerCase();
                const maxResults = Math.min(parseInt(limit, 10), 50);

                const conversations = await prisma.conversation.findMany({
                    where: {
                        accountId,
                        OR: [
                            { messages: { some: { content: { contains: searchTerm, mode: 'insensitive' } } } },
                            { guestEmail: { contains: searchTerm, mode: 'insensitive' } },
                            { guestName: { contains: searchTerm, mode: 'insensitive' } },
                            { wooCustomer: { firstName: { contains: searchTerm, mode: 'insensitive' } } },
                            { wooCustomer: { lastName: { contains: searchTerm, mode: 'insensitive' } } },
                            { wooCustomer: { email: { contains: searchTerm, mode: 'insensitive' } } }
                        ]
                    },
                    include: {
                        wooCustomer: { select: { firstName: true, lastName: true, email: true } },
                        messages: { take: 1, orderBy: { createdAt: 'desc' } },
                        assignee: { select: { fullName: true } }
                    },
                    orderBy: { updatedAt: 'desc' },
                    take: maxResults
                });

                return { results: conversations, query: q };
            } catch (error) {
                Logger.error('Failed to search conversations', { error });
                return reply.code(500).send({ error: 'Failed to search conversations' });
            }
        });

        // POST /conversations
        fastify.post('/conversations', async (request, reply) => {
            const { accountId: bodyAccountId, wooCustomerId, visitorToken } = request.body as any;
            const accountId = request.accountId;
            if (!accountId) return reply.code(400).send({ error: 'Account ID required' });
            if (bodyAccountId && bodyAccountId !== accountId) {
                return reply.code(400).send({ error: 'Account ID mismatch' });
            }

            const conv = await chatService.createConversation(accountId, wooCustomerId, visitorToken);
            return conv;
        });

        // GET /email-accounts - List configured email accounts for sending
        fastify.get('/email-accounts', async (request, reply) => {
            try {
                const accountId = request.accountId;
                if (!accountId) return reply.code(400).send({ error: 'Account ID required' });

                const accounts = await prisma.emailAccount.findMany({
                    where: {
                        accountId,
                        OR: [
                            { smtpEnabled: true },
                            { relayEndpoint: { not: null } }
                        ]
                    },
                    select: { id: true, name: true, email: true, isDefault: true }
                });
                return accounts;
            } catch (error) {
                Logger.error('Failed to fetch email accounts', { error });
                return reply.code(500).send({ error: 'Failed to fetch email accounts' });
            }
        });

        // POST /compose - Create conversation and send new email
        fastify.post('/compose', async (request, reply) => {
            try {
                const accountId = request.accountId;
                const userId = request.user?.id;

                let to, cc, subject, body, emailAccountId;
                const attachments: any[] = [];

                if (request.isMultipart()) {
                    const parts = request.parts();
                    for await (const part of parts) {
                        if (part.type === 'file') {
                            const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
                            const filename = uniqueSuffix + '-' + part.filename;
                            const filePath = path.join(attachmentsDir, filename);
                            await pipeline(part.file, fs.createWriteStream(filePath));
                            attachments.push({
                                filename: part.filename,
                                path: filePath,
                                contentType: part.mimetype
                            });
                        } else {
                            if (part.fieldname === 'to') to = (part as any).value;
                            if (part.fieldname === 'cc') cc = (part as any).value;
                            if (part.fieldname === 'subject') subject = (part as any).value;
                            if (part.fieldname === 'body') body = (part as any).value;
                            if (part.fieldname === 'emailAccountId') emailAccountId = (part as any).value;
                        }
                    }
                } else {
                    ({ to, cc, subject, body, emailAccountId } = request.body as any);
                }

                if (!accountId) return reply.code(400).send({ error: 'Account ID required' });
                if (!to || !subject || !body || !emailAccountId) {
                    return reply.code(400).send({ error: 'Missing required fields: to, subject, body, emailAccountId' });
                }

                // Validate email format
                const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
                if (!emailRegex.test(to)) {
                    return reply.code(400).send({ error: 'Invalid email format for "to" address' });
                }

                let wooCustomerId: string | null = null;
                const existingCustomer = await prisma.wooCustomer.findFirst({
                    where: { accountId, email: to }
                });
                if (existingCustomer) wooCustomerId = existingCustomer.id;

                const conversation = await prisma.conversation.create({
                    data: {
                        accountId,
                        channel: 'EMAIL',
                        status: 'OPEN',
                        guestEmail: to,
                        wooCustomerId,
                        assignedTo: userId
                    }
                });

                let fullContent = `Subject: ${subject}\n\n${body}`;

                if (attachments.length > 0) {
                    fullContent += '\n\nAttachments:\n';
                    attachments.forEach(att => {
                        const filename = path.basename(att.path);
                        const url = `/uploads/attachments/${filename}`;
                        fullContent += `[${att.filename}](${url})\n`;
                    });
                }

                await chatService.addMessage(conversation.id, fullContent, 'AGENT', userId, false);

                const emailService = new EmailService();
                await emailService.sendEmail(accountId, emailAccountId, to, subject, body, attachments, {
                    source: 'INBOX',
                    sourceId: conversation.id
                });

                if (cc && cc.trim()) {
                    const ccRecipients = cc.split(',').map((e: string) => e.trim()).filter(Boolean);
                    for (const ccEmail of ccRecipients) {
                        await emailService.sendEmail(accountId, emailAccountId, ccEmail, subject, body, attachments, {
                            source: 'INBOX',
                            sourceId: conversation.id
                        });
                    }
                }

                Logger.info('Composed and sent new email', { conversationId: conversation.id, to });
                return { success: true, conversationId: conversation.id };
            } catch (error: any) {
                Logger.error('Failed to compose email', { error: error.message });
                return reply.code(500).send({ error: error.message || 'Failed to send email' });
            }
        });

        // POST /compose-ai - Generate AI-assisted email draft for new composition
        fastify.post('/compose-ai', async (request, reply) => {
            try {
                const accountId = request.accountId;
                const { recipient, subject, currentDraft } = request.body as {
                    recipient?: string;
                    subject?: string;
                    currentDraft?: string;
                };

                if (!accountId) return reply.code(400).send({ error: 'Account ID required' });
                if (!recipient || !subject) {
                    return reply.code(400).send({ error: 'Recipient and subject are required for AI assistance' });
                }

                const result = await InboxAIService.generateComposeAssist(accountId, recipient, subject, currentDraft);
                if (result.error) return reply.code(400).send({ error: result.error });
                return { draft: result.draft };
            } catch (error) {
                Logger.error('Failed to generate compose AI draft', { error });
                return reply.code(500).send({ error: 'Failed to generate AI draft' });
            }
        });

        // GET /unread-count
        fastify.get('/unread-count', async (request, reply) => {
            try {
                const accountId = request.accountId;
                if (!accountId) return reply.code(400).send({ error: 'Account ID required' });
                const count = await chatService.getUnreadCount(accountId);
                return { count };
            } catch (error) {
                Logger.error('Failed to get unread count', { error });
                return reply.code(500).send({ error: 'Failed to get unread count' });
            }
        });

        // --- Settings ---
        fastify.get('/settings', async (request, reply) => {
            const accountId = request.accountId;
            if (!accountId) return {};
            const feature = await prisma.accountFeature.findUnique({
                where: { accountId_featureKey: { accountId, featureKey: 'CHAT_SETTINGS' } }
            });
            return feature?.config || {};
        });

        fastify.post('/settings', async (request, reply) => {
            const accountId = request.accountId;
            if (!accountId) return {};
            const { enabled, businessHours, autoReply, position, showOnMobile, primaryColor, headerText, welcomeMessage, businessTimezone } = request.body as any;
            const config = { enabled, businessHours, autoReply, position, showOnMobile, primaryColor, headerText, welcomeMessage, businessTimezone };

            await prisma.accountFeature.upsert({
                where: { accountId_featureKey: { accountId, featureKey: 'CHAT_SETTINGS' } },
                update: { config, isEnabled: true },
                create: { accountId, featureKey: 'CHAT_SETTINGS', isEnabled: true, config }
            });
            return { success: true };
        });

        // GET /:id
        fastify.get<{ Params: { id: string } }>('/:id', async (request, reply) => {
            const accountId = request.accountId;
            if (!accountId) return reply.code(400).send({ error: 'Account ID required' });
            const conv = await chatService.getConversation(accountId, request.params.id);
            if (!conv) return reply.code(404).send({ error: 'Not found' });
            return conv;
        });

        // GET /:id/available-channels
        fastify.get<{ Params: { id: string } }>('/:id/available-channels', async (request, reply) => {
            try {
                const conv = await prisma.conversation.findUnique({
                    where: { id: request.params.id },
                    include: {
                        wooCustomer: true,
                        socialAccount: true,
                        mergedFrom: { include: { socialAccount: true } }
                    }
                });

                if (!conv || conv.accountId !== request.accountId) {
                    return reply.code(404).send({ error: 'Not found' });
                }

                const channels: Array<{ channel: string; identifier: string; available: boolean }> = [];

                if (conv.channel === 'EMAIL' && (conv.wooCustomer?.email || conv.guestEmail)) {
                    channels.push({
                        channel: 'EMAIL',
                        identifier: conv.wooCustomer?.email || conv.guestEmail || 'Unknown',
                        available: true
                    });
                } else if (conv.channel === 'CHAT' && conv.visitorToken) {
                    channels.push({
                        channel: 'CHAT',
                        identifier: conv.guestName || 'Visitor',
                        available: true
                    });
                } else if (['FACEBOOK', 'INSTAGRAM', 'TIKTOK'].includes(conv.channel) && conv.socialAccount) {
                    channels.push({
                        channel: conv.channel,
                        identifier: conv.socialAccount.name,
                        available: true
                    });
                } else if (conv.channel === 'SMS' && conv.externalConversationId) {
                    channels.push({
                        channel: 'SMS',
                        identifier: conv.externalConversationId,
                        available: true
                    });
                }

                for (const merged of conv.mergedFrom) {
                    if (['FACEBOOK', 'INSTAGRAM', 'TIKTOK'].includes(merged.channel) && merged.socialAccount) {
                        if (!channels.find(c => c.channel === merged.channel)) {
                            channels.push({
                                channel: merged.channel,
                                identifier: merged.socialAccount.name,
                                available: true
                            });
                        }
                    } else if (merged.channel === 'EMAIL' && merged.guestEmail) {
                        if (!channels.find(c => c.channel === 'EMAIL')) {
                            channels.push({
                                channel: 'EMAIL',
                                identifier: merged.guestEmail,
                                available: true
                            });
                        }
                    } else if (merged.channel === 'SMS' && merged.externalConversationId) {
                        if (!channels.find(c => c.channel === 'SMS' && c.identifier === merged.externalConversationId)) {
                            channels.push({
                                channel: 'SMS',
                                identifier: merged.externalConversationId,
                                available: true
                            });
                        }
                    }
                }

                return { channels, currentChannel: conv.channel };
            } catch (error) {
                Logger.error('Failed to get available channels', { error });
                return reply.code(500).send({ error: 'Failed to get available channels' });
            }
        });

        // PUT /:id
        fastify.put<{ Params: { id: string } }>('/:id', async (request, reply) => {
            const { status, assignedTo, wooCustomerId } = request.body as any;
            const { id } = request.params;
            const accountId = request.accountId;
            if (!accountId) return reply.code(400).send({ error: 'Account ID required' });

            if (status) await chatService.updateStatus(accountId, id, status);
            if (assignedTo) await chatService.assignConversation(accountId, id, assignedTo);
            if (wooCustomerId) await chatService.linkCustomer(accountId, id, wooCustomerId);
            return { success: true };
        });

        // POST /:id/merge
        fastify.post<{ Params: { id: string } }>('/:id/merge', async (request, reply) => {
            const { sourceId } = request.body as any;
            const accountId = request.accountId;
            if (!accountId) return reply.code(400).send({ error: 'Account ID required' });

            await chatService.mergeConversations(accountId, request.params.id, sourceId);
            return { success: true };
        });

        // POST /:id/read
        fastify.post<{ Params: { id: string } }>('/:id/read', async (request, reply) => {
            try {
                const accountId = request.accountId;
                if (!accountId) return reply.code(400).send({ error: 'Account ID required' });

                await chatService.markAsRead(accountId, request.params.id);
                return { success: true };
            } catch (error) {
                Logger.error('Failed to mark conversation as read', { error });
                return reply.code(500).send({ error: 'Failed to mark as read' });
            }
        });

        // POST /:id/ai-draft
        fastify.post<{ Params: { id: string } }>('/:id/ai-draft', async (request, reply) => {
            try {
                const conversationId = request.params.id;
                const accountId = request.accountId;
                const { currentDraft } = request.body as { currentDraft?: string };
                if (!accountId) return reply.code(400).send({ error: 'Account ID required' });

                const result = await InboxAIService.generateDraftReply(conversationId, accountId, currentDraft);
                if (result.error) return reply.code(400).send({ error: result.error });
                return { draft: result.draft };
            } catch (error) {
                Logger.error('Failed to generate AI draft', { error });
                return reply.code(500).send({ error: 'Failed to generate AI draft' });
            }
        });
    };
};

