/**
 * Canned Responses Routes
 * 
 * Handles canned response templates and labels for the inbox.
 * Extracted from chat.ts for maintainability.
 */

import { FastifyPluginAsync } from 'fastify';
import { prisma } from '../../utils/prisma';
import { requireAuthFastify } from '../../middleware/auth';

export const cannedResponseRoutes: FastifyPluginAsync = async (fastify) => {
    fastify.addHook('preHandler', requireAuthFastify);

    // --- Canned Response Labels ---
    fastify.get('/canned-labels', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return [];
        const labels = await prisma.cannedResponseLabel.findMany({
            where: { accountId },
            orderBy: { name: 'asc' }
        });
        return labels;
    });

    fastify.post('/canned-labels', async (request, reply) => {
        const { name, color } = request.body as any;
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'Account ID required' });
        if (!name?.trim()) return reply.code(400).send({ error: 'Name is required' });

        try {
            const label = await prisma.cannedResponseLabel.create({
                data: { name: name.trim(), color: color || '#6366f1', accountId }
            });
            return label;
        } catch (error: any) {
            if (error.code === 'P2002') {
                return reply.code(409).send({ error: 'A label with this name already exists' });
            }
            throw error;
        }
    });

    fastify.put<{ Params: { id: string } }>('/canned-labels/:id', async (request, reply) => {
        const { name, color } = request.body as any;
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'Account ID required' });

        // Verify ownership before update
        const existing = await prisma.cannedResponseLabel.findFirst({
            where: { id: request.params.id, accountId }
        });
        if (!existing) return reply.code(404).send({ error: 'Label not found' });

        try {
            const label = await prisma.cannedResponseLabel.update({
                where: { id: request.params.id },
                data: {
                    ...(name && { name: name.trim() }),
                    ...(color && { color })
                }
            });
            return label;
        } catch (error: any) {
            if (error.code === 'P2002') {
                return reply.code(409).send({ error: 'A label with this name already exists' });
            }
            throw error;
        }
    });

    fastify.delete<{ Params: { id: string } }>('/canned-labels/:id', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'Account ID required' });

        // Verify ownership before delete
        const existing = await prisma.cannedResponseLabel.findFirst({
            where: { id: request.params.id, accountId }
        });
        if (!existing) return reply.code(404).send({ error: 'Label not found' });

        await prisma.cannedResponseLabel.delete({ where: { id: request.params.id } });
        return { success: true };
    });

    // --- Canned Responses ---
    fastify.get('/canned-responses', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return [];
        const responses = await prisma.cannedResponse.findMany({
            where: { accountId },
            include: { label: true },
            orderBy: [{ shortcut: 'asc' }]
        });
        return responses;
    });

    fastify.post('/canned-responses', async (request, reply) => {
        const { shortcut, content, labelId } = request.body as any;
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'Account ID required' });
        const resp = await prisma.cannedResponse.create({
            data: { shortcut, content, labelId: labelId || null, accountId },
            include: { label: true }
        });
        return resp;
    });

    fastify.put<{ Params: { id: string } }>('/canned-responses/:id', async (request, reply) => {
        const { shortcut, content, labelId } = request.body as any;
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'Account ID required' });

        // Verify ownership before update
        const existing = await prisma.cannedResponse.findFirst({
            where: { id: request.params.id, accountId }
        });
        if (!existing) return reply.code(404).send({ error: 'Canned response not found' });

        const resp = await prisma.cannedResponse.update({
            where: { id: request.params.id },
            data: { shortcut, content, labelId: labelId || null },
            include: { label: true }
        });
        return resp;
    });

    fastify.delete<{ Params: { id: string } }>('/canned-responses/:id', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'Account ID required' });

        // Verify ownership before delete
        const existing = await prisma.cannedResponse.findFirst({
            where: { id: request.params.id, accountId }
        });
        if (!existing) return reply.code(404).send({ error: 'Canned response not found' });

        await prisma.cannedResponse.delete({ where: { id: request.params.id } });
        return { success: true };
    });
};

/**
 * Inbox Macros Routes
 * 
 * Handles automated macro actions for the inbox.
 * Extracted from chat.ts for maintainability.
 */

import { FastifyPluginAsync } from 'fastify';
import { prisma } from '../../utils/prisma';
import { requireAuthFastify } from '../../middleware/auth';

export const macroRoutes: FastifyPluginAsync = async (fastify) => {
    fastify.addHook('preHandler', requireAuthFastify);

    // GET /macros - List all macros for account
    fastify.get('/macros', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return [];
        return prisma.inboxMacro.findMany({
            where: { accountId },
            orderBy: { sortOrder: 'asc' }
        });
    });

    // POST /macros - Create a new macro
    fastify.post('/macros', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'Account required' });
        const { name, icon, color, actions } = request.body as any;
        return prisma.inboxMacro.create({
            data: { accountId, name, icon, color, actions }
        });
    });

    // PUT /macros/:id - Update a macro
    fastify.put<{ Params: { id: string } }>('/macros/:id', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'Account required' });
        const { name, icon, color, actions, sortOrder } = request.body as any;

        // Verify ownership before update
        const existing = await prisma.inboxMacro.findFirst({
            where: { id: request.params.id, accountId }
        });
        if (!existing) return reply.code(404).send({ error: 'Macro not found' });

        return prisma.inboxMacro.update({
            where: { id: request.params.id },
            data: { name, icon, color, actions, sortOrder }
        });
    });

    // DELETE /macros/:id - Delete a macro
    fastify.delete<{ Params: { id: string } }>('/macros/:id', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'Account required' });

        // Verify ownership before delete
        const existing = await prisma.inboxMacro.findFirst({
            where: { id: request.params.id, accountId }
        });
        if (!existing) return reply.code(404).send({ error: 'Macro not found' });

        await prisma.inboxMacro.delete({ where: { id: request.params.id } });
        return { success: true };
    });

    // POST /macros/:id/execute - Execute a macro on a conversation
    fastify.post<{ Params: { id: string } }>('/macros/:id/execute', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'Account required' });
        const { conversationId } = request.body as any;
        if (!conversationId) return reply.code(400).send({ error: 'conversationId required' });

        // Verify macro belongs to this account
        const macro = await prisma.inboxMacro.findFirst({ where: { id: request.params.id, accountId } });
        if (!macro) return reply.code(404).send({ error: 'Macro not found' });

        const actions = macro.actions as any[];
        // Verify conversation belongs to this account
        const conv = await prisma.conversation.findFirst({ where: { id: conversationId, accountId } });
        if (!conv) return reply.code(404).send({ error: 'Conversation not found' });

        for (const action of actions) {
            if (action.type === 'ASSIGN' && action.userId) {
                await prisma.conversation.update({
                    where: { id: conversationId },
                    data: { assignedTo: action.userId }
                });
            }
            if (action.type === 'ADD_TAG' && action.labelId) {
                await prisma.conversationLabelAssignment.upsert({
                    where: { conversationId_labelId: { conversationId, labelId: action.labelId } },
                    create: { conversationId, labelId: action.labelId },
                    update: {}
                });
            }
            if (action.type === 'CLOSE') {
                await prisma.conversation.update({
                    where: { id: conversationId },
                    data: { status: 'CLOSED' }
                });
            }
            if (action.type === 'REOPEN') {
                await prisma.conversation.update({
                    where: { id: conversationId },
                    data: { status: 'OPEN' }
                });
            }
        }

        return { success: true, actionsExecuted: actions.length };
    });
};

/**
 * Dashboard Route - Fastify Plugin
 */

import { FastifyPluginAsync } from 'fastify';
import { requireAuthFastify } from '../middleware/auth';
import { prisma } from '../utils/prisma';
import { Logger } from '../utils/logger';
import { AdsTools } from '../services/tools/AdsTools';
import { cacheAside, cacheDelete, CacheTTL, CacheNamespace, invalidateCache } from '../utils/cache';

const dashboardRoutes: FastifyPluginAsync = async (fastify) => {
    fastify.addHook('preHandler', requireAuthFastify);

    // GET /api/dashboard/inbox-count
    // Cached for 30 seconds to reduce database load from frequent UI polls
    fastify.get('/inbox-count', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account' });

        try {
            const openCount = await cacheAside(
                `inbox-count:${accountId}`,
                async () => prisma.conversation.count({
                    where: { accountId, status: 'OPEN' }
                }),
                { ttl: CacheTTL.SHORT, namespace: 'dashboard' }
            );
            return { open: openCount };
        } catch (error) {
            Logger.error('Failed to fetch inbox count', { error, accountId });
            return reply.code(500).send({ error: 'Failed to fetch inbox count' });
        }
    });

    // GET /api/dashboard/ad-suggestions
    fastify.get<{ Querystring: { refresh?: string } }>('/ad-suggestions', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account' });

        try {
            // Fetch saved context to pass to optimizer
            const savedContext = await prisma.adSuggestionContext.findUnique({
                where: { accountId },
                select: { context: true }
            });

            const result = await AdsTools.getAdOptimizationSuggestions(accountId, {
                userContext: savedContext?.context,
                includeInventory: true
            });

            if (typeof result === 'string') {
                return {
                    suggestions: [],
                    action_items: [],
                    message: result
                };
            }

            return result;
        } catch (error) {
            Logger.error('Failed to fetch ad suggestions', { error, accountId });
            return reply.code(500).send({ error: 'Failed to fetch ad suggestions' });
        }
    });

    // GET /api/dashboard/ad-suggestions/context
    fastify.get('/ad-suggestions/context', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account' });

        try {
            const context = await prisma.adSuggestionContext.findUnique({
                where: { accountId },
                select: { context: true, updatedAt: true }
            });

            return { context: context?.context || '', updatedAt: context?.updatedAt || null };
        } catch (error) {
            Logger.error('Failed to fetch ad suggestion context', { error, accountId });
            return reply.code(500).send({ error: 'Failed to fetch context' });
        }
    });

    // POST /api/dashboard/ad-suggestions/context
    fastify.post<{ Body: { context: string } }>('/ad-suggestions/context', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account' });

        try {
            const { context } = request.body;

            if (typeof context !== 'string') {
                return reply.code(400).send({ error: 'Context must be a string' });
            }

            // Upsert the context
            const saved = await prisma.adSuggestionContext.upsert({
                where: { accountId },
                update: { context },
                create: { accountId, context }
            });

            Logger.info('Ad suggestion context updated', { accountId, contextLength: context.length });

            return { success: true, updatedAt: saved.updatedAt };
        } catch (error) {
            Logger.error('Failed to save ad suggestion context', { error, accountId });
            return reply.code(500).send({ error: 'Failed to save context' });
        }
    });

    // POST /api/dashboard/ad-suggestions/feedback
    // Saves user feedback on a specific recommendation for learning
    interface FeedbackBody {
        recommendationId: string;
        action: 'dismiss' | 'feedback';
        dismissReason?: string;
        userFeedback?: string;
        recommendation?: {
            headline?: string;
            category?: string;
            platform?: string;
            source?: string;
            tags?: string[];
        };
    }

    fastify.post<{ Body: FeedbackBody }>('/ad-suggestions/feedback', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account' });

        try {
            const { recommendationId, action, dismissReason, userFeedback, recommendation } = request.body;

            if (!recommendationId) {
                return reply.code(400).send({ error: 'recommendationId is required' });
            }

            // Create a log entry for this feedback
            await prisma.recommendationLog.create({
                data: {
                    accountId,
                    recommendationId,
                    text: recommendation?.headline || recommendationId,
                    category: recommendation?.category || 'unknown',
                    priority: 3,
                    platform: recommendation?.platform,
                    confidenceScore: 0,
                    confidenceLevel: 'n/a',
                    status: action === 'dismiss' ? 'dismissed' : 'pending',
                    dismissedAt: action === 'dismiss' ? new Date() : null,
                    dismissReason: dismissReason || null,
                    userFeedback: userFeedback || null,
                    tags: recommendation?.tags ? JSON.stringify(recommendation.tags) : null
                }
            });

            Logger.info('Recommendation feedback saved', {
                accountId,
                recommendationId,
                action,
                dismissReason,
                hasFeedback: !!userFeedback
            });

            return { success: true };
        } catch (error) {
            Logger.error('Failed to save recommendation feedback', { error, accountId });
            return reply.code(500).send({ error: 'Failed to save feedback' });
        }
    });

    /** Why namespace: dashboard layout is per-user and only changes on explicit save */
    const LAYOUT_NAMESPACE = 'dash-layout';

    // GET Layout
    fastify.get('/', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account' });
        const userId = request.user?.id ?? '';

        return cacheAside(
            `${userId}:${accountId}`,
            async () => {
                let layout = await prisma.dashboardLayout.findFirst({
                    where: { accountId, userId },
                    include: { widgets: { orderBy: { sortOrder: 'asc' } } }
                });

                if (!layout) {
                    layout = await prisma.dashboardLayout.create({
                        data: {
                            accountId,
                            userId,
                            name: 'Main Dashboard',
                            isDefault: true,
                            widgets: {
                                create: [
                                    { widgetKey: 'total-sales', position: { x: 0, y: 0, w: 4, h: 4 }, sortOrder: 0 },
                                    { widgetKey: 'recent-orders', position: { x: 4, y: 0, w: 4, h: 4 }, sortOrder: 1 },
                                    { widgetKey: 'marketing-roas', position: { x: 8, y: 0, w: 4, h: 4 }, sortOrder: 2 },
                                    { widgetKey: 'sales-chart', position: { x: 0, y: 4, w: 8, h: 6 }, sortOrder: 3 },
                                    { widgetKey: 'top-products', position: { x: 8, y: 4, w: 4, h: 6 }, sortOrder: 4 },
                                    { widgetKey: 'customer-growth', position: { x: 0, y: 10, w: 6, h: 6 }, sortOrder: 5 }
                                ]
                            }
                        },
                        include: { widgets: { orderBy: { sortOrder: 'asc' } } }
                    });
                }

                return layout;
            },
            { ttl: CacheTTL.MEDIUM, namespace: LAYOUT_NAMESPACE }
        );
    });

    // SAVE Layout (Widgets Update)
    fastify.post<{ Body: { widgets: Array<{ widgetKey: string; position: any; settings?: any }> } }>('/', async (request, reply) => {
        const accountId = request.accountId;
        if (!accountId) return reply.code(400).send({ error: 'No account' });

        const layout = await prisma.dashboardLayout.findFirst({
            where: { accountId, userId: request.user?.id }
        });

        if (!layout) return reply.code(404).send({ error: 'Dashboard not found' });

        const { widgets } = request.body;

        await prisma.$transaction([
            prisma.dashboardWidget.deleteMany({ where: { dashboardId: layout.id } }),
            prisma.dashboardWidget.createMany({
                data: widgets.map((w, index) => ({
                    dashboardId: layout.id,
                    widgetKey: w.widgetKey,
                    position: w.position,
                    settings: w.settings || {},
                    sortOrder: index
                }))
            })
        ]);

        /** Bust the layout cache so next GET picks up the new widgets */
        const userId = request.user?.id ?? '';
        await cacheDelete(`${userId}:${accountId}`, { namespace: LAYOUT_NAMESPACE });

        const updated = await prisma.dashboardLayout.findUnique({
            where: { id: layout.id },
            include: { widgets: { orderBy: { sortOrder: 'asc' } } }
        });

        return updated;
    });
};

