/**
 * Gold Price Report Routes - Fastify Plugin
 * 
 * Provides endpoints for gold price margin analysis reports.
 * Shows products/variants with gold price enabled, sorted by profit margin.
 */

import { FastifyPluginAsync } from 'fastify';
import { z } from 'zod';
import { prisma } from '../utils/prisma';
import { requireAuthFastify } from '../middleware/auth';
import {
    calculateGoldCogs,
    calculateMargin,
    parseAccountGoldPrices,
    AccountGoldPrices
} from '../utils/goldPriceCalculations';
import { sumMiscCosts } from '../utils/miscCosts';

/** Default and max page sizes for pagination */
const DEFAULT_PAGE_SIZE = 50;
const MAX_PAGE_SIZE = 200;

/** Query params schema for margin report */
const marginQuerySchema = z.object({
    page: z.coerce.number().int().min(1).default(1),
    limit: z.coerce.number().int().min(1).max(MAX_PAGE_SIZE).default(DEFAULT_PAGE_SIZE)
});

interface GoldPriceProduct {
    id: string;
    wooId: number;
    parentWooId?: number;
    name: string;
    variantName?: string;
    sku?: string;
    price: number;
    goldCogs: number;
    profitMargin: number;
    goldPriceType?: string;
    weight?: number;
    mainImage?: string;
    isVariant: boolean;
}

/**
 * Extracts variant name from WooCommerce rawData attributes.
 */
function extractVariantName(rawData: unknown, fallbackId: number): string {
    const data = rawData as { attributes?: { option: string }[] } | undefined;
    const attributes = data?.attributes || [];
    return attributes.map(a => a.option).join(' / ') || `Variant ${fallbackId}`;
}

const goldPriceReportRoutes: FastifyPluginAsync = async (fastify) => {
    // Pre-handler for auth
    fastify.addHook('preHandler', requireAuthFastify);

    /**
     * GET /api/reports/gold-price/margin
     * 
     * Returns gold price enabled products/variants sorted by profit margin (lowest first).
     * Supports pagination via `page` and `limit` query params.
     */
    fastify.get('/gold-price/margin', async (request, reply) => {
        const accountId = (request.headers['x-account-id'] as string) || (request as any).accountId;
        if (!accountId) {
            return reply.status(400).send({ error: 'Account ID required' });
        }

        // Parse pagination params
        const { page, limit } = marginQuerySchema.parse(request.query);

        // Fetch account gold prices
        const account = await prisma.account.findUnique({
            where: { id: accountId },
            select: {
                goldPrice18ct: true,
                goldPrice9ct: true,
                goldPrice18ctWhite: true,
                goldPrice9ctWhite: true
            }
        });

        if (!account) {
            return reply.status(404).send({ error: 'Account not found' });
        }

        const accountPrices = parseAccountGoldPrices(account);

        // Fetch products with gold price enabled
        const products = await prisma.wooProduct.findMany({
            where: {
                accountId,
                isGoldPriceApplied: true
            },
            select: {
                id: true,
                wooId: true,
                name: true,
                sku: true,
                price: true,
                weight: true,
                goldPriceType: true,
                miscCosts: true,
                mainImage: true
            }
        });

        // Fetch variations with gold price enabled
        const variations = await prisma.productVariation.findMany({
            where: {
                product: { accountId },
                isGoldPriceApplied: true
            },
            select: {
                id: true,
                wooId: true,
                sku: true,
                price: true,
                weight: true,
                goldPriceType: true,
                miscCosts: true,
                rawData: true,
                product: {
                    select: {
                        wooId: true,
                        name: true,
                        mainImage: true
                    }
                }
            }
        });

        const results: GoldPriceProduct[] = [];

        // Process products
        for (const p of products) {
            const baseGoldCogs = calculateGoldCogs(
                Number(p.weight) || 0,
                p.goldPriceType,
                accountPrices
            );
            const goldCogs = baseGoldCogs + sumMiscCosts(p.miscCosts);
            const price = Number(p.price) || 0;
            const profitMargin = calculateMargin(price, goldCogs);

            results.push({
                id: p.id,
                wooId: p.wooId,
                name: p.name,
                sku: p.sku || undefined,
                price,
                goldCogs,
                profitMargin,
                goldPriceType: p.goldPriceType || undefined,
                weight: Number(p.weight) || undefined,
                mainImage: p.mainImage || undefined,
                isVariant: false
            });
        }

        // Process variations
        for (const v of variations) {
            const variantName = extractVariantName(v.rawData, v.wooId);

            const baseGoldCogs = calculateGoldCogs(
                Number(v.weight) || 0,
                v.goldPriceType,
                accountPrices
            );
            const goldCogs = baseGoldCogs + sumMiscCosts(v.miscCosts);
            const price = Number(v.price) || 0;
            const profitMargin = calculateMargin(price, goldCogs);

            results.push({
                id: v.id,
                wooId: v.wooId,
                parentWooId: v.product.wooId,
                name: v.product.name,
                variantName,
                sku: v.sku || undefined,
                price,
                goldCogs,
                profitMargin,
                goldPriceType: v.goldPriceType || undefined,
                weight: Number(v.weight) || undefined,
                mainImage: v.product.mainImage || undefined,
                isVariant: true
            });
        }

        // Sort by profit margin (lowest first)
        results.sort((a, b) => a.profitMargin - b.profitMargin);

        // Apply pagination
        const totalCount = results.length;
        const totalPages = Math.ceil(totalCount / limit);
        const startIndex = (page - 1) * limit;
        const paginatedResults = results.slice(startIndex, startIndex + limit);

        return reply.send({
            count: totalCount,
            page,
            limit,
            totalPages,
            products: paginatedResults
        });
    });

    /**
     * GET /api/reports/gold-price/summary
     * 
     * Returns a summary for the dashboard widget.
     * Optimized to fetch only what's needed for the widget.
     */
    fastify.get('/gold-price/summary', async (request, reply) => {
        const accountId = (request.headers['x-account-id'] as string) || (request as any).accountId;
        if (!accountId) {
            return reply.status(400).send({ error: 'Account ID required' });
        }

        // Count products with gold price
        const productCount = await prisma.wooProduct.count({
            where: {
                accountId,
                isGoldPriceApplied: true
            }
        });

        // Count variations with gold price
        const variationCount = await prisma.productVariation.count({
            where: {
                product: { accountId },
                isGoldPriceApplied: true
            }
        });

        const totalCount = productCount + variationCount;

        // Get lowest margin items (top 3)
        const account = await prisma.account.findUnique({
            where: { id: accountId },
            select: {
                goldPrice18ct: true,
                goldPrice9ct: true,
                goldPrice18ctWhite: true,
                goldPrice9ctWhite: true
            }
        });

        let lowestMarginItems: { name: string; margin: number }[] = [];

        if (account && totalCount > 0) {
            const accountPrices = parseAccountGoldPrices(account);

            // Fetch limited items to calculate margins (optimization: only fetch what we might need)
            const products = await prisma.wooProduct.findMany({
                where: { accountId, isGoldPriceApplied: true },
                select: { name: true, price: true, weight: true, goldPriceType: true, miscCosts: true },
                take: 20
            });

            const variations = await prisma.productVariation.findMany({
                where: { product: { accountId }, isGoldPriceApplied: true },
                select: {
                    price: true,
                    weight: true,
                    goldPriceType: true,
                    miscCosts: true,
                    rawData: true,
                    product: { select: { name: true } }
                },
                take: 20
            });

            const allItems: { name: string; margin: number }[] = [];

            for (const p of products) {
                const goldCogs = calculateGoldCogs(Number(p.weight), p.goldPriceType, accountPrices) + sumMiscCosts(p.miscCosts);
                const margin = calculateMargin(Number(p.price), goldCogs);
                allItems.push({ name: p.name, margin });
            }

            for (const v of variations) {
                const variantName = extractVariantName(v.rawData, 0);
                const name = variantName && variantName !== 'Variant 0'
                    ? `${v.product.name} - ${variantName}`
                    : v.product.name;

                const goldCogs = calculateGoldCogs(Number(v.weight), v.goldPriceType, accountPrices) + sumMiscCosts(v.miscCosts);
                const margin = calculateMargin(Number(v.price), goldCogs);
                allItems.push({ name, margin });
            }

            // Sort and take top 3 lowest
            allItems.sort((a, b) => a.margin - b.margin);
            lowestMarginItems = allItems.slice(0, 3);
        }

        return reply.send({
            totalCount,
            productCount,
            variationCount,
            lowestMarginItems
        });
    });
};

export default goldPriceReportRoutes;

/**
 * Health Check Route - Fastify Plugin
 * 
 * Provides health and readiness endpoints for monitoring.
 */

import { FastifyPluginAsync } from 'fastify';
import { prisma } from '../utils/prisma';
import { redisClient } from '../utils/redis';
import { esClient } from '../utils/elastic';
import { Logger } from '../utils/logger';

interface HealthStatus {
    status: 'healthy' | 'degraded' | 'unhealthy';
    timestamp: string;
    uptime: number;
    version: string;
    checks: {
        database: boolean;
        redis: boolean;
        elasticsearch: boolean;
    };
}

const healthRoutes: FastifyPluginAsync = async (fastify) => {
    /**
     * GET /health
     * Basic health check - returns 200 if server is running.
     */
    fastify.get('/', async (request, reply) => {
        return {
            status: 'healthy',
            timestamp: new Date().toISOString(),
            uptime: process.uptime()
        };
    });

    /**
     * GET /health/ready
     * Readiness check - verifies all dependencies are connected.
     */
    fastify.get('/ready', async (request, reply) => {
        const checks = {
            database: false,
            redis: false,
            elasticsearch: false
        };

        // Check database
        try {
            await prisma.$queryRaw`SELECT 1`;
            checks.database = true;
        } catch (error) {
            Logger.warn('[Health] Database check failed', { error });
        }

        // Check Redis
        try {
            await redisClient.ping();
            checks.redis = true;
        } catch (error) {
            Logger.warn('[Health] Redis check failed', { error });
        }

        // Check Elasticsearch
        try {
            const esHealth = await esClient.cluster.health();
            checks.elasticsearch = esHealth.status !== 'red';
        } catch (error) {
            Logger.warn('[Health] Elasticsearch check failed', { error });
        }

        const healthyCount = Object.values(checks).filter(Boolean).length;
        const allHealthy = healthyCount === 3;
        const allDown = healthyCount === 0;

        // Determine overall status
        let overallStatus: 'healthy' | 'degraded' | 'unhealthy';
        if (allHealthy) {
            overallStatus = 'healthy';
        } else if (allDown) {
            overallStatus = 'unhealthy';
        } else {
            overallStatus = 'degraded';
        }

        const status: HealthStatus = {
            status: overallStatus,
            timestamp: new Date().toISOString(),
            uptime: process.uptime(),
            version: process.env.npm_package_version || '1.0.0',
            checks
        };

        // Return 200 for healthy/degraded, 503 only if ALL services are down
        // This allows the container to be marked healthy even if ES is still starting
        return reply.code(allDown ? 503 : 200).send(status);
    });

    /**
     * GET /health/live
     * Liveness check - simple ping for container orchestrators.
     */
    fastify.get('/live', async (request, reply) => {
        return reply.code(200).send('OK');
    });

    /**
     * GET /health/version
     * App version check for PWA update detection.
     * Returns current server version and optional update metadata.
     */
    fastify.get('/version', async (_request, _reply) => {
        // Build version - auto-generated at build time or from environment
        const version = process.env.APP_VERSION || new Date().toISOString().split('T')[0].replace(/-/g, '.');

        return {
            version,
            // Optional: Add release notes or feature highlights
            message: 'Latest improvements and bug fixes',
            features: [
                'Performance improvements',
                'Bug fixes and stability'
            ]
        };
    });
};

export default healthRoutes;

/**
 * BOM Inventory Sync Routes
 * 
 * Handles BOM-based inventory synchronization with WooCommerce.
 * Extracted from inventory.ts for maintainability.
 */

import { FastifyPluginAsync } from 'fastify';
import { prisma } from '../../utils/prisma';
import { requireAuthFastify } from '../../middleware/auth';
import { Logger } from '../../utils/logger';
import { BOMInventorySyncService } from '../../services/BOMInventorySyncService';

export const bomSyncRoutes: FastifyPluginAsync = async (fastify) => {
    fastify.addHook('preHandler', requireAuthFastify);

    /**
     * POST /products/:productId/bom/sync
     * Sync a single product's inventory to WooCommerce based on BOM calculation.
     */
    fastify.post<{ Params: { productId: string } }>('/products/:productId/bom/sync', async (request, reply) => {
        const accountId = request.accountId!;
        const { productId } = request.params;
        const query = request.query as { variationId?: string };
        const variationId = parseInt(query.variationId || '0', 10);

        try {
            const result = await BOMInventorySyncService.syncProductToWoo(accountId, productId, variationId);

            if (!result.success) {
                return reply.code(400).send({
                    error: result.error || 'Sync failed',
                    result
                });
            }

            return result;
        } catch (error) {
            Logger.error('Error syncing BOM inventory', { error, accountId, productId });
            return reply.code(500).send({ error: 'Failed to sync inventory to WooCommerce' });
        }
    });

    /**
     * GET /products/:productId/bom/diagnose
     * Diagnose why a product's BOM sync might not be working.
     */
    fastify.get<{ Params: { productId: string } }>('/products/:productId/bom/diagnose', async (request, reply) => {
        const accountId = request.accountId!;
        const { productId } = request.params;
        const query = request.query as { variationId?: string };
        const variationId = parseInt(query.variationId || '0', 10);

        try {
            // Step 1: Check if product exists
            const product = await prisma.wooProduct.findUnique({
                where: { id: productId },
                select: { id: true, wooId: true, name: true, accountId: true }
            });

            if (!product) {
                return {
                    status: 'error',
                    reason: 'PRODUCT_NOT_FOUND',
                    message: `Product with ID ${productId} does not exist in the database.`
                };
            }

            if (product.accountId !== accountId) {
                return {
                    status: 'error',
                    reason: 'WRONG_ACCOUNT',
                    message: `Product belongs to a different account.`
                };
            }

            // Step 2: Check if BOM exists
            const bom = await prisma.bOM.findUnique({
                where: {
                    productId_variationId: { productId, variationId }
                },
                include: {
                    items: {
                        include: {
                            childProduct: { select: { id: true, wooId: true, name: true } },
                            childVariation: { select: { wooId: true, sku: true, stockQuantity: true } },
                            internalProduct: { select: { id: true, name: true, stockQuantity: true } }
                        }
                    }
                }
            });

            if (!bom) {
                return {
                    status: 'error',
                    reason: 'NO_BOM',
                    message: `No BOM found for product "${product.name}" with variationId=${variationId}. ` +
                        `If this is a variation, make sure variationId matches the WooCommerce variation ID.`,
                    productName: product.name,
                    wooId: product.wooId,
                    variationIdUsed: variationId
                };
            }

            if (bom.items.length === 0) {
                return {
                    status: 'error',
                    reason: 'NO_BOM_ITEMS',
                    message: `BOM exists but has no component items. Add child products or internal products to the BOM.`,
                    productName: product.name,
                    bomId: bom.id
                };
            }

            // Step 3: Categorize items
            const activeItems = bom.items.filter(i => i.isActive);
            const deactivatedItems = bom.items.filter(i => !i.isActive);
            const wooItems = activeItems.filter(i => i.childProductId);
            const internalItems = activeItems.filter(i => i.internalProductId);

            // Step 4: Try the calculation
            const calculation = await BOMInventorySyncService.calculateEffectiveStockLocal(productId, variationId);

            return {
                status: 'ok',
                message: 'BOM configuration looks correct. Sync should work.',
                productName: product.name,
                wooId: product.wooId,
                variationId,
                bomId: bom.id,
                itemBreakdown: {
                    total: bom.items.length,
                    active: activeItems.length,
                    deactivated: deactivatedItems.length,
                    wooCommerceProducts: wooItems.length,
                    internalProducts: internalItems.length
                },
                items: bom.items.map(item => ({
                    type: item.internalProductId ? 'internal' : 'woocommerce',
                    quantity: item.quantity,
                    isActive: item.isActive,
                    deactivatedReason: item.deactivatedReason || null,
                    childName: item.childProduct?.name || item.internalProduct?.name || 'Unknown',
                    childStock: item.childVariation?.stockQuantity ??
                        item.internalProduct?.stockQuantity ??
                        'N/A (fetch from WooCommerce)'
                })),
                effectiveStockCalculation: calculation ? {
                    effectiveStock: calculation.effectiveStock,
                    currentWooStock: calculation.currentWooStock,
                    needsSync: calculation.needsSync,
                    components: calculation.components
                } : 'Calculation returned null - check component stock values'
            };
        } catch (error: any) {
            Logger.error('Error diagnosing BOM sync', { error, accountId, productId });
            return reply.code(500).send({
                status: 'error',
                reason: 'EXCEPTION',
                message: error.message
            });
        }
    });

    /**
     * POST /bom/sync-all
     * Bulk sync ALL BOM parent products for the account to WooCommerce.
     */
    fastify.post('/bom/sync-all', async (request, reply) => {
        const accountId = request.accountId!;

        const { QueueFactory, QUEUES } = await import('../../services/queue/QueueFactory');

        const bomCount = await prisma.bOM.count({
            where: {
                product: { accountId },
                items: {
                    some: {
                        OR: [
                            { childProductId: { not: null } },
                            { internalProductId: { not: null } }
                        ]
                    }
                }
            }
        });

        const queue = QueueFactory.getQueue(QUEUES.BOM_SYNC);
        const jobId = `bom_sync_${accountId.replace(/:/g, '_')}`;

        const existingJob = await queue.getJob(jobId);
        if (existingJob) {
            const state = await existingJob.getState();
            if (['active', 'waiting', 'delayed'].includes(state)) {
                // Check if job is stale (active but not progressing for too long)
                // This handles the "BullMQ Silence" scenario where a worker crashed
                const processedOn = existingJob.processedOn;
                const now = Date.now();
                const STALE_THRESHOLD_MS = 10 * 60 * 1000; // 10 minutes

                if (state === 'active' && processedOn && (now - processedOn > STALE_THRESHOLD_MS)) {
                    // Job is stale - force remove it
                    Logger.warn(`[BOMSync] Detected stale active job, force removing`, {
                        accountId,
                        jobId,
                        processedOn: new Date(processedOn).toISOString(),
                        staleDurationMs: now - processedOn
                    });
                    try {
                        await existingJob.moveToFailed(new Error('Job stale - forcefully removed'), '0');
                        await existingJob.remove();
                    } catch (e) {
                        Logger.warn(`[BOMSync] Failed to remove stale job, proceeding anyway`, { error: e });
                    }
                } else {
                    return {
                        status: 'already_running',
                        message: `BOM sync is already ${state} for this account.`,
                        estimatedProducts: bomCount
                    };
                }
            } else {
                try { await existingJob.remove(); } catch (e) { /* ignore */ }
            }
        }

        await queue.add(QUEUES.BOM_SYNC, { accountId }, {
            jobId,
            priority: 10,
            removeOnComplete: true,
            removeOnFail: 100
        });

        Logger.info(`[BOMInventorySync] Dispatched queue job`, { accountId, jobId, bomCount });

        return {
            status: 'queued',
            message: `BOM sync queued for ${bomCount} products. Check sync history for results.`,
            estimatedProducts: bomCount,
            jobId
        };
    });

    /**
     * GET /bom/sync-status
     * Check current status of BOM sync job for this account.
     */
    fastify.get('/bom/sync-status', async (request, reply) => {
        const accountId = request.accountId!;
        const { QueueFactory, QUEUES } = await import('../../services/queue/QueueFactory');

        const queue = QueueFactory.getQueue(QUEUES.BOM_SYNC);
        const jobId = `bom_sync_${accountId.replace(/:/g, '_')}`;

        try {
            const existingJob = await queue.getJob(jobId);
            if (existingJob) {
                const state = await existingJob.getState();
                if (['active', 'waiting', 'delayed'].includes(state)) {
                    return { isSyncing: true, state };
                }
            }
            return { isSyncing: false, state: null };
        } catch (err) {
            Logger.error('Error checking BOM sync status', { error: err, accountId });
            return { isSyncing: false, state: null };
        }
    });

    /**
     * DELETE /bom/sync-cancel
     * Cancel a stuck or running BOM sync job for this account.
     * Uses aggressive cleanup for orphaned jobs.
     */
    fastify.delete('/bom/sync-cancel', async (request, reply) => {
        const accountId = request.accountId!;
        const { QueueFactory, QUEUES } = await import('../../services/queue/QueueFactory');
        const { redisClient } = await import('../../utils/redis');

        const queue = QueueFactory.getQueue(QUEUES.BOM_SYNC);
        const jobId = `bom_sync_${accountId.replace(/:/g, '_')}`;

        try {
            const existingJob = await queue.getJob(jobId);
            if (existingJob) {
                const state = await existingJob.getState();

                // Try standard removal methods first
                try {
                    await existingJob.remove();
                    Logger.info(`[BOMSync] Cancelled sync job`, { accountId, jobId, previousState: state });
                    return {
                        success: true,
                        message: 'Sync job cancelled successfully',
                        previousState: state
                    };
                } catch (removeErr: any) {
                    // Job is locked - try moveToFailed
                    Logger.warn(`[BOMSync] Standard remove failed, trying moveToFailed`, {
                        error: removeErr.message, jobId
                    });

                    try {
                        await existingJob.moveToFailed(new Error('Cancelled by user'), '0');
                        // Try to remove again after moving to failed
                        try { await existingJob.remove(); } catch (e) { /* ignore */ }

                        Logger.info(`[BOMSync] Force-failed locked sync job`, { accountId, jobId });
                        return {
                            success: true,
                            message: 'Sync job force-cancelled (was locked)',
                            previousState: state
                        };
                    } catch (failErr: any) {
                        // Last resort: directly remove from Redis
                        Logger.warn(`[BOMSync] moveToFailed also failed, using Redis force-clean`, {
                            error: failErr.message, jobId
                        });

                        // Force remove all traces of the job from Redis
                        const queueName = QUEUES.BOM_SYNC;
                        const keysToDelete = [
                            `bull:${queueName}:${jobId}`,
                            `bull:${queueName}:${jobId}:lock`,
                            `bull:${queueName}:${jobId}:logs`,
                        ];

                        // Remove from all state sets
                        await redisClient.zrem(`bull:${queueName}:active`, jobId);
                        await redisClient.zrem(`bull:${queueName}:waiting`, jobId);
                        await redisClient.zrem(`bull:${queueName}:delayed`, jobId);
                        await redisClient.zrem(`bull:${queueName}:failed`, jobId);
                        await redisClient.zrem(`bull:${queueName}:completed`, jobId);

                        // Delete job keys
                        for (const key of keysToDelete) {
                            await redisClient.del(key);
                        }

                        Logger.info(`[BOMSync] Force-cleaned job from Redis`, { accountId, jobId });
                        return {
                            success: true,
                            message: 'Sync job force-cleaned from Redis (orphaned job)',
                            previousState: state
                        };
                    }
                }
            }

            return {
                success: true,
                message: 'No active sync job found to cancel'
            };
        } catch (err: any) {
            Logger.error('Error cancelling BOM sync', { error: err.message, accountId });
            return reply.code(500).send({
                success: false,
                error: `Failed to cancel sync job: ${err.message}`
            });
        }
    });

    /**
     * GET /bom/pending-changes
     * Returns all BOM products with current vs effective stock comparison.
     */
    fastify.get('/bom/pending-changes', async (request, reply) => {
        const accountId = request.accountId!;

        try {
            const bomsWithChildProducts = await prisma.bOM.findMany({
                where: {
                    product: { accountId },
                    items: {
                        some: {
                            isActive: true,
                            OR: [
                                { childProductId: { not: null } },
                                { internalProductId: { not: null } }
                            ]
                        }
                    }
                },
                include: {
                    product: {
                        select: {
                            id: true,
                            wooId: true,
                            name: true,
                            sku: true,
                            mainImage: true,
                            // Include variations so we can lookup variant-specific data
                            variations: {
                                select: {
                                    wooId: true,
                                    sku: true,
                                    images: true,
                                    rawData: true
                                }
                            }
                        }
                    }
                }
            });

            Logger.info(`[BOMSync] Found ${bomsWithChildProducts.length} BOMs with child products`, { accountId });

            const pendingChanges = [];
            let calculationFailures = 0;

            for (const bom of bomsWithChildProducts) {
                try {
                    const calculation = await BOMInventorySyncService.calculateEffectiveStockLocal(
                        bom.productId,
                        bom.variationId
                    );

                    if (calculation) {
                        // For variants, get variant-specific data
                        let displayName = bom.product.name;
                        let displaySku = bom.product.sku;
                        let displayImage = bom.product.mainImage;
                        let displayWooId = bom.product.wooId;

                        if (bom.variationId > 0) {
                            // Find the matching variation
                            const variation = bom.product.variations.find(v => v.wooId === bom.variationId);
                            if (variation) {
                                displayWooId = variation.wooId;
                                displaySku = variation.sku || displaySku;

                                // Get variant name from rawData or construct from attributes
                                const rawData = variation.rawData as any;
                                if (rawData?.attributes?.length > 0) {
                                    const attrStr = rawData.attributes
                                        .map((a: any) => a.option)
                                        .filter(Boolean)
                                        .join(', ');
                                    displayName = `${bom.product.name} - ${attrStr}`;
                                } else {
                                    displayName = `${bom.product.name} (Variant #${variation.wooId})`;
                                }

                                // Get variant image
                                const images = variation.images as any[];
                                if (images?.length > 0 && images[0]?.src) {
                                    displayImage = images[0].src;
                                } else if (rawData?.image?.src) {
                                    displayImage = rawData.image.src;
                                }
                            }
                        }

                        pendingChanges.push({
                            productId: bom.product.id,
                            wooId: displayWooId,
                            name: displayName,
                            sku: displaySku,
                            mainImage: displayImage,
                            variationId: bom.variationId,
                            currentWooStock: calculation.currentWooStock,
                            effectiveStock: calculation.effectiveStock,
                            needsSync: calculation.needsSync,
                            components: calculation.components
                        });
                    } else {
                        calculationFailures++;
                        Logger.warn(`[BOMSync] calculateEffectiveStock returned null for product`, {
                            productId: bom.productId,
                            variationId: bom.variationId,
                            productName: bom.product.name
                        });
                    }
                } catch (calcError) {
                    calculationFailures++;
                    Logger.error(`[BOMSync] calculateEffectiveStock threw error`, {
                        productId: bom.productId,
                        variationId: bom.variationId,
                        error: calcError
                    });
                }
            }

            Logger.info(`[BOMSync] Results: ${pendingChanges.length} success, ${calculationFailures} failures`, { accountId });

            pendingChanges.sort((a, b) => {
                if (a.needsSync !== b.needsSync) return a.needsSync ? -1 : 1;
                return a.name.localeCompare(b.name);
            });

            return {
                total: pendingChanges.length,
                needsSync: pendingChanges.filter(p => p.needsSync).length,
                inSync: pendingChanges.filter(p => !p.needsSync).length,
                products: pendingChanges
            };
        } catch (error) {
            Logger.error('Error fetching pending BOM changes', { error, accountId });
            return reply.code(500).send({ error: 'Failed to fetch pending changes' });
        }
    });

    /**
     * GET /bom/sync-history
     * Returns recent BOM sync logs from AuditLog.
     */
    fastify.get('/bom/sync-history', async (request, reply) => {
        const accountId = request.accountId!;
        const query = request.query as { limit?: string };
        const limit = Math.min(parseInt(query.limit || '50', 10), 100);

        try {
            const logs = await prisma.auditLog.findMany({
                where: {
                    accountId,
                    source: 'SYSTEM_BOM'
                },
                orderBy: { createdAt: 'desc' },
                take: limit,
                select: {
                    id: true,
                    resourceId: true,
                    previousValue: true,
                    details: true,
                    createdAt: true
                }
            });

            const productIds = [...new Set(logs.map(l => l.resourceId))];
            const products = await prisma.wooProduct.findMany({
                where: { id: { in: productIds } },
                select: { id: true, name: true, sku: true }
            });
            const productMap = new Map(products.map(p => [p.id, p]));

            const enrichedLogs = logs.map(log => {
                const product = productMap.get(log.resourceId);
                const prev = log.previousValue as any;
                const details = log.details as any;

                return {
                    id: log.id,
                    productId: log.resourceId,
                    productName: product?.name || 'Unknown Product',
                    productSku: product?.sku,
                    previousStock: prev?.stock_quantity ?? null,
                    newStock: details?.stock_quantity ?? null,
                    trigger: details?.trigger || 'BOM_SYNC',
                    createdAt: log.createdAt
                };
            });

            return {
                total: enrichedLogs.length,
                logs: enrichedLogs
            };
        } catch (error) {
            Logger.error('Error fetching BOM sync history', { error, accountId });
            return reply.code(500).send({ error: 'Failed to fetch sync history' });
        }
    });

    /**
     * GET /bom/consumption-history
     * Returns recent BOM component consumption (deduction ledger entries) for this account.
     * Why: The frontend `useBOMSync` hook exposes `consumptionHistory` state — this endpoint feeds it.
     */
    fastify.get('/bom/consumption-history', async (request, reply) => {
        const accountId = request.accountId!;
        const query = request.query as { limit?: string };
        const limit = Math.min(parseInt(query.limit || '50', 10), 100);

        try {
            const entries = await prisma.bOMDeductionLedger.findMany({
                where: {
                    accountId,
                    status: { in: ['COMPLETED', 'REVERSED'] }
                },
                orderBy: { createdAt: 'desc' },
                take: limit,
                select: {
                    id: true,
                    orderId: true,
                    componentName: true,
                    componentType: true,
                    quantityDeducted: true,
                    previousStock: true,
                    newStock: true,
                    status: true,
                    createdAt: true
                }
            });

            // Enrich with order numbers via a single batch lookup
            const orderIds = [...new Set(entries.map(e => e.orderId))];
            const orders = await prisma.wooOrder.findMany({
                where: { accountId, wooId: { in: orderIds } },
                select: { wooId: true, number: true }
            });
            const orderMap = new Map(orders.map(o => [o.wooId, o.number]));

            const enriched = entries.map(e => ({
                id: e.id,
                orderId: e.orderId,
                orderNumber: orderMap.get(e.orderId) || `#${e.orderId}`,
                productName: e.componentName,
                componentName: e.componentName,
                quantityDeducted: e.quantityDeducted,
                previousStock: e.previousStock,
                newStock: e.newStock,
                createdAt: e.createdAt
            }));

            return { entries: enriched };
        } catch (error) {
            Logger.error('Error fetching consumption history', { error, accountId });
            return reply.code(500).send({ error: 'Failed to fetch consumption history' });
        }
    });
};

/**
 * Google OAuth Routes - Fastify Plugin
 * Google Ads OAuth authorization and callback.
 */

import { FastifyPluginAsync } from 'fastify';
import { AdsService } from '../services/ads';
import { requireAuthFastify } from '../middleware/auth';
import { Logger } from '../utils/logger';
import { buildCallbackUrl, buildFrontendUrl, getAppUrl } from './oauthHelpers';

const CALLBACK_SUFFIX = 'google/callback';

const oauthGoogleRoutes: FastifyPluginAsync = async (fastify) => {
    /**
     * GET /google/callback-url - Return the actual callback URL the server uses.
     * Why: Frontend needs to display this to admins for Google Cloud Console setup,
     * and it may differ from window.location.origin when API_URL is set.
     */
    fastify.get('/google/callback-url', { preHandler: requireAuthFastify }, async (request) => {
        return { callbackUrl: buildCallbackUrl(request, CALLBACK_SUFFIX) };
    });

    /**
     * GET /google/authorize - Initiate Google OAuth
     */
    fastify.get('/google/authorize', { preHandler: requireAuthFastify }, async (request, reply) => {
        try {
            const accountId = request.accountId;
            const query = request.query as { redirect?: string; reconnectId?: string };
            const frontendRedirect = query.redirect || '/settings/integrations';
            const reconnectId = query.reconnectId;

            if (!accountId) return reply.code(400).send({ error: 'No account selected' });

            const state = Buffer.from(JSON.stringify({ accountId, frontendRedirect, reconnectId })).toString('base64url');
            const callbackUrl = buildCallbackUrl(request, CALLBACK_SUFFIX);
            const authUrl = await AdsService.getGoogleAuthUrl(callbackUrl, state);
            return { authUrl };
        } catch (error: any) {
            Logger.error('Failed to generate Google OAuth URL', { error });
            return reply.code(500).send({ error: error.message });
        }
    });

    /**
     * GET /google/callback - Handle Google OAuth callback
     */
    fastify.get('/google/callback', async (request, reply) => {
        let frontendRedirect = buildFrontendUrl('/marketing?tab=ads');

        try {
            const query = request.query as { code?: string; state?: string; error?: string };
            const { code, state, error } = query;

            if (error) {
                Logger.warn('Google OAuth denied', { error });
                return reply.redirect(buildFrontendUrl('/marketing?tab=ads', { error: 'oauth_denied' }));
            }

            if (!code || !state) {
                return reply.redirect(buildFrontendUrl('/marketing?tab=ads', { error: 'missing_params' }));
            }

            let stateData: { accountId: string; frontendRedirect: string; reconnectId?: string };
            try {
                stateData = JSON.parse(Buffer.from(state, 'base64url').toString('utf-8'));
                /* State contains a relative path — use it as the redirect base */
                if (stateData.frontendRedirect) {
                    frontendRedirect = buildFrontendUrl(stateData.frontendRedirect);
                }
            } catch {
                return reply.redirect(buildFrontendUrl('/marketing?tab=ads', { error: 'invalid_state' }));
            }

            const redirectUri = buildCallbackUrl(request, CALLBACK_SUFFIX);
            const tokens = await AdsService.exchangeGoogleCode(code, redirectUri);

            // If reconnecting an existing account, update its tokens
            if (stateData.reconnectId) {
                await AdsService.updateAccountTokens(stateData.reconnectId, {
                    accessToken: tokens.accessToken,
                    refreshToken: tokens.refreshToken || ''
                });
                return reply.redirect(buildFrontendUrl(stateData.frontendRedirect || '/marketing?tab=ads', { success: 'google_reconnected' }));
            }

            // Otherwise create new pending account
            const pendingAccount = await AdsService.connectAccount(stateData.accountId, {
                platform: 'GOOGLE',
                externalId: 'PENDING_SETUP',
                accessToken: tokens.accessToken,
                refreshToken: tokens.refreshToken || '',
                name: 'Google Ads (Pending Setup)'
            });

            return reply.redirect(buildFrontendUrl(
                stateData.frontendRedirect || '/marketing?tab=ads',
                { success: 'google_pending', pendingId: pendingAccount.id }
            ));

        } catch (error: any) {
            Logger.error('Google OAuth callback failed', { error: error.message });
            return reply.redirect(buildFrontendUrl('/marketing?tab=ads', { error: 'oauth_failed', message: error.message }));
        }
    });
};

export default oauthGoogleRoutes;

/**
 * Products Route - Fastify Plugin
 */

import { FastifyPluginAsync } from 'fastify';
import { ProductsService } from '../services/products';
import { requireAuthFastify } from '../middleware/auth';
import { WooService } from '../services/woo';
import { prisma } from '../utils/prisma';
import { Logger } from '../utils/logger';
import { SeoScoringService } from '../services/SeoScoringService';
import { MerchantCenterService } from '../services/MerchantCenterService';
import { IndexingService } from '../services/search/IndexingService';
import { SearchConsoleService } from '../services/search-console/SearchConsoleService';
import { esClient } from '../utils/elastic';
import { marked } from 'marked';
import { z } from 'zod';
import { REVENUE_STATUSES } from '../constants/orderStatus';
import { AuditService } from '../services/AuditService';
import { cacheAside, CacheTTL, invalidateCache } from '../utils/cache';

const searchQuerySchema = z.object({
    page: z.coerce.number().int().positive().default(1),
    limit: z.coerce.number().int().positive().max(100).default(20),
    q: z.string().optional().default('')
});

const productIdParamSchema = z.object({
    id: z.coerce.number().int().positive()
});

const updateProductBodySchema = z.object({
    binLocation: z.string().optional(),
    name: z.string().optional(),
    stockStatus: z.string().optional(),
    manageStock: z.boolean().optional(),
    backorders: z.enum(['no', 'notify', 'yes']).optional(),
    isGoldPriceApplied: z.boolean().optional(),
    goldPriceType: z.string().nullable().optional(),
    sku: z.string().optional(),
    price: z.union([z.string(), z.number()]).transform(val => String(val)).optional(),
    salePrice: z.union([z.string(), z.number()]).transform(val => String(val)).optional(),
    weight: z.union([z.string(), z.number()]).optional(),
    length: z.union([z.string(), z.number()]).optional(),
    width: z.union([z.string(), z.number()]).optional(),
    height: z.union([z.string(), z.number()]).optional(),
    description: z.string().optional(),
    short_description: z.string().optional(),
    cogs: z.union([z.string(), z.number()]).transform(val => val === '' ? undefined : Number(val)).optional(),
    supplierId: z.string().optional(),
    images: z.array(z.any()).optional(),
    focusKeyword: z.string().optional(),
    variations: z.array(z.any()).optional()
});

const createProductBodySchema = z.object({
    name: z.string().min(1)
});

const rewriteDescriptionBodySchema = z.object({
    currentDescription: z.string().optional(),
    productName: z.string().optional(),
    categories: z.string().optional(),
    shortDescription: z.string().optional(),
    focusKeyword: z.string().optional()
});

const stockUpdateBodySchema = z.object({
    stockQuantity: z.number().int().min(0, 'Stock quantity must be a non-negative integer')
});

const productsRoutes: FastifyPluginAsync = async (fastify) => {
    fastify.addHook('preHandler', requireAuthFastify);

    // GET / - Search products (cached for 60s)
    fastify.get('/', async (request, reply) => {
        try {
            const accountId = request.accountId!;
            const { page, limit, q } = searchQuerySchema.parse(request.query);

            // Cache product search results for 60 seconds
            // Key includes query params to avoid returning wrong results
            const cacheKey = `products:list:${accountId}:${page}:${limit}:${q || 'all'}`;
            const result = await cacheAside(
                cacheKey,
                () => ProductsService.searchProducts(accountId, q, page, limit),
                { ttl: CacheTTL.SHORT * 2, namespace: 'products' } // 60s cache
            );

            return result;
        } catch (error: any) {
            Logger.error('Error', { error });
            return reply.code(500).send({ error: 'Failed to fetch products' });
        }
    });
    // POST / - Create product (Currently disabled - products should be created in WooCommerce)
    fastify.post('/', async (_request, reply) => {
        return reply.code(501).send({ error: 'Product creation not yet implemented. Please create products in WooCommerce directly.' });
    });

    // GET /:id - Get single product
    fastify.get<{ Params: { id: string } }>('/:id', async (request, reply) => {
        try {
            const accountId = request.accountId!;
            const { id: wooId } = productIdParamSchema.parse(request.params);

            const product = await ProductsService.getProductByWooId(accountId, wooId);
            if (!product) return reply.code(404).send({ error: 'Product not found' });

            return product;
        } catch (error: any) {
            Logger.error('Error', { error });
            return reply.code(500).send({ error: 'Failed to fetch product' });
        }
    });

    // POST /:id/sync - Force sync from Woo
    fastify.post<{ Params: { id: string } }>('/:id/sync', async (request, reply) => {
        try {
            const accountId = request.accountId!;
            const { id: wooId } = productIdParamSchema.parse(request.params);

            const woo = await WooService.forAccount(accountId);
            const p = await woo.getProduct(wooId);

            if (!p) return reply.code(404).send({ error: 'Product not found in WooCommerce' });

            // For variable products (including ATUM's custom types), fetch full variation data
            // Check for variations existence, not just type name, to support plugins like ATUM Product Levels
            let variationsData: any[] = [];
            const hasVariations = p.variations?.length > 0 || p.type?.includes('variable');
            if (hasVariations && p.variations?.length > 0) {
                variationsData = await woo.getProductVariations(wooId);
                Logger.info(`Fetched ${variationsData.length} variations for product ${wooId} (type: ${p.type})`);
            }

            // No longer embed variationsData on parent rawData — all variation
            // data is read from the ProductVariation table. The variationsData
            // array is still fetched above for upserting ProductVariation rows below.
            const rawDataClean = { ...p };

            await prisma.wooProduct.upsert({
                where: { accountId_wooId: { accountId, wooId: p.id } },
                update: {
                    name: p.name,
                    sku: p.sku,
                    price: p.price === '' ? null : p.price,
                    stockStatus: p.stock_status,
                    stockQuantity: p.stock_quantity ?? null,
                    manageStock: p.manage_stock ?? false,
                    rawData: rawDataClean as any,
                    mainImage: p.images?.[0]?.src,
                    weight: p.weight ? parseFloat(p.weight) : null,
                    length: p.dimensions?.length ? parseFloat(p.dimensions.length) : null,
                    width: p.dimensions?.width ? parseFloat(p.dimensions.width) : null,
                    height: p.dimensions?.height ? parseFloat(p.dimensions.height) : null,
                    images: p.images || []
                },
                create: {
                    accountId,
                    wooId: p.id,
                    name: p.name,
                    sku: p.sku,
                    price: p.price === '' ? null : p.price,
                    stockStatus: p.stock_status,
                    stockQuantity: p.stock_quantity ?? null,
                    manageStock: p.manage_stock ?? false,
                    permalink: p.permalink,
                    mainImage: p.images?.[0]?.src,
                    weight: p.weight ? parseFloat(p.weight) : null,
                    length: p.dimensions?.length ? parseFloat(p.dimensions.length) : null,
                    width: p.dimensions?.width ? parseFloat(p.dimensions.width) : null,
                    height: p.dimensions?.height ? parseFloat(p.dimensions.height) : null,
                    images: p.images || [],
                    rawData: rawDataClean as any
                }
            });

            const upsertedProduct = await prisma.wooProduct.findUnique({
                where: { accountId_wooId: { accountId, wooId: p.id } }
            });

            // Upsert variations so manageStock / stockQuantity are persisted
            if (upsertedProduct && variationsData.length > 0) {
                for (const v of variationsData) {
                    await prisma.productVariation.upsert({
                        where: {
                            productId_wooId: {
                                productId: upsertedProduct.id,
                                wooId: v.id
                            }
                        },
                        update: {
                            sku: v.sku || null,
                            price: v.price === '' ? null : v.price,
                            salePrice: v.sale_price === '' ? null : v.sale_price,
                            stockQuantity: v.stock_quantity ?? null,
                            stockStatus: v.stock_status || 'instock',
                            manageStock: v.manage_stock ?? false,
                            weight: v.weight ? parseFloat(v.weight) : null,
                            length: v.dimensions?.length ? parseFloat(v.dimensions.length) : null,
                            width: v.dimensions?.width ? parseFloat(v.dimensions.width) : null,
                            height: v.dimensions?.height ? parseFloat(v.dimensions.height) : null,
                            rawData: v as any
                        },
                        create: {
                            productId: upsertedProduct.id,
                            wooId: v.id,
                            sku: v.sku || null,
                            price: v.price === '' ? null : v.price,
                            salePrice: v.sale_price === '' ? null : v.sale_price,
                            stockQuantity: v.stock_quantity ?? null,
                            stockStatus: v.stock_status || 'instock',
                            manageStock: v.manage_stock ?? false,
                            weight: v.weight ? parseFloat(v.weight) : null,
                            length: v.dimensions?.length ? parseFloat(v.dimensions.length) : null,
                            width: v.dimensions?.width ? parseFloat(v.dimensions.width) : null,
                            height: v.dimensions?.height ? parseFloat(v.dimensions.height) : null,
                            rawData: v as any
                        }
                    });
                }
                Logger.info(`Synced ${variationsData.length} variations for product ${wooId}`);
            }

            if (upsertedProduct) {
                const currentSeoData = (upsertedProduct.seoData as any) || {};
                const focusKeyword = currentSeoData.focusKeyword || '';

                const seoResult = SeoScoringService.calculateScore(upsertedProduct, focusKeyword);
                const mcResult = MerchantCenterService.validateCompliance(upsertedProduct);

                await prisma.wooProduct.update({
                    where: { id: upsertedProduct.id },
                    data: {
                        seoScore: seoResult.score,
                        seoData: { ...currentSeoData, analysis: seoResult.tests },
                        merchantCenterScore: mcResult.score,
                        merchantCenterIssues: mcResult.issues as any
                    }
                });

                try {
                    await IndexingService.indexProduct(accountId, {
                        ...upsertedProduct,
                        seoScore: seoResult.score,
                        merchantCenterScore: mcResult.score
                    });
                } catch (err) {
                    Logger.warn("Failed to index product during manual sync", { error: err });
                }
            }

            const finalProduct = await ProductsService.getProductByWooId(accountId, wooId);
            return finalProduct;

        } catch (error: any) {
            Logger.error("Force Sync Error", { error });
            return reply.code(500).send({ error: 'Failed to sync product: ' + error.message });
        }
    });

    // PATCH /:id - Update product
    fastify.patch<{ Params: { id: string } }>('/:id', async (request, reply) => {
        try {
            const accountId = request.accountId!;
            const { id: wooId } = productIdParamSchema.parse(request.params);
            const { binLocation, name, stockStatus, manageStock, backorders, isGoldPriceApplied, goldPriceType, sku, price, salePrice, weight, length, width, height, description, short_description, cogs, supplierId, images, focusKeyword, variations } = updateProductBodySchema.parse(request.body);

            let product = await ProductsService.updateProduct(accountId, wooId, {
                binLocation, name, stockStatus, manageStock, backorders, isGoldPriceApplied, goldPriceType,
                sku, price, salePrice, weight, length, width, height, description, short_description,
                cogs, supplierId, images, variations
            });

            // Log the update to audit trail for Edit History
            const changedFields: Record<string, any> = {};
            if (binLocation !== undefined) changedFields.binLocation = binLocation;
            if (name !== undefined) changedFields.name = name;
            if (stockStatus !== undefined) changedFields.stockStatus = stockStatus;
            if (manageStock !== undefined) changedFields.manageStock = manageStock;
            if (backorders !== undefined) changedFields.backorders = backorders;
            if (isGoldPriceApplied !== undefined) changedFields.isGoldPriceApplied = isGoldPriceApplied;
            if (sku !== undefined) changedFields.sku = sku;
            if (price !== undefined) changedFields.price = price;
            if (salePrice !== undefined) changedFields.salePrice = salePrice;
            if (cogs !== undefined) changedFields.cogs = cogs;
            if (supplierId !== undefined) changedFields.supplierId = supplierId;
            if (focusKeyword !== undefined) changedFields.focusKeyword = focusKeyword;
            if (description !== undefined) changedFields.description = '[updated]';
            if (short_description !== undefined) changedFields.short_description = '[updated]';

            if (Object.keys(changedFields).length > 0) {
                await AuditService.log(
                    accountId,
                    request.user?.id || null,
                    'UPDATE',
                    'PRODUCT',
                    wooId.toString(),
                    changedFields
                );
            }

            // Recalculate SEO if needed
            // We use the updated product data plus the focus keyword from body (or existing)
            // Ideally we need to fetch the fresh product to get everything
            const freshProduct = await ProductsService.getProductByWooId(accountId, wooId);

            if (freshProduct) {
                // If focusKeyword is passed, we might want to save it somewhere? 
                // Currently it seems to be in seoData json blob in prisma.
                // We should update that first if it changed.

                const currentSeoData = (product.seoData as any) || {};
                const kw = focusKeyword !== undefined ? focusKeyword : (currentSeoData.focusKeyword || '');

                const seoResult = SeoScoringService.calculateScore(freshProduct, kw);
                const mcResult = MerchantCenterService.validateCompliance(freshProduct);

                // Update scores in DB
                await prisma.wooProduct.update({
                    where: { id: product.id },
                    data: {
                        seoScore: seoResult.score,
                        seoData: { ...currentSeoData, focusKeyword: kw, analysis: seoResult.tests },
                        merchantCenterScore: mcResult.score,
                        merchantCenterIssues: mcResult.issues as any
                    }
                });

                // Re-fetch to return with new scores
                product = (await ProductsService.getProductByWooId(accountId, wooId))!;

                // Re-index
                try {
                    await IndexingService.indexProduct(accountId, {
                        ...product,
                        seoScore: seoResult.score,
                        merchantCenterScore: mcResult.score
                    });
                } catch (err) {
                    Logger.warn("Failed to re-index product after update", { error: err });
                }
            }

            // Invalidate product list cache after update
            await invalidateCache('products', accountId);

            return product;
        } catch (error: any) {
            Logger.error('Error', { error });
            return reply.code(500).send({ error: 'Failed to update product' });
        }
    });

    // GET /:id/stock - Get stock info with BOM calculation
    fastify.get<{ Params: { id: string } }>('/:id/stock', async (request, reply) => {
        try {
            const accountId = request.accountId!;
            const { id: wooId } = productIdParamSchema.parse(request.params);

            // Find local product by wooId
            const product = await prisma.wooProduct.findUnique({
                where: { accountId_wooId: { accountId, wooId } },
                select: { id: true }
            });

            if (!product) {
                return reply.code(404).send({ error: 'Product not found' });
            }

            const { InventoryService } = await import('../services/InventoryService');
            const stockInfo = await InventoryService.getProductStock(accountId, product.id);

            return stockInfo;
        } catch (error: any) {
            Logger.error('Error fetching stock', { error });
            return reply.code(500).send({ error: 'Failed to fetch stock info' });
        }
    });

    // PUT /:id/stock - Update stock quantity (only for non-BOM products)
    fastify.put<{ Params: { id: string }; Body: { stockQuantity: number } }>('/:id/stock', async (request, reply) => {
        try {
            const accountId = request.accountId!;
            const { id: wooId } = productIdParamSchema.parse(request.params);

            // Validate request body with Zod
            const parseResult = stockUpdateBodySchema.safeParse(request.body);
            if (!parseResult.success) {
                return reply.code(400).send({
                    error: parseResult.error.issues[0]?.message || 'Invalid stock quantity'
                });
            }
            const { stockQuantity } = parseResult.data;

            // Find local product with BOM items that have child products
            const product = await prisma.wooProduct.findUnique({
                where: { accountId_wooId: { accountId, wooId } },
                include: {
                    boms: {
                        select: {
                            id: true,
                            items: {
                                where: { childProductId: { not: null } },
                                select: { id: true }
                            }
                        }
                    }
                }
            });

            if (!product) {
                return reply.code(404).send({ error: 'Product not found' });
            }

            // Block updates only for products with BOMs that have child product components
            const hasBOMWithChildProducts = product.boms.some(bom => bom.items.length > 0);
            if (hasBOMWithChildProducts) {
                return reply.code(400).send({
                    error: 'Cannot manually update stock for products with BOM. Stock is calculated from components.'
                });
            }

            // Block stock management on variable parent products — stock should be on variants only
            const productRaw = product.rawData as any;
            const isVariable = productRaw?.type?.includes('variable') || productRaw?.variations?.length > 0;
            if (isVariable) {
                return reply.code(400).send({
                    error: 'Cannot set stock on a variable product parent. Update stock on individual variants instead.'
                });
            }

            // Update local stock
            await prisma.wooProduct.update({
                where: { id: product.id },
                data: {
                    stockQuantity,
                    manageStock: true
                }
            });

            // Sync to WooCommerce (non-blocking, log failures)
            try {
                const woo = await WooService.forAccount(accountId);
                await woo.updateProduct(wooId, {
                    manage_stock: true,
                    stock_quantity: stockQuantity
                });
            } catch (wooErr) {
                Logger.warn('Failed to sync stock to WooCommerce', { error: wooErr, accountId, wooId });
            }

            return {
                success: true,
                stockQuantity,
                manageStock: true
            };
        } catch (error: any) {
            Logger.error('Error updating stock', { error });
            return reply.code(500).send({ error: 'Failed to update stock' });
        }
    });

    // PUT /:id/variants/:variantId/stock - Update variant stock quantity
    fastify.put<{ Params: { id: string; variantId: string }; Body: { stockQuantity: number } }>(
        '/:id/variants/:variantId/stock',
        async (request, reply) => {
            try {
                const accountId = request.accountId!;
                const { id: wooId } = productIdParamSchema.parse(request.params);
                const variantWooId = parseInt(request.params.variantId, 10);

                if (isNaN(variantWooId) || variantWooId <= 0) {
                    return reply.code(400).send({ error: 'Invalid variant ID' });
                }

                // Validate request body
                const parseResult = stockUpdateBodySchema.safeParse(request.body);
                if (!parseResult.success) {
                    return reply.code(400).send({
                        error: parseResult.error.issues[0]?.message || 'Invalid stock quantity'
                    });
                }
                const { stockQuantity } = parseResult.data;

                // Find the product and variation
                const product = await prisma.wooProduct.findUnique({
                    where: { accountId_wooId: { accountId, wooId } },
                    select: { id: true }
                });

                if (!product) {
                    return reply.code(404).send({ error: 'Product not found' });
                }

                const variation = await prisma.productVariation.findUnique({
                    where: { productId_wooId: { productId: product.id, wooId: variantWooId } }
                });

                if (!variation) {
                    return reply.code(404).send({ error: 'Variation not found' });
                }

                // Update local variation stock
                await prisma.productVariation.update({
                    where: { id: variation.id },
                    data: {
                        stockQuantity,
                        manageStock: true,
                        stockStatus: stockQuantity > 0 ? 'instock' : 'outofstock'
                    }
                });

                // Sync to WooCommerce (non-blocking)
                try {
                    const woo = await WooService.forAccount(accountId);
                    await woo.updateProductVariation(wooId, variantWooId, {
                        manage_stock: true,
                        stock_quantity: stockQuantity
                    });
                } catch (wooErr) {
                    Logger.warn('Failed to sync variant stock to WooCommerce', {
                        error: wooErr,
                        accountId,
                        productWooId: wooId,
                        variantWooId
                    });
                }

                return {
                    success: true,
                    variantWooId,
                    stockQuantity,
                    manageStock: true
                };
            } catch (error: any) {
                Logger.error('Error updating variant stock', { error });
                return reply.code(500).send({ error: 'Failed to update variant stock' });
            }
        }
    );

    // GET /:id/sales-history - Get sales history from Elasticsearch
    fastify.get<{ Params: { id: string } }>('/:id/sales-history', async (request, reply) => {
        try {
            const accountId = request.accountId!;
            const { id: wooId } = productIdParamSchema.parse(request.params);
            const { page, limit } = searchQuerySchema.parse(request.query);
            const from = (page - 1) * limit;

            const response = await esClient.search({
                index: 'orders',
                size: limit,
                from,
                query: {
                    bool: {
                        must: [
                            { term: { accountId } },
                            {
                                nested: {
                                    path: 'line_items',
                                    query: { term: { 'line_items.productId': wooId } },
                                    inner_hits: { name: 'matched_items', size: 10 }
                                }
                            }
                        ],
                        filter: [
                            { terms: { status: REVENUE_STATUSES } }
                        ]
                    }
                },
                sort: [{ date_created: { order: 'desc' } } as any]
            });

            const hits = response.hits.hits;
            const total = typeof response.hits.total === 'number'
                ? response.hits.total
                : response.hits.total?.value || 0;

            const sales = hits.map((hit: any) => {
                const order = hit._source;
                const matchedItems = hit.inner_hits?.matched_items?.hits?.hits || [];
                let quantity = 0;
                let lineTotal = 0;

                matchedItems.forEach((itemHit: any) => {
                    const item = itemHit._source;
                    quantity += item.quantity || 0;
                    lineTotal += parseFloat(item.total) || 0;
                });

                return {
                    orderId: order.id,
                    orderNumber: order.number || `#${order.id}`,
                    date: order.date_created,
                    status: order.status,
                    customerName: order.billing
                        ? `${order.billing.first_name || ''} ${order.billing.last_name || ''}`.trim() || order.billing.email
                        : 'Guest',
                    customerEmail: order.billing?.email,
                    quantity,
                    lineTotal,
                    orderTotal: parseFloat(order.total) || 0,
                    currency: order.currency || 'USD'
                };
            });

            return {
                sales,
                total,
                page,
                limit,
                totalPages: Math.ceil(total / limit)
            };

        } catch (error: any) {
            Logger.error('Error fetching product sales history', { error });
            return reply.code(500).send({ error: 'Failed to fetch sales history' });
        }
    });

    // POST /:id/rewrite-description - AI rewrite enhanced with GSC keyword data
    fastify.post<{ Params: { id: string } }>('/:id/rewrite-description', async (request, reply) => {
        try {
            const accountId = request.accountId!;
            const { id: wooId } = productIdParamSchema.parse(request.params);
            const { currentDescription, productName, categories, shortDescription, focusKeyword } = rewriteDescriptionBodySchema.parse(request.body);

            const account = await prisma.account.findUnique({
                where: { id: accountId },
                select: { openRouterApiKey: true, aiModel: true }
            });

            if (!account?.openRouterApiKey) {
                return reply.code(400).send({
                    error: 'No OpenRouter API key configured. Please add your API key in Settings > AI.'
                });
            }

            // Fetch GSC keyword data for this product's permalink
            // Why best-effort: GSC may not be connected; we degrade gracefully to the original behaviour
            let searchKeywordsBlock = '';
            try {
                const product = await prisma.wooProduct.findUnique({
                    where: { accountId_wooId: { accountId, wooId } },
                    select: { permalink: true, seoData: true }
                });

                if (product?.permalink) {
                    const gscQueries = await SearchConsoleService.getPageAnalytics(accountId, product.permalink);

                    if (gscQueries.length > 0) {
                        const topKeywords = gscQueries
                            .sort((a, b) => b.clicks - a.clicks)
                            .slice(0, 15);

                        const keywordLines = topKeywords.map((kw, i) =>
                            `${i + 1}. "${kw.query}" — ${kw.clicks} clicks, ${kw.impressions} impressions, avg position ${kw.position}`
                        ).join('\n');

                        searchKeywordsBlock = [
                            'Top Search Queries from Google Search Console (real data from the last 28 days):',
                            keywordLines,
                            '',
                            'Naturally weave the highest-performing keywords above into the rewritten description. Do NOT keyword-stuff.',
                        ].join('\n');

                        Logger.info('GSC keywords injected into rewrite prompt', {
                            accountId, wooId, keywordCount: topKeywords.length
                        });
                    }
                }
            } catch (gscErr) {
                // Non-fatal: GSC data is supplementary
                Logger.warn('Failed to fetch GSC data for product rewrite, continuing without', {
                    error: gscErr, accountId, wooId
                });
            }

            const promptConfig = await prisma.aIPrompt.findUnique({
                where: { promptId: 'product_description' }
            });

            const defaultPrompt = `{{search_keywords}}
Rewrite the following product description to be more engaging, SEO-friendly, and persuasive.
Product Name: {{product_name}}
Focus Keyword: {{focus_keyword}}
Current Categories: {{category}}
Short Description: {{short_description}}

Current Description:
{{current_description}}

Return ONLY the rewritten description in Markdown format. Do not include any conversational preamble.`;

            let promptContent = promptConfig?.content || defaultPrompt;

            const resolvedFocusKeyword = focusKeyword || '';

            let prompt = promptContent
                .replace(/\{\{product_name\}\}/g, productName || '')
                .replace(/\{\{current_description\}\}/g, currentDescription || '')
                .replace(/\{\{short_description\}\}/g, shortDescription || '')
                .replace(/\{\{category\}\}/g, categories || '')
                .replace(/\{\{focus_keyword\}\}/g, resolvedFocusKeyword)
                .replace(/\{\{search_keywords\}\}/g, searchKeywordsBlock);

            const model = account.aiModel || 'openai/gpt-4o';

            const response = await fetch('https://openrouter.ai/api/v1/chat/completions', {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${account.openRouterApiKey}`,
                    'HTTP-Referer': process.env.APP_URL || 'http://localhost:5173',
                    'X-Title': `${process.env.APP_NAME || 'Commerce Platform'} Product Rewrite`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    model,
                    messages: [{ role: 'user', content: prompt }],
                    max_tokens: 2000,
                    temperature: 0.7
                })
            });

            if (!response.ok) {
                const errorText = await response.text();
                Logger.error('OpenRouter API error during rewrite', { error: errorText, status: response.status });

                let errorMessage = 'Failed to generate description.';
                if (response.status === 401) {
                    errorMessage = 'Invalid OpenRouter API key. Please check your credentials in Settings > Intelligence.';
                } else if (response.status === 429) {
                    errorMessage = 'Rate limit exceeded. Please try again in a moment.';
                } else if (response.status === 402) {
                    errorMessage = 'Insufficient credits on OpenRouter. Please top up your account.';
                } else {
                    errorMessage = `OpenRouter API error (${response.status}). Please try again.`;
                }

                return reply.code(502).send({ error: errorMessage });
            }

            const data = await response.json();
            const generatedDescription = data.choices?.[0]?.message?.content || '';

            Logger.info('AI rewrite response received', {
                hasContent: !!generatedDescription,
                contentLength: generatedDescription?.length
            });

            if (!generatedDescription) {
                return reply.code(500).send({ error: 'AI returned empty response' });
            }

            // marked.parse returns a Promise in newer versions
            const formattedDescription = await marked.parse(generatedDescription.trim());

            Logger.info('AI rewrite complete', {
                formattedLength: formattedDescription?.length
            });

            return { description: formattedDescription };

        } catch (error: any) {
            Logger.error('Error rewriting product description', { error });
            return reply.code(500).send({ error: 'Failed to rewrite description' });
        }
    });
};

