/**
 * AccountBackupService
 * 
 * Facade for backup operations, delegating to modular components.
 * Provides settings management and scheduled backup orchestration.
 * 
 * Modular sub-services (in backup/):
 * - backupStorage.ts: File storage operations
 * - backupGenerator.ts: Data collection and serialization
 * - restoreService.ts: Data restoration logic
 */

import { prisma } from '../utils/prisma';
import { Logger } from '../utils/logger';
import {
    BackupSettings,
    AccountBackup,
    BackupOptions,
    BackupPreview,
    StoredBackupInfo,
    RestoreResult,
    ScheduledBackupResult,
    FREQUENCY_MS,
    saveBackupToStorage,
    getStoredBackups,
    getBackupFilePath,
    deleteStoredBackup,
    applyRetentionPolicy,
} from './backup';
import { generateBackup, getBackupPreview } from './backup/backupGenerator';
import { restoreFromBackup } from './backup/restoreService';

// Re-export types for backward compatibility
export type {
    BackupSettings,
    AccountBackup,
    BackupOptions,
    BackupPreview,
    StoredBackupInfo,
};

export class AccountBackupService {
    // =========================================
    // SETTINGS MANAGEMENT
    // =========================================

    /**
     * Get backup settings for an account
     */
    static async getSettings(accountId: string): Promise<BackupSettings> {
        const settings = await prisma.accountBackupSettings.findUnique({
            where: { accountId },
        });

        if (!settings) {
            return {
                isEnabled: false,
                frequency: 'WEEKLY',
                maxBackups: 5,
                lastBackupAt: null,
                nextBackupAt: null,
            };
        }

        return {
            isEnabled: settings.isEnabled,
            frequency: settings.frequency as 'DAILY' | 'EVERY_3_DAYS' | 'WEEKLY',
            maxBackups: settings.maxBackups,
            lastBackupAt: settings.lastBackupAt,
            nextBackupAt: settings.nextBackupAt,
        };
    }

    /**
     * Update backup settings for an account
     */
    static async updateSettings(
        accountId: string,
        updates: Partial<Pick<BackupSettings, 'isEnabled' | 'frequency' | 'maxBackups'>>
    ): Promise<BackupSettings> {
        // Calculate next backup time if enabling
        let nextBackupAt: Date | undefined;
        if (updates.isEnabled) {
            const frequency = updates.frequency || 'WEEKLY';
            nextBackupAt = new Date(Date.now() + FREQUENCY_MS[frequency]);
        } else if (updates.isEnabled === false) {
            nextBackupAt = undefined; // Will be set to null
        }

        const settings = await prisma.accountBackupSettings.upsert({
            where: { accountId },
            update: {
                ...updates,
                ...(nextBackupAt !== undefined && { nextBackupAt }),
                ...(updates.isEnabled === false && { nextBackupAt: null }),
            },
            create: {
                accountId,
                isEnabled: updates.isEnabled ?? false,
                frequency: updates.frequency ?? 'WEEKLY',
                maxBackups: updates.maxBackups ?? 5,
                nextBackupAt: updates.isEnabled ? nextBackupAt : null,
            },
        });

        return {
            isEnabled: settings.isEnabled,
            frequency: settings.frequency as 'DAILY' | 'EVERY_3_DAYS' | 'WEEKLY',
            maxBackups: settings.maxBackups,
            lastBackupAt: settings.lastBackupAt,
            nextBackupAt: settings.nextBackupAt,
        };
    }

    // =========================================
    // DELEGATED STORAGE OPERATIONS
    // =========================================

    /** @see backupStorage.saveBackupToStorage */
    static saveBackupToStorage = saveBackupToStorage;

    /** @see backupStorage.getStoredBackups */
    static getStoredBackups = getStoredBackups;

    /** @see backupStorage.getBackupFilePath */
    static getBackupFilePath = getBackupFilePath;

    /** @see backupStorage.deleteStoredBackup */
    static deleteStoredBackup = deleteStoredBackup;

    /**
     * Apply retention policy - delete oldest backups if exceeding max
     */
    static async applyRetentionPolicy(accountId: string): Promise<number> {
        return applyRetentionPolicy(accountId, this.getSettings);
    }

    // =========================================
    // DELEGATED GENERATION OPERATIONS
    // =========================================

    /** @see backupGenerator.generateBackup */
    static generateBackup = generateBackup;

    /** @see backupGenerator.getBackupPreview */
    static getBackupPreview = getBackupPreview;

    // =========================================
    // DELEGATED RESTORE OPERATIONS
    // =========================================

    /** @see restoreService.restoreFromBackup */
    static restoreFromBackup = restoreFromBackup;

    // =========================================
    // SCHEDULED BACKUP RUNNER
    // =========================================

    /**
     * Check and run due scheduled backups (called by SchedulerService)
     */
    static async runScheduledBackups(): Promise<ScheduledBackupResult> {
        const now = new Date();

        // Find accounts with due backups
        const dueAccounts = await prisma.accountBackupSettings.findMany({
            where: {
                isEnabled: true,
                nextBackupAt: { lte: now },
            },
            include: { account: { select: { id: true, name: true } } },
        });

        let processed = 0;
        let failed = 0;

        for (const settings of dueAccounts) {
            try {
                Logger.info('[AccountBackup] Running scheduled backup', {
                    accountId: settings.accountId,
                    accountName: settings.account.name,
                });

                // Generate backup
                const backup = await this.generateBackup(settings.accountId);
                if (!backup) {
                    failed++;
                    continue;
                }

                // Save to storage
                await this.saveBackupToStorage(settings.accountId, backup, 'SCHEDULED');

                // Apply retention policy
                await this.applyRetentionPolicy(settings.accountId);

                processed++;
            } catch (error) {
                Logger.error('[AccountBackup] Scheduled backup failed', {
                    accountId: settings.accountId,
                    error,
                });
                failed++;
            }
        }

        if (processed > 0 || failed > 0) {
            Logger.info('[AccountBackup] Scheduled backup run complete', { processed, failed });
        }

        return { processed, failed };
    }
}

/**
 * BOM Consumption Service
 * 
 * Handles automatic stock deduction when BOM parent products are sold.
 * When an order contains a product with a BOM, this service:
 * 1. Deducts stock from each BOM component
 * 2. Updates component stock in WooCommerce
 * 3. Triggers cascade recalculation for any other BOM products using those components
 * 
 * Locking Strategy:
 * - Primary: Redis SETNX with TTL (fast distributed lock)
 * - Fallback: PostgreSQL advisory lock (when Redis unavailable)
 */

import { prisma, Prisma } from '../utils/prisma';
import { Logger } from '../utils/logger';
import { WooService } from './woo';
import { EventBus, EVENTS } from './events';
import { BOMInventorySyncService } from './BOMInventorySyncService';
import { redisClient } from '../utils/redis';

interface OrderLineItem {
    product_id: number;
    variation_id: number;
    quantity: number;
    name: string;
}

interface ComponentDeduction {
    componentType: 'WooProduct' | 'ProductVariation' | 'InternalProduct';
    componentId: string;
    componentName: string;
    wooId?: number;
    parentWooId?: number; // For variations
    quantityDeducted: number;
    previousStock: number;
    newStock: number;
}

/**
 * Retry a function with exponential backoff.
 * Best practice for external API calls that may transiently fail.
 */
async function withRetry<T>(
    fn: () => Promise<T>,
    options: { maxAttempts?: number; baseDelayMs?: number; context?: string } = {}
): Promise<T> {
    const { maxAttempts = 3, baseDelayMs = 1000, context = 'operation' } = options;
    let lastError: Error | null = null;

    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
        try {
            return await fn();
        } catch (err: any) {
            lastError = err;
            const isRetryable = !err.message?.includes('not found') &&
                !err.message?.includes('invalid_id') &&
                !err.message?.includes('401') &&
                !err.message?.includes('403');

            if (!isRetryable || attempt === maxAttempts) {
                throw err;
            }

            const delay = baseDelayMs * Math.pow(2, attempt - 1);
            Logger.warn(`[BOMConsumption] ${context} failed (attempt ${attempt}/${maxAttempts}), retrying in ${delay}ms`, {
                error: err.message
            });
            await new Promise(resolve => setTimeout(resolve, delay));
        }
    }

    throw lastError;
}

export class BOMConsumptionService {
    /**
     * pending_deductions:{accountId}:{orderId} -> JSON of DeductionPlan
     */
    private static readonly PENDING_KEY_PREFIX = 'bom_pending:';
    private static readonly LOCK_KEY = 'bom:processing_queue';
    private static readonly ORDER_LOCK_PREFIX = 'bom:lock:order:';
    private static readonly LOCK_TTL_SECONDS = 60;
    private static readonly BATCH_SIZE = 10;
    private static readonly ORDER_LOCK_TTL_SECONDS = 300; // 5 minutes
    private static readonly CONSUMED_KEY_PREFIX = 'bom:consumed:';
    private static readonly CONSUMED_TTL_SECONDS = 86400; // 24 hours
    private static readonly MAX_RETRIES = 3;


    /**
     * Process an order and consume BOM component stock.
     * Triggered when order status becomes 'processing' or 'completed'.
     * Uses Redis + DB ledger to prevent duplicate consumption on re-syncs.
     */
    static async consumeOrderComponents(
        accountId: string,
        order: any
    ): Promise<{ consumed: ComponentDeduction[]; errors: string[]; skipped?: boolean }> {
        const consumed: ComponentDeduction[] = [];
        const errors: string[] = [];

        // Why both statuses: some payment gateways skip 'processing' and go
        // directly to 'completed'. The dedup below prevents double-consumption
        // when an order transitions processing → completed.
        const status = (order.status || '').toLowerCase();
        if (status !== 'processing' && status !== 'completed') {
            Logger.debug(`[BOMConsumption] Skipping order ${order.id} - status is ${status}`, { accountId });
            return { consumed, errors };
        }

        // Layer 1: Redis dedup (fast path, 24h TTL)
        const consumedKey = `${this.CONSUMED_KEY_PREFIX}${accountId}:${order.id}`;
        const alreadyConsumed = await redisClient.get(consumedKey);
        if (alreadyConsumed) {
            Logger.debug(`[BOMConsumption] Order ${order.id} already consumed (Redis), skipping`, { accountId });
            return { consumed, errors, skipped: true };
        }

        // Layer 2: DB dedup fallback — Redis key may have expired after 24h.
        // The ledger is the authoritative source of truth for past consumption.
        const orderId = typeof order.id === 'number' ? order.id : parseInt(order.id, 10);
        const ledgerEntry = await prisma.bOMDeductionLedger.findFirst({
            where: { accountId, orderId, status: { in: ['COMPLETED', 'EXECUTED'] } }
        });
        if (ledgerEntry) {
            // Re-set the Redis key so subsequent sync cycles don't hit DB again
            await redisClient.setex(consumedKey, this.CONSUMED_TTL_SECONDS, 'recovered');
            Logger.debug(`[BOMConsumption] Order ${order.id} already consumed (DB ledger), skipping`, { accountId });
            return { consumed, errors, skipped: true };
        }

        // Acquire lock to prevent concurrent processing of same order
        const lockKey = `${this.ORDER_LOCK_PREFIX}${accountId}:${order.id}`;
        const lockInfo = await this.acquireLock(lockKey, accountId, orderId);
        if (!lockInfo.acquired) {
            Logger.warn(`[BOMConsumption] Order ${order.id} is being processed by another worker, skipping`, { accountId });
            return { consumed, errors, skipped: true };
        }

        const lineItems: OrderLineItem[] = order.line_items || [];
        if (lineItems.length === 0) {
            Logger.debug(`[BOMConsumption] Order ${order.id} has no line items`, { accountId });
            await this.releaseLock(lockKey, lockInfo.usedPostgres, accountId, orderId);
            return { consumed, errors };
        }

        Logger.info(`[BOMConsumption] Processing order ${order.id} with ${lineItems.length} line items`, { accountId });

        try {
            // PHASE 1: PLANNING
            // Calculate all intended deductions without executing them yet
            const deductionPlan: ComponentDeduction[] = [];

            for (const item of lineItems) {
                const plan = await this.planLineItemDeductions(accountId, item);
                deductionPlan.push(...plan);
            }

            if (deductionPlan.length === 0) {
                Logger.info(`[BOMConsumption] No BOM components to deduct for order ${order.id}`, { accountId });
                await this.releaseLock(lockKey, lockInfo.usedPostgres, accountId, orderId);
                return { consumed, errors };
            }

            // PHASE 2: TRACKING
            // Save the plan to Redis for crash recovery
            await this.trackPendingDeduction(accountId, orderId, deductionPlan);

            // PHASE 3: EXECUTION
            // Execute deductions one by one
            const modifiedComponents: { productId: string; variationId?: number; isInternal?: boolean }[] = [];
            const wooService = await WooService.forAccount(accountId);

            // Stage ledger payloads — flushed as a single createMany after the loop.
            // Why: N individual create() calls inside the loop cause N round-trips;
            // createMany batches them into one INSERT for the price of one round-trip.
            const ledgerRows: Array<{
                accountId: string;
                orderId: number;
                componentType: string;
                componentId: string;
                componentName: string;
                wooId?: number;
                parentWooId?: number;
                quantityDeducted: number;
                previousStock: number;
                newStock: number;
            }> = [];

            for (const deduction of deductionPlan) {
                try {
                    await this.executeDeduction(accountId, deduction, wooService);

                    // Stage ledger entry — will be flushed below if all succeed
                    ledgerRows.push({
                        accountId,
                        orderId,
                        componentType: deduction.componentType,
                        componentId: deduction.componentId,
                        componentName: deduction.componentName,
                        wooId: deduction.wooId,
                        parentWooId: deduction.parentWooId,
                        quantityDeducted: deduction.quantityDeducted,
                        previousStock: deduction.previousStock,
                        newStock: deduction.newStock
                    });

                    consumed.push(deduction);

                    if (deduction.componentType === 'ProductVariation') {
                        modifiedComponents.push({ productId: deduction.componentId, variationId: deduction.wooId });
                    } else if (deduction.componentType === 'WooProduct') {
                        modifiedComponents.push({ productId: deduction.componentId });
                    } else if (deduction.componentType === 'InternalProduct') {
                        // Internal products also need cascade — other BOM parents
                        // using the same internal component need their effective stock recalculated.
                        modifiedComponents.push({ productId: deduction.componentId, isInternal: true });
                    }
                } catch (err: any) {
                    const errMsg = `Failed to execute deduction for ${deduction.componentName}: ${err.message}`;
                    Logger.error(`[BOMConsumption] ${errMsg}`, { accountId, deduction });
                    errors.push(errMsg);

                    // CRITICAL: If an error occurs during execution, attempting rollback
                    // Note: In case of PROCESS CRASH, the Recovery Job will handle this.
                    // This block handles runtime errors (e.g. API 500).
                    Logger.warn(`[BOMConsumption] Triggering immediate rollback due to error`, { accountId, orderId });
                    await this.rollbackDeductions(accountId, consumed);
                    throw err;
                }
            }

            // Flush all ledger entries in a single bulk INSERT — N→1 DB round-trip
            if (ledgerRows.length > 0) {
                await prisma.bOMDeductionLedger.createMany({ data: ledgerRows });
            }

            // PHASE 4: CASCADE SYNC
            // This is "best effort" - simpler to just log errors if it fails rather than rollback
            for (const comp of modifiedComponents) {
                try {
                    await this.cascadeSyncAffectedProducts(
                        accountId,
                        comp.productId,
                        comp.variationId,
                        comp.isInternal ? 'internalProduct' : 'wooProduct'
                    );
                } catch (err: any) {
                    Logger.error(`[BOMConsumption] Cascade sync failed for component ${comp.productId}`, { accountId, error: err.message });
                }
            }

            // PHASE 5: COMPLETION
            // Mark as consumed, remove pending log
            await redisClient.setex(consumedKey, this.CONSUMED_TTL_SECONDS, new Date().toISOString());
            await this.clearPendingDeduction(accountId, orderId);

            // Close ledger lifecycle: EXECUTED → COMPLETED
            await prisma.bOMDeductionLedger.updateMany({
                where: { accountId, orderId, status: 'EXECUTED' },
                data: { status: 'COMPLETED' }
            });

            Logger.info(`[BOMConsumption] Order ${order.id} complete: ${consumed.length} components consumed`, { accountId });

        } catch (error: any) {
            Logger.error(`[BOMConsumption] Order processing failed`, { accountId, orderId, error: error.message });
            // Re-throw so BullMQ marks job as failed and retries kick in
            throw error;
        } finally {
            await this.releaseLock(lockKey, lockInfo.usedPostgres, accountId, orderId);
        }

        return { consumed, errors };
    }

    // --- REVERSAL FOR CANCELLED / REFUNDED ORDERS ---

    /**
     * Reverse BOM component consumption when an order is cancelled or refunded.
     * Uses the `BOMDeductionLedger` (COMPLETED entries) to deterministically
     * reverse each deduction — no stock-guessing heuristic needed.
     *
     * Idempotent: if entries are already REVERSED, this is a no-op.
     */
    static async reverseOrderConsumption(
        accountId: string,
        order: any
    ): Promise<{ reversed: number; errors: string[] }> {
        const errors: string[] = [];
        const orderId = typeof order.id === 'number' ? order.id : parseInt(order.id, 10);

        // Find completed deductions for this order
        const entries = await prisma.bOMDeductionLedger.findMany({
            where: { accountId, orderId, status: 'COMPLETED' }
        });

        if (entries.length === 0) {
            Logger.debug(`[BOMConsumption] No completed deductions to reverse for order ${orderId}`, { accountId });
            return { reversed: 0, errors };
        }

        // Acquire lock to prevent concurrent reversal
        const lockKey = `${this.ORDER_LOCK_PREFIX}reversal:${accountId}:${orderId}`;
        const lockInfo = await this.acquireLock(lockKey, accountId, orderId);
        if (!lockInfo.acquired) {
            Logger.warn(`[BOMConsumption] Order ${orderId} reversal already in progress, skipping`, { accountId });
            return { reversed: 0, errors: ['Reversal already in progress'] };
        }

        try {
            Logger.info(`[BOMConsumption] Reversing ${entries.length} deductions for cancelled/refunded order ${orderId}`, { accountId });

            // Convert ledger entries to ComponentDeduction format
            const deductions: ComponentDeduction[] = entries.map(e => ({
                componentType: e.componentType as ComponentDeduction['componentType'],
                componentId: e.componentId,
                componentName: e.componentName,
                wooId: e.wooId ?? undefined,
                parentWooId: e.parentWooId ?? undefined,
                quantityDeducted: e.quantityDeducted,
                previousStock: e.previousStock,
                newStock: e.newStock
            }));

            // Reverse the deductions (adds stock back)
            await this.rollbackDeductions(accountId, deductions);

            // Mark ledger entries as reversed
            await prisma.bOMDeductionLedger.updateMany({
                where: { accountId, orderId, status: 'COMPLETED' },
                data: { status: 'REVERSED', rolledBackAt: new Date() }
            });

            // Clear the consumed key so the order doesn't look "consumed" if re-processed
            const consumedKey = `${this.CONSUMED_KEY_PREFIX}${accountId}:${orderId}`;
            await redisClient.del(consumedKey);

            // Cascade BOM sync for all affected components
            const modifiedComponents: { productId: string; variationId?: number; isInternal?: boolean }[] = [];
            for (const d of deductions) {
                if (d.componentType === 'ProductVariation') {
                    modifiedComponents.push({ productId: d.componentId, variationId: d.wooId });
                } else if (d.componentType === 'WooProduct') {
                    modifiedComponents.push({ productId: d.componentId });
                } else if (d.componentType === 'InternalProduct') {
                    modifiedComponents.push({ productId: d.componentId, isInternal: true });
                }
            }

            for (const comp of modifiedComponents) {
                try {
                    await this.cascadeSyncAffectedProducts(
                        accountId,
                        comp.productId,
                        comp.variationId,
                        comp.isInternal ? 'internalProduct' : 'wooProduct'
                    );
                } catch (err: any) {
                    Logger.error(`[BOMConsumption] Cascade sync failed during reversal for ${comp.productId}`, { accountId, error: err.message });
                }
            }

            Logger.info(`[BOMConsumption] Reversed ${entries.length} deductions for order ${orderId}`, { accountId });
            return { reversed: entries.length, errors };

        } catch (error: any) {
            Logger.error(`[BOMConsumption] Order reversal failed`, { accountId, orderId, error: error.message });
            errors.push(error.message);
            return { reversed: 0, errors };
        } finally {
            await this.releaseLock(lockKey, lockInfo.usedPostgres, accountId, orderId);
        }
    }

    // --- ROLLBACK & RECOVERY MECHANISMS ---

    /**
     * Flag this order as having pending deductions.
     * The DB ledger is the source of truth for actual deductions — this flag
     * only exists so the recovery job can find stalled orders quickly.
     */
    private static async trackPendingDeduction(accountId: string, orderId: number, _plan: ComponentDeduction[]) {
        const key = `${this.PENDING_KEY_PREFIX}${accountId}:${orderId}`;
        await redisClient.setex(key, 1800, '1');
    }

    private static async clearPendingDeduction(accountId: string, orderId: number) {
        const key = `${this.PENDING_KEY_PREFIX}${accountId}:${orderId}`;
        await redisClient.del(key);
    }

    /**
     * Revert stock deductions (Compensating Transaction).
     * Adds the deducted quantity back to the current stock.
     */
    static async rollbackDeductions(accountId: string, deductions: ComponentDeduction[]) {
        if (deductions.length === 0) return;

        Logger.info(`[BOMConsumption] Rolling back ${deductions.length} deductions`, { accountId });
        const wooService = await WooService.forAccount(accountId);

        for (const deduction of deductions) {
            try {
                // Add quantity back
                const rollbackQty = deduction.quantityDeducted;

                if (deduction.componentType === 'InternalProduct') {
                    await prisma.internalProduct.update({
                        where: { id: deduction.componentId },
                        data: { stockQuantity: { increment: rollbackQty } }
                    });
                } else if (deduction.componentType === 'ProductVariation') {
                    // Update Local — increment first so local DB is the source of truth
                    const localVar = await prisma.productVariation.update({
                        where: { productId_wooId: { productId: deduction.componentId, wooId: deduction.wooId! } },
                        data: { stockQuantity: { increment: rollbackQty } },
                        select: { stockQuantity: true }
                    });
                    // Why local DB as authority: if executeDeduction's WooCommerce write failed
                    // (e.g. network timeout), Woo still has the old pre-deduction stock. Using
                    // `freshWooStock + rollbackQty` would inflate stock beyond the true value.
                    // The local DB always reflects the correct state after the atomic increment.
                    await withRetry(() => wooService.updateProductVariation(
                        deduction.parentWooId!,
                        deduction.wooId!,
                        { stock_quantity: localVar.stockQuantity ?? 0, manage_stock: true }
                    ));
                } else if (deduction.componentType === 'WooProduct') {
                    // Update Local — increment first so local DB is the source of truth
                    const localProd = await prisma.wooProduct.update({
                        where: { id: deduction.componentId },
                        data: { stockQuantity: { increment: rollbackQty } },
                        select: { stockQuantity: true }
                    });
                    // Why local DB as authority: same rationale as the ProductVariation path above.
                    await withRetry(() => wooService.updateProduct(
                        deduction.wooId!,
                        { stock_quantity: localProd.stockQuantity ?? 0, manage_stock: true }
                    ));
                }

                Logger.info(`[BOMConsumption] Rolled back deduction for ${deduction.componentName}`, { accountId });
            } catch (error: any) {
                Logger.error(`[BOMConsumption] Failed to rollback deduction for ${deduction.componentName}`, { error: error.message });
                // Continue rolling back others even if one fails
            }
        }
    }

    /**
     * RECOVERY JOB: Find stalled deductions using the DB ledger.
     * Queries for EXECUTED ledger entries whose orderId doesn't have a
     * consumed key in Redis — indicating the process crashed mid-deduction.
     * Deterministic: ledger entries prove deductions happened, no stock guessing.
     */
    static async recoverStalledDeductions() {
        // Phase 1: Check Redis pending keys for backward compat (old-format recovery)
        const keys = await redisClient.keys(`${this.PENDING_KEY_PREFIX}*`);

        for (const key of keys) {
            try {
                const parts = key.split(':');
                if (parts.length < 3) continue;
                const accountId = parts[1];
                const orderId = parseInt(parts[2], 10);

                const consumedKey = `${this.CONSUMED_KEY_PREFIX}${accountId}:${orderId}`;
                const isConsumed = await redisClient.get(consumedKey);

                if (isConsumed) {
                    await redisClient.del(key);
                    continue;
                }

                // Use ledger for deterministic recovery
                await this.ledgerBasedRollback(accountId, orderId);
                await redisClient.del(key);
            } catch (err) {
                Logger.error(`[BOMConsumption] Recovery failed for key ${key}`, { err });
            }
        }

        // Phase 2: Ledger-only recovery — find orphaned EXECUTED entries
        // (entries older than 30 min without a consumed key)
        const cutoff = new Date(Date.now() - 30 * 60 * 1000);
        const orphanedEntries = await prisma.bOMDeductionLedger.findMany({
            where: {
                status: 'EXECUTED',
                createdAt: { lt: cutoff }
            },
            distinct: ['accountId', 'orderId'],
            select: { accountId: true, orderId: true }
        });

        for (const { accountId, orderId } of orphanedEntries) {
            const consumedKey = `${this.CONSUMED_KEY_PREFIX}${accountId}:${orderId}`;
            const isConsumed = await redisClient.get(consumedKey);
            if (isConsumed) {
                // Promote orphaned EXECUTED → COMPLETED so they're not re-processed
                await prisma.bOMDeductionLedger.updateMany({
                    where: { accountId, orderId, status: 'EXECUTED' },
                    data: { status: 'COMPLETED' }
                });
                continue;
            }

            try {
                Logger.warn(`[BOMConsumption] Ledger-based recovery for stalled Order ${orderId}`, { accountId });
                await this.ledgerBasedRollback(accountId, orderId);
            } catch (err) {
                Logger.error(`[BOMConsumption] Ledger recovery failed`, { accountId, orderId, err });
            }
        }
    }

    /**
     * Deterministic rollback using the deduction ledger.
     * Queries all EXECUTED entries for the order and rolls each one back.
     * No stock-comparison heuristic needed — if it's in the ledger, it happened.
     */
    private static async ledgerBasedRollback(accountId: string, orderId: number) {
        const entries = await prisma.bOMDeductionLedger.findMany({
            where: { accountId, orderId, status: 'EXECUTED' }
        });

        if (entries.length === 0) return;

        Logger.info(`[BOMConsumption] Ledger rollback: ${entries.length} deductions for Order ${orderId}`, { accountId });

        // Convert ledger entries to ComponentDeduction format for rollback
        const deductions: ComponentDeduction[] = entries.map(e => ({
            componentType: e.componentType as ComponentDeduction['componentType'],
            componentId: e.componentId,
            componentName: e.componentName,
            wooId: e.wooId ?? undefined,
            parentWooId: e.parentWooId ?? undefined,
            quantityDeducted: e.quantityDeducted,
            previousStock: e.previousStock,
            newStock: e.newStock
        }));

        await this.rollbackDeductions(accountId, deductions);

        // Mark all entries as rolled back
        await prisma.bOMDeductionLedger.updateMany({
            where: { accountId, orderId, status: 'EXECUTED' },
            data: { status: 'ROLLED_BACK', rolledBackAt: new Date() }
        });
    }

    // --- REFACTORED HELPERS ---

    /**
     * Plan deductions without executing (Read-Only phase)
     */
    private static async planLineItemDeductions(
        accountId: string,
        item: OrderLineItem
    ): Promise<ComponentDeduction[]> {
        const deductions: ComponentDeduction[] = [];

        // Find product
        const product = await prisma.wooProduct.findFirst({
            where: { accountId, wooId: item.product_id },
            select: { id: true, wooId: true, name: true }
        });
        if (!product) return [];

        const variationId = item.variation_id || 0;
        const bom = await prisma.bOM.findUnique({
            where: { productId_variationId: { productId: product.id, variationId } },
            include: {
                items: {
                    where: { isActive: true },
                    include: {
                        childProduct: { select: { id: true, wooId: true, name: true, stockQuantity: true, rawData: true } },
                        childVariation: { select: { productId: true, wooId: true, sku: true, stockQuantity: true, rawData: true } },
                        internalProduct: { select: { id: true, name: true, stockQuantity: true } }
                    }
                }
            }
        });

        if (!bom || bom.items.length === 0) return [];

        for (const bomItem of bom.items) {
            // Why wasteFactor: accounts for material loss during manufacturing (e.g. 0.10 = 10% waste)
            const waste = Number(bomItem.wasteFactor) || 0;
            const quantityToDeduct = Number(bomItem.quantity) * (1 + waste) * item.quantity;

            if (bomItem.internalProduct) {
                const prev = bomItem.internalProduct.stockQuantity;
                deductions.push({
                    componentType: 'InternalProduct',
                    componentId: bomItem.internalProduct.id,
                    componentName: bomItem.internalProduct.name,
                    quantityDeducted: quantityToDeduct,
                    previousStock: prev,
                    newStock: prev - quantityToDeduct
                });
            } else if (bomItem.childVariation && bomItem.childProduct) {
                const rawData = bomItem.childVariation.rawData as any;
                const prev = bomItem.childVariation.stockQuantity ?? rawData?.stock_quantity ?? 0;
                deductions.push({
                    componentType: 'ProductVariation',
                    componentId: bomItem.childProduct.id,
                    componentName: `${bomItem.childProduct.name} (Var ${bomItem.childVariation.sku})`,
                    wooId: bomItem.childVariation.wooId,
                    parentWooId: bomItem.childProduct.wooId,
                    quantityDeducted: quantityToDeduct,
                    previousStock: prev,
                    newStock: prev - quantityToDeduct
                });
            } else if (bomItem.childProduct) {
                // Guard: skip variable parent products — BOM should link to a specific variation
                const childRaw = bomItem.childProduct.rawData as any;
                const isVariable = childRaw?.type?.includes('variable') || childRaw?.variations?.length > 0;
                if (isVariable) {
                    Logger.warn(`[BOMConsumption] Skipping deduction on variable parent product — BOM should link to a specific variation`, {
                        componentName: bomItem.childProduct.name,
                        wooId: bomItem.childProduct.wooId
                    });
                    continue;
                }
                const prev = bomItem.childProduct.stockQuantity ?? childRaw?.stock_quantity ?? 0;
                deductions.push({
                    componentType: 'WooProduct',
                    componentId: bomItem.childProduct.id,
                    componentName: bomItem.childProduct.name,
                    wooId: bomItem.childProduct.wooId,
                    quantityDeducted: quantityToDeduct,
                    previousStock: prev,
                    newStock: prev - quantityToDeduct
                });
            }
        }
        return deductions;
    }

    private static async executeDeduction(
        accountId: string,
        deduction: ComponentDeduction,
        wooService: any
    ) {
        // Why atomic decrement: using absolute SET races with concurrent PO receives.
        // The planned newStock is still recorded in the ledger for audit purposes.
        const qty = deduction.quantityDeducted;

        if (deduction.componentType === 'InternalProduct') {
            const updated = await prisma.internalProduct.update({
                where: { id: deduction.componentId },
                data: { stockQuantity: { decrement: qty } },
                select: { stockQuantity: true }
            });
            // Why floor: negative stock in WooCommerce confuses customers and order workflows.
            if (updated.stockQuantity !== null && updated.stockQuantity < 0) {
                Logger.warn('[BOM] Component stock went negative after deduction', {
                    componentType: 'InternalProduct',
                    componentId: deduction.componentId,
                    newStock: updated.stockQuantity,
                    deducted: qty
                });
            }
        } else if (deduction.componentType === 'ProductVariation') {
            const updated = await prisma.productVariation.update({
                where: { productId_wooId: { productId: deduction.componentId, wooId: deduction.wooId! } },
                data: { stockQuantity: { decrement: qty } },
                select: { stockQuantity: true }
            });
            // Clamp to 0 for WooCommerce — negative stock causes UX issues
            const wooStock = Math.max(0, updated.stockQuantity ?? 0);
            if (updated.stockQuantity !== null && updated.stockQuantity < 0) {
                Logger.warn('[BOM] Component stock went negative after deduction', {
                    componentType: 'ProductVariation', wooId: deduction.wooId,
                    dbStock: updated.stockQuantity, wooStock, deducted: qty
                });
            }
            await withRetry(
                () => wooService.updateProductVariation(deduction.parentWooId!, deduction.wooId!, { stock_quantity: wooStock, manage_stock: true }),
                { context: `Update variation ${deduction.wooId}` }
            );
        } else if (deduction.componentType === 'WooProduct') {
            const updated = await prisma.wooProduct.update({
                where: { id: deduction.componentId },
                data: { stockQuantity: { decrement: qty } },
                select: { stockQuantity: true }
            });
            const wooStock = Math.max(0, updated.stockQuantity ?? 0);
            if (updated.stockQuantity !== null && updated.stockQuantity < 0) {
                Logger.warn('[BOM] Component stock went negative after deduction', {
                    componentType: 'WooProduct', wooId: deduction.wooId,
                    dbStock: updated.stockQuantity, wooStock, deducted: qty
                });
            }
            await withRetry(
                () => wooService.updateProduct(deduction.wooId!, { stock_quantity: wooStock, manage_stock: true }),
                { context: `Update product ${deduction.wooId}` }
            );
        }
    }

    /**
     * Acquire a lock for order processing.
     * Uses Redis SETNX as primary, falls back to PostgreSQL advisory lock.
     * Returns lock info for proper release.
     */
    private static async acquireLock(
        lockKey: string,
        accountId: string,
        orderId: number
    ): Promise<{ acquired: boolean; usedPostgres: boolean }> {
        // Try Redis first (faster, distributed)
        try {
            const result = await redisClient.setnx(lockKey, new Date().toISOString());
            if (result === 1) {
                await redisClient.expire(lockKey, this.ORDER_LOCK_TTL_SECONDS);
                return { acquired: true, usedPostgres: false };
            }
            // Lock held by another process
            return { acquired: false, usedPostgres: false };
        } catch (redisError) {
            Logger.warn('[BOMConsumption] Redis unavailable, falling back to PostgreSQL advisory lock', {
                lockKey,
                error: redisError instanceof Error ? redisError.message : 'Unknown'
            });
        }

        // Fallback: PostgreSQL advisory lock
        // Create a consistent numeric hash from accountId + orderId
        const lockId = this.hashToInt32(`${accountId}:${orderId}`);

        try {
            const result = await prisma.$queryRaw<{ pg_try_advisory_lock: boolean }[]>`
                SELECT pg_try_advisory_lock(${lockId}) as pg_try_advisory_lock
            `;
            const acquired = result[0]?.pg_try_advisory_lock === true;

            if (acquired) {
                Logger.debug('[BOMConsumption] PostgreSQL advisory lock acquired', { lockId, accountId, orderId });
            }

            return { acquired, usedPostgres: true };
        } catch (pgError) {
            Logger.error('[BOMConsumption] Both Redis and PostgreSQL locking failed', {
                lockKey,
                error: pgError instanceof Error ? pgError.message : 'Unknown'
            });
            // If both fail, return not acquired (safe: skip processing rather than double-process)
            return { acquired: false, usedPostgres: false };
        }
    }

    /**
     * Release a lock (Redis or PostgreSQL based on how it was acquired).
     */
    private static async releaseLock(
        lockKey: string,
        usedPostgres: boolean,
        accountId: string,
        orderId: number
    ): Promise<void> {
        if (usedPostgres) {
            // Release PostgreSQL advisory lock
            const lockId = this.hashToInt32(`${accountId}:${orderId}`);
            try {
                await prisma.$queryRaw`SELECT pg_advisory_unlock(${lockId})`;
                Logger.debug('[BOMConsumption] PostgreSQL advisory lock released', { lockId });
            } catch (error) {
                Logger.error('[BOMConsumption] Failed to release PostgreSQL advisory lock', {
                    lockId,
                    error: error instanceof Error ? error.message : 'Unknown'
                });
            }
        } else {
            // Release Redis lock
            try {
                await redisClient.del(lockKey);
            } catch (error) {
                Logger.warn('[BOMConsumption] Failed to release Redis lock (may have expired)', {
                    lockKey,
                    error: error instanceof Error ? error.message : 'Unknown'
                });
            }
        }
    }

    /**
     * Create a 32-bit signed integer hash from a string.
     * Used for PostgreSQL advisory locks which require bigint.
     */
    private static hashToInt32(str: string): number {
        let hash = 0;
        for (let i = 0; i < str.length; i++) {
            const char = str.charCodeAt(i);
            hash = ((hash << 5) - hash) + char;
            hash = hash & hash; // Convert to 32-bit integer
        }
        return hash;
    }

    // consumeLineItemComponents was removed — superseded by planLineItemDeductions + executeDeduction pattern

    /**
     * After a component's stock changes, find all BOM products that use it
     * and trigger a sync for each to update their effective stock in WooCommerce.
     *
     * @param componentType - Whether the component is a WooCommerce product or an internal product.
     *   Defaults to 'wooProduct' for backward compatibility.
     */
    static async cascadeSyncAffectedProducts(
        accountId: string,
        componentProductId: string,
        componentVariationId?: number,
        componentType: 'wooProduct' | 'internalProduct' = 'wooProduct'
    ): Promise<void> {
        // Why no variation filter: we must cascade to ALL parent BOMs that reference
        // this component, not just those using a specific variation. A stock change
        // in the component affects every parent's effective stock calculation.
        const whereClause = componentType === 'internalProduct'
            ? { internalProductId: componentProductId }
            : { childProductId: componentProductId };

        const affectedBomItems = await prisma.bOMItem.findMany({
            where: {
                isActive: true,
                ...whereClause
            },
            include: {
                bom: {
                    include: {
                        product: { select: { id: true, wooId: true, name: true, accountId: true } }
                    }
                }
            }
        });

        // Filter to only this account's BOMs
        const accountBoms = affectedBomItems.filter(item => item.bom.product.accountId === accountId);

        if (accountBoms.length === 0) {
            Logger.debug(`[BOMConsumption] No affected BOM products found for component ${componentProductId} (type: ${componentType})`, { accountId });
            return;
        }

        Logger.info(`[BOMConsumption] Cascade syncing ${accountBoms.length} affected BOM products for ${componentType} ${componentProductId}`, { accountId });

        // Sync each affected BOM product
        for (const item of accountBoms) {
            try {
                await BOMInventorySyncService.syncProductToWoo(
                    accountId,
                    item.bom.productId,
                    item.bom.variationId
                );
                Logger.debug(`[BOMConsumption] Cascade synced ${item.bom.product.name}`, { accountId });
            } catch (err: any) {
                Logger.error(`[BOMConsumption] Failed to cascade sync ${item.bom.product.name}`, {
                    accountId,
                    productId: item.bom.productId,
                    error: err.message
                });
            }
        }
    }
}

/**
 * Blocked Contact Service
 * 
 * Manages blocked contacts for inbox filtering.
 * Blocked contacts have their messages auto-resolved without autoreplies.
 * 
 * OPTIMIZATION: Uses Redis set caching for O(1) blocked contact lookups during
 * email ingestion. Cache is invalidated on block/unblock operations.
 */

import { prisma } from '../utils/prisma';
import { Logger } from '../utils/logger';
import { redisClient as redis } from '../utils/redis';

// Cache TTL: 5 minutes - allows quick updates while avoiding constant DB queries
const BLOCKED_CACHE_TTL = 300;

/**
 * Get Redis key for blocked contacts set
 */
function getBlockedSetKey(accountId: string): string {
    return `blocked:emails:${accountId}`;
}

export class BlockedContactService {
    /**
     * Check if an email is blocked for a given account.
     * 
     * PERFORMANCE: Uses Redis set membership check (O(1)) with fallback to DB.
     * The blocked emails set is populated on first check and cached.
     */
    static async isBlocked(accountId: string, email: string): Promise<boolean> {
        const normalizedEmail = email.toLowerCase();
        const cacheKey = getBlockedSetKey(accountId);

        try {
            // Check if set exists and check membership in one call
            const [exists, isMember] = await Promise.all([
                redis.exists(cacheKey),
                redis.sismember(cacheKey, normalizedEmail)
            ]);

            if (exists) {
                return isMember === 1;
            }

            // Cache miss - populate from database
            const blocked = await prisma.blockedContact.findMany({
                where: { accountId },
                select: { email: true }
            });

            // Populate Redis set (or create empty marker)
            if (blocked.length > 0) {
                await redis.sadd(cacheKey, ...blocked.map(b => b.email));
            } else {
                // Use a special marker to indicate "set exists but is empty"
                await redis.sadd(cacheKey, '__EMPTY_SET__');
            }
            await redis.expire(cacheKey, BLOCKED_CACHE_TTL);

            return blocked.some(b => b.email === normalizedEmail);
        } catch (redisError) {
            // Redis unavailable - fall back to database
            Logger.debug('[BlockedContact] Redis unavailable, falling back to DB', { accountId });
            const blocked = await prisma.blockedContact.findUnique({
                where: {
                    accountId_email: { accountId, email: normalizedEmail }
                }
            });
            return !!blocked;
        }
    }

    /**
     * Block a contact by email.
     * 
     * NOTE: Invalidates cache to ensure consistency.
     */
    static async blockContact(
        accountId: string,
        email: string,
        blockedBy?: string,
        reason?: string
    ): Promise<{ success: boolean; error?: string }> {
        try {
            await prisma.blockedContact.upsert({
                where: {
                    accountId_email: { accountId, email: email.toLowerCase() }
                },
                create: {
                    accountId,
                    email: email.toLowerCase(),
                    blockedBy,
                    reason
                },
                update: {
                    blockedBy,
                    reason,
                    blockedAt: new Date()
                }
            });

            // Invalidate cache so next check repopulates
            try {
                await redis.del(getBlockedSetKey(accountId));
            } catch { /* Redis unavailable is fine */ }

            Logger.info('[BlockedContact] Contact blocked', { accountId, email });
            return { success: true };
        } catch (error) {
            Logger.error('[BlockedContact] Failed to block contact', { error, accountId, email });
            return { success: false, error: 'Failed to block contact' };
        }
    }

    /**
     * Unblock a contact by email.
     * 
     * NOTE: Invalidates cache to ensure consistency.
     */
    static async unblockContact(
        accountId: string,
        email: string
    ): Promise<{ success: boolean; error?: string }> {
        try {
            await prisma.blockedContact.deleteMany({
                where: {
                    accountId,
                    email: email.toLowerCase()
                }
            });

            // Invalidate cache so next check repopulates
            try {
                await redis.del(getBlockedSetKey(accountId));
            } catch { /* Redis unavailable is fine */ }

            Logger.info('[BlockedContact] Contact unblocked', { accountId, email });
            return { success: true };
        } catch (error) {
            Logger.error('[BlockedContact] Failed to unblock contact', { error, accountId, email });
            return { success: false, error: 'Failed to unblock contact' };
        }
    }

    /**
     * List all blocked contacts for an account.
     */
    static async listBlocked(accountId: string) {
        return prisma.blockedContact.findMany({
            where: { accountId },
            include: {
                blocker: { select: { id: true, fullName: true } }
            },
            orderBy: { blockedAt: 'desc' }
        });
    }

    /**
     * Get a single blocked contact.
     */
    static async getBlockedContact(accountId: string, email: string) {
        return prisma.blockedContact.findUnique({
            where: {
                accountId_email: { accountId, email: email.toLowerCase() }
            },
            include: {
                blocker: { select: { id: true, fullName: true } }
            }
        });
    }
}

/**
 * Co-Pilot ROI Service
 * 
 * Calculates and tracks the value generated by AI Co-Pilot recommendations.
 * Provides attribution metrics for executive dashboards.
 * Part of AI Co-Pilot v2.
 */

import { prisma } from '../utils/prisma';
import { Logger } from '../utils/logger';


export interface ROISummary {
    period: {
        start: Date;
        end: Date;
        days: number;
    };

    // Revenue attribution
    revenue: {
        /** Revenue from campaigns affected by AI recommendations */
        attributedRevenue: number;
        /** Estimated revenue increase due to AI actions */
        estimatedLift: number;
        /** Percentage improvement vs baseline */
        liftPercentage: number;
    };

    // Cost savings
    savings: {
        /** Money saved from paused underperforming campaigns */
        pausedCampaignSavings: number;
        /** Budget reallocated from low to high performers */
        reallocationSavings: number;
        /** Total cost avoided */
        totalSavings: number;
    };

    // Action metrics
    actions: {
        /** Total recommendations generated */
        totalRecommendations: number;
        /** Recommendations executed */
        executed: number;
        /** Recommendations pending user review */
        pendingReview: number;
        /** Recommendations dismissed */
        dismissed: number;
        /** Execution rate percentage */
        executionRate: number;
    };

    // Time value
    timeValue: {
        /** Estimated hours of manual work saved */
        hoursSaved: number;
        /** Dollar value of time saved (at avg agency rate) */
        dollarValue: number;
    };

    // Breakdown by action type
    byActionType: Array<{
        type: string;
        count: number;
        estimatedValue: number;
    }>;

    // Top impactful actions
    topActions: Array<{
        id: string;
        type: string;
        description: string;
        valueGenerated: number;
        executedAt: Date;
    }>;
}

// Average time to perform actions manually (in minutes)
const ACTION_TIME_ESTIMATES: Record<string, number> = {
    budget_increase: 10,
    budget_decrease: 10,
    pause: 5,
    enable: 5,
    add_keyword: 15,
    adjust_bid: 10,
    create_campaign: 60,
    audience_sync: 30,
    ad_copy: 45
};

// Average agency hourly rate for time value calculation
const AGENCY_HOURLY_RATE = 150;


export class CoPilotROIService {

    /**
     * Get comprehensive ROI summary for an account
     */
    static async getROISummary(
        accountId: string,
        periodDays: number = 30
    ): Promise<ROISummary> {
        const periodEnd = new Date();
        const periodStart = new Date();
        periodStart.setDate(periodStart.getDate() - periodDays);

        // Get all action logs for the period
        const actionLogs = await prisma.adActionLog.findMany({
            where: {
                accountId,
                createdAt: { gte: periodStart, lte: periodEnd }
            },
            orderBy: { createdAt: 'desc' }
        });

        // Get recommendation logs
        const recommendations = await prisma.recommendationLog.findMany({
            where: {
                accountId,
                createdAt: { gte: periodStart, lte: periodEnd }
            }
        });

        // Calculate action metrics
        const executedActions = actionLogs.filter(a => a.status === 'executed');
        const pendingActions = actionLogs.filter(a => a.status === 'pending');
        const dismissedActions = recommendations.filter(r => r.status === 'dismissed');

        // Calculate savings from paused campaigns
        const pauseActions = executedActions.filter(a => a.actionType === 'pause');
        const pausedSavings = await this.calculatePausedSavings(accountId, pauseActions, periodDays);

        // Calculate budget reallocation value
        const budgetActions = executedActions.filter(a =>
            a.actionType === 'budget_increase' || a.actionType === 'budget_decrease'
        );
        const reallocationValue = await this.calculateReallocationValue(accountId, budgetActions);

        // Calculate time savings
        const timeSaved = this.calculateTimeSaved(executedActions);

        // Calculate revenue attribution
        const revenueAttribution = await this.calculateRevenueAttribution(
            accountId,
            executedActions,
            periodStart,
            periodEnd
        );

        // Group by action type
        const byActionType = this.groupByActionType(executedActions);

        // Get top impactful actions
        const topActions = await this.getTopActions(accountId, executedActions.slice(0, 10));

        return {
            period: {
                start: periodStart,
                end: periodEnd,
                days: periodDays
            },
            revenue: revenueAttribution,
            savings: {
                pausedCampaignSavings: pausedSavings,
                reallocationSavings: reallocationValue,
                totalSavings: pausedSavings + reallocationValue
            },
            actions: {
                totalRecommendations: recommendations.length,
                executed: executedActions.length,
                pendingReview: pendingActions.length,
                dismissed: dismissedActions.length,
                executionRate: recommendations.length > 0
                    ? (executedActions.length / recommendations.length) * 100
                    : 0
            },
            timeValue: timeSaved,
            byActionType,
            topActions
        };
    }

    /**
     * Calculate savings from paused campaigns
     */
    private static async calculatePausedSavings(
        accountId: string,
        pauseActions: any[],
        periodDays: number
    ): Promise<number> {
        let totalSavings = 0;

        for (const action of pauseActions) {
            // Get campaign's daily spend before pause
            const metadata = action.metadata as any;
            if (metadata?.campaignBudget) {
                // Calculate days saved (from pause to now or end of period)
                const pauseDate = new Date(action.executedAt || action.createdAt);
                const now = new Date();
                const daysSaved = Math.min(
                    Math.floor((now.getTime() - pauseDate.getTime()) / (1000 * 60 * 60 * 24)),
                    periodDays
                );

                // Multiply daily budget by days saved
                totalSavings += (metadata.campaignBudget * daysSaved);
            }
        }

        return totalSavings;
    }

    /**
     * Calculate value from budget reallocation
     */
    private static async calculateReallocationValue(
        accountId: string,
        budgetActions: any[]
    ): Promise<number> {
        let totalValue = 0;

        // Budget increases on high-performers generate value
        for (const action of budgetActions) {
            if (action.actionType === 'budget_increase') {
                const metadata = action.metadata as any;
                if (metadata?.amount && metadata?.campaignRoas) {
                    // Value = (budget increase * ROAS improvement opportunity)
                    // Estimate 10% ROAS improvement from optimized allocation
                    const potentialRevenue = metadata.amount * (metadata.campaignRoas + 0.1);
                    const baselineRevenue = metadata.amount * metadata.campaignRoas;
                    totalValue += (potentialRevenue - baselineRevenue);
                }
            }
        }

        return Math.max(0, totalValue);
    }

    /**
     * Calculate time saved by automated actions
     */
    private static calculateTimeSaved(executedActions: any[]): {
        hoursSaved: number;
        dollarValue: number;
    } {
        let totalMinutes = 0;

        for (const action of executedActions) {
            const timeEstimate = ACTION_TIME_ESTIMATES[action.actionType] || 10;
            totalMinutes += timeEstimate;
        }

        const hoursSaved = totalMinutes / 60;
        const dollarValue = hoursSaved * AGENCY_HOURLY_RATE;

        return { hoursSaved, dollarValue };
    }

    /**
     * Calculate revenue attribution from AI actions
     */
    private static async calculateRevenueAttribution(
        accountId: string,
        executedActions: any[],
        periodStart: Date,
        periodEnd: Date
    ): Promise<{
        attributedRevenue: number;
        estimatedLift: number;
        liftPercentage: number;
    }> {
        // Get outcome data from recommendation logs
        const outcomes = await prisma.recommendationLog.findMany({
            where: {
                accountId,
                status: 'implemented',
                outcomeRecordedAt: { not: null },
                implementedAt: { gte: periodStart, lte: periodEnd }
            },
            select: {
                id: true,
                roasBefore: true,
                roasAfter: true,
                dataPoints: true
            }
        });

        let totalLift = 0;
        let baselineRevenue = 0;

        for (const outcome of outcomes) {
            if (outcome.roasBefore && outcome.roasAfter) {
                const improvement = outcome.roasAfter - outcome.roasBefore;
                if (improvement > 0) {
                    // Estimate revenue lift based on ROAS improvement
                    // Assuming average campaign spend context
                    totalLift += improvement * 100; // Simplified calculation
                }
            }
        }


        // Get total ad revenue for the period
        const { AdsService } = await import('./ads');
        const adAccounts = await AdsService.getAdAccounts(accountId);

        let totalAdRevenue = 0;
        for (const adAccount of adAccounts) {
            try {
                if (adAccount.platform === 'GOOGLE') {
                    const insights = await AdsService.getGoogleInsights(adAccount.id) as any;
                    totalAdRevenue += insights?.conversionsValue || 0;
                } else if (adAccount.platform === 'META') {
                    const insights = await AdsService.getMetaInsights(adAccount.id) as any;
                    totalAdRevenue += insights?.purchase_roas?.reduce((sum: number, r: any) => sum + (r.value || 0), 0) || 0;
                }
            } catch {
                // Skip on error
            }
        }

        // Attribute a portion of revenue to AI actions
        // Conservative estimate: 5% of revenue attributable to AI optimization
        const attributionRate = 0.05;
        const attributedRevenue = totalAdRevenue * attributionRate;

        return {
            attributedRevenue,
            estimatedLift: totalLift,
            liftPercentage: totalAdRevenue > 0 ? (attributedRevenue / totalAdRevenue) * 100 : 0
        };
    }

    /**
     * Group actions by type with value estimates
     */
    private static groupByActionType(executedActions: any[]): Array<{
        type: string;
        count: number;
        estimatedValue: number;
    }> {
        const groups = new Map<string, { count: number; value: number }>();

        for (const action of executedActions) {
            const existing = groups.get(action.actionType) || { count: 0, value: 0 };
            const timeValue = (ACTION_TIME_ESTIMATES[action.actionType] || 10) / 60 * AGENCY_HOURLY_RATE;

            groups.set(action.actionType, {
                count: existing.count + 1,
                value: existing.value + timeValue
            });
        }

        return Array.from(groups.entries()).map(([type, data]) => ({
            type,
            count: data.count,
            estimatedValue: data.value
        })).sort((a, b) => b.estimatedValue - a.estimatedValue);
    }

    /**
     * Get top impactful actions
     */
    private static async getTopActions(
        accountId: string,
        recentActions: any[]
    ): Promise<Array<{
        id: string;
        type: string;
        description: string;
        valueGenerated: number;
        executedAt: Date;
    }>> {
        return recentActions.map(action => {
            const metadata = action.metadata as any;
            const timeValue = (ACTION_TIME_ESTIMATES[action.actionType] || 10) / 60 * AGENCY_HOURLY_RATE;

            let description = '';
            switch (action.actionType) {
                case 'pause':
                    description = `Paused underperforming campaign: ${metadata?.campaignName || 'Unknown'}`;
                    break;
                case 'enable':
                    description = `Enabled campaign: ${metadata?.campaignName || 'Unknown'}`;
                    break;
                case 'budget_increase':
                    description = `Increased budget by $${metadata?.amount || 0} for ${metadata?.campaignName || 'campaign'}`;
                    break;
                case 'budget_decrease':
                    description = `Decreased budget by $${metadata?.amount || 0} for ${metadata?.campaignName || 'campaign'}`;
                    break;
                case 'add_keyword':
                    description = `Added keyword: ${metadata?.keyword || 'Unknown'}`;
                    break;
                default:
                    description = `${action.actionType} action on ${metadata?.campaignName || 'campaign'}`;
            }

            return {
                id: action.id,
                type: action.actionType,
                description,
                valueGenerated: timeValue + (metadata?.estimatedValue || 0),
                executedAt: action.executedAt || action.createdAt
            };
        });
    }

    /**
     * Get quick stats for dashboard widget
     */
    static async getQuickStats(accountId: string): Promise<{
        totalValue: number;
        actionsExecuted: number;
        hoursSaved: number;
        pendingActions: number;
    }> {
        const summary = await this.getROISummary(accountId, 30);

        return {
            totalValue: summary.savings.totalSavings + summary.timeValue.dollarValue,
            actionsExecuted: summary.actions.executed,
            hoursSaved: Math.round(summary.timeValue.hoursSaved * 10) / 10,
            pendingActions: summary.actions.pendingReview
        };
    }
}

