export class InvoiceService {

    /**
     * Creates or updates the single invoice template for an account.
     * Only one template is allowed per account - always overwrites existing.
     */
    async createTemplate(accountId: string, data: { name: string, layout: any }) {
        // Find existing template for this account
        const existing = await prisma.invoiceTemplate.findFirst({
            where: { accountId }
        });

        if (existing) {
            // Update existing template
            return await prisma.invoiceTemplate.update({
                where: { id: existing.id },
                data: {
                    name: data.name,
                    layout: data.layout
                }
            });
        }

        // Create new template
        return await prisma.invoiceTemplate.create({
            data: {
                accountId,
                name: data.name,
                layout: data.layout
            }
        });
    }

    async updateTemplate(id: string, accountId: string, data: { name?: string, layout?: any }) {
        // Ensure belongs to account
        const existing = await prisma.invoiceTemplate.findFirst({
            where: { id, accountId }
        });

        if (!existing) throw new Error("Template not found or access denied");

        return await prisma.invoiceTemplate.update({
            where: { id },
            data: {
                ...data
            }
        });
    }

    async getTemplate(id: string, accountId: string) {
        return await prisma.invoiceTemplate.findFirst({
            where: { id, accountId }
        });
    }

    async getTemplates(accountId: string) {
        return await prisma.invoiceTemplate.findMany({
            where: { accountId },
            orderBy: { createdAt: 'desc' }
        });
    }

    async deleteTemplate(id: string, accountId: string) {
        const existing = await prisma.invoiceTemplate.findFirst({
            where: { id, accountId }
        });

        if (!existing) throw new Error("Template not found or access denied");

        return await prisma.invoiceTemplate.delete({
            where: { id }
        });
    }

    /**
     * Generates a PDF for an order based on a template.
     * Uses pdfkit to generate a professional PDF invoice.
     */
    async generateInvoicePdf(accountId: string, orderId: string, templateId: string): Promise<{ relativeUrl: string, absolutePath: string }> {
        // 1. Fetch Order Data with raw JSON
        const order = await prisma.wooOrder.findUnique({
            where: { id: orderId }
        });

        if (!order) throw new Error("Order not found");

        // 2. Fetch Template
        const template = await prisma.invoiceTemplate.findFirst({
            where: { id: templateId, accountId }
        });

        if (!template) throw new Error("Invoice Template not found");

        Logger.info(`Generating PDF for Order`, { orderNumber: order.number, templateName: template.name });

        // 3. Parse raw order data for invoice details
        const rawData = order.rawData as any || {};
        const billing = rawData.billing || {};
        const lineItems = rawData.line_items || [];

        // 4. Generate PDF invoice
        const fileName = `invoice-${order.number}-${Date.now()}.pdf`;
        const filePath = path.join(INVOICE_DIR, fileName);

        await this.createPdf(filePath, order, billing, lineItems, template);

        Logger.info(`Invoice PDF saved`, { filePath });

        // Return relative URL and absolute path
        return {
            relativeUrl: `/uploads/invoices/${fileName}`,
            absolutePath: filePath
        };
    }

    /**
     * Create PDF file using PDFKit based on the saved template layout
     */
    private createPdf(filePath: string, order: any, billing: any, lineItems: any[], template: any): Promise<void> {
        return new Promise((resolve, reject) => {
            const doc = new PDFDocument({ margin: 50, size: 'A4' });
            const stream = fs.createWriteStream(filePath);

            doc.on('error', reject);
            doc.pipe(stream);

            // Parse template layout
            let layoutData = template.layout;
            Logger.info('Template layout raw type', { type: typeof layoutData, hasLayout: !!layoutData });

            if (typeof layoutData === 'string') {
                try {
                    layoutData = JSON.parse(layoutData);
                    Logger.info('Parsed layout from string');
                } catch (e) {
                    Logger.error('Failed to parse template layout', { error: e });
                }
            }

            const grid = layoutData?.grid || [];
            const items = layoutData?.items || [];

            Logger.info('Template layout extracted', {
                gridCount: grid.length,
                itemsCount: items.length,
                itemTypes: items.map((i: any) => i.type)
            });

            // Helpers — use Intl.NumberFormat with order currency for consistency with HTML preview
            const orderCurrency = (order.rawData as any)?.currency || 'AUD';
            const formatCurrency = (val: any) => {
                try {
                    return new Intl.NumberFormat('en-US', { style: 'currency', currency: orderCurrency }).format(parseFloat(val || 0));
                } catch {
                    return `$${parseFloat(val || 0).toFixed(2)}`;
                }
            };
            const formatDate = (d: Date) => d.toLocaleDateString('en-AU', { day: '2-digit', month: '2-digit', year: 'numeric' });

            /** Decode HTML entities (&#NNN; and common named entities) to actual characters. */
            const decodeEntities = (text: string): string => {
                return text
                    .replace(/&#(\d+);/g, (_, code) => String.fromCharCode(parseInt(code, 10)))
                    .replace(/&#x([0-9a-fA-F]+);/g, (_, code) => String.fromCharCode(parseInt(code, 16)))
                    .replace(/&amp;/g, '&')
                    .replace(/&lt;/g, '<')
                    .replace(/&gt;/g, '>')
                    .replace(/&quot;/g, '"')
                    .replace(/&apos;/g, "'");
            };

            // Page dimensions (A4 with 50pt margins)
            const pageWidth = 495; // 595 - 100 (margins)
            const colWidth = pageWidth / 12;
            const rowHeight = 30;
            const marginLeft = 50;
            const marginTop = 50;

            // Sort grid items by Y position
            const sortedGrid = [...grid].sort((a: any, b: any) => a.y - b.y);

            let currentY = marginTop;

            // Find item config by ID
            const getItemConfig = (id: string) => items.find((i: any) => i.id === id);

            // Render a single block
            const renderBlock = (itemConfig: any, x: number, width: number, startY: number): number => {
                if (!itemConfig) return 0;

                let blockHeight = 0;
                const type = itemConfig.type;

                switch (type) {
                    case 'header': {
                        // Header with logo and business details
                        doc.fontSize(10);
                        if (itemConfig.businessDetails) {
                            const lines = itemConfig.businessDetails.split('\n');
                            lines.forEach((line: string, i: number) => {
                                doc.text(line, x + width - 200, startY + (i * 12), { width: 200, align: 'right' });
                            });
                            blockHeight = Math.max(blockHeight, lines.length * 12 + 10);
                        }
                        if (itemConfig.logo) {
                            try {
                                // Resolve relative URL to local file path
                                const logoUrl: string = itemConfig.logo;
                                if (logoUrl.startsWith('/uploads/')) {
                                    const localPath = path.join(__dirname, '../../', logoUrl);
                                    if (fs.existsSync(localPath)) {
                                        doc.image(localPath, x, startY, { width: 120, height: 60, fit: [120, 60] });
                                    } else {
                                        Logger.warn('Logo file not found on disk', { logoUrl, localPath });
                                    }
                                }
                            } catch (e) {
                                Logger.warn('Failed to render logo in PDF', { error: e });
                            }
                        }
                        blockHeight = Math.max(blockHeight, 60);
                        break;
                    }

                    case 'customer_details': {
                        doc.fontSize(10).font('Helvetica-Bold');
                        doc.text('Bill To:', x, startY);
                        doc.font('Helvetica').fontSize(9);
                        let custY = startY + 15;
                        if (billing.first_name || billing.last_name) {
                            doc.text(`${billing.first_name || ''} ${billing.last_name || ''}`, x, custY);
                            custY += 12;
                        }
                        if (billing.company) {
                            doc.text(billing.company, x, custY);
                            custY += 12;
                        }
                        if (billing.address_1) {
                            doc.text(billing.address_1, x, custY);
                            custY += 12;
                        }
                        if (billing.address_2) {
                            doc.text(billing.address_2, x, custY);
                            custY += 12;
                        }
                        if (billing.city || billing.state || billing.postcode) {
                            doc.text(`${billing.city || ''}${billing.city && billing.state ? ', ' : ''}${billing.state || ''} ${billing.postcode || ''}`, x, custY);
                            custY += 12;
                        }
                        if (billing.country) {
                            doc.text(billing.country, x, custY);
                            custY += 12;
                        }
                        if (billing.email) {
                            doc.fillColor('#4f46e5').text(billing.email, x, custY);
                            doc.fillColor('black');
                            custY += 12;
                        }
                        if (billing.phone) {
                            doc.text(billing.phone, x, custY);
                            custY += 12;
                        }
                        blockHeight = custY - startY + 10;
                        break;
                    }

                    case 'order_details': {
                        doc.fontSize(9);
                        const rawData = order.rawData as any || {};
                        const shippingMethod = rawData.shipping_lines?.[0]?.method_title || 'N/A';
                        const paymentMethod = rawData.payment_method_title || order.paymentMethod || 'N/A';
                        // Use WooCommerce's date_created for consistency with client-side rendering
                        const orderDate = rawData.date_created
                            ? formatDate(new Date(rawData.date_created))
                            : formatDate(order.createdAt);

                        const detailsData = [
                            ['Order Number:', order.number],
                            ['Order Date:', orderDate],
                            ['Payment Method:', paymentMethod],
                            ['Shipping Method:', shippingMethod]
                        ];

                        let detY = startY;
                        detailsData.forEach(([label, value]) => {
                            doc.font('Helvetica').fillColor('#64748b').text(label, x, detY, { continued: false });
                            doc.font('Helvetica-Bold').fillColor('black').text(value, x + 100, detY);
                            detY += 14;
                        });
                        blockHeight = detY - startY + 10;
                        break;
                    }

                    case 'order_table': {
                        // Use full page width for the table regardless of grid placement
                        doc.fontSize(9).font('Helvetica-Bold');
                        const tableX = 50; // marginLeft
                        const fullTableWidth = pageWidth;
                        const descWidth = fullTableWidth * 0.55;
                        const qtyWidth = 40;
                        const priceWidth = 70;
                        const totalWidth = fullTableWidth - descWidth - qtyWidth - priceWidth;

                        doc.text('Description', tableX, startY);
                        doc.text('Qty', tableX + descWidth, startY, { width: qtyWidth, align: 'center' });
                        doc.text('Unit Price', tableX + descWidth + qtyWidth, startY, { width: priceWidth, align: 'right' });
                        doc.text('Total', tableX + descWidth + qtyWidth + priceWidth, startY, { width: totalWidth, align: 'right' });

                        doc.moveTo(tableX, startY + 12).lineTo(tableX + fullTableWidth, startY + 12).stroke();

                        let tableY = startY + 18;
                        doc.font('Helvetica').fontSize(9);

                        // Keys to exclude from metadata display (internal plugin/system keys)
                        const excludedKeyPatterns = [
                            /^_/, /^pa_/, /wcpa/i, /meta_data/i,
                            /^reduced_stock/i, /label_map/i, /droppable/i, /^id$/i, /^key$/i
                        ];
                        const isExcludedKey = (key: string) => excludedKeyPatterns.some(p => p.test(key));

                        lineItems.forEach((item: any) => {
                            // Check for page break
                            if (tableY > 720) {
                                doc.addPage();
                                tableY = 50;
                            }

                            const itemName = item.name || 'Product';
                            const qty = item.quantity || 1;
                            const unitPrice = qty > 0 ? (parseFloat(item.total || 0) / qty) : 0;

                            doc.text(itemName, tableX, tableY, { width: descWidth - 10 });
                            doc.text(String(qty), tableX + descWidth, tableY, { width: qtyWidth, align: 'center' });
                            doc.text(formatCurrency(unitPrice), tableX + descWidth + qtyWidth, tableY, { width: priceWidth, align: 'right' });
                            doc.text(formatCurrency(item.total), tableX + descWidth + qtyWidth + priceWidth, tableY, { width: totalWidth, align: 'right' });

                            // Display user-facing metadata with proper filtering
                            const itemMeta = (item.meta_data || []).filter((m: any) => {
                                const key = m.key || '';
                                if (isExcludedKey(key)) return false;
                                if (!m.display_key && !m.display_value) return false;
                                return true;
                            });
                            if (itemMeta.length > 0) {
                                tableY += 12;
                                doc.fontSize(8).fillColor('#64748b');
                                itemMeta.slice(0, 6).forEach((m: any) => {
                                    const label = m.display_key || m.key.replace(/_/g, ' ');
                                    const val = typeof m.value === 'object' ? JSON.stringify(m.value) : (m.display_value || m.value);
                                    doc.text(decodeEntities(`${label}: ${val}`), tableX + 10, tableY, { width: descWidth - 20 });
                                    tableY += 10;
                                });
                                doc.fillColor('black').fontSize(9);
                            }

                            tableY += 14;
                        });

                        // Totals integrated into table — use rawData for consistency
                        const rawOrderData = order.rawData as any || {};
                        doc.moveTo(tableX, tableY).lineTo(tableX + fullTableWidth, tableY).stroke();
                        tableY += 10;

                        const taxVal = parseFloat(rawOrderData.total_tax ?? order.taxTotal ?? 0);
                        const shipVal = parseFloat(rawOrderData.shipping_total ?? order.shippingTotal ?? 0);
                        const totalVal = parseFloat(rawOrderData.total ?? order.total ?? 0);
                        const subtotal = totalVal - taxVal - shipVal;
                        const totalsX = tableX + fullTableWidth - 170;

                        doc.font('Helvetica').fontSize(9);
                        doc.text('Subtotal', totalsX, tableY);
                        doc.text(formatCurrency(subtotal), totalsX + 80, tableY, { width: 70, align: 'right' });
                        tableY += 14;

                        if (shipVal > 0) {
                            doc.text('Shipping', totalsX, tableY);
                            doc.text(formatCurrency(shipVal), totalsX + 80, tableY, { width: 70, align: 'right' });
                            tableY += 14;
                        }

                        const discountVal = parseFloat(rawOrderData.discount_total ?? 0);
                        if (discountVal > 0) {
                            doc.fillColor('#059669'); // emerald
                            doc.text('Discount', totalsX, tableY);
                            doc.text(`-${formatCurrency(discountVal)}`, totalsX + 80, tableY, { width: 70, align: 'right' });
                            tableY += 14;
                            doc.fillColor('black');
                        }

                        doc.text('Tax', totalsX, tableY);
                        doc.text(formatCurrency(taxVal), totalsX + 80, tableY, { width: 70, align: 'right' });
                        tableY += 16;

                        doc.font('Helvetica-Bold').fontSize(11);
                        doc.text('Total', totalsX, tableY);
                        doc.text(formatCurrency(totalVal), totalsX + 80, tableY, { width: 70, align: 'right' });
                        tableY += 20;

                        blockHeight = tableY - startY;
                        break;
                    }

                    case 'totals': {
                        // Standalone totals block — use rawData for consistency
                        const rawTotals = order.rawData as any || {};
                        const totTax = parseFloat(rawTotals.total_tax ?? order.taxTotal ?? 0);
                        const totShip = parseFloat(rawTotals.shipping_total ?? order.shippingTotal ?? 0);
                        const totTotal = parseFloat(rawTotals.total ?? order.total ?? 0);
                        const subtotalVal = totTotal - totTax - totShip;

                        doc.fontSize(9).font('Helvetica');

                        let totY = startY;
                        doc.text('Subtotal:', x, totY);
                        doc.text(formatCurrency(subtotalVal), x + 80, totY, { width: 70, align: 'right' });
                        totY += 14;

                        if (totShip > 0) {
                            doc.text('Shipping:', x, totY);
                            doc.text(formatCurrency(totShip), x + 80, totY, { width: 70, align: 'right' });
                            totY += 14;
                        }

                        const totDiscount = parseFloat(rawTotals.discount_total ?? 0);
                        if (totDiscount > 0) {
                            doc.fillColor('#059669');
                            doc.text('Discount:', x, totY);
                            doc.text(`-${formatCurrency(totDiscount)}`, x + 80, totY, { width: 70, align: 'right' });
                            totY += 14;
                            doc.fillColor('black');
                        }

                        doc.text('Tax:', x, totY);
                        doc.text(formatCurrency(totTax), x + 80, totY, { width: 70, align: 'right' });
                        totY += 16;

                        doc.font('Helvetica-Bold').fontSize(11);
                        doc.text('Total:', x, totY);
                        doc.text(formatCurrency(totTotal), x + 80, totY, { width: 70, align: 'right' });

                        blockHeight = totY - startY + 20;
                        break;
                    }

                    case 'text': {
                        let textContent = itemConfig.content || '';
                        const rawData = order.rawData as any || {};
                        // Handlebars replacement with dot-notation support
                        textContent = textContent.replace(/\{\{(.*?)\}\}/g, (_: string, key: string) => {
                            const k = key.trim();
                            // Try order fields first, then rawData for WooCommerce fields
                            if (k.includes('.')) {
                                const parts = k.split('.');
                                // Check rawData first (has billing, shipping, etc.)
                                let value: any = rawData;
                                for (const part of parts) {
                                    value = value?.[part];
                                }
                                if (value != null) return String(value);
                                // Fallback to order model
                                value = order;
                                for (const part of parts) {
                                    value = (value as any)?.[part];
                                }
                                return value != null ? String(value) : `{{${k}}}`;
                            }
                            // Top-level keys: check order model then rawData
                            if ((order as any)[k] != null) return String((order as any)[k]);
                            if (rawData[k] != null) return String(rawData[k]);
                            return `{{${k}}}`;
                        });

                        const style = itemConfig.style || {};
                        doc.fontSize(parseInt(style.fontSize) || 10);
                        if (style.fontWeight === 'bold') doc.font('Helvetica-Bold');
                        else doc.font('Helvetica');

                        doc.text(textContent, x, startY, { width, align: style.textAlign || 'left' });
                        blockHeight = doc.heightOfString(textContent, { width }) + 10;
                        break;
                    }

                    case 'image': {
                        // Standalone image block
                        if (itemConfig.content) {
                            try {
                                const imgUrl: string = itemConfig.content;
                                if (imgUrl.startsWith('/uploads/')) {
                                    const localPath = path.join(__dirname, '../../', imgUrl);
                                    if (fs.existsSync(localPath)) {
                                        doc.image(localPath, x, startY, { width, fit: [width, 150] });
                                        blockHeight = 150;
                                    } else {
                                        Logger.warn('Image file not found on disk', { imgUrl, localPath });
                                        blockHeight = 20;
                                    }
                                }
                            } catch (e) {
                                Logger.warn('Failed to render image in PDF', { error: e });
                                blockHeight = 20;
                            }
                        } else {
                            blockHeight = 20;
                        }
                        break;
                    }

                    case 'footer': {
                        doc.fontSize(9).font('Helvetica');
                        const footerText = itemConfig.content || 'Thank you for your business!';
                        doc.text(footerText, x, startY, { width, align: 'center' });
                        blockHeight = doc.heightOfString(footerText, { width }) + 10;
                        break;
                    }

                    case 'row': {
                        // Row container - render children horizontally
                        const children = itemConfig.children || [];
                        if (children.length > 0) {
                            const childWidth = width / children.length;
                            let maxChildHeight = 0;

                            children.forEach((childId: string, idx: number) => {
                                const childConfig = getItemConfig(childId);
                                if (childConfig) {
                                    const childHeight = renderBlock(childConfig, x + (idx * childWidth), childWidth - 10, startY);
                                    maxChildHeight = Math.max(maxChildHeight, childHeight);
                                }
                            });

                            blockHeight = maxChildHeight;
                        }
                        break;
                    }

                    default:
                        blockHeight = 20;
                }

                return blockHeight;
            };

            // Render each grid item in order
            sortedGrid.forEach((gridItem: any) => {
                const itemConfig = getItemConfig(gridItem.i);
                if (!itemConfig) return;

                const x = marginLeft + (gridItem.x * colWidth);
                const width = gridItem.w * colWidth;

                // Check for page break
                if (currentY > 720 && itemConfig.type !== 'footer') {
                    doc.addPage();
                    currentY = marginTop;
                }

                const blockHeight = renderBlock(itemConfig, x, width, currentY);
                currentY += blockHeight + 10; // Add spacing between blocks
            });

            // Register handlers before ending doc to avoid race condition
            stream.on('finish', resolve);
            stream.on('error', reject);

            doc.end();
        });
    }
}

/**
 * Marketing Service
 * 
 * Manages marketing campaigns, automations, and email templates.
 * Merge tag resolution delegated to MergeTagResolver.
 */

import { MarketingCampaign, MarketingAutomation, EmailTemplate } from '@prisma/client';
import { Logger } from '../utils/logger';
import { prisma } from '../utils/prisma';
import { SegmentService } from './SegmentService';
import { resolveMergeTags } from './MergeTagResolver';

export class MarketingService {
    private segmentService: SegmentService;

    constructor() {
        this.segmentService = new SegmentService();
    }

    // -------------------
    // Campaigns (Broadcasts)
    // -------------------

    async listCampaigns(accountId: string) {
        return prisma.marketingCampaign.findMany({
            where: { accountId },
            orderBy: { createdAt: 'desc' }
        });
    }

    async getCampaign(id: string, accountId: string) {
        return prisma.marketingCampaign.findFirst({
            where: { id, accountId }
        });
    }

    async createCampaign(accountId: string, data: Partial<MarketingCampaign>) {
        const segmentId = data.segmentId && data.segmentId.trim() !== '' ? data.segmentId : undefined;

        Logger.info(`Creating campaign`, { accountId, segmentId: segmentId || 'ALL' });

        return prisma.marketingCampaign.create({
            data: {
                accountId,
                name: data.name || 'Untitled Campaign',
                subject: data.subject || '',
                content: data.content || '',
                status: 'DRAFT',
                scheduledAt: data.scheduledAt,
                segmentId: segmentId
            }
        });
    }

    async updateCampaign(id: string, accountId: string, data: Partial<MarketingCampaign>) {
        const { id: _, accountId: __, createdAt: ___, ...updateData } = data;
        return prisma.marketingCampaign.updateMany({
            where: { id, accountId },
            data: { ...(updateData as any), updatedAt: new Date() }
        });
    }

    async deleteCampaign(id: string, accountId: string) {
        return prisma.marketingCampaign.deleteMany({ where: { id, accountId } });
    }

    async sendTestEmail(campaignId: string, email: string) {
        Logger.info(`Sending test email`, { campaignId, email });
        return { success: true };
    }

    async sendCampaign(campaignId: string, accountId: string) {
        const campaign = await this.getCampaign(campaignId, accountId);
        if (!campaign) throw new Error('Campaign not found');

        let totalRecipients = 0;

        if (campaign.segmentId) {
            totalRecipients = await this.segmentService.getSegmentCount(accountId, campaign.segmentId);
        } else {
            totalRecipients = await prisma.wooCustomer.count({
                where: { accountId, email: { not: '' } }
            });
        }

        Logger.info(`Sending Campaign`, { campaignId, recipientCount: totalRecipients, segmentId: campaign.segmentId || 'ALL' });

        await prisma.marketingCampaign.update({
            where: { id: campaignId },
            data: { status: 'SENDING', sentAt: new Date(), recipientsCount: totalRecipients }
        });

        let processedCount = 0;
        const BATCH_SIZE = 1000;

        try {
            if (campaign.segmentId) {
                for await (const batch of this.segmentService.iterateCustomersInSegment(accountId, campaign.segmentId, BATCH_SIZE)) {
                    processedCount += batch.length;
                }
            } else {
                let cursor: string | undefined;
                while (true) {
                    const params: any = {
                        where: { accountId, email: { not: '' } },
                        select: { id: true, email: true },
                        take: BATCH_SIZE,
                        orderBy: { id: 'asc' }
                    };

                    if (cursor) {
                        params.cursor = { id: cursor };
                        params.skip = 1;
                    }

                    const customers = await prisma.wooCustomer.findMany(params);
                    if (customers.length === 0) break;

                    processedCount += customers.length;

                    if (customers.length < BATCH_SIZE) break;
                    cursor = customers[customers.length - 1].id;
                }
            }
        } catch (err) {
            Logger.error('Error sending campaign', err);
        }

        await prisma.marketingCampaign.update({
            where: { id: campaignId },
            data: { status: 'SENT', sentCount: processedCount }
        });

        return { success: true, count: processedCount };
    }

    // -------------------
    // Automations
    // -------------------

    async listAutomations(accountId: string) {
        return prisma.marketingAutomation.findMany({
            where: { accountId },
            include: {
                enrollments: {
                    where: { status: 'ACTIVE' },
                    select: { id: true }
                }
            },
            orderBy: { createdAt: 'desc' }
        });
    }

    async getAutomation(id: string, accountId: string) {
        return prisma.marketingAutomation.findFirst({
            where: { id, accountId },
            include: { steps: { orderBy: { stepOrder: 'asc' } } }
        });
    }

    async upsertAutomation(accountId: string, data: any) {
        const { id, name, triggerType, triggerConfig, steps, isActive } = data;

        if (id) {
            return prisma.marketingAutomation.update({
                where: { id },
                data: {
                    name,
                    triggerType,
                    triggerConfig,
                    isActive,
                    flowDefinition: data.flowDefinition,
                    status: isActive ? 'ACTIVE' : 'PAUSED'
                }
            });
        }

        return prisma.marketingAutomation.create({
            data: {
                accountId,
                name,
                triggerType,
                triggerConfig,
                isActive: isActive || false,
                flowDefinition: data.flowDefinition,
                status: isActive ? 'ACTIVE' : 'PAUSED'
            }
        });
    }

    async deleteAutomation(id: string, accountId: string) {
        return prisma.marketingAutomation.deleteMany({ where: { id, accountId } });
    }

    // -------------------
    // Templates
    // -------------------

    async listTemplates(accountId: string) {
        return prisma.emailTemplate.findMany({
            where: { accountId },
            orderBy: { updatedAt: 'desc' }
        });
    }

    async upsertTemplate(accountId: string, data: any) {
        const { id, name, subject, content, designJson } = data;

        if (id) {
            return prisma.emailTemplate.update({
                where: { id },
                data: { name, subject, content, designJson }
            });
        }

        return prisma.emailTemplate.create({
            data: { accountId, name, subject, content, designJson }
        });
    }

    async deleteTemplate(id: string, accountId: string) {
        return prisma.emailTemplate.deleteMany({ where: { id, accountId } });
    }

    // Delegate merge tag resolution to MergeTagResolver
    resolveWooCommerceMergeTags = resolveMergeTags;
}

import { PrismaClient } from '@prisma/client';
import { prisma } from '../utils/prisma';

interface PicklistItem {
    productId: string; // or component product ID
    sku: string;
    name: string;
    binLocation: string;
    quantityUpdates: {
        orderNumber: string;
        quantity: number;
        wooOrderId: number;
    }[];
    totalQuantity: number;
    stockStatus: string;
    imageUrl?: string;
    manageStock: boolean;
}

export class PicklistService {

    /**
     * Generate a batch picklist for orders
     */
    async generatePicklist(accountId: string, options: {
        status?: string; // Default 'processing'
        limit?: number;
    }) {
        const status = options.status || 'processing';

        // 1. Fetch Orders
        const orders = await prisma.wooOrder.findMany({
            where: {
                accountId,
                status: status
            },
            orderBy: { dateCreated: 'asc' },
            take: options.limit || 50,
            include: {
                // We need rawData to get line items because WooOrder schema stores them in rawData json usually, 
                // unless we have normalized line items. 
                // Check schema: WooOrder doesn't have normalized LineItems table yet? 
                // Inspect schema: "rawData Json".
                // Use rawData.
            }
        });

        // 2. Pre-fetch Products
        const allProductIds = new Set<number>();
        for (const order of orders) {
            const raw = order.rawData as any;
            const lineItems = raw.line_items || [];
            for (const item of lineItems) {
                if (item.product_id) allProductIds.add(item.product_id);
            }
        }

        const productCache = await this.prefetchProducts(accountId, Array.from(allProductIds));

        // 3. Aggregate Items
        const itemMap = new Map<string, PicklistItem>(); // Key: ProductID (or VariantID)

        for (const order of orders) {
            const raw = order.rawData as any;
            const lineItems = raw.line_items || [];
            const orderNumber = order.number;
            const wooOrderId = order.wooId;

            for (const item of lineItems) {
                // Item: { product_id, variation_id, quantity, name, sku ... }
                // We need to resolve logical ID. prefer variation_id if present, else product_id
                const productId = item.product_id;
                const variationId = item.variation_id || 0;
                const quantity = item.quantity;

                await this.processLineItem(accountId, productId, variationId, quantity, orderNumber, wooOrderId, productCache, innerItem => {
                    // Skip products that don't have inventory tracking enabled
                    if (!innerItem.manageStock) {
                        return;
                    }

                    const key = `${innerItem.productId}`;

                    if (!itemMap.has(key)) {
                        itemMap.set(key, {
                            productId: String(innerItem.productId),
                            sku: innerItem.sku,
                            name: innerItem.name,
                            binLocation: innerItem.binLocation || '',
                            stockStatus: innerItem.stockStatus || 'unknown',
                            imageUrl: innerItem.image?.src,
                            manageStock: innerItem.manageStock,
                            quantityUpdates: [],
                            totalQuantity: 0
                        });
                    }

                    const entry = itemMap.get(key)!;
                    entry.quantityUpdates.push({
                        orderNumber,
                        quantity: innerItem.quantity,
                        wooOrderId
                    });
                    entry.totalQuantity += innerItem.quantity;
                });
            }
        }

        // 4. Convert map to array and Sort by Bin Location
        const result = Array.from(itemMap.values()).filter(item => {
            // Filter: "Pull only in-stock products"
            // If stockStatus is 'outofstock', exclude?
            // Or maybe check managed stock?
            return item.stockStatus === 'instock' || item.stockStatus === 'onbackorder'; // Usually pick lists include backordered if we want to try picking? 
            // User said "Pull only in-stock". strict.
            // return item.stockStatus === 'instock'; 
        });

        // Sort alphanumerically by bin location
        result.sort((a, b) => {
            const binA = a.binLocation || 'ZZZZ'; // Empty bins go last
            const binB = b.binLocation || 'ZZZZ';
            return binA.localeCompare(binB, undefined, { numeric: true, sensitivity: 'base' });
        });

        return result;
    }

    private async prefetchProducts(accountId: string, initialProductIds: number[]): Promise<Map<number, any>> {
        const productMap = new Map<number, any>();
        const idsToFetch = new Set<number>(initialProductIds);
        const fetchedIds = new Set<number>();

        while (idsToFetch.size > 0) {
            const batchIds = Array.from(idsToFetch).filter(id => !fetchedIds.has(id));
            if (batchIds.length === 0) break;

            // Mark as fetching/fetched to avoid dupes in this loop
            batchIds.forEach(id => fetchedIds.add(id));
            // Also remove from idsToFetch
            batchIds.forEach(id => idsToFetch.delete(id));

            // Fetch batch
            const products = await prisma.wooProduct.findMany({
                where: {
                    accountId,
                    wooId: { in: batchIds }
                },
                include: {
                    boms: {
                        include: {
                            items: {
                                include: {
                                    childProduct: true
                                }
                            }
                        }
                    },
                    variations: true // We fetch all variations to filter in memory
                }
            });

            for (const product of products) {
                productMap.set(product.wooId, product);

                // Check for BOMs and add child products to fetch list
                if (product.boms && product.boms.length > 0) {
                    for (const bom of product.boms) {
                        for (const item of bom.items) {
                            if (item.childProduct && !fetchedIds.has(item.childProduct.wooId) && !productMap.has(item.childProduct.wooId)) {
                                idsToFetch.add(item.childProduct.wooId);
                            }
                        }
                    }
                }
            }
        }
        return productMap;
    }

    /**
     * Recursive function to resolve BOMs
     */
    private async processLineItem(
        accountId: string,
        productId: number,
        variationId: number,
        quantity: number,
        orderContext: string,
        wooOrderId: number,
        productCache: Map<number, any>,
        callback: (item: { productId: number, sku: string, name: string, quantity: number, binLocation: string | null, stockStatus: string | null, image: any, manageStock: boolean }) => void
    ) {
        // Check if this product/variant has a BOM
        // Prisma BOM model: productId (String UUID) -> we have wooId (Int).
        // Need to find internal internal ID first.

        // 1. Find internal Product
        let product = productCache.get(productId);

        if (!product) {
            // Fallback: try fetching if missing (edge case or race condition)
            product = await prisma.wooProduct.findFirst({
                where: { accountId, wooId: productId },
                include: {
                    boms: {
                        include: {
                            items: {
                                include: {
                                    childProduct: true
                                }
                            }
                        }
                    },
                    variations: {
                        where: { wooId: variationId !== 0 ? variationId : undefined }
                    }
                }
            });
        }

        if (!product) {
            // Product not synced? Just return as is with basic BOM fallback if possible (impossible without sync)
            // Or just skip?
            // Best effort: treat as raw item - skip as we can't determine if it manages stock
            callback({
                productId,
                sku: 'UNKNOWN',
                name: `Unknown Product #${productId}`,
                quantity,
                binLocation: '',
                stockStatus: 'unknown',
                image: null,
                manageStock: false // Unknown products don't get added
            });
            return;
        }

        // 2. Check for BOM matching variant or parent
        /* 
           BOM Selection Logic:
           - Look for BOM with variationId === variationId
           - If not found, look for BOM with variationId === 0 (Parent BOM)
           - If neither, it's a regular product
        */
        let activeBOM = product.boms.find((b: any) => b.variationId === variationId);
        if (!activeBOM && variationId !== 0) {
            activeBOM = product.boms.find((b: any) => b.variationId === 0);
        }

        if (activeBOM && activeBOM.items.length > 0) {
            // It's a bundle/manufactured item. Process components.
            for (const component of activeBOM.items) {
                if (component.childProduct) {
                    // Recursive call for component
                    // component.quantity is per unit.
                    const componentQty = Number(component.quantity) * quantity;

                    await this.processLineItem(
                        accountId,
                        component.childProduct.wooId,
                        0, // Components typically tracked as main products or specific variants? 
                        // Our BOMItem links to childProduct (WooProduct). 
                        // WooProduct stores a single specific variant sometimes? 
                        // Actually WooProduct is 1:1 with Woo ID. If it's a variant, it has its own WooProduct row if we sync variants as products?
                        // Wait, our schema: WooProduct has `wooId`. If variants are synced as separate rows, then ok.
                        // If variants are inside the same row, we have a problem.
                        // Assumption: Variants are synced as separate WooProduct rows or we only link main products?
                        // Let's assume childProduct gives us the correct entity.
                        componentQty,
                        orderContext,
                        wooOrderId,
                        productCache,
                        callback
                    );
                } else {
                    // Supplier item (raw material without WooProduct)? OR just missing link?
                    // If it's purely internal, we might want to list it?
                    // "List the component products".
                    // If no childProduct, maybe skip or list as raw material?
                }
            }
        } else {
            // No BOM, it's a leaf product.
            const raw = product.rawData as any;

            // Resolve Variation Logic
            let finalBinLocation = product.binLocation;
            let manageStock = raw?.manage_stock === true;

            // If we have a variation ID and we fetched variations, check if we have a match
            if (variationId !== 0 && product.variations && product.variations.length > 0) {
                const variant = product.variations.find((v: any) => v.wooId === variationId);

                if (variant) {
                    if (variant.binLocation) {
                        finalBinLocation = variant.binLocation;
                    }
                    // Use variant's manage_stock flag — parent may not manage stock on variable products
                    const variantRaw = variant.rawData as any;
                    manageStock = variant.manageStock || variantRaw?.manage_stock === true;
                }
            }

            callback({
                productId: variationId !== 0 ? variationId : product.wooId,
                sku: (variationId !== 0) ? (product.variations?.find((v: any) => v.wooId === variationId)?.sku || product.sku || '') : (product.sku || ''),
                name: product.name,
                quantity,
                binLocation: finalBinLocation,
                stockStatus: product.stockStatus,
                image: product.images ? (product.images as any)[0] : null,
                manageStock
            });
        }
    }
}

import { PrismaClient, PurchaseOrder, PurchaseOrderItem } from '@prisma/client';
import { prisma } from '../utils/prisma';
import { WooService } from './woo';
import { Logger } from '../utils/logger';
import { BOMConsumptionService } from './BOMConsumptionService';

/** Max retries for WooCommerce API calls in background sync */
const WOO_MAX_RETRIES = 3;
/** Base delay (ms) for exponential backoff — doubles each retry */
const WOO_BASE_DELAY_MS = 2000;

/**
 * Retry wrapper for WooCommerce API calls.
 * Why: WooCommerce may throttle with 429 or return transient 5xx errors.
 * Uses exponential backoff: 2s → 4s → 8s.
 */
async function wooRetry(fn: () => Promise<void>, label: string): Promise<void> {
    for (let attempt = 1; attempt <= WOO_MAX_RETRIES; attempt++) {
        try {
            await fn();
            return;
        } catch (err: any) {
            const status = err?.response?.status ?? err?.status ?? 0;
            const isRetryable = status === 429 || status >= 500;
            if (!isRetryable || attempt === WOO_MAX_RETRIES) {
                Logger.warn(`WooCommerce sync failed after ${attempt} attempt(s): ${label}`, {
                    error: err?.message ?? err, status
                });
                return; // Swallow — background sync must not throw
            }
            const delay = WOO_BASE_DELAY_MS * Math.pow(2, attempt - 1);
            Logger.info(`WooCommerce rate-limited/transient error, retrying in ${delay}ms: ${label}`, { attempt, status });
            await new Promise(r => setTimeout(r, delay));
        }
    }
}

export class PurchaseOrderService {

    /**
     * List Purchase Orders for an account with optional status filtering
     */
    async listPurchaseOrders(accountId: string, status?: string) {
        return prisma.purchaseOrder.findMany({
            where: {
                accountId,
                ...(status ? { status } : {})
            },
            include: {
                supplier: true,
                items: true
            },
            orderBy: { createdAt: 'desc' }
        });
    }

    /**
     * Get a single Purchase Order by ID
     */
    async getPurchaseOrder(accountId: string, poId: string) {
        return prisma.purchaseOrder.findFirst({
            where: { id: poId, accountId },
            include: {
                supplier: true,
                items: {
                    include: {
                        product: true,
                        supplierItem: true
                    }
                }
            }
        });
    }

    /**
     * Create a new Purchase Order
     */
    async createPurchaseOrder(accountId: string, data: {
        supplierId: string;
        items: {
            productId?: string;
            supplierItemId?: string;
            variationWooId?: number | null;
            quantity: number;
            unitCost: number;
            name: string;
            sku?: string;
        }[];
        notes?: string;
        orderDate?: string;
        expectedDate?: string;
        trackingNumber?: string;
        trackingLink?: string;
    }) {
        // Calculate totals
        let totalAmount = 0;
        const itemsToCreate = data.items.map(item => {
            const lineTotal = item.quantity * item.unitCost;
            totalAmount += lineTotal;
            return {
                productId: item.productId,
                supplierItemId: item.supplierItemId,
                variationWooId: item.variationWooId || null,
                quantity: item.quantity,
                unitCost: item.unitCost,
                totalCost: lineTotal,
                name: item.name,
                sku: item.sku
            };
        });

        return prisma.purchaseOrder.create({
            data: {
                accountId,
                supplierId: data.supplierId,
                status: 'DRAFT',
                notes: data.notes,
                orderDate: data.orderDate ? new Date(data.orderDate) : null,
                expectedDate: data.expectedDate ? new Date(data.expectedDate) : null,
                trackingNumber: data.trackingNumber || null,
                trackingLink: data.trackingLink || null,
                totalAmount,
                items: {
                    create: itemsToCreate
                }
            }
        });
    }

    /**
     * Update a Purchase Order (Status, Fields, AND Items)
     */
    async updatePurchaseOrder(accountId: string, poId: string, data: {
        status?: string;
        supplierId?: string;
        notes?: string;
        orderDate?: string;
        expectedDate?: string;
        trackingNumber?: string;
        trackingLink?: string;
        items?: {
            productId?: string;
            supplierItemId?: string;
            variationWooId?: number | null;
            quantity: number;
            unitCost: number;
            name: string;
            sku?: string;
        }[];
    }) {
        // Guard: RECEIVED POs restrict status and item updates
        const existing = await prisma.purchaseOrder.findFirst({
            where: { id: poId, accountId },
            select: { status: true }
        });
        if (existing?.status === 'RECEIVED') {
            if (data.status && data.status !== 'RECEIVED' && data.status !== 'DRAFT' && data.status !== 'ORDERED') {
                throw new Error('Cannot edit a RECEIVED Purchase Order status to anything other than DRAFT or ORDERED. Revert first.');
            }
            if (data.items && data.items.length > 0 && data.status !== 'DRAFT' && data.status !== 'ORDERED') {
                throw new Error('Cannot edit items on a RECEIVED Purchase Order. Revert to DRAFT or ORDERED first.');
            }
        }

        // Build update payload dynamically
        const updateData: Record<string, unknown> = {};

        if (data.status !== undefined) updateData.status = data.status;
        if (data.supplierId !== undefined) updateData.supplierId = data.supplierId;
        if (data.notes !== undefined) updateData.notes = data.notes;
        if (data.orderDate !== undefined) updateData.orderDate = data.orderDate ? new Date(data.orderDate) : null;
        if (data.expectedDate !== undefined) updateData.expectedDate = data.expectedDate ? new Date(data.expectedDate) : null;
        if (data.trackingNumber !== undefined) updateData.trackingNumber = data.trackingNumber || null;
        if (data.trackingLink !== undefined) updateData.trackingLink = data.trackingLink || null;

        // If items are provided, recalculate totalAmount and replace items
        if (data.items && data.items.length > 0) {
            let totalAmount = 0;
            const itemsToCreate = data.items.map(item => {
                const lineTotal = item.quantity * item.unitCost;
                totalAmount += lineTotal;
                return {
                    productId: item.productId || null,
                    supplierItemId: item.supplierItemId || null,
                    variationWooId: item.variationWooId || null,
                    quantity: item.quantity,
                    unitCost: item.unitCost,
                    totalCost: lineTotal,
                    name: item.name,
                    sku: item.sku || null
                };
            });

            updateData.totalAmount = totalAmount;

            // Transaction to delete old items and create new ones
            // Bug fix: scope to accountId to prevent cross-account writes
            return prisma.$transaction(async (tx) => {
                // Verify ownership before mutating
                const owned = await tx.purchaseOrder.findFirst({
                    where: { id: poId, accountId },
                    select: { id: true }
                });
                if (!owned) throw new Error('Purchase Order not found or access denied');

                // Delete existing items
                await tx.purchaseOrderItem.deleteMany({
                    where: { purchaseOrderId: poId }
                });

                // Update PO and create new items
                return tx.purchaseOrder.update({
                    where: { id: poId },
                    data: {
                        ...updateData,
                        items: {
                            create: itemsToCreate
                        }
                    }
                });
            });
        }

        // No items update, just update fields
        return prisma.purchaseOrder.updateMany({
            where: { id: poId, accountId },
            data: updateData
        });
    }

    /**
     * Delete a Purchase Order that is still in DRAFT status.
     * Why guard on DRAFT: ORDERED/RECEIVED POs may have stock applied or
     * supplier acknowledgements — deleting them would leave orphan state.
     */
    async deletePurchaseOrder(accountId: string, poId: string): Promise<void> {
        const existing = await prisma.purchaseOrder.findFirst({
            where: { id: poId, accountId },
            select: { status: true }
        });

        if (!existing) {
            throw new Error('Purchase Order not found');
        }

        if (existing.status !== 'DRAFT') {
            throw new Error('Only DRAFT Purchase Orders can be deleted');
        }

        // Why: PurchaseOrderItem has onDelete: Cascade — Prisma deletes items automatically
        await prisma.purchaseOrder.delete({ where: { id: poId } });
    }

    /**
     * Calculate Inbound Inventory Quantity for a specific Product
     * Sums quantity from POs with status 'ORDERED'
     */
    async getInboundInventory(accountId: string, productId: string, variationWooId?: number): Promise<number> {
        const where: any = {
            productId,
            purchaseOrder: {
                accountId,
                status: 'ORDERED'
            }
        };
        // When a specific variation is requested, narrow to that variation only
        if (variationWooId !== undefined) {
            where.variationWooId = variationWooId;
        }

        const aggregations = await prisma.purchaseOrderItem.aggregate({
            where,
            _sum: {
                quantity: true
            }
        });

        return aggregations._sum.quantity || 0;
    }

    /**
     * Receive stock from a Purchase Order.
     * Increments stockQuantity on linked products/variants and syncs to WooCommerce.
     */
    async receiveStock(accountId: string, poId: string): Promise<{ updated: number; errors: string[]; updatedProductIds: string[] }> {
        // Guard: prevent double-receive which would double stock counts
        const currentStatus = await prisma.purchaseOrder.findFirst({
            where: { id: poId, accountId },
            select: { status: true }
        });
        if (currentStatus?.status === 'RECEIVED') {
            Logger.warn('receiveStock called on already-RECEIVED PO, skipping', { poId });
            return { updated: 0, errors: ['PO is already RECEIVED — stock not applied again'], updatedProductIds: [] };
        }

        const po = await prisma.purchaseOrder.findFirst({
            where: { id: poId, accountId },
            include: {
                items: {
                    include: {
                        product: {
                            include: {
                                boms: {
                                    select: {
                                        id: true,
                                        items: {
                                            where: {
                                                OR: [
                                                    { childProductId: { not: null } },
                                                    { internalProductId: { not: null } }
                                                ]
                                            },
                                            select: { id: true }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        });

        if (!po) {
            throw new Error('Purchase Order not found');
        }

        const errors: string[] = [];
        const updatedProductIds: string[] = [];
        let updated = 0;

        // Collect WooCommerce sync tasks to run in background after response
        const wooSyncTasks: Array<() => Promise<void>> = [];

        // Get WooService for syncing
        let wooService: WooService | null = null;
        try {
            wooService = await WooService.forAccount(accountId);
        } catch (err) {
            Logger.warn('Unable to connect to WooCommerce for stock sync', { error: err, accountId });
        }

        // Pre-fetch all ProductVariation rows this PO touches in a single query.
        // Why: avoids a separate findUnique per item inside the loop (N+1).
        const variationWooIds = po.items
            .filter(i => i.variationWooId != null)
            .map(i => ({ productId: i.product!.id, wooId: i.variationWooId! }));

        const variationRows = variationWooIds.length > 0
            ? await prisma.productVariation.findMany({
                where: {
                    OR: variationWooIds.map(v => ({
                        productId: v.productId,
                        wooId: v.wooId
                    }))
                }
            })
            : [];

        // Key: `${productId}:${wooId}` — unique per variation
        const variationMap = new Map(
            variationRows.map(v => [`${v.productId}:${v.wooId}`, v])
        );

        for (const item of po.items) {
            if (!item.productId || !item.product) {
                continue; // Skip items without linked product
            }

            // Skip BOM products - their stock is derived from components
            const hasBOM = item.product.boms?.some(bom => bom.items.length > 0) ?? false;
            if (hasBOM) {
                Logger.warn('Skipped stock update for BOM product', { productId: item.product.id, productName: item.product.name });
                errors.push(`${item.product.name} is a BOM product - stock not updated`);
                continue;
            }

            try {
                const product = item.product;

                // Check if this item targets a specific variation
                if (item.variationWooId) {
                    // Look up variation from pre-fetched Map — no per-item DB query
                    const variation = variationMap.get(`${product.id}:${item.variationWooId}`) ?? null;

                    if (variation) {
                        // Atomic increment + status in single query to prevent crash-induced drift
                        const variationResult = await prisma.$queryRawUnsafe<Array<{ stock_quantity: number }>>(
                            `UPDATE "ProductVariation" SET "stockQuantity" = "stockQuantity" + $1, "manageStock" = true, "stockStatus" = CASE WHEN "stockQuantity" + $1 > 0 THEN 'instock' ELSE 'outofstock' END WHERE "id" = $2 RETURNING "stockQuantity" AS stock_quantity`,
                            item.quantity, variation.id
                        );
                        const newStock = variationResult[0]?.stock_quantity ?? 0;

                        Logger.info('Stock received for variation', {
                            productId: product.id,
                            variationWooId: item.variationWooId,
                            previousStock: (variation.stockQuantity ?? 0),
                            addedQuantity: item.quantity,
                            newStock
                        });

                        // Queue WooCommerce sync for background with retry
                        if (wooService) {
                            const woo = wooService;
                            const pWooId = product.wooId;
                            const vWooId = item.variationWooId;
                            const stock = newStock;
                            wooSyncTasks.push(() => wooRetry(
                                () => woo.updateProductVariation(pWooId, vWooId, {
                                    manage_stock: true,
                                    stock_quantity: stock
                                }),
                                `receive variation ${vWooId} on product ${pWooId}`
                            ));
                        }
                    } else {
                        // Variation not found locally — this is an error, not safe to fall through to parent
                        Logger.error('Variation not found locally for stock receive', {
                            productId: product.id,
                            variationWooId: item.variationWooId
                        });
                        errors.push(`${item.name}: Variation ${item.variationWooId} not found locally — sync products first`);
                        continue;
                    }
                } else {
                    // Simple product stock update
                    // Variable products must have variationWooId specified — skip with error
                    const productRaw = product.rawData as any;
                    const isVariable = productRaw?.type?.includes('variable') || productRaw?.variations?.length > 0;
                    if (isVariable) {
                        errors.push(`${product.name}: Cannot set stock on variable parent — specify a variation`);
                        continue;
                    }

                    const previousStock = product.stockQuantity ?? 0;

                    // Atomic increment + status in single query to prevent crash-induced drift
                    const productResult = await prisma.$queryRawUnsafe<Array<{ stock_quantity: number }>>(
                        `UPDATE "WooProduct" SET "stockQuantity" = "stockQuantity" + $1, "manageStock" = true, "stockStatus" = CASE WHEN "stockQuantity" + $1 > 0 THEN 'instock' ELSE 'outofstock' END WHERE "id" = $2 RETURNING "stockQuantity" AS stock_quantity`,
                        item.quantity, product.id
                    );
                    const newStock = productResult[0]?.stock_quantity ?? 0;

                    Logger.info('Stock received for product', {
                        productId: product.id,
                        wooId: product.wooId,
                        previousStock,
                        addedQuantity: item.quantity,
                        newStock
                    });

                    // Queue WooCommerce sync for background with retry
                    if (wooService) {
                        const woo = wooService;
                        const pWooId = product.wooId;
                        const stock = newStock;
                        wooSyncTasks.push(() => wooRetry(
                            () => woo.updateProduct(pWooId, {
                                manage_stock: true,
                                stock_quantity: stock
                            }),
                            `receive product ${pWooId}`
                        ));
                    }
                }

                updated++;

                // Track this product for cascade BOM sync + ES re-index
                updatedProductIds.push(product.id);
            } catch (err) {
                const errorMsg = `Failed to update stock for item "${item.name}": ${(err as Error).message}`;
                Logger.error('Error receiving stock for PO item', { error: err, itemId: item.id });
                errors.push(errorMsg);
            }
        }

        // Transition PO to RECEIVED after all stock increments have been committed.
        // Why: without this the double-receive guard (line 263) never triggers,
        // allowing every call to re-apply stock — a data-corruption bug.
        // TODO(improvement): Track wooSyncStatus separately (pending/complete/failed)
        // so admins can retry just the WooCommerce push without unreceive+re-receive.
        await prisma.purchaseOrder.update({
            where: { id: poId },
            data: { status: 'RECEIVED' }
        });

        // Fire-and-forget: WooCommerce sync + BOM cascade run in background
        // Why: WooCommerce API calls take ~2s each — with 24 items that exceeds
        // the Nginx 60s timeout. DB updates (above) are already committed.
        if (wooSyncTasks.length > 0 || updatedProductIds.length > 0) {
            const bgAccountId = accountId;
            const bgPoId = poId;
            const bgProductIds = [...updatedProductIds];
            const bgTasks = [...wooSyncTasks];

            setImmediate(() => {
                (async () => {
                    // Sync stock to WooCommerce sequentially to avoid rate limits
                    for (const task of bgTasks) {
                        await task();
                    }
                    Logger.info('WooCommerce stock sync completed for PO receive', {
                        poId: bgPoId, syncedItems: bgTasks.length
                    });

                    // Cascade BOM sync
                    for (const productId of bgProductIds) {
                        try {
                            await BOMConsumptionService.cascadeSyncAffectedProducts(bgAccountId, productId);
                        } catch (syncErr) {
                            Logger.warn('Cascade BOM sync failed for component', {
                                productId, error: (syncErr as Error).message
                            });
                        }
                    }
                })().catch(err => {
                    Logger.error('Background WooCommerce sync failed', { poId: bgPoId, error: err });
                });
            });
        }

        return { updated, errors, updatedProductIds };
    }

    /**
     * Unreceive stock from a Purchase Order.
     * Reverses stock changes when a PO transitions away from RECEIVED.
     */
    async unreceiveStock(accountId: string, poId: string): Promise<{ updated: number; errors: string[]; updatedProductIds: string[] }> {
        // Guard: only unreceive POs that are currently RECEIVED
        const currentStatus = await prisma.purchaseOrder.findFirst({
            where: { id: poId, accountId },
            select: { status: true }
        });
        if (currentStatus?.status !== 'RECEIVED') {
            Logger.warn('unreceiveStock called on non-RECEIVED PO, skipping', { poId, status: currentStatus?.status });
            return { updated: 0, errors: ['PO is not RECEIVED — nothing to unreceive'], updatedProductIds: [] };
        }

        const po = await prisma.purchaseOrder.findFirst({
            where: { id: poId, accountId },
            include: {
                items: {
                    include: {
                        product: {
                            include: {
                                boms: {
                                    select: {
                                        id: true,
                                        items: {
                                            where: {
                                                OR: [
                                                    { childProductId: { not: null } },
                                                    { internalProductId: { not: null } }
                                                ]
                                            },
                                            select: { id: true }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        });

        if (!po) {
            throw new Error('Purchase Order not found');
        }

        const errors: string[] = [];
        const updatedProductIds: string[] = [];
        let updated = 0;

        // Collect WooCommerce sync tasks to run in background after response
        const wooSyncTasks: Array<() => Promise<void>> = [];

        let wooService: WooService | null = null;
        try {
            wooService = await WooService.forAccount(accountId);
        } catch (err) {
            Logger.warn('Unable to connect to WooCommerce for stock unreceive', { error: err, accountId });
        }

        // Pre-fetch all ProductVariation rows this PO touches in a single query.
        // Why: avoids a separate findUnique per item inside the loop (N+1).
        const unreceiveVariationIds = po.items
            .filter(i => i.variationWooId != null && i.product != null)
            .map(i => ({ productId: i.product!.id, wooId: i.variationWooId! }));

        const unreceiveVariationRows = unreceiveVariationIds.length > 0
            ? await prisma.productVariation.findMany({
                where: {
                    OR: unreceiveVariationIds.map(v => ({
                        productId: v.productId,
                        wooId: v.wooId
                    }))
                }
            })
            : [];

        const unreceiveVariationMap = new Map(
            unreceiveVariationRows.map(v => [`${v.productId}:${v.wooId}`, v])
        );

        for (const item of po.items) {
            if (!item.productId || !item.product) continue;

            const hasBOM = item.product.boms?.some(bom => bom.items.length > 0) ?? false;
            if (hasBOM) continue;

            try {
                const product = item.product;

                if (item.variationWooId) {
                    // Look up variation from pre-fetched Map — no per-item DB query
                    const variation = unreceiveVariationMap.get(`${product.id}:${item.variationWooId}`) ?? null;

                    if (variation) {
                        // Atomic decrement + status in single query to prevent crash-induced drift.
                        // $queryRaw (tagged template) — Prisma parameterizes all values; eliminates
                        // SQL injection risk vs $queryRawUnsafe with string interpolation.
                        const variationResult = await prisma.$queryRaw<Array<{ stock_quantity: number }>>`
                            UPDATE "ProductVariation"
                            SET "stockQuantity" = "stockQuantity" - ${item.quantity},
                                "stockStatus" = CASE WHEN "stockQuantity" - ${item.quantity} > 0
                                                     THEN 'instock' ELSE 'outofstock' END
                            WHERE "id" = ${variation.id}
                            RETURNING "stockQuantity" AS stock_quantity
                        `;
                        const newStock = variationResult[0]?.stock_quantity ?? 0;

                        // Queue WooCommerce sync for background with retry
                        if (wooService) {
                            const woo = wooService;
                            const pWooId = product.wooId;
                            const vWooId = item.variationWooId;
                            const stock = newStock;
                            wooSyncTasks.push(() => wooRetry(
                                () => woo.updateProductVariation(pWooId, vWooId, {
                                    stock_quantity: stock
                                }),
                                `unreceive variation ${vWooId} on product ${pWooId}`
                            ));
                        }
                    }
                } else {
                    // Simple product stock reversal
                    // Variable products must have variationWooId specified — skip
                    const productRaw = product.rawData as any;
                    const isVariable = productRaw?.type?.includes('variable') || productRaw?.variations?.length > 0;
                    if (isVariable) {
                        errors.push(`${product.name}: Cannot reverse stock on variable parent — specify a variation`);
                        continue;
                    }

                    // Atomic decrement + status in single query to prevent crash-induced drift.
                    // $queryRaw (tagged template) — parameterized, no SQL injection risk.
                    // No Math.max(0) clamping — keep local DB truthful so WooCommerce stays in sync.
                    const productResult = await prisma.$queryRaw<Array<{ stock_quantity: number }>>`
                        UPDATE "WooProduct"
                        SET "stockQuantity" = "stockQuantity" - ${item.quantity},
                            "stockStatus" = CASE WHEN "stockQuantity" - ${item.quantity} > 0
                                                 THEN 'instock' ELSE 'outofstock' END
                        WHERE "id" = ${product.id}
                        RETURNING "stockQuantity" AS stock_quantity
                    `;
                    const newStock = productResult[0]?.stock_quantity ?? 0;

                    // Queue WooCommerce sync for background with retry
                    if (wooService) {
                        const woo = wooService;
                        const pWooId = product.wooId;
                        const stock = newStock;
                        wooSyncTasks.push(() => wooRetry(
                            () => woo.updateProduct(pWooId, {
                                stock_quantity: stock
                            }),
                            `unreceive product ${pWooId}`
                        ));
                    }
                }

                updated++;
                updatedProductIds.push(product.id);

                Logger.info('Stock unreceived for item', {
                    productId: product.id,
                    itemName: item.name,
                    quantity: item.quantity,
                    variationWooId: item.variationWooId
                });
            } catch (err) {
                const errorMsg = `Failed to unreceive stock for "${item.name}": ${(err as Error).message}`;
                Logger.error('Error unreceiving stock for PO item', { error: err, itemId: item.id });
                errors.push(errorMsg);
            }
        }

        // Fire-and-forget: WooCommerce sync + BOM cascade run in background
        if (wooSyncTasks.length > 0 || updatedProductIds.length > 0) {
            const bgAccountId = accountId;
            const bgPoId = poId;
            const bgProductIds = [...updatedProductIds];
            const bgTasks = [...wooSyncTasks];

            setImmediate(() => {
                (async () => {
                    for (const task of bgTasks) {
                        await task();
                    }
                    Logger.info('WooCommerce stock sync completed for PO unreceive', {
                        poId: bgPoId, syncedItems: bgTasks.length
                    });

                    for (const productId of bgProductIds) {
                        try {
                            await BOMConsumptionService.cascadeSyncAffectedProducts(bgAccountId, productId);
                        } catch (syncErr) {
                            Logger.warn('Cascade BOM sync failed during unreceive', {
                                productId, error: (syncErr as Error).message
                            });
                        }
                    }
                })().catch(err => {
                    Logger.error('Background WooCommerce unreceive sync failed', { poId: bgPoId, error: err });
                });
            });
        }

        // Why: always transition away from RECEIVED — even if all items errored,
        // partial stock decrements may have occurred. Leaving the PO in RECEIVED
        // would allow repeated unreceive attempts, compounding stock drift.
        await prisma.purchaseOrder.update({
            where: { id: poId },
            data: { status: 'ORDERED' }
        });
        Logger.info('PO status transitioned to ORDERED after unreceive', { poId, updated, errorCount: errors.length });

        return { updated, errors, updatedProductIds };
    }
}

import { PrismaClient, User } from '@prisma/client';
import { authenticator } from 'otplib';
import * as qrcode from 'qrcode';
import { generateToken } from '../utils/auth';
import crypto from 'crypto';
import { prisma } from '../utils/prisma';
import { Logger } from '../utils/logger';

export class SecurityService {

    // -------------------
    // Helper: Hash Token
    // -------------------

    /**
     * Hashes a token using SHA-256 for secure storage.
     * Client receives plaintext token; DB stores only the hash.
     */
    private static hashToken(token: string): string {
        return crypto.createHash('sha256').update(token).digest('hex');
    }

    // -------------------
    // Two-Factor Auth
    // -------------------

    static async generateTwoFactorSecret(user: User) {
        const secret = authenticator.generateSecret();
        const otpauth = authenticator.keyuri(user.email, process.env.APP_NAME || 'Commerce Platform', secret);
        const qrCodeUrl = await qrcode.toDataURL(otpauth);

        return {
            secret,
            qrCodeUrl
        };
    }

    static verifyTwoFactorToken(token: string, secret: string): boolean {
        return authenticator.check(token, secret);
    }

    static async enableTwoFactor(userId: string, secret: string) {
        // Generate backup codes — return plaintext to user once, store hashes
        const backupCodes = Array.from({ length: 10 }, () => crypto.randomBytes(4).toString('hex'));
        const hashedBackupCodes = backupCodes.map(code => this.hashToken(code));

        await prisma.user.update({
            where: { id: userId },
            data: {
                twoFactorSecret: secret,
                isTwoFactorEnabled: true,
                twoFactorBackupCodes: hashedBackupCodes as any
            }
        });

        return backupCodes;
    }

    // -------------------
    // Session Management
    // -------------------

    static async createSession(userId: string, ipAddress?: string, userAgent?: string) {
        // Create Refresh Token first to get the session ID
        const refreshTokenPlain = crypto.randomBytes(40).toString('hex');
        const refreshTokenHash = this.hashToken(refreshTokenPlain);
        // EDGE CASE FIX: Extended refresh token expiry to 30 days (was 7 days)
        const expiresAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000); // 30 days

        const refreshTokenRecord = await prisma.refreshToken.create({
            data: {
                token: refreshTokenHash, // Store hash, not plaintext
                userId,
                expiresAt,
                ipAddress,
                userAgent
            }
        });

        // Create Access Token with sessionId for current session identification
        const accessToken = generateToken({ userId, sessionId: refreshTokenRecord.id });

        // Log JWT fingerprint for debugging multi-container secret mismatches
        const secret = process.env.JWT_SECRET || '';
        const fingerprint = crypto.createHash('sha256').update(secret.substring(0, 8)).digest('hex').substring(0, 12);
        Logger.debug('[SecurityService] Token generated', { userId, sessionId: refreshTokenRecord.id, jwtFingerprint: fingerprint });

        return { accessToken, refreshToken: refreshTokenPlain }; // Return plaintext to client
    }

    static async refreshSession(token: string, ipAddress?: string, userAgent?: string) {
        // Hash the incoming token to compare against stored hash
        const tokenHash = this.hashToken(token);

        const refreshToken = await prisma.refreshToken.findUnique({
            where: { token: tokenHash },
            include: { user: true }
        });

        if (!refreshToken || refreshToken.revokedAt || new Date() > refreshToken.expiresAt) {
            // Token Reuse Detection: if token not found, could be reuse attempt
            Logger.warn('Refresh token validation failed', {
                reason: !refreshToken ? 'not_found' : refreshToken.revokedAt ? 'revoked' : 'expired'
            });
            throw new Error('Invalid refresh token');
        }

        // Rotate Token - generate new plaintext, store new hash
        const newRefreshTokenPlain = crypto.randomBytes(40).toString('hex');
        const newRefreshTokenHash = this.hashToken(newRefreshTokenPlain);
        // EDGE CASE FIX: 30-day expiry for rotated refresh tokens
        const newExpiresAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000); // 30 days

        // Revoke old + create new atomically to prevent session loss on crash
        // and eliminate race conditions on concurrent refresh calls
        const [, newRefreshTokenRecord] = await prisma.$transaction([
            prisma.refreshToken.update({
                where: { id: refreshToken.id },
                data: { revokedAt: new Date() }
            }),
            prisma.refreshToken.create({
                data: {
                    token: newRefreshTokenHash, // Store hash
                    userId: refreshToken.userId,
                    expiresAt: newExpiresAt,
                    ipAddress,
                    userAgent
                }
            })
        ]);

        // Include new sessionId in access token
        const newAccessToken = generateToken({ userId: refreshToken.userId, sessionId: newRefreshTokenRecord.id });

        return { accessToken: newAccessToken, refreshToken: newRefreshTokenPlain }; // Return plaintext
    }

    static async revokeUserSessions(userId: string) {
        await prisma.refreshToken.updateMany({
            where: { userId, revokedAt: null },
            data: { revokedAt: new Date() }
        });
    }

    /**
     * Revokes ALL existing refresh tokens across all users.
     * Use when migrating from plaintext to hashed token storage.
     */
    static async revokeAllSessions() {
        const result = await prisma.refreshToken.updateMany({
            where: { revokedAt: null },
            data: { revokedAt: new Date() }
        });
        Logger.info('Revoked all existing refresh tokens', { count: result.count });
        return result.count;
    }
}

import { CustomerSegment, Prisma } from '@prisma/client';
import { prisma } from '../utils/prisma';
import crypto from 'crypto';

interface SegmentRule {
    field: string;
    operator: string;
    value: any;
}

interface SegmentCriteria {
    type: 'AND' | 'OR';
    rules: SegmentRule[];
}

/**
 * Result type for exportable customer data.
 * Contains both raw and SHA256-hashed identifiers for ad platform uploads.
 */
export interface ExportableCustomerData {
    emails: string[];
    phones: string[];
    hashedEmails: string[];
    hashedPhones: string[];
    totalCount: number;
}

export class SegmentService {

    async createSegment(accountId: string, data: { name: string; description?: string; criteria: any }) {
        return prisma.customerSegment.create({
            data: {
                accountId,
                name: data.name,
                description: data.description,
                criteria: data.criteria
            }
        });
    }

    async updateSegment(id: string, accountId: string, data: { name?: string; description?: string; criteria?: any }) {
        return prisma.customerSegment.updateMany({
            where: { id, accountId },
            data: {
                ...data,
                updatedAt: new Date()
            }
        });
    }

    async deleteSegment(id: string, accountId: string) {
        return prisma.customerSegment.deleteMany({
            where: { id, accountId }
        });
    }

    async getSegment(id: string, accountId: string) {
        return prisma.customerSegment.findFirst({
            where: { id, accountId }
        });
    }

    async listSegments(accountId: string) {
        return prisma.customerSegment.findMany({
            where: { accountId },
            orderBy: { createdAt: 'desc' },
            include: {
                _count: {
                    select: { campaigns: true }
                }
            }
        });
    }

    /**
     * previewCustomers - Returns a list of customers matching the segment criteria
     */
    async previewCustomers(accountId: string, segmentId: string) {
        const segment = await this.getSegment(segmentId, accountId);
        if (!segment) throw new Error('Segment not found');

        const criteria = segment.criteria as unknown as SegmentCriteria;
        const whereClause = this.buildWhereClause(accountId, criteria);

        return prisma.wooCustomer.findMany({
            where: whereClause,
            take: 50 // Preview limit
        });
    }

    /**
     * getCustomerIdsInSegment - Returns ALL customer IDs matching the segment (for broadcasts)
     */
    async getCustomerIdsInSegment(accountId: string, segmentId: string) {
        const segment = await this.getSegment(segmentId, accountId);
        if (!segment) return [];

        const criteria = segment.criteria as unknown as SegmentCriteria;
        const whereClause = this.buildWhereClause(accountId, criteria);

        const customers = await prisma.wooCustomer.findMany({
            where: whereClause,
            select: { id: true, email: true, wooId: true }
        });

        return customers;
    }

    /**
     * getSegmentCount - Returns the count of customers in a segment
     */
    async getSegmentCount(accountId: string, segmentId: string): Promise<number> {
        const segment = await this.getSegment(segmentId, accountId);
        if (!segment) return 0;

        const criteria = segment.criteria as unknown as SegmentCriteria;
        const whereClause = this.buildWhereClause(accountId, criteria);

        return prisma.wooCustomer.count({ where: whereClause });
    }

    /**
     * iterateCustomersInSegment - Yields batches of customers in a segment
     */
    async *iterateCustomersInSegment(accountId: string, segmentId: string, batchSize = 1000) {
        const segment = await this.getSegment(segmentId, accountId);
        if (!segment) return;

        const criteria = segment.criteria as unknown as SegmentCriteria;
        const whereClause = this.buildWhereClause(accountId, criteria);

        let cursor: string | undefined;

        while (true) {
            const params: any = {
                where: whereClause,
                take: batchSize,
                orderBy: { id: 'asc' },
                select: { id: true, email: true }
            };

            if (cursor) {
                params.cursor = { id: cursor };
                params.skip = 1;
            }

            const batch = await prisma.wooCustomer.findMany(params);

            if (batch.length === 0) break;

            yield batch;

            if (batch.length < batchSize) break;

            cursor = batch[batch.length - 1].id;
        }
    }

    /**
     * getExportableCustomers - Returns customer identifiers for ad platform sync
     * 
     * Retrieves all customers in a segment and returns both raw and SHA256-hashed
     * emails/phones. Both Meta Custom Audiences and Google Customer Match require
     * SHA256 hashing for privacy compliance.
     * 
     * @param accountId - The account ID
     * @param segmentId - The segment to export
     * @returns Object containing raw and hashed emails/phones
     * @throws Error if segment not found or segment is empty
     */
    async getExportableCustomers(accountId: string, segmentId: string): Promise<ExportableCustomerData> {
        const segment = await this.getSegment(segmentId, accountId);
        if (!segment) {
            throw new Error('Segment not found');
        }

        const criteria = segment.criteria as unknown as SegmentCriteria;
        const whereClause = this.buildWhereClause(accountId, criteria);

        // Fetch all customers with email and rawData (phone is in rawData.billing.phone)
        const customers = await prisma.wooCustomer.findMany({
            where: whereClause,
            select: {
                email: true,
                rawData: true
            }
        });

        // EDGE CASE: Handle empty segments gracefully with clear error message
        if (customers.length === 0) {
            throw new Error(`No customers match this segment. The segment "${segment.name}" has 0 customers matching the current criteria. Please adjust the segment rules or wait for more customer data.`);
        }

        const emails: string[] = [];
        const phones: string[] = [];
        const hashedEmails: string[] = [];
        const hashedPhones: string[] = [];

        for (const customer of customers) {
            // Process email
            if (customer.email) {
                const normalizedEmail = customer.email.toLowerCase().trim();
                emails.push(normalizedEmail);
                hashedEmails.push(this.sha256Hash(normalizedEmail));
            }

            // Process phone - extract from rawData.billing.phone
            const rawData = customer.rawData as Record<string, any> | null;
            const phone = rawData?.billing?.phone || rawData?.phone;
            if (phone && typeof phone === 'string') {
                const normalizedPhone = phone.replace(/\D/g, '');
                if (normalizedPhone.length >= 10) {
                    phones.push(normalizedPhone);
                    hashedPhones.push(this.sha256Hash(normalizedPhone));
                }
            }
        }

        return {
            emails,
            phones,
            hashedEmails,
            hashedPhones,
            totalCount: customers.length
        };
    }


    /**
     * SHA256 hash for PII before sending to ad platforms.
     * Both Meta and Google require this for Customer Match / Custom Audiences.
     */
    private sha256Hash(value: string): string {
        return crypto.createHash('sha256').update(value).digest('hex');
    }

    private buildWhereClause(accountId: string, criteria: SegmentCriteria): Prisma.WooCustomerWhereInput {
        if (!criteria || !criteria.rules || criteria.rules.length === 0) {
            return { accountId }; // Return all if no rules? Or none? Let's say all for now or handle empty.
        }

        const conditions: Prisma.WooCustomerWhereInput[] = criteria.rules.map(rule => {
            return this.mapRuleToPrisma(rule);
        });

        if (criteria.type === 'OR') {
            return {
                accountId,
                OR: conditions
            };
        }

        // Default AND
        return {
            accountId,
            AND: conditions
        };
    }

    private mapRuleToPrisma(rule: SegmentRule): Prisma.WooCustomerWhereInput {
        const { field, operator, value } = rule;

        // Numeric fields
        if (field === 'totalSpent' || field === 'ordersCount') {
            const numValue = Number(value);
            switch (operator) {
                case 'gt': return { [field]: { gt: numValue } };
                case 'lt': return { [field]: { lt: numValue } };
                case 'gte': return { [field]: { gte: numValue } };
                case 'lte': return { [field]: { lte: numValue } };
                case 'eq': return { [field]: { equals: numValue } };
                default: return {};
            }
        }

        // String fields
        if (field === 'email' || field === 'firstName' || field === 'lastName') {
            switch (operator) {
                case 'contains': return { [field]: { contains: value, mode: 'insensitive' } };
                case 'equals': return { [field]: { equals: value, mode: 'insensitive' } };
                case 'startsWith': return { [field]: { startsWith: value, mode: 'insensitive' } };
                default: return {};
            }
        }

        return {};
    }
}

export const segmentService = new SegmentService();

