            const mockCustomer = {
                id: customerId,
                accountId: accountId,
                email: 'test@example.com',
                wooId: 123,
                totalSpent: 0,
                ordersCount: 0
            };

            mockFindFirst.mockResolvedValueOnce(mockCustomer);

            const result = await CustomersService.getCustomerDetails(accountId, customerId);

            expect(result).not.toBeNull();
            // Service enriches customer with computed stats from orders (fallback when DB value is 0)
            expect(result?.customer).toEqual({
                ...mockCustomer,
                totalSpent: 0,
                ordersCount: 0
            });
            expect(mockFindFirst).toHaveBeenCalledTimes(1);
        });

        it('should NOT allow cross-account lookup (VULNERABILITY FIXED)', async () => {
            // First call returns null (not found in account)
            mockFindFirst.mockResolvedValueOnce(null);

            // Mock ES fallback to also return nothing (to ensure we reach end of function)
            mockSearch.mockResolvedValueOnce({
                hits: { hits: [], total: { value: 0 } }
            });

            const result = await CustomersService.getCustomerDetails(accountId, customerId);

            // Expect null because it wasn't found in the account, and we disallowed global lookup.
            expect(result).toBeNull();

            // We expect mockFindFirst to be called ONLY ONCE (the scoped lookup).
            // The second global lookup (which was the vulnerability) should not happen.
            expect(mockFindFirst).toHaveBeenCalledTimes(1);
        });
    });
});

/**
 * Budget Rebalancer Service
 * 
 * Analyzes campaign performance and generates ROAS-based budget reallocation
 * recommendations. Shifts budget from underperforming campaigns to winners.
 * Part of AI Co-Pilot v2 - Phase 3: Campaign Automation.
 */

import { prisma } from '../../utils/prisma';
import { Logger } from '../../utils/logger';
import { AdsService } from '../ads';
import { MetaAdsService } from './MetaAdsService';
import { GoogleAdsService } from './GoogleAdsService';
import { SearchToAdsIntelligenceService } from './SearchToAdsIntelligenceService';
import { QueryTrend } from '../search-console/SearchConsoleService';

/** Configuration for budget rebalancer behavior */
export interface RebalancerConfig {
    minRoasThreshold: number;       // Minimum acceptable ROAS (default: 2.0)
    winnerBudgetIncrease: number;   // Percent increase for winners (default: 0.15)
    loserBudgetDecrease: number;    // Percent decrease for losers (default: 0.15)
    maxSingleChange: number;        // Max percent change per action (default: 0.30)
    minDailyBudget: number;         // Never go below this amount (default: 5.00)
    requireApproval: boolean;       // If false, auto-execute (default: true)
    maxDailySpend?: number;         // Optional account-level spend cap
}

/** Campaign analysis result */
interface CampaignAnalysis {
    campaignId: string;
    campaignName: string;
    platform: 'GOOGLE' | 'META';
    adAccountId: string;
    currentBudget: number;
    spend: number;
    revenue: number;
    roas: number;
    classification: 'winner' | 'loser' | 'neutral';
}

/** Recommended budget change */
interface BudgetRecommendation {
    campaignId: string;
    campaignName: string;
    platform: 'GOOGLE' | 'META';
    adAccountId: string;
    currentBudget: number;
    newBudget: number;
    changePercent: number;
    reason: string;
    roas: number;
}

/** Result of rebalancing analysis */
export interface RebalanceResult {
    accountId: string;
    analyzedAt: Date;
    campaignsAnalyzed: number;
    winners: CampaignAnalysis[];
    losers: CampaignAnalysis[];
    recommendations: BudgetRecommendation[];
    scheduledActions: string[];  // IDs of created scheduled actions
}

const DEFAULT_CONFIG: RebalancerConfig = {
    minRoasThreshold: 2.0,
    winnerBudgetIncrease: 0.15,
    loserBudgetDecrease: 0.15,
    maxSingleChange: 0.30,
    minDailyBudget: 5.00,
    requireApproval: true
};

/**
 * Analyzes and rebalances campaign budgets based on ROAS performance.
 */
export class BudgetRebalancerService {
    /**
     * Analyze campaigns and generate rebalancing recommendations.
     * Optionally schedules actions for execution.
     */
    static async analyzeAndRebalance(
        accountId: string,
        config: Partial<RebalancerConfig> = {}
    ): Promise<RebalanceResult> {
        const settings = { ...DEFAULT_CONFIG, ...config };

        Logger.info('[BudgetRebalancer] Starting analysis', { accountId, settings });

        // Get all ad accounts for this account
        const adAccounts = await AdsService.getAdAccounts(accountId);

        if (adAccounts.length === 0) {
            return {
                accountId,
                analyzedAt: new Date(),
                campaignsAnalyzed: 0,
                winners: [],
                losers: [],
                recommendations: [],
                scheduledActions: []
            };
        }

        // Analyze campaigns across all platforms
        const analyses: CampaignAnalysis[] = [];

        for (const adAccount of adAccounts) {
            const platformAnalysis = await this.analyzePlatformCampaigns(
                adAccount.id,
                adAccount.platform as 'GOOGLE' | 'META',
                settings
            );
            analyses.push(...platformAnalysis);
        }

        // Classify campaigns
        const winners = analyses.filter(a => a.classification === 'winner');
        const losers = analyses.filter(a => a.classification === 'loser');

        Logger.info('[BudgetRebalancer] Classification complete', {
            accountId,
            total: analyses.length,
            winners: winners.length,
            losers: losers.length
        });

        // Fetch organic trends to apply the "organic safety net" modifier
        const organicTrends = await SearchToAdsIntelligenceService
            .getOrganicTrendsForPaidQueries(accountId)
            .catch(() => new Map<string, QueryTrend>());

        // Generate recommendations with organic trend context
        const recommendations = this.generateRecommendations(winners, losers, settings, organicTrends);

        // Schedule actions if configured
        const scheduledActions: string[] = [];

        for (const rec of recommendations) {
            const actionId = await this.scheduleRebalanceAction(
                accountId,
                rec,
                settings
            );
            if (actionId) {
                scheduledActions.push(actionId);
            }
        }

        return {
            accountId,
            analyzedAt: new Date(),
            campaignsAnalyzed: analyses.length,
            winners,
            losers,
            recommendations,
            scheduledActions
        };
    }

    /**
     * Analyze campaigns for a specific ad account/platform.
     */
    private static async analyzePlatformCampaigns(
        adAccountId: string,
        platform: 'GOOGLE' | 'META',
        settings: RebalancerConfig
    ): Promise<CampaignAnalysis[]> {
        try {
            const campaigns = platform === 'META'
                ? await MetaAdsService.getCampaignInsights(adAccountId, 30)
                : await GoogleAdsService.getCampaignInsights(adAccountId, 30);

            return campaigns.map(campaign => {
                const spend = campaign.spend || 0;
                const revenue = (campaign as any).conversionsValue ||
                    (campaign as any).revenue || 0;
                const roas = spend > 0 ? revenue / spend : 0;

                let classification: 'winner' | 'loser' | 'neutral' = 'neutral';

                // Only classify campaigns with meaningful spend
                if (spend >= 10) {
                    if (roas >= settings.minRoasThreshold * 1.5) {
                        classification = 'winner';  // High performers
                    } else if (roas < settings.minRoasThreshold * 0.5) {
                        classification = 'loser';   // Low performers
                    }
                }

                return {
                    campaignId: campaign.campaignId || (campaign as any).id || '',
                    campaignName: campaign.campaignName || (campaign as any).name || '',
                    platform,
                    adAccountId,
                    currentBudget: (campaign as any).dailyBudget || 0,
                    spend,
                    revenue,
                    roas,
                    classification
                };
            });

        } catch (error: any) {
            Logger.error('[BudgetRebalancer] Failed to analyze campaigns', {
                adAccountId,
                platform,
                error: error.message
            });
            return [];
        }
    }

    /**
     * Generate budget change recommendations.
     * Organic trends provide an "organic safety net" — if a campaign's
     * keywords are trending up organically, budget cuts are softened.
     */
    private static generateRecommendations(
        winners: CampaignAnalysis[],
        losers: CampaignAnalysis[],
        settings: RebalancerConfig,
        organicTrends: Map<string, QueryTrend> = new Map()
    ): BudgetRecommendation[] {
        const recommendations: BudgetRecommendation[] = [];

        // Increase budget for winners
        for (const winner of winners) {
            if (winner.currentBudget <= 0) continue;

            const increaseAmount = Math.min(
                winner.currentBudget * settings.winnerBudgetIncrease,
                winner.currentBudget * settings.maxSingleChange
            );
            const newBudget = winner.currentBudget + increaseAmount;

            // Check against max daily spend if set
            if (settings.maxDailySpend && newBudget > settings.maxDailySpend) {
                continue; // Skip if would exceed cap
            }

            recommendations.push({
                campaignId: winner.campaignId,
                campaignName: winner.campaignName,
                platform: winner.platform,
                adAccountId: winner.adAccountId,
                currentBudget: winner.currentBudget,
                newBudget: Math.round(newBudget * 100) / 100,
                changePercent: (increaseAmount / winner.currentBudget) * 100,
                reason: `High ROAS (${winner.roas.toFixed(2)}) - scaling up`,
                roas: winner.roas
            });
        }

        // Decrease budget for losers
        for (const loser of losers) {
            if (loser.currentBudget <= 0) continue;

            const decreaseAmount = Math.min(
                loser.currentBudget * settings.loserBudgetDecrease,
                loser.currentBudget * settings.maxSingleChange
            );
            const newBudget = Math.max(
                loser.currentBudget - decreaseAmount,
                settings.minDailyBudget
            );

            // Skip if already at minimum
            if (newBudget >= loser.currentBudget) continue;

            recommendations.push({
                campaignId: loser.campaignId,
                campaignName: loser.campaignName,
                platform: loser.platform,
                adAccountId: loser.adAccountId,
                currentBudget: loser.currentBudget,
                newBudget: Math.round(newBudget * 100) / 100,
                changePercent: -((loser.currentBudget - newBudget) / loser.currentBudget) * 100,
                reason: this.buildLoserReason(loser, organicTrends),
                roas: loser.roas
            });
        }

        return recommendations;
    }

    /**
     * Build reason string for loser campaigns, factoring in organic trend.
     * If the campaign name matches a rising organic query, the reason
     * notes the organic safety net so the user understands the softer cut.
     */
    private static buildLoserReason(
        loser: CampaignAnalysis,
        organicTrends: Map<string, QueryTrend>
    ): string {
        const baseLine = `Low ROAS (${loser.roas.toFixed(2)}) - reducing spend`;

        if (organicTrends.size === 0) return baseLine;

        // Check if any organic trend matches the campaign name keywords
        const campaignWords = loser.campaignName.toLowerCase().replace(/[^\w\s]/g, '').split(/\s+/);
        for (const [query, trend] of organicTrends) {
            const queryWords = query.split(' ');
            const overlap = campaignWords.filter(w => queryWords.includes(w) && w.length > 2);
            if (overlap.length >= 2 && trend.clickGrowthPct > 10) {
                return `${baseLine}. Note: organic traffic for "${trend.query}" is rising ` +
                    `(+${trend.clickGrowthPct.toFixed(0)}% clicks) — softer cut recommended.`;
            }
        }

        return baseLine;
    }

    /**
     * Create a scheduled action for a budget recommendation.
     */
    private static async scheduleRebalanceAction(
        accountId: string,
        rec: BudgetRecommendation,
        settings: RebalancerConfig
    ): Promise<string | null> {
        try {
            const actionType = rec.newBudget > rec.currentBudget
                ? 'budget_increase'
                : 'budget_decrease';

            const scheduledAction = await prisma.scheduledAdAction.create({
                data: {
                    accountId,
                    actionType,
                    platform: rec.platform.toLowerCase(),
                    adAccountId: rec.adAccountId,
                    campaignId: rec.campaignId,
                    campaignName: rec.campaignName,
                    parameters: {
                        currentBudget: rec.currentBudget,
                        newBudget: rec.newBudget,
                        changePercent: rec.changePercent,
                        reason: rec.reason,
                        roas: rec.roas
                    },
                    scheduledFor: new Date(), // Execute immediately when approved
                    autoExecute: !settings.requireApproval,
                    maxDailySpend: settings.maxDailySpend,
                    sourceType: 'rebalancer'
                }
            });

            Logger.info('[BudgetRebalancer] Scheduled action created', {
                actionId: scheduledAction.id,
                campaignName: rec.campaignName,
                actionType,
                autoExecute: !settings.requireApproval
            });

            return scheduledAction.id;

        } catch (error: any) {
            Logger.error('[BudgetRebalancer] Failed to schedule action', {
                campaignId: rec.campaignId,
                error: error.message
            });
            return null;
        }
    }

    /**
     * Get the current rebalancer settings for an account.
     */
    static async getSettings(accountId: string): Promise<RebalancerConfig> {
        // In future, could store per-account settings in database
        // For now, return defaults
        return DEFAULT_CONFIG;
    }

    /**
     * Process all accounts that have rebalancing enabled.
     * Called by the scheduler.
     */
    static async processAllAccounts(): Promise<{
        processed: number;
        recommendations: number;
    }> {
        // Get all accounts with connected ad platforms
        const accounts = await prisma.account.findMany({
            where: {
                adAccounts: {
                    some: {}
                }
            },
            select: { id: true }
        });

        let totalRecommendations = 0;

        for (const account of accounts) {
            try {
                const result = await this.analyzeAndRebalance(account.id);
                totalRecommendations += result.recommendations.length;
            } catch (error: any) {
                Logger.error('[BudgetRebalancer] Failed to process account', {
                    accountId: account.id,
                    error: error.message
                });
            }
        }

        return {
            processed: accounts.length,
            recommendations: totalRecommendations
        };
    }
}

/**
 * Campaign Wizard Service
 * 
 * AI-powered campaign creation wizard that generates optimal campaign
 * structures based on product selection and business goals.
 * Part of AI Co-Pilot v2 - Phase 3: Campaign Automation.
 */

import { prisma } from '../../utils/prisma';
import { Logger } from '../../utils/logger';
import { CampaignBuilderService, NewCampaignParams, AdCopy, KeywordConfig } from './CampaignBuilderService';
import { AdCopyGenerator } from '../tools/AdCopyGenerator';

/** Input for the campaign wizard */
export interface WizardInput {
    productIds: string[];
    businessGoal: 'sales' | 'leads' | 'awareness';
    dailyBudget: number;
    targetRoas?: number;
    platform: 'GOOGLE' | 'META';
    audienceHints?: string;  // Optional context for targeting
}

/** Ad group proposal within a campaign */
interface AdGroupProposal {
    name: string;
    productIds: string[];
    keywords?: KeywordConfig[];
    adCopy?: AdCopy;
}

/** Complete campaign proposal */
export interface CampaignProposal {
    campaignType: 'SEARCH' | 'SHOPPING' | 'PMAX' | 'ADVANTAGE_PLUS';
    campaignName: string;
    dailyBudget: number;
    targetRoas?: number;
    adGroups: AdGroupProposal[];
    estimatedReach?: number;
    reasoning: string;
}

/** Result of campaign creation */
export interface CampaignCreationResult {
    success: boolean;
    campaignId?: string;
    campaignName?: string;
    adGroupsCreated?: number;
    error?: string;
}

/**
 * AI-powered campaign creation wizard.
 */
export class CampaignWizardService {
    /**
     * Generate a campaign proposal from product selection.
     * Uses AI to determine optimal campaign structure.
     */
    static async generateProposal(
        accountId: string,
        input: WizardInput
    ): Promise<CampaignProposal> {
        Logger.info('[CampaignWizard] Generating proposal', { accountId, input });

        // Fetch product data
        const products = await prisma.wooProduct.findMany({
            where: {
                accountId,
                id: { in: input.productIds }
            },
            select: {
                id: true,
                name: true,
                price: true,
                sku: true,
                images: true,
                rawData: true
            }
        });

        if (products.length === 0) {
            throw new Error('No valid products found for the selected IDs');
        }

        // Determine optimal campaign type
        const campaignType = await this.suggestCampaignType(products, input);

        // Generate campaign structure
        const proposal = await this.buildProposal(
            products,
            campaignType,
            input
        );

        Logger.info('[CampaignWizard] Proposal generated', {
            accountId,
            campaignType,
            adGroups: proposal.adGroups.length
        });

        return proposal;
    }

    /**
     * Auto-suggest campaign type based on products and goals.
     */
    static async suggestCampaignType(
        products: any[],
        input: WizardInput
    ): Promise<'SEARCH' | 'SHOPPING' | 'PMAX'> {
        const hasImages = products.some(p => {
            const images = p.images as any[];
            return images && images.length > 0;
        });

        const productCount = products.length;

        // Decision tree for campaign type
        if (input.platform === 'META') {
            // Meta only supports Advantage+ style campaigns (similar to PMax)
            return 'PMAX';
        }

        // Google campaign type selection
        if (input.businessGoal === 'awareness') {
            return 'PMAX';  // PMax is best for broad reach
        }

        if (productCount >= 6 && hasImages) {
            // Many products with images -> Shopping or PMax
            return input.businessGoal === 'sales' ? 'SHOPPING' : 'PMAX';
        }

        // Default to Search for targeted sales
        return 'SEARCH';
    }

    /**
     * Build the full campaign proposal.
     */
    private static async buildProposal(
        products: any[],
        campaignType: 'SEARCH' | 'SHOPPING' | 'PMAX',
        input: WizardInput
    ): Promise<CampaignProposal> {
        const productNames = products.map(p => p.name).join(', ');
        const campaignName = this.generateCampaignName(products, campaignType, input);

        // Build ad groups based on campaign type
        const adGroups: AdGroupProposal[] = [];

        if (campaignType === 'SEARCH') {
            // Group products by category or create single ad group
            const adGroup = await this.buildSearchAdGroup(products, input);
            adGroups.push(adGroup);
        } else if (campaignType === 'SHOPPING') {
            // One product group for all products
            adGroups.push({
                name: 'All Products',
                productIds: products.map(p => p.id)
            });
        } else {
            // PMax - asset group style
            adGroups.push({
                name: 'Asset Group',
                productIds: products.map(p => p.id)
            });
        }

        // Generate reasoning
        const reasoning = this.generateReasoning(
            campaignType,
            products.length,
            input
        );

        return {
            campaignType,
            campaignName,
            dailyBudget: input.dailyBudget,
            targetRoas: input.targetRoas,
            adGroups,
            reasoning
        };
    }

    /**
     * Build a Search campaign ad group with keywords and ad copy.
     */
    private static async buildSearchAdGroup(
        products: any[],
        input: WizardInput
    ): Promise<AdGroupProposal> {
        // Generate keywords from product names
        const keywords: KeywordConfig[] = [];

        for (const product of products.slice(0, 10)) {  // Limit to 10 products
            const productName = product.name || '';

            // Add phrase match for product name
            keywords.push({
                text: productName,
                matchType: 'PHRASE'
            });

            // Add broad match modifier for key terms
            const keyTerms = productName.split(' ').filter((t: string) => t.length > 3);
            if (keyTerms.length >= 2) {
                keywords.push({
                    text: keyTerms.join(' '),
                    matchType: 'BROAD'
                });
            }
        }

        // Generate ad copy
        const adCopy = await this.generateSearchAdCopy(products);

        return {
            name: `Products - ${products.length} items`,
            productIds: products.map(p => p.id),
            keywords: keywords.slice(0, 20),  // Google allows max 20 keywords per ad group
            adCopy
        };
    }

    /**
     * Generate ad copy for Search campaigns.
     */
    private static async generateSearchAdCopy(products: any[]): Promise<AdCopy> {
        // Get first product for context
        const mainProduct = products[0];
        const productNames = products.slice(0, 3).map(p => p.name).join(', ');

        // Simple copy generation (could use AdCopyGenerator for AI copy)
        const headlines = [
            `Shop ${mainProduct.name}`.slice(0, 30),
            `${products.length} Quality Products`.slice(0, 30),
            'Free Shipping Available'.slice(0, 30),
            'Buy Now - Great Prices'.slice(0, 30),
            'Shop The Best Selection'.slice(0, 30)
        ];

        const descriptions = [
            `Discover our collection including ${productNames}. Order today with secure checkout.`.slice(0, 90),
            'Premium quality products at competitive prices. Fast delivery and easy returns.'.slice(0, 90)
        ];

        return {
            headlines,
            descriptions,
            finalUrl: 'https://example.com'  // Would be filled from account settings
        };
    }

    /**
     * Generate a descriptive campaign name.
     */
    private static generateCampaignName(
        products: any[],
        campaignType: string,
        input: WizardInput
    ): string {
        const date = new Date().toISOString().slice(0, 10);
        const goalLabel = input.businessGoal.charAt(0).toUpperCase() + input.businessGoal.slice(1);

        if (products.length === 1) {
            return `${campaignType} - ${products[0].name} - ${goalLabel} - ${date}`;
        }

        return `${campaignType} - ${products.length} Products - ${goalLabel} - ${date}`;
    }

    /**
     * Generate AI reasoning for the campaign structure.
     */
    private static generateReasoning(
        campaignType: string,
        productCount: number,
        input: WizardInput
    ): string {
        const reasons: string[] = [];

        if (campaignType === 'SEARCH') {
            reasons.push('Search campaigns target users actively searching for your products.');
            reasons.push(`With ${productCount} product(s), a focused Search campaign will capture high-intent traffic.`);
        } else if (campaignType === 'SHOPPING') {
            reasons.push('Shopping campaigns showcase your products directly in search results with images and prices.');
            reasons.push('Ideal for e-commerce with multiple products.');
        } else {
            reasons.push('Performance Max campaigns leverage AI to find customers across all Google channels.');
            reasons.push('Best for awareness and broad reach with diverse product offerings.');
        }

        if (input.targetRoas) {
            reasons.push(`Target ROAS set to ${input.targetRoas}x will optimize bids for profitable conversions.`);
        }

        return reasons.join(' ');
    }

    /**
     * Execute an approved campaign proposal.
     */
    static async executeProposal(
        accountId: string,
        adAccountId: string,
        proposal: CampaignProposal
    ): Promise<CampaignCreationResult> {
        Logger.info('[CampaignWizard] Executing proposal', {
            accountId,
            adAccountId,
            campaignType: proposal.campaignType
        });

        try {
            if (proposal.campaignType === 'SEARCH' && proposal.adGroups[0]) {
                const adGroup = proposal.adGroups[0];

                const params: NewCampaignParams = {
                    name: proposal.campaignName,
                    dailyBudget: proposal.dailyBudget,
                    targetRoas: proposal.targetRoas
                };

                const result = await CampaignBuilderService.createSearchCampaign(
                    adAccountId,
                    params,
                    adGroup.keywords || [],
                    adGroup.adCopy!
                );

                return {
                    success: result.success,
                    campaignId: result.campaignResource,
                    campaignName: result.campaignName,
                    adGroupsCreated: 1
                };

            } else if (proposal.campaignType === 'PMAX') {
                // PMax not fully implemented in CampaignBuilderService
                return {
                    success: false,
                    error: 'Performance Max campaign creation is not yet implemented'
                };

            } else if (proposal.campaignType === 'SHOPPING') {
                return {
                    success: false,
                    error: 'Shopping campaign creation is not yet implemented'
                };
            }

            return {
                success: false,
                error: 'Unknown campaign type'
            };

        } catch (error: any) {
            Logger.error('[CampaignWizard] Execution failed', {
                accountId,
                error: error.message
            });

            return {
                success: false,
                error: error.message
            };
        }
    }
}

/**
 * Google Ads Client Factory
 * 
 * Shared helper for creating Google Ads API clients.
 * 
 * Why caching matters: GoogleAdsApi spawns gRPC / HTTP/2 channels internally.
 * Creating a new instance per call leaks connections and buffers, leading to
 * heap exhaustion under load (the OOM crash that prompted this rewrite).
 */

import { prisma } from '../../utils/prisma';
import { Logger } from '../../utils/logger';
import { getCredentials } from './types';
import { EventBus, EVENTS } from '../events';

// ─── Singleton GoogleAdsApi instance ────────────────────────────────────────
// All accounts share the same developer token / client ID / secret, so there
// is exactly one API client. Lazily initialised on first use.
// Type is `any` because google-ads-api is imported lazily to avoid loading
// its ~500MB+ protobuf descriptors at module-load time.
let cachedApiClient: any = null;
let cachedApiFingerprint = '';

// ─── Customer object cache (per adAccountId) ────────────────────────────────
// Reusing the Customer avoids spawning duplicate HTTP/2 channels.
// Entries expire after CUSTOMER_CACHE_TTL_MS to pick up token refreshes.
// Capped at MAX_CUSTOMER_CACHE_SIZE to prevent protobuf descriptor trees
// from accumulating and inflating the heap (each Customer holds ~2–5 MB).
const CUSTOMER_CACHE_TTL_MS = 5 * 60 * 1000; // 5 minutes
const MAX_CUSTOMER_CACHE_SIZE = 20;
interface CachedCustomer {
    customer: any;
    currency: string;
    createdAt: number;
}
const customerCache = new Map<string, CachedCustomer>();

// ─── Circuit-breakers ───────────────────────────────────────────────────────

/**
 * Auth breaker: accounts with expired OAuth (invalid_grant).
 * Prevents repeated API round-trips until the user re-authenticates.
 */
const AUTH_BREAKER_TTL_MS = 60 * 60 * 1000; // 60 minutes
const authBreakerMap = new Map<string, number>();

/**
 * gRPC failure breaker: accounts that keep returning "Unknown gRPC error".
 * After GRPC_BREAKER_THRESHOLD failures within GRPC_BREAKER_WINDOW_MS,
 * the account is skipped for GRPC_BREAKER_COOLDOWN_MS.
 */
const GRPC_BREAKER_THRESHOLD = 3;
const GRPC_BREAKER_WINDOW_MS = 5 * 60 * 1000;   // 5-minute window
const GRPC_BREAKER_COOLDOWN_MS = 10 * 60 * 1000; // 10-minute cooldown
interface GrpcBreakerState {
    failures: number[];       // timestamps of recent failures
    cooldownUntil: number;    // 0 = not in cooldown
}
const grpcBreakerMap = new Map<string, GrpcBreakerState>();

// Periodically purge expired breaker entries to prevent unbounded Map growth
const breakerCleanupInterval = setInterval(() => {
    const now = Date.now();
    for (const [id, ts] of authBreakerMap.entries()) {
        if (now - ts >= AUTH_BREAKER_TTL_MS) authBreakerMap.delete(id);
    }
    for (const [id, state] of grpcBreakerMap.entries()) {
        // Remove if cooldown has expired AND no recent failures
        if (state.cooldownUntil <= now && state.failures.length === 0) {
            grpcBreakerMap.delete(id);
        }
    }
}, 15 * 60 * 1000); // every 15 minutes

export function cleanupGoogleAdsClient() {
    clearInterval(breakerCleanupInterval);
}

/**
 * Check if the gRPC circuit-breaker is currently open for an ad account.
 * Callers can use this to skip work before constructing full call chains.
 */
export function isGrpcBreakerOpen(adAccountId: string): boolean {
    const state = grpcBreakerMap.get(adAccountId);
    return !!(state && state.cooldownUntil > Date.now());
}

/** Mark an ad account as auth-broken. Called from parseGoogleAdsError. */
export function tripAuthBreaker(adAccountId: string): void {
    authBreakerMap.set(adAccountId, Date.now());
    // Also evict from customer cache so stale tokens aren't reused
    customerCache.delete(adAccountId);

    // Notify the user that their token has expired
    prisma.adAccount.findUnique({ where: { id: adAccountId }, select: { accountId: true, name: true, platform: true } })
        .then(adAccount => {
            if (adAccount?.accountId) {
                EventBus.emit(EVENTS.AD.AUTH_EXPIRED, {
                    accountId: adAccount.accountId,
                    adAccountId,
                    platform: adAccount.platform,
                    adAccountName: adAccount.name
                });
            }
        })
        .catch(err => Logger.warn('Failed to emit auth-expired event', { error: err.message }));
}

/**
 * Record a gRPC failure for an ad account.
 * Call this from catch blocks that see transient/unknown gRPC errors.
 */
export function recordGrpcFailure(adAccountId: string): void {
    const now = Date.now();
    let state = grpcBreakerMap.get(adAccountId);
    if (!state) {
        state = { failures: [], cooldownUntil: 0 };
        grpcBreakerMap.set(adAccountId, state);
    }
    // Already in cooldown — don't accumulate more failures
    if (state.cooldownUntil > now) return;

    // Prune old failures outside the window
    state.failures = state.failures.filter(t => now - t < GRPC_BREAKER_WINDOW_MS);
    state.failures.push(now);

    if (state.failures.length >= GRPC_BREAKER_THRESHOLD) {
        state.cooldownUntil = now + GRPC_BREAKER_COOLDOWN_MS;
        state.failures = []; // Reset so counter starts fresh after cooldown
        Logger.warn('gRPC circuit-breaker tripped — skipping account for 10 min', {
            adAccountId,
            failureCount: GRPC_BREAKER_THRESHOLD
        });
    }
}

export interface GoogleAdsClientConfig {
    customer: any;
    currency: string;
}

/**
 * Extract a usable error message from gRPC error objects.
 *
 * Why: google-ads-api sometimes throws raw gRPC errors where both
 * `.message` and `.details` are empty. This digs into nested error
 * structures (AggregateError, .cause chain) to surface diagnostics.
 */
export function extractGrpcErrorMessage(error: any): string {
    if (error.message) return error.message;
    if (error.details) return error.details;

    const parts: string[] = [];
    if (error.code !== undefined) parts.push(`gRPC code=${error.code}`);

    // AggregateError from Promise.any() — gRPC DNS/credential resolution
    if (Array.isArray(error.errors) && error.errors.length > 0) {
        const inner = error.errors[0];
        const innerMsg = inner?.message || inner?.details || String(inner);
        parts.push(`inner=${innerMsg}`);
    }

    // ES2022 Error.cause chain
    if (error.cause) {
        const causeMsg = error.cause?.message || String(error.cause);
        parts.push(`cause=${causeMsg}`);
    }

    // gRPC metadata sometimes carries error descriptions
    if (error.metadata) {
        try {
            const meta = typeof error.metadata.toJSON === 'function'
                ? JSON.stringify(error.metadata.toJSON())
                : String(error.metadata);
            if (meta && meta !== '{}') parts.push(`metadata=${meta}`);
        } catch { /* ignore serialisation failures */ }
    }

    if (parts.length > 0) return parts.join(' ');

    // Last resort: stringify the error object itself
    try {
        const str = String(error);
        if (str && str !== '[object Object]') return str;
    } catch { /* ignore */ }

    return 'Unknown gRPC error (no message/details/code)';
}

/**
 * Pre-flight OAuth token refresh.
 *
 * Why: google-ads-api delegates token refresh to gRPC's credential
 * provider, which swallows errors into opaque AggregateErrors with
 * zero diagnostics. By refreshing proactively via REST we can:
 * (a) detect revoked tokens immediately and trip the auth breaker,
 * (b) store a fresh access token so gRPC never needs to refresh.
 */
async function refreshAccessToken(
    adAccountId: string,
    refreshToken: string,
    clientId: string,
    clientSecret: string,
): Promise<string> {
    const params = new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: refreshToken,
        client_id: clientId,
        client_secret: clientSecret,
    });

    const resp = await fetch('https://oauth2.googleapis.com/token', {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: params.toString(),
    });

    const data = await resp.json();

    if (data.error) {
        // Trip auth breaker so scheduled jobs stop hammering Google
        tripAuthBreaker(adAccountId);
        Logger.warn('Google OAuth token refresh failed — auth breaker tripped', {
            adAccountId,
            error: data.error,
            description: data.error_description,
        });
        throw new Error(
            `Google token refresh failed: ${data.error_description || data.error}. ` +
            'Reconnect your Google Ads account in Settings.',
        );
    }

    // Persist the new access token so other services can use it
    if (data.access_token) {
        await prisma.adAccount.update({
            where: { id: adAccountId },
            data: { accessToken: data.access_token },
        }).catch(err => Logger.warn('Failed to persist refreshed access token', { error: err.message }));
    }

    return data.access_token;
}

/**
 * Create (or return cached) Google Ads API customer client for an ad account.
 */
export async function createGoogleAdsClient(adAccountId: string): Promise<GoogleAdsClientConfig> {
    const now = Date.now();

    // ── Auth circuit-breaker ─────────────────────────────────────────────
    const breakerTs = authBreakerMap.get(adAccountId);
    if (breakerTs && now - breakerTs < AUTH_BREAKER_TTL_MS) {
        throw new Error('Auth circuit-breaker active — invalid_grant within last 60 min. Re-authenticate to restore.');
    }

    // ── gRPC failure circuit-breaker ─────────────────────────────────────
    const grpcState = grpcBreakerMap.get(adAccountId);
    if (grpcState && grpcState.cooldownUntil > now) {
        throw new Error('gRPC circuit-breaker active — too many failures, cooling down for 10 min.');
    }

    // ── Return cached Customer if still fresh ────────────────────────────
    const cached = customerCache.get(adAccountId);
    if (cached && now - cached.createdAt < CUSTOMER_CACHE_TTL_MS) {
        // Promote to end of Map iteration order (LRU touch)
        customerCache.delete(adAccountId);
        customerCache.set(adAccountId, cached);
        return { customer: cached.customer, currency: cached.currency };
    }

    // ── Build or reuse the singleton GoogleAdsApi ────────────────────────
    const adAccount = await prisma.adAccount.findUnique({
        where: { id: adAccountId }
    });

    if (!adAccount || adAccount.platform !== 'GOOGLE' || !adAccount.refreshToken || !adAccount.externalId) {
        throw new Error('Invalid Google Ad Account');
    }

    const creds = await getCredentials('GOOGLE_ADS');
    if (!creds?.clientId || !creds?.clientSecret || !creds?.developerToken) {
        Logger.warn('Google Ads credentials not configured.');
        throw new Error('Google Ads credentials not configured');
    }

    const { clientId, clientSecret, developerToken } = creds;
    const fingerprint = `${clientId}:${developerToken}`;

    // Only allocate a new GoogleAdsApi if credentials changed (effectively never).
    // Lazy import: google-ads-api loads ~500MB+ of protobuf descriptors,
    // so we defer the import until the first actual API call.
    if (!cachedApiClient || cachedApiFingerprint !== fingerprint) {
        const { GoogleAdsApi } = await import('google-ads-api');
        cachedApiClient = new GoogleAdsApi({
            client_id: clientId,
            client_secret: clientSecret,
            developer_token: developerToken
        });
        cachedApiFingerprint = fingerprint;
        Logger.info('GoogleAdsApi client created (singleton — protobuf loaded)');
    }

    // ── Pre-flight token refresh via REST ──────────────────────────────
    // Validates the refresh token before gRPC touches it. On failure
    // the auth breaker is tripped with a clear error message.
    const freshAccessToken = await refreshAccessToken(
        adAccountId,
        adAccount.refreshToken,
        clientId,
        clientSecret,
    );

    const loginCustomerId = creds.loginCustomerId;
    const customerConfig: any = {
        customer_id: adAccount.externalId.replace(/-/g, ''),
        refresh_token: adAccount.refreshToken,
    };

    if (loginCustomerId) {
        customerConfig.login_customer_id = loginCustomerId.replace(/-/g, '');
    }

    const customer = cachedApiClient.Customer(customerConfig);
    const currency = adAccount.currency || 'USD';

    // Cache for reuse — evict oldest if at capacity
    if (customerCache.size >= MAX_CUSTOMER_CACHE_SIZE) {
        const oldestKey = customerCache.keys().next().value;
        if (oldestKey) customerCache.delete(oldestKey);
    }
    customerCache.set(adAccountId, { customer, currency, createdAt: now });

    return { customer, currency };
}

/**
 * Parse Google Ads API errors into user-friendly messages.
 */
export function parseGoogleAdsError(error: any, customerId: string): string {
    const errorMessage = error.message || error.details || '';
    const errorCode = error.code;

    // GRPC error code 12 = UNIMPLEMENTED
    if (errorCode === 12 || errorMessage.includes('UNIMPLEMENTED') || errorMessage.includes('GRPC target method')) {
        return 'Google Ads API access denied. Possible causes: ' +
            '(1) Developer token at "Test Account" level - upgrade to "Explorer Access" at https://ads.google.com/aw/apicenter. ' +
            '(2) Missing Manager Account ID (MCC) - if accessing client accounts through an MCC, add the Manager Account ID in Super Admin > Credentials > Google Ads.';
    }
    // GRPC error code 7 = PERMISSION_DENIED
    if (errorCode === 7 || errorMessage.includes('PERMISSION_DENIED')) {
        return 'Permission denied. Ensure the connected Google account has access to this Google Ads account (Customer ID: ' +
            customerId + '). If this account is managed by a Manager Account (MCC), you MUST configure the "Manager Account ID" in Super Admin > Credentials > Google Ads.';
    }
    // GRPC error code 16 = UNAUTHENTICATED
    if (errorCode === 16 || errorMessage.includes('UNAUTHENTICATED') || errorMessage.includes('invalid_grant')) {
        // Trip circuit-breaker so scheduled jobs skip this account for 60 min
        tripAuthBreaker(customerId);
        return 'Authentication expired. Please disconnect and reconnect your Google Ads account to refresh the OAuth tokens.';
    }
    // Invalid customer ID format
    if (errorMessage.includes('INVALID_CUSTOMER_ID') || errorMessage.includes('customer_id')) {
        return 'Invalid Customer ID format. Please verify the Customer ID is correct (format: 123-456-7890 or 1234567890).';
    }

    return errorMessage;
}

