/**
 * Meta Messaging Service (Facebook Messenger & Instagram DMs)
 * Handles Meta Graph API v24.0 messaging operations.
 * 
 * Why: Enables unified inbox to receive and send messages through
 * Facebook Pages and Instagram Business accounts.
 */

import { prisma } from '../../utils/prisma';
import { Logger } from '../../utils/logger';
import { EventBus, EVENTS } from '../events';

const GRAPH_API_VERSION = 'v24.0';
const GRAPH_API_BASE = `https://graph.facebook.com/${GRAPH_API_VERSION}`;

interface MetaMessagePayload {
    recipientId: string;
    message: string;
    messageType?: 'RESPONSE' | 'UPDATE' | 'MESSAGE_TAG';
}

interface MetaWebhookEntry {
    id: string;
    time: number;
    messaging?: MetaWebhookMessage[];
}

interface MetaWebhookMessage {
    sender: { id: string };
    recipient: { id: string };
    timestamp: number;
    message?: {
        mid: string;
        text?: string;
        attachments?: Array<{
            type: string;
            payload: { url?: string };
        }>;
    };
    read?: { watermark: number };
    delivery?: { mids: string[]; watermark: number };
}

export class MetaMessagingService {
    /**
     * Send a message via Facebook Messenger or Instagram DM.
     * Requires the page/IG account to be connected with messaging permissions.
     */
    static async sendMessage(
        socialAccountId: string,
        payload: MetaMessagePayload
    ): Promise<{ messageId: string } | null> {
        try {
            const socialAccount = await prisma.socialAccount.findUnique({
                where: { id: socialAccountId },
            });

            if (!socialAccount || !socialAccount.isActive) {
                Logger.warn('[MetaMessaging] Social account not found or inactive', { socialAccountId });
                return null;
            }

            const { platform, accessToken, externalId } = socialAccount;

            // Determine the correct endpoint based on platform
            const endpoint = platform === 'INSTAGRAM'
                ? `${GRAPH_API_BASE}/${externalId}/messages`
                : `${GRAPH_API_BASE}/${externalId}/messages`;

            const response = await fetch(endpoint, {
                method: 'POST',
                headers: {
                    Authorization: `Bearer ${accessToken}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    recipient: { id: payload.recipientId },
                    message: { text: payload.message },
                    messaging_type: payload.messageType || 'RESPONSE',
                }),
            });

            if (!response.ok) {
                const errorData = await response.json().catch(() => ({}));
                throw new Error(JSON.stringify(errorData));
            }

            const data = await response.json();

            Logger.info('[MetaMessaging] Message sent', {
                platform,
                recipientId: payload.recipientId,
                messageId: data.message_id,
            });

            EventBus.emit(EVENTS.SOCIAL.MESSAGE_SENT, {
                platform,
                socialAccountId,
                messageId: data.message_id,
            });

            return { messageId: data.message_id };
        } catch (error: any) {
            Logger.error('[MetaMessaging] Failed to send message', {
                socialAccountId,
                error: error.message,
            });
            return null;
        }
    }

    /**
     * Process incoming webhook events from Meta.
     * Creates or updates conversations based on incoming messages.
     */
    static async processWebhookEvent(
        entries: MetaWebhookEntry[]
    ): Promise<void> {
        for (const entry of entries) {
            const pageId = entry.id;

            // Find the social account by externalId (page ID)
            const socialAccount = await prisma.socialAccount.findFirst({
                where: {
                    externalId: pageId,
                    platform: { in: ['FACEBOOK', 'INSTAGRAM'] },
                    isActive: true,
                },
                include: { account: true },
            });

            if (!socialAccount) {
                Logger.warn('[MetaMessaging] No social account found for page', { pageId });
                continue;
            }

            for (const event of entry.messaging || []) {
                await this.handleMessageEvent(socialAccount, event);
            }
        }
    }

    /**
     * Handle individual message events (new message, read, delivery).
     */
    private static async handleMessageEvent(
        socialAccount: any,
        event: MetaWebhookMessage
    ): Promise<void> {
        const { sender, message, read, delivery } = event;

        // Skip if it's our own message (sent by the page)
        if (sender.id === socialAccount.externalId) {
            return;
        }

        // Handle read receipts
        if (read) {
            Logger.debug('[MetaMessaging] Read receipt', { watermark: read.watermark });
            return;
        }

        // Handle delivery confirmations
        if (delivery) {
            Logger.debug('[MetaMessaging] Delivery confirmation', { mids: delivery.mids });
            return;
        }

        // Handle new incoming message
        if (message) {
            await this.handleIncomingMessage(socialAccount, sender.id, message, event.timestamp);
        }
    }

    /**
     * Create or update conversation and add the incoming message.
     */
    private static async handleIncomingMessage(
        socialAccount: any,
        senderId: string,
        message: NonNullable<MetaWebhookMessage['message']>,
        timestamp: number
    ): Promise<void> {
        const accountId = socialAccount.accountId;
        const platform = socialAccount.platform as 'FACEBOOK' | 'INSTAGRAM';
        const channel = platform === 'FACEBOOK' ? 'FACEBOOK' : 'INSTAGRAM';

        // Build external conversation ID (platform + page + sender)
        const externalConversationId = `${platform}:${socialAccount.externalId}:${senderId}`;

        // Find or create conversation
        let conversation = await prisma.conversation.findFirst({
            where: {
                accountId,
                externalConversationId,
            },
        });

        if (!conversation) {
            // Fetch sender profile for display name
            const senderProfile = await this.getUserProfile(socialAccount.accessToken, senderId);
            const guestName = senderProfile?.name || `${platform} User`;

            conversation = await prisma.conversation.create({
                data: {
                    accountId,
                    channel,
                    externalConversationId,
                    socialAccountId: socialAccount.id,
                    guestName,
                    status: 'OPEN',
                    priority: 'MEDIUM',
                },
            });

            Logger.info('[MetaMessaging] Created new conversation', {
                conversationId: conversation.id,
                channel,
                senderId,
            });
        } else {
            // Re-open conversation if it was closed
            if (conversation.status !== 'OPEN') {
                await prisma.conversation.update({
                    where: { id: conversation.id },
                    data: { status: 'OPEN', updatedAt: new Date() },
                });
            }
        }

        // Build message content
        let content = message.text || '';
        if (message.attachments?.length) {
            const attachmentLinks = message.attachments
                .filter(a => a.payload?.url)
                .map(a => `[Attachment: ${a.type}](${a.payload.url})`)
                .join('\n');
            content = content ? `${content}\n\n${attachmentLinks}` : attachmentLinks;
        }

        // Create the message
        const newMessage = await prisma.message.create({
            data: {
                conversationId: conversation.id,
                content,
                contentType: message.attachments?.length ? 'FILE' : 'TEXT',
                senderType: 'CUSTOMER',
                senderId: senderId,
            },
        });

        Logger.info('[MetaMessaging] Message received and stored', {
            conversationId: conversation.id,
            messageId: newMessage.id,
            platform,
        });

        // Emit event for real-time updates
        EventBus.emit(EVENTS.SOCIAL.MESSAGE_RECEIVED, {
            accountId,
            conversationId: conversation.id,
            messageId: newMessage.id,
            platform,
            senderId,
        });
    }

    /**
     * Fetch user profile from Meta Graph API.
     */
    private static async getUserProfile(
        accessToken: string,
        userId: string
    ): Promise<{ name?: string; profilePic?: string } | null> {
        try {
            const url = new URL(`${GRAPH_API_BASE}/${userId}`);
            url.searchParams.set('fields', 'name,profile_pic');
            url.searchParams.set('access_token', accessToken);

            const response = await fetch(url.toString());
            if (!response.ok) {
                throw new Error(`HTTP ${response.status}`);
            }
            return await response.json();
        } catch (error: any) {
            Logger.warn('[MetaMessaging] Failed to fetch user profile', {
                userId,
                error: error.message,
            });
            return null;
        }
    }

    /**
     * Get Instagram Business Account ID linked to a Facebook Page.
     * Required for IG DM integration.
     */
    static async getInstagramBusinessAccount(
        pageAccessToken: string,
        pageId: string
    ): Promise<{ igUserId: string; username: string } | null> {
        try {
            const url = new URL(`${GRAPH_API_BASE}/${pageId}`);
            url.searchParams.set('fields', 'instagram_business_account{id,username}');
            url.searchParams.set('access_token', pageAccessToken);

            const response = await fetch(url.toString());
            if (!response.ok) {
                throw new Error(`HTTP ${response.status}`);
            }

            const data = await response.json();
            const igAccount = data.instagram_business_account;
            if (!igAccount) {
                return null;
            }

            return {
                igUserId: igAccount.id,
                username: igAccount.username,
            };
        } catch (error: any) {
            Logger.error('[MetaMessaging] Failed to get Instagram business account', {
                pageId,
                error: error.message,
            });
            return null;
        }
    }

    /**
     * Verify webhook signature for security.
     */
    static verifyWebhookSignature(
        signature: string,
        payload: string,
        appSecret: string
    ): boolean {
        const crypto = require('crypto');
        const expectedSignature = 'sha256=' + crypto
            .createHmac('sha256', appSecret)
            .update(payload)
            .digest('hex');

        return crypto.timingSafeEqual(
            Buffer.from(signature),
            Buffer.from(expectedSignature)
        );
    }

    /**
     * List Facebook Pages the user has access to.
     * Used during OAuth to let user select which page to connect.
     */
    static async listUserPages(
        userAccessToken: string
    ): Promise<Array<{ id: string; name: string; accessToken: string }>> {
        try {
            const url = new URL(`${GRAPH_API_BASE}/me/accounts`);
            url.searchParams.set('fields', 'id,name,access_token');
            url.searchParams.set('access_token', userAccessToken);

            const response = await fetch(url.toString());
            if (!response.ok) {
                throw new Error(`HTTP ${response.status}`);
            }

            const data = await response.json();
            // Map snake_case from API to camelCase for our code
            return (data.data || []).map((page: any) => ({
                id: page.id,
                name: page.name,
                accessToken: page.access_token,
            }));
        } catch (error: any) {
            Logger.error('[MetaMessaging] Failed to list user pages', {
                error: error.message,
            });
            return [];
        }
    }
}

/**
 * AI Content Brief Service
 *
 * Generates AI-powered content briefs for target keywords using
 * OpenRouter. Combines Search Console data with AI analysis to
 * produce actionable content recommendations.
 */

import { prisma } from '../../utils/prisma';
import { Logger } from '../../utils/logger';
import { SearchConsoleService } from './SearchConsoleService';

/** Content brief output */
export interface ContentBrief {
    keyword: string;
    currentPosition: number | null;
    currentClicks: number;
    currentImpressions: number;
    brief: {
        suggestedTitle: string;
        metaDescription: string;
        wordCount: number;
        headingOutline: string[];
        keyTopics: string[];
        internalLinkSuggestions: string[];
        contentType: string;
        tone: string;
    };
    generatedAt: string;
}

export class ContentBriefService {

    /**
     * Generate an AI content brief for a keyword.
     * Uses the account's OpenRouter API key and current Search Console data.
     */
    static async generateBrief(
        accountId: string,
        keyword: string,
        keywordId?: string
    ): Promise<ContentBrief> {
        // Get current search data for context
        const analytics = await SearchConsoleService.getSearchAnalytics(accountId, { days: 28 });
        const kwData = analytics.find(q => q.query.toLowerCase() === keyword.toLowerCase());

        // Get related queries for topic coverage
        const relatedQueries = analytics
            .filter(q => q.query.includes(keyword.split(' ')[0]) && q.query !== keyword.toLowerCase())
            .slice(0, 10)
            .map(q => q.query);

        // Get AI generation (OpenRouter)
        const account = await prisma.account.findUnique({
            where: { id: accountId },
            select: { openRouterApiKey: true, aiModel: true }
        });

        let brief: ContentBrief['brief'];

        if (account?.openRouterApiKey) {
            brief = await this.generateAIBrief(
                account.openRouterApiKey,
                account.aiModel || 'google/gemini-2.0-flash-001',
                keyword,
                kwData,
                relatedQueries
            );
        } else {
            // Template-based fallback when no API key
            brief = this.generateTemplateBrief(keyword, kwData, relatedQueries);
        }

        return {
            keyword,
            currentPosition: kwData?.position ?? null,
            currentClicks: kwData?.clicks ?? 0,
            currentImpressions: kwData?.impressions ?? 0,
            brief,
            generatedAt: new Date().toISOString(),
        };
    }

    /**
     * Generate brief using OpenRouter AI
     */
    private static async generateAIBrief(
        apiKey: string,
        model: string,
        keyword: string,
        kwData: any,
        relatedQueries: string[]
    ): Promise<ContentBrief['brief']> {
        const prompt = `You are an expert SEO content strategist. Generate a comprehensive content brief for the target keyword.

Target Keyword: "${keyword}"
Current Position: ${kwData?.position ?? 'Not ranking'}
Current Clicks: ${kwData?.clicks ?? 0}
Current Impressions: ${kwData?.impressions ?? 0}
Related Queries: ${relatedQueries.join(', ') || 'None found'}

Generate a JSON response with these exact fields:
{
  "suggestedTitle": "Compelling SEO-optimized title (60 chars max)",
  "metaDescription": "Compelling meta description (155 chars max)",
  "wordCount": recommended word count as a number,
  "headingOutline": ["H2: heading", "H3: subheading", ...] array of 5-8 headings,
  "keyTopics": ["topic1", "topic2", ...] array of 5-10 key topics to cover,
  "internalLinkSuggestions": ["descriptive link anchor text"] array of 3-5 suggestions,
  "contentType": "blog post" | "guide" | "landing page" | "product page" | "comparison",
  "tone": "informational" | "commercial" | "transactional" | "navigational"
}

Return ONLY the JSON, no markdown formatting or explanation.`;

        try {
            const response = await fetch('https://openrouter.ai/api/v1/chat/completions', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${apiKey}`,
                },
                body: JSON.stringify({
                    model,
                    messages: [{ role: 'user', content: prompt }],
                    temperature: 0.7,
                    max_tokens: 1000,
                })
            });

            if (!response.ok) {
                throw new Error(`OpenRouter API error: ${response.status}`);
            }

            const data = await response.json();
            const content = data.choices?.[0]?.message?.content || '';

            // Parse JSON from response (handle potential markdown wrapping)
            const jsonMatch = content.match(/\{[\s\S]*\}/);
            if (jsonMatch) {
                return JSON.parse(jsonMatch[0]);
            }

            throw new Error('No valid JSON in AI response');
        } catch (error) {
            Logger.warn('AI content brief generation failed, using template', { error, keyword });
            return this.generateTemplateBrief(keyword, kwData, relatedQueries);
        }
    }

    /**
     * Template-based fallback brief when AI is unavailable
     */
    private static generateTemplateBrief(
        keyword: string,
        kwData: any,
        relatedQueries: string[]
    ): ContentBrief['brief'] {
        const titleKeyword = keyword.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
        const isCommercial = keyword.includes('buy') || keyword.includes('best') || keyword.includes('review');

        return {
            suggestedTitle: isCommercial
                ? `Best ${titleKeyword}: Complete Guide & Top Picks (${new Date().getFullYear()})`
                : `${titleKeyword}: Everything You Need to Know (${new Date().getFullYear()})`,
            metaDescription: `Discover everything about ${keyword}. Our comprehensive guide covers key topics, expert tips, and actionable advice to help you succeed.`,
            wordCount: isCommercial ? 2000 : 1500,
            headingOutline: [
                `H2: What is ${titleKeyword}?`,
                `H2: Key Benefits of ${titleKeyword}`,
                `H2: How to Get Started with ${titleKeyword}`,
                `H2: Common Mistakes to Avoid`,
                `H2: Expert Tips and Best Practices`,
                `H2: Frequently Asked Questions`,
            ],
            keyTopics: [keyword, ...relatedQueries.slice(0, 5)],
            internalLinkSuggestions: [
                `Related guide on ${relatedQueries[0] || keyword}`,
                `Product page for ${keyword}`,
                `Compare ${keyword} options`,
            ],
            contentType: isCommercial ? 'comparison' : 'guide',
            tone: isCommercial ? 'commercial' : 'informational',
        };
    }
}

/**
 * Keyword Group Service
 *
 * CRUD for keyword groups and group-level aggregate metrics.
 * Groups organize tracked keywords into logical categories
 * (e.g. "Brand Terms", "Product Category", "Long-tail").
 */

import { prisma } from '../../utils/prisma';
import { Logger } from '../../utils/logger';

/** Max groups per account */
const MAX_GROUPS_PER_ACCOUNT = 20;

/** Group summary with aggregate metrics */
export interface KeywordGroupSummary {
    id: string;
    name: string;
    color: string;
    keywordCount: number;
    avgPosition: number | null;
    totalClicks: number;
    totalImpressions: number;
    avgCtr: number | null;
    createdAt: Date;
}

export class KeywordGroupService {

    /**
     * Create a new keyword group.
     */
    static async createGroup(accountId: string, name: string, color?: string): Promise<KeywordGroupSummary> {
        const trimmed = name.trim();
        if (!trimmed || trimmed.length > 100) {
            throw new Error('Group name must be 1-100 characters');
        }

        const count = await prisma.keywordGroup.count({ where: { accountId } });
        if (count >= MAX_GROUPS_PER_ACCOUNT) {
            throw new Error(`Maximum of ${MAX_GROUPS_PER_ACCOUNT} groups reached`);
        }

        const group = await prisma.keywordGroup.create({
            data: {
                accountId,
                name: trimmed,
                color: color || '#6366f1',
            },
            include: { keywords: { where: { isActive: true } } }
        });

        return mapGroupToSummary(group);
    }

    /**
     * Update group name/color.
     */
    static async updateGroup(accountId: string, groupId: string, data: { name?: string; color?: string }): Promise<KeywordGroupSummary> {
        const group = await prisma.keywordGroup.update({
            where: { id: groupId, accountId },
            data: {
                ...(data.name && { name: data.name.trim() }),
                ...(data.color && { color: data.color }),
            },
            include: { keywords: { where: { isActive: true } } }
        });

        return mapGroupToSummary(group);
    }

    /**
     * Delete a group (keywords are unassigned, not deleted).
     */
    static async deleteGroup(accountId: string, groupId: string): Promise<void> {
        await prisma.keywordGroup.deleteMany({
            where: { id: groupId, accountId }
        });
    }

    /**
     * List all groups with aggregate metrics.
     */
    static async listGroups(accountId: string): Promise<KeywordGroupSummary[]> {
        const groups = await prisma.keywordGroup.findMany({
            where: { accountId },
            include: { keywords: { where: { isActive: true } } },
            orderBy: { name: 'asc' }
        });

        return groups.map(mapGroupToSummary);
    }

    /**
     * Assign a keyword to a group.
     */
    static async assignKeyword(accountId: string, keywordId: string, groupId: string | null): Promise<void> {
        // Verify group belongs to account (if not null)
        if (groupId) {
            const group = await prisma.keywordGroup.findFirst({
                where: { id: groupId, accountId }
            });
            if (!group) throw new Error('Group not found');
        }

        await prisma.trackedKeyword.updateMany({
            where: { id: keywordId, accountId },
            data: { groupId }
        });
    }

    /**
     * Bulk assign keywords to a group.
     */
    static async bulkAssign(accountId: string, keywordIds: string[], groupId: string | null): Promise<number> {
        if (groupId) {
            const group = await prisma.keywordGroup.findFirst({
                where: { id: groupId, accountId }
            });
            if (!group) throw new Error('Group not found');
        }

        const result = await prisma.trackedKeyword.updateMany({
            where: { id: { in: keywordIds }, accountId },
            data: { groupId }
        });

        return result.count;
    }
}

/** Map Prisma group + keywords to summary with metrics */
function mapGroupToSummary(group: any): KeywordGroupSummary {
    const keywords = group.keywords || [];
    const withPosition = keywords.filter((k: any) => k.currentPosition && k.currentPosition > 0);

    const totalClicks = keywords.reduce((sum: number, k: any) => sum + (k.currentClicks || 0), 0);
    const totalImpressions = keywords.reduce((sum: number, k: any) => sum + (k.currentImpressions || 0), 0);

    return {
        id: group.id,
        name: group.name,
        color: group.color,
        keywordCount: keywords.length,
        avgPosition: withPosition.length > 0
            ? Math.round((withPosition.reduce((sum: number, k: any) => sum + k.currentPosition, 0) / withPosition.length) * 10) / 10
            : null,
        totalClicks,
        totalImpressions,
        avgCtr: totalImpressions > 0 ? Math.round((totalClicks / totalImpressions) * 10000) / 100 : null,
        createdAt: group.createdAt,
    };
}

/**
 * Keyword Revenue Attribution Service
 *
 * Correlates tracked keywords with revenue by matching:
 * 1. AnalyticsSessions with Google organic referrer
 * 2. Landing page paths matching keyword targetUrl
 * 3. Purchase events from those sessions
 *
 * Updates TrackedKeyword.estimatedRevenue during the daily refresh cycle.
 */

import { prisma } from '../../utils/prisma';
import { Logger } from '../../utils/logger';

/** Revenue attribution result for a single keyword */
export interface KeywordRevenueAttribution {
    keywordId: string;
    keyword: string;
    targetUrl: string | null;
    sessions: number;
    conversions: number;
    estimatedRevenue: number;
}

export class KeywordRevenueService {

    /**
     * Calculate and update revenue attribution for all tracked keywords.
     * Called during the daily keyword refresh cycle.
     *
     * Strategy:
     * - Find AnalyticsSessions from Google organic traffic (referrer contains 'google')
     * - Match sessions whose landing pages (first pageview URL) contain the keyword's targetUrl path
     * - Sum up purchase event revenue from those sessions
     * - For keywords without a targetUrl, match based on search query parameters in the URL
     */
    static async refreshRevenueAttribution(accountId: string): Promise<number> {
        const keywords = await prisma.trackedKeyword.findMany({
            where: { accountId, isActive: true }
        });

        if (keywords.length === 0) return 0;

        // Get the last 30 days of analytics sessions from Google organic
        const thirtyDaysAgo = new Date();
        thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

        const organicSessions = await prisma.analyticsSession.findMany({
            where: {
                accountId,
                createdAt: { gte: thirtyDaysAgo },
                OR: [
                    { referrer: { contains: 'google', mode: 'insensitive' } },
                    { utmSource: { contains: 'google', mode: 'insensitive' } },
                    { firstTouchSource: { contains: 'google', mode: 'insensitive' } },
                ],
            },
            include: {
                events: {
                    where: {
                        type: { in: ['pageview', 'purchase'] }
                    },
                    orderBy: { createdAt: 'asc' }
                }
            }
        });

        if (organicSessions.length === 0) {
            Logger.debug('No Google organic sessions found for revenue attribution', { accountId });
            return 0;
        }

        let updated = 0;
        const ops: any[] = [];

        for (const kw of keywords) {
            let revenue = 0;
            let sessions = 0;
            let conversions = 0;

            for (const session of organicSessions) {
                const pageviews = session.events.filter(e => e.type === 'pageview');
                const purchases = session.events.filter(e => e.type === 'purchase');

                if (pageviews.length === 0) continue;

                // Check if this session's landing page matches the keyword's target URL
                let isMatch = false;

                if (kw.targetUrl) {
                    // Extract path from targetUrl for comparison
                    const targetPath = extractPath(kw.targetUrl);
                    isMatch = pageviews.some(pv => {
                        const pvPath = extractPath(pv.url);
                        return pvPath.includes(targetPath) || targetPath.includes(pvPath);
                    });
                } else {
                    // Without targetUrl, check if the keyword appears in any pageview URL
                    const kwSlug = kw.keyword.replace(/\s+/g, '-').toLowerCase();
                    isMatch = pageviews.some(pv => {
                        const pvUrl = pv.url.toLowerCase();
                        return pvUrl.includes(kwSlug) || pvUrl.includes(kw.keyword.replace(/\s+/g, '+'));
                    });
                }

                if (isMatch) {
                    sessions++;
                    for (const purchase of purchases) {
                        const payload = purchase.payload as any;
                        if (payload?.revenue || payload?.total) {
                            revenue += parseFloat(String(payload.revenue || payload.total)) || 0;
                            conversions++;
                        }
                    }
                }
            }

            // Only update if we have data (don't zero out existing values when there's no traffic)
            if (sessions > 0) {
                ops.push(prisma.trackedKeyword.update({
                    where: { id: kw.id },
                    data: { estimatedRevenue: Math.round(revenue * 100) / 100 }
                }));
                updated++;
            }
        }

        if (ops.length > 0) {
            await prisma.$transaction(ops);
        }

        Logger.info('Keyword revenue attribution refreshed', { accountId, updated });
        return updated;
    }

    /**
     * Get revenue attribution for all tracked keywords (read-only, from denormalized data).
     */
    static async getRevenueReport(accountId: string): Promise<KeywordRevenueAttribution[]> {
        const keywords = await prisma.trackedKeyword.findMany({
            where: { accountId, isActive: true, estimatedRevenue: { gt: 0 } },
            orderBy: { estimatedRevenue: 'desc' }
        });

        return keywords.map(kw => ({
            keywordId: kw.id,
            keyword: kw.keyword,
            targetUrl: kw.targetUrl,
            sessions: 0, // Would need to re-query for live session count
            conversions: 0,
            estimatedRevenue: kw.estimatedRevenue ?? 0,
        }));
    }
}

/**
 * Extract URL path, removing protocol and domain.
 */
function extractPath(url: string): string {
    try {
        const parsed = new URL(url.startsWith('http') ? url : `https://${url}`);
        return parsed.pathname.replace(/\/+$/, '').toLowerCase();
    } catch {
        // Fallback: treat the whole thing as a path
        return url.replace(/^https?:\/\/[^/]+/, '').replace(/\/+$/, '').toLowerCase();
    }
}

/**
 * SEO Digest Service
 *
 * Generates a weekly SEO performance digest by aggregating data from:
 * - Search Console (impressions, clicks, position changes)
 * - Tracked keywords (rank movements, new entries/exits)
 * - Competitor analysis (gap changes)
 * - Revenue attribution (keyword-driven revenue)
 *
 * Can be consumed via API preview or sent as a scheduled email.
 */

import { prisma } from '../../utils/prisma';
import { Logger } from '../../utils/logger';
import { SearchConsoleService } from './SearchConsoleService';

/** SEO Digest sections */
export interface SeoDigest {
    generatedAt: string;
    period: { start: string; end: string };
    summary: {
        totalClicks: number;
        totalImpressions: number;
        avgPosition: number;
        clicksChange: number;       // vs previous period
        impressionsChange: number;
        positionChange: number;     // positive = improved
    };
    topMovers: {
        improved: Array<{ keyword: string; oldPosition: number; newPosition: number; delta: number }>;
        declined: Array<{ keyword: string; oldPosition: number; newPosition: number; delta: number }>;
    };
    topKeywords: Array<{
        keyword: string;
        clicks: number;
        impressions: number;
        position: number;
        estimatedRevenue: number;
    }>;
    newKeywords: Array<{ keyword: string; position: number; impressions: number }>;
    alerts: string[];
}

export class SeoDigestService {

    /**
     * Generate a full SEO digest for the account.
     * Covers the last 7 days vs the previous 7 days.
     */
    static async generateDigest(accountId: string): Promise<SeoDigest> {
        const now = new Date();
        const endDate = new Date(now);
        endDate.setDate(endDate.getDate() - 3); // SC data lag
        const startDate = new Date(endDate);
        startDate.setDate(startDate.getDate() - 7);
        const prevEnd = new Date(startDate);
        const prevStart = new Date(prevEnd);
        prevStart.setDate(prevStart.getDate() - 7);

        // Fetch current and previous period data
        const [current, previous] = await Promise.all([
            SearchConsoleService.getSearchAnalytics(accountId, {
                startDate: formatDate(startDate),
                endDate: formatDate(endDate),
                rowLimit: 1000,
            }),
            SearchConsoleService.getSearchAnalytics(accountId, {
                startDate: formatDate(prevStart),
                endDate: formatDate(prevEnd),
                rowLimit: 1000,
            }),
        ]);

        // Compute aggregate metrics
        const currentTotals = aggregateMetrics(current);
        const previousTotals = aggregateMetrics(previous);

        // Build previous period lookup
        const prevMap = new Map(previous.map(q => [q.query, q]));
        const currMap = new Map(current.map(q => [q.query, q]));

        // Find top movers
        const improved: SeoDigest['topMovers']['improved'] = [];
        const declined: SeoDigest['topMovers']['declined'] = [];
        const newKeywords: SeoDigest['newKeywords'] = [];

        for (const q of current) {
            const prev = prevMap.get(q.query);
            if (!prev) {
                if (q.impressions > 5) {
                    newKeywords.push({ keyword: q.query, position: q.position, impressions: q.impressions });
                }
                continue;
            }

            const delta = Math.round((prev.position - q.position) * 10) / 10;
            if (delta >= 3) {
                improved.push({ keyword: q.query, oldPosition: prev.position, newPosition: q.position, delta });
            } else if (delta <= -3) {
                declined.push({ keyword: q.query, oldPosition: prev.position, newPosition: q.position, delta: Math.abs(delta) });
            }
        }

        improved.sort((a, b) => b.delta - a.delta);
        declined.sort((a, b) => b.delta - a.delta);
        newKeywords.sort((a, b) => b.impressions - a.impressions);

        // Get tracked keywords with revenue for top keywords section
        const trackedKeywords = await prisma.trackedKeyword.findMany({
            where: { accountId, isActive: true },
            orderBy: { currentClicks: 'desc' },
            take: 10,
        });

        const topKeywords = trackedKeywords.map(kw => ({
            keyword: kw.keyword,
            clicks: kw.currentClicks ?? 0,
            impressions: kw.currentImpressions ?? 0,
            position: kw.currentPosition ?? 0,
            estimatedRevenue: kw.estimatedRevenue ?? 0,
        }));

        // Generate alerts
        const alerts: string[] = [];
        if (currentTotals.totalClicks < previousTotals.totalClicks * 0.8) {
            alerts.push(`⚠️ Organic clicks dropped by ${Math.round((1 - currentTotals.totalClicks / (previousTotals.totalClicks || 1)) * 100)}% this week`);
        }
        if (declined.length > improved.length * 2) {
            alerts.push(`⚠️ More keywords declining (${declined.length}) than improving (${improved.length})`);
        }
        if (newKeywords.length > 5) {
            alerts.push(`✅ ${newKeywords.length} new keywords appeared in search results`);
        }
        if (improved.length > 5) {
            alerts.push(`✅ ${improved.length} keywords improved position by 3+ places`);
        }

        return {
            generatedAt: now.toISOString(),
            period: { start: formatDate(startDate), end: formatDate(endDate) },
            summary: {
                totalClicks: currentTotals.totalClicks,
                totalImpressions: currentTotals.totalImpressions,
                avgPosition: currentTotals.avgPosition,
                clicksChange: currentTotals.totalClicks - previousTotals.totalClicks,
                impressionsChange: currentTotals.totalImpressions - previousTotals.totalImpressions,
                positionChange: Math.round((previousTotals.avgPosition - currentTotals.avgPosition) * 10) / 10,
            },
            topMovers: {
                improved: improved.slice(0, 10),
                declined: declined.slice(0, 10),
            },
            topKeywords,
            newKeywords: newKeywords.slice(0, 10),
            alerts,
        };
    }
}

/** Aggregate clicks, impressions, and average position */
function aggregateMetrics(rows: Array<{ clicks: number; impressions: number; position: number }>) {
    if (rows.length === 0) return { totalClicks: 0, totalImpressions: 0, avgPosition: 0 };

    const totalClicks = rows.reduce((s, r) => s + r.clicks, 0);
    const totalImpressions = rows.reduce((s, r) => s + r.impressions, 0);
    const avgPosition = Math.round((rows.reduce((s, r) => s + r.position, 0) / rows.length) * 10) / 10;

    return { totalClicks, totalImpressions, avgPosition };
}

/** Format Date to YYYY-MM-DD */
function formatDate(d: Date): string {
    return d.toISOString().split('T')[0];
}

import { esClient, isElasticsearchAvailable } from '../../utils/elastic';
import { Logger } from '../../utils/logger';

export class IndexingService {

    private static async createIndexIfNotExists(indexName: string, mapping: any) {
        try {
            const exists = await esClient.indices.exists({ index: indexName });
            if (!exists) {
                try {
                    await esClient.indices.create({
                        index: indexName,
                        settings: (mapping as any).settings || {},
                        mappings: { properties: (mapping as any).properties || mapping }
                    });
                    Logger.info(`Elasticsearch index '${indexName}' created.`);
                } catch (createError: any) {
                    // Race condition: another process created the index between our exists check and create call
                    if (createError.meta?.body?.error?.type === 'resource_already_exists_exception') {
                        Logger.info(`Index '${indexName}' was created by another process, skipping.`);
                    } else {
                        throw createError;
                    }
                }
            } else {
                try {
                    // Update settings for existing index
                    if ((mapping as any).settings) {
                        await esClient.indices.putSettings({
                            index: indexName,
                            settings: (mapping as any).settings
                        });
                    }
                    // Update mapping for existing index (merge new fields)
                    await esClient.indices.putMapping({
                        index: indexName,
                        properties: (mapping as any).properties || mapping
                    });
                    Logger.info(`Updated mapping for existing index '${indexName}'`);
                } catch (mappingError: any) {
                    // If mapping update fails due to type conflict, recreate the index
                    if (mappingError.message?.includes('cannot be changed from type') ||
                        mappingError.meta?.body?.error?.type === 'illegal_argument_exception') {

                        Logger.warn(`Mapping conflict detected for index '${indexName}'. Recreating index...`, { error: mappingError.message });

                        await esClient.indices.delete({ index: indexName });
                        await esClient.indices.create({
                            index: indexName,
                            settings: (mapping as any).settings || {},
                            mappings: { properties: (mapping as any).properties || mapping }
                        });
                        Logger.info(`Recreated index '${indexName}' with new mapping.`);
                    } else {
                        throw mappingError;
                    }
                }
            }
        } catch (error: any) {
            Logger.error(`Failed to create/update index ${indexName}`, { error: error.message });
        }
    }

    static async initializeIndices() {
        Logger.info('Initializing Elasticsearch indices...');
        const commonSettings = { number_of_shards: 1, number_of_replicas: 0 };

        // 1. Customers
        await this.createIndexIfNotExists('customers', {
            settings: {
                max_result_window: 50000
            },
            properties: {
                accountId: { type: 'keyword' },
                id: { type: 'keyword' },
                email: { type: 'keyword' },
                firstName: { type: 'text', fields: { keyword: { type: 'keyword' } } },
                lastName: { type: 'text', fields: { keyword: { type: 'keyword' } } },
                totalSpent: { type: 'float' },
                ordersCount: { type: 'integer' },
                dateCreated: { type: 'date' }
            }
        });

        // 2. Products
        await this.createIndexIfNotExists('products', {
            settings: {
                max_result_window: 50000
            },
            properties: {
                accountId: { type: 'keyword' },
                id: { type: 'keyword' },
                wooId: { type: 'integer' },
                name: { type: 'text' },
                sku: { type: 'keyword' },
                stock_status: { type: 'keyword' },
                stock_quantity: { type: 'integer' },
                low_stock_amount: { type: 'integer' },
                price: { type: 'float' },
                date_created: { type: 'date' },
                mainImage: { type: 'keyword' },
                images: { type: 'nested', properties: { src: { type: 'keyword' } } },
                categories: { type: 'nested', properties: { name: { type: 'keyword' } } },
                seoScore: { type: 'integer' },
                merchantCenterScore: { type: 'integer' },
                cogs: { type: 'float' },
                type: { type: 'keyword' }
            }
        });

        // 3. Orders
        await this.createIndexIfNotExists('orders', {
            settings: {
                max_result_window: 50000
            },
            properties: {
                accountId: { type: 'keyword' },
                id: { type: 'keyword' },
                status: { type: 'keyword' },
                total: { type: 'float' },
                total_tax: { type: 'float' },
                net_sales: { type: 'float' },
                currency: { type: 'keyword' },
                date_created: { type: 'date' },
                tags: { type: 'keyword' },
                billing: { properties: { first_name: { type: 'text' }, last_name: { type: 'text' }, email: { type: 'keyword' } } },
                line_items: {
                    type: 'nested',
                    properties: {
                        name: { type: 'text', fields: { keyword: { type: 'keyword' } } },
                        sku: { type: 'keyword' },
                        productId: { type: 'keyword' },
                        variationId: { type: 'keyword' },
                        quantity: { type: 'integer' },
                        total: { type: 'float' },
                        total_tax: { type: 'float' },
                        net_total: { type: 'float' },
                        meta_data: {
                            type: 'nested',
                            properties: { key: { type: 'keyword' }, value: { type: 'text' } }
                        }
                    }
                },
            }
        });

        // 4. Ad Spend
        await this.createIndexIfNotExists('ad_spend', {
            settings: {
                max_result_window: 50000
            },
            properties: {
                accountId: { type: 'keyword' },
                spend: { type: 'float' },
                impressions: { type: 'integer' },
                clicks: { type: 'integer' },
                roas: { type: 'float' },
                currency: { type: 'keyword' },
                date_start: { type: 'date' },
                date_stop: { type: 'date' }
            }
        });

        // 5. Reviews
        await this.createIndexIfNotExists('reviews', {
            settings: {
                max_result_window: 50000
            },
            properties: {
                accountId: { type: 'keyword' },
                id: { type: 'keyword' },
                productId: { type: 'keyword' },
                productName: { type: 'text' },
                reviewer: { type: 'text' },
                rating: { type: 'integer' },
                content: { type: 'text' },
                status: { type: 'keyword' },
                dateCreated: { type: 'date' }
            }
        });

        Logger.info('Elasticsearch indices initialization complete.');
    }

    static async indexCustomer(accountId: string, customer: any, refresh: boolean = true) {
        await esClient.index({
            index: 'customers',
            id: `${accountId}_${customer.id}`,
            document: {
                accountId,
                id: customer.id,
                email: customer.email,
                firstName: customer.first_name,
                lastName: customer.last_name,
                totalSpent: parseFloat(customer.total_spent || '0'),
                ordersCount: customer.orders_count || 0,
                dateCreated: customer.date_created
            },
            refresh
        });
    }

    static async indexProduct(accountId: string, product: any, refresh: boolean = true) {
        // Handle both Prisma object (camelCase) and raw Woo object (snake_case)
        const rawData = product.rawData || product;

        await esClient.index({
            index: 'products',
            id: `${accountId}_${product.id}`,
            document: {
                accountId,
                id: product.id,
                wooId: product.wooId || product.id,
                name: product.name,
                sku: product.sku,
                stock_status: product.stockStatus || product.stock_status,
                stock_quantity: product.stockQuantity ?? product.stock_quantity ?? null,
                low_stock_amount: product.low_stock_amount ?? 5,
                price: parseFloat(product.price?.toString() || '0'),
                date_created: product.createdAt || product.date_created,
                mainImage: product.mainImage || product.images?.[0]?.src || null,
                images: (Array.isArray(product.images) ? product.images : rawData.images)?.map((img: any) => ({ src: img.src })) || [],
                categories: rawData.categories?.map((cat: any) => ({ name: cat.name })) || [],
                seoScore: product.seoScore || 0,
                merchantCenterScore: product.merchantCenterScore || 0,
                cogs: product.cogs ? parseFloat(product.cogs.toString()) : 0,
                type: rawData.type || 'simple',
                variations: product.variations?.map((v: any) => ({
                    id: v.id,
                    stock_status: v.stockStatus || v.stock_status,
                    stock_quantity: v.stockQuantity ?? v.stock_quantity ?? null,
                    price: parseFloat(v.price?.toString() || '0'),
                    sku: v.sku
                })) || []
            },
            refresh
        });
    }

    static async indexOrder(accountId: string, order: any, tags: string[] = [], refresh: boolean = true) {
        await esClient.index({
            index: 'orders',
            id: `${accountId}_${order.id}`,
            document: {
                accountId,
                id: order.id,
                status: order.status.toLowerCase(),
                total: parseFloat(order.total),
                total_tax: parseFloat(order.total_tax || '0'),
                net_sales: parseFloat(order.total) - parseFloat(order.total_tax || '0'),
                currency: order.currency,
                date_created: IndexingService.formatDateToUTC(order.date_created_gmt || order.date_created),
                payment_method_title: order.payment_method_title || '',
                customer_id: order.customer_id || 0,
                tags: tags || [],
                billing: order.billing,
                line_items: order.line_items?.map((item: any) => ({
                    name: item.name,
                    sku: item.sku,
                    productId: item.product_id,
                    variationId: item.variation_id || 0,
                    quantity: item.quantity,
                    total: parseFloat(item.total || '0') + parseFloat(item.total_tax || '0'),
                    total_tax: parseFloat(item.total_tax || '0'),
                    net_total: parseFloat(item.total || '0'),
                    meta_data: item.meta_data?.map((m: any) => ({
                        key: m.key,
                        value: typeof m.value === 'string' ? m.value : JSON.stringify(m.value)
                    })) || []
                })) || [],
                meta_data: order.meta_data?.map((m: any) => ({
                    key: m.key,
                    value: typeof m.value === 'string' ? m.value : JSON.stringify(m.value)
                })) || []
            },
            refresh
        });
    }

    static async indexReview(accountId: string, review: any, refresh: boolean = true) {
        await esClient.index({
            index: 'reviews',
            id: `${accountId}_${review.id}`,
            document: {
                accountId,
                id: review.id,
                productId: review.product_id,
                productName: review.product_name,
