            }
        }
    }

    static async deleteAccountData(accountId: string) {
        Logger.info(`Deleting Elasticsearch data for account ${accountId}...`);
        const indices = ['customers', 'products', 'orders', 'reviews', 'ad_spend'];

        for (const index of indices) {
            try {
                const exists = await esClient.indices.exists({ index });
                if (exists) {
                    await esClient.deleteByQuery({
                        index,
                        query: {
                            term: { accountId: accountId }
                        },
                        refresh: true
                    });
                }
            } catch (error: any) {
                Logger.error(`Failed to delete data from index ${index} for account ${accountId}`, { error: error.message });
            }
        }

        // Failsafe Verification
        let remainingDocs = 0;
        for (const index of indices) {
            try {
                const exists = await esClient.indices.exists({ index });
                if (exists) {
                    const { count } = await esClient.count({
                        index,
                        query: {
                            term: { accountId: accountId }
                        }
                    });
                    if (count > 0) {
                        remainingDocs += count;
                        Logger.warn(`Failsafe Warning: ${count} documents remain in ${index} for account ${accountId} after deletion query.`);
                    }
                }
            } catch (e) { /* ignore check error */ }
        }

        if (remainingDocs === 0) {
            Logger.info(`Successfully verified deletion of all ES data for account ${accountId}.`);
        }
    }

    private static formatDateToUTC(dateString: string): string {
        if (!dateString) return new Date().toISOString();
        // If it already ends in Z, assume it's UTC
        if (dateString.endsWith('Z')) return dateString;
        // Otherwise, append Z to force UTC interpretation for GMT strings
        return `${dateString}Z`;
    }
}

import { BaseSync, SyncResult } from './BaseSync';
import { WooService } from '../woo';
import { prisma } from '../../utils/prisma';
import { IndexingService } from '../search/IndexingService';
import { Logger } from '../../utils/logger';
import { WooCustomerSchema, WooCustomer } from './wooSchemas';


export class CustomerSync extends BaseSync {
    protected entityType = 'customers';

    protected async sync(woo: WooService, accountId: string, incremental: boolean, job?: any, syncId?: string): Promise<SyncResult> {
        const after = incremental ? await this.getLastSync(accountId) : undefined;
        let page = 1;
        let hasMore = true;
        let totalProcessed = 0;
        let totalDeleted = 0;
        let totalSkipped = 0;

        const syncStartedAt = new Date();

        while (hasMore) {
            // Optimized: Increased page size from 25 to 100 for fewer API round-trips
            const { data: rawCustomers, totalPages } = await woo.getCustomers({ page, after, per_page: 100 });
            if (!rawCustomers.length) {
                hasMore = false;
                break;
            }

            // Validate customers with Zod schema
            const customers: WooCustomer[] = [];
            for (const raw of rawCustomers) {
                const result = WooCustomerSchema.safeParse(raw);
                if (result.success) {
                    customers.push(result.data);
                } else {
                    totalSkipped++;
                    Logger.debug(`Skipping invalid customer`, {
                        accountId, syncId, customerId: raw?.id,
                        errors: result.error.issues.map(i => i.message).slice(0, 3)
                    });
                }
            }

            if (!customers.length) {
                page++;
                continue;
            }

            // Optimized: Batch upserts in transactions of 50 for better throughput
            const BATCH_SIZE = 50;
            const failedWooIds: number[] = [];
            for (let i = 0; i < customers.length; i += BATCH_SIZE) {
                const batch = customers.slice(i, i + BATCH_SIZE);

                // Execute batch upserts concurrently (no transaction — each upsert is idempotent)
                await Promise.all(
                    batch.map((c) =>
                        prisma.wooCustomer.upsert({
                            where: { accountId_wooId: { accountId, wooId: c.id } },
                            update: {
                                totalSpent: c.total_spent ?? 0,
                                ordersCount: c.orders_count ?? 0,
                                rawData: c as any
                            },
                            create: {
                                accountId,
                                wooId: c.id,
                                email: c.email,
                                firstName: c.first_name,
                                lastName: c.last_name,
                                totalSpent: c.total_spent ?? 0,
                                ordersCount: c.orders_count ?? 0,
                                rawData: c as any
                            }
                        }).catch((err) => {
                            totalSkipped++;
                            failedWooIds.push(c.id);
                            Logger.warn('Failed to upsert customer', {
                                accountId, syncId, wooId: c.id, error: err.message
                            });
                        })
                    )
                );
            }

            // Preserve existing records that failed to upsert (transient DB errors)
            // so updatedAt-based reconciliation doesn't delete them
            if (failedWooIds.length > 0) {
                await prisma.$executeRawUnsafe(
                    `UPDATE "WooCustomer" SET "updatedAt" = NOW() WHERE "accountId" = $1 AND "wooId" = ANY($2::int[])`,
                    accountId, failedWooIds
                );
            }

            // Bulk index all customers in one ES call
            try {
                await IndexingService.bulkIndexCustomers(accountId, customers);
            } catch (error: any) {
                Logger.warn('Bulk index customers failed', { accountId, syncId, error: error.message });
            }
            totalProcessed += customers.length;

            Logger.info(`Synced batch of ${customers.length} customers`, { accountId, syncId, page, totalPages });
            // Use WooCommerce's x-wp-totalpages header instead of batch size
            // (batch size is unreliable when Zod validation skips records from a full page)
            if (page >= totalPages) hasMore = false;

            if (job) {
                const progress = totalPages > 0 ? Math.round((page / totalPages) * 100) : 100;
                await job.updateProgress(progress);
                if (!(await job.isActive())) throw new Error('Cancelled');
            }

            page++;

            // Throttle API pagination to avoid overwhelming the WooCommerce store
            if (hasMore) await new Promise(r => setTimeout(r, 500));
        }

        // Reconciliation: remove customers not touched during this full sync.
        // Count-first pattern: evaluate the 30% safety cap via SQL count() rather
        // than loading every stale wooId into Node memory.
        if (!incremental && totalProcessed > 0) {
            const staleCount = await prisma.wooCustomer.count({
                where: { accountId, updatedAt: { lt: syncStartedAt } }
            });

            if (staleCount > 0) {
                const localTotal = await prisma.wooCustomer.count({ where: { accountId } });
                const maxDeletions = Math.max(10, Math.floor(localTotal * 0.3));

                if (staleCount > maxDeletions) {
                    Logger.warn(`Customer reconciliation aborted: would delete ${staleCount}/${localTotal} (>30% cap)`, {
                        accountId, syncId, toDelete: staleCount, localTotal
                    });
                } else {
                    // Stream ES deletions in chunks so we never hold the full ID list.
                    const ES_DELETE_CHUNK = 500;
                    let cursor: string | undefined;
                    while (true) {
                        const chunk: { id: string; wooId: number }[] = await prisma.wooCustomer.findMany({
                            where: { accountId, updatedAt: { lt: syncStartedAt } },
                            select: { id: true, wooId: true },
                            orderBy: { id: 'asc' },
                            take: ES_DELETE_CHUNK,
                            ...(cursor ? { cursor: { id: cursor }, skip: 1 } : {})
                        });
                        if (chunk.length === 0) break;
                        await Promise.allSettled(
                            chunk.map(c => IndexingService.deleteCustomer(accountId, c.wooId).catch(() => { }))
                        );
                        cursor = chunk[chunk.length - 1].id;
                        if (chunk.length < ES_DELETE_CHUNK) break;
                    }

                    const { count } = await prisma.wooCustomer.deleteMany({
                        where: { accountId, updatedAt: { lt: syncStartedAt } }
                    });
                    totalDeleted = count;
                    Logger.info(`Reconciliation: Deleted ${totalDeleted} orphaned customers`, { accountId, syncId });
                }
            }
        }
        // --- Auto-Link: Link guest conversations to newly synced customers ---
        // Find guest conversations where guestEmail matches a WooCustomer email
        const linkedCount = await this.linkGuestConversationsToCustomers(accountId);
        if (linkedCount > 0) {
            Logger.info(`Auto-linked ${linkedCount} guest conversations to customers`, { accountId, syncId });
        }

        return { itemsProcessed: totalProcessed, itemsDeleted: totalDeleted };
    }

    /**
     * Auto-link guest conversations to WooCommerce customers by matching email addresses.
     * @returns Number of conversations linked
     */
    private async linkGuestConversationsToCustomers(accountId: string): Promise<number> {
        // Find guest conversations (no wooCustomerId, but has guestEmail)
        const guestConversations = await prisma.conversation.findMany({
            where: {
                accountId,
                wooCustomerId: null,
                guestEmail: { not: null }
            },
            select: { id: true, guestEmail: true }
        });

        if (guestConversations.length === 0) return 0;

        // Build a map of email -> conversations
        const emailToConvs = new Map<string, string[]>();
        for (const conv of guestConversations) {
            if (!conv.guestEmail) continue;
            const email = conv.guestEmail.toLowerCase();
            if (!emailToConvs.has(email)) {
                emailToConvs.set(email, []);
            }
            emailToConvs.get(email)!.push(conv.id);
        }

        // Find matching customers
        const emails = Array.from(emailToConvs.keys());
        const matchingCustomers = await prisma.wooCustomer.findMany({
            where: {
                accountId,
                email: { in: emails, mode: 'insensitive' }
            },
            select: { id: true, email: true }
        });

        let linkedCount = 0;
        for (const customer of matchingCustomers) {
            const convIds = emailToConvs.get(customer.email.toLowerCase());
            if (!convIds || convIds.length === 0) continue;

            // Update all matching conversations
            await prisma.conversation.updateMany({
                where: { id: { in: convIds } },
                data: {
                    wooCustomerId: customer.id,
                    guestEmail: null,
                    guestName: null
                }
            });
            linkedCount += convIds.length;
        }

        return linkedCount;
    }
}

import { BaseSync, SyncResult } from './BaseSync';
import { WooService } from '../woo';
import { prisma } from '../../utils/prisma';
import { EventBus, EVENTS } from '../events';
import { Logger } from '../../utils/logger';
import { IndexingService } from '../search/IndexingService';
import { WooReviewSchema, WooReview } from './wooSchemas';
import { Prisma } from '@prisma/client';


/**
 * Lightweight order projection for review matching.
 * Only the fields needed for scoring — excludes the full rawData blob
 * which is 10-50KB per order and caused the OOM crash.
 */
interface LightweightOrder {
    id: string;
    number: string;
    dateCreated: Date;
    customerId: number | null;
    billingEmail: string | null;
    billingFirst: string | null;
    billingLast: string | null;
    lineItems: Array<{ product_id: number; variation_id?: number }>;
}

interface OrderMatchResult {
    orderId: string;
    orderNumber: string;
    score: number;
    daysDiff: number;
}

/**
 * Normalizes email for comparison: lowercase, trim, remove + addressing.
 */
function normalizeEmail(email: string | null | undefined): string | null {
    if (!email) return null;
    const trimmed = email.trim().toLowerCase();
    const atIndex = trimmed.indexOf('@');
    if (atIndex === -1) return trimmed;
    const localPart = trimmed.substring(0, atIndex);
    const domain = trimmed.substring(atIndex);
    const plusIndex = localPart.indexOf('+');
    if (plusIndex !== -1) {
        return localPart.substring(0, plusIndex) + domain;
    }
    return trimmed;
}

/**
 * Compares reviewer name against order billing name.
 */
function namesMatch(reviewerName: string, billingFirst: string | undefined, billingLast: string | undefined): boolean {
    if (!reviewerName) return false;
    const normalizedReviewer = reviewerName.toLowerCase().trim();
    const fullBilling = `${billingFirst || ''} ${billingLast || ''}`.toLowerCase().trim();

    if (normalizedReviewer === fullBilling) return true;

    const first = (billingFirst || '').toLowerCase().trim();
    const last = (billingLast || '').toLowerCase().trim();
    if (first && last && normalizedReviewer.includes(first) && normalizedReviewer.includes(last)) {
        return true;
    }

    const reviewerParts = normalizedReviewer.split(/\s+/);
    if (last && reviewerParts.some(part => part === last)) {
        return true;
    }

    return false;
}


export class ReviewSync extends BaseSync {
    protected entityType = 'reviews';

    protected async sync(woo: WooService, accountId: string, incremental: boolean, job?: any, syncId?: string): Promise<SyncResult> {
        const after = incremental ? await this.getLastSync(accountId) : undefined;
        let page = 1;
        let hasMore = true;
        let totalProcessed = 0;
        let totalDeleted = 0;
        let totalSkipped = 0;

        const syncStartedAt = new Date();

        while (hasMore) {
            const { data: rawReviews, totalPages } = await woo.getReviews({ page, after, per_page: 100 });
            if (!rawReviews.length) {
                hasMore = false;
                break;
            }

            // Validate reviews with Zod schema
            const reviews: WooReview[] = [];
            for (const raw of rawReviews) {
                const result = WooReviewSchema.safeParse(raw);
                if (result.success) {
                    reviews.push(result.data);
                } else {
                    totalSkipped++;
                    Logger.debug(`Skipping invalid review`, {
                        accountId, syncId, reviewId: raw?.id,
                        errors: result.error.issues.map(i => i.message).slice(0, 3)
                    });
                }
            }

            if (!reviews.length) {
                page++;
                continue;
            }

            // --- OOM FIX: Pre-fetch orders ONCE per batch with lightweight projection ---
            // Instead of querying all orders per review (N+1), compute the widest
            // date window across the entire batch and fetch matching orders once.
            const reviewDates = reviews.map(r => {
                const rd = r as any;
                return new Date(rd.date_created_gmt || r.date_created).getTime();
            });
            const batchLookback = new Date(Math.min(...reviewDates));
            batchLookback.setDate(batchLookback.getDate() - 180);
            const batchLatest = new Date(Math.max(...reviewDates));

            // Extract only matching-relevant fields from JSONB server-side.
            // This avoids deserializing the full rawData blob (~10-50KB/order).
            const batchOrders = await prisma.$queryRaw<LightweightOrder[]>`
                SELECT
                    id,
                    number,
                    "dateCreated",
                    COALESCE(("rawData"->>'customer_id')::int, 0) AS "customerId",
                    "rawData"->'billing'->>'email'      AS "billingEmail",
                    "rawData"->'billing'->>'first_name'  AS "billingFirst",
                    "rawData"->'billing'->>'last_name'   AS "billingLast",
                    COALESCE(
                        (
                            SELECT jsonb_agg(jsonb_build_object(
                                'product_id', (li->>'product_id')::int,
                                'variation_id', (li->>'variation_id')::int
                            ))
                            FROM jsonb_array_elements("rawData"->'line_items') AS li
                        ),
                        '[]'::jsonb
                    ) AS "lineItems"
                FROM "WooOrder"
                WHERE "accountId" = ${accountId}
                  AND "dateCreated" >= ${batchLookback}
                  AND "dateCreated" <= ${batchLatest}
                ORDER BY "dateCreated" DESC
            `;

            // Build product → orders index for O(1) lookup per review
            const productOrderIndex = new Map<number, LightweightOrder[]>();
            for (const order of batchOrders) {
                // line_items may come back as a JSON string from $queryRaw
                const items = typeof order.lineItems === 'string'
                    ? JSON.parse(order.lineItems)
                    : (order.lineItems || []);
                order.lineItems = items;
                for (const item of items) {
                    const pid = item.product_id;
                    if (pid) {
                        if (!productOrderIndex.has(pid)) productOrderIndex.set(pid, []);
                        productOrderIndex.get(pid)!.push(order);
                    }
                    const vid = item.variation_id;
                    if (vid && vid !== pid) {
                        if (!productOrderIndex.has(vid)) productOrderIndex.set(vid, []);
                        productOrderIndex.get(vid)!.push(order);
                    }
                }
            }

            // --- N+1 FIX: Batch-fetch customers by email ---
            const reviewerEmails = [...new Set(
                reviews
                    .map(r => (r as any).reviewer_email as string | undefined)
                    .filter((e): e is string => !!e)
            )];
            const batchCustomers = reviewerEmails.length > 0
                ? await prisma.wooCustomer.findMany({
                    where: { accountId, email: { in: reviewerEmails } },
                    select: { id: true, wooId: true, email: true }
                })
                : [];
            const customerByEmail = new Map<string, { id: string; wooId: number; email: string }>(
                batchCustomers.map(c => [c.email, c])
            );

            // --- N+1 FIX: Batch-check existing reviews for isRecent detection ---
            const batchWooIds = reviews.map(r => r.id);
            const existingReviews = await prisma.wooReview.findMany({
                where: { wooId: { in: batchWooIds }, accountId },
                select: { wooId: true }
            });
            const existingWooIds = new Set(existingReviews.map(r => r.wooId));

            for (const r of reviews) {
                const reviewData = r as any;
                const reviewerEmail = reviewData.reviewer_email;

                // 1. Find Customer (from pre-fetched batch)
                let wooCustomerId: string | null = null;
                let customerData: { id: string; wooId: number; email: string } | null = null;
                if (reviewerEmail) {
                    customerData = customerByEmail.get(reviewerEmail) || null;
                    if (customerData) wooCustomerId = customerData.id;
                }

                // 2. Find Order — use pre-fetched batch orders (OOM fix)
                let wooOrderId: string | null = null;
                const reviewDate = new Date(reviewData.date_created_gmt || r.date_created);
                const reviewLookback = new Date(reviewDate);
                reviewLookback.setDate(reviewLookback.getDate() - 180);

                // Get candidate orders via product index (O(1) lookup)
                const candidateOrders = productOrderIndex.get(r.product_id) || [];

                // Filter to the per-review time window
                const potentialOrders = candidateOrders.filter(o => {
                    const od = new Date(o.dateCreated).getTime();
                    return od >= reviewLookback.getTime() && od <= reviewDate.getTime();
                });

                // Find the best matching order
                const matches: OrderMatchResult[] = [];

                for (const order of potentialOrders) {
                    // Check customer/email/name match with tiered scoring
                    let matchScore = 0;
                    const normalizedOrderEmail = normalizeEmail(order.billingEmail);
                    const normalizedReviewerEmail = normalizeEmail(reviewerEmail);

                    // Priority 1: Exact WooCommerce customer ID match (score 100)
                    if (customerData) {
                        if (order.customerId === customerData.wooId) {
                            matchScore = 100;
                        } else if (normalizedOrderEmail === normalizeEmail(customerData.email)) {
                            matchScore = 90; // Email match via customer record
                        }
                    }

                    // Priority 2: Direct email match with normalization (score 80)
                    if (matchScore === 0 && normalizedReviewerEmail && normalizedOrderEmail === normalizedReviewerEmail) {
                        matchScore = 80;
                    }

                    // Priority 3: Name-based match fallback (score 60)
                    if (matchScore === 0 && r.reviewer && namesMatch(r.reviewer, order.billingFirst || undefined, order.billingLast || undefined)) {
                        matchScore = 60;
                    }

                    // Priority 4: Product-only match with tight temporal proximity (score 40)
                    if (matchScore === 0) {
                        const daysDiff = (reviewDate.getTime() - new Date(order.dateCreated).getTime()) / (1000 * 60 * 60 * 24);
                        if (daysDiff >= 7 && daysDiff <= 60) {
                            matchScore = 40;
                        }
                    }

                    if (matchScore > 0) {
                        const daysDiff = Math.abs(
                            (reviewDate.getTime() - new Date(order.dateCreated).getTime()) / (1000 * 60 * 60 * 24)
                        );
                        matches.push({
                            orderId: order.id,
                            orderNumber: order.number,
                            score: matchScore,
                            daysDiff
                        });
                    }
                }

                // Sort by score (highest first), then by date proximity (closest first)
                matches.sort((a, b) => {
                    if (b.score !== a.score) return b.score - a.score;
                    return a.daysDiff - b.daysDiff;
                });

                if (matches.length > 0) {
                    wooOrderId = matches[0].orderId;
                    Logger.debug(`Matched review ${r.id} to order ${matches[0].orderNumber}`, {
                        accountId,
                        syncId,
                        matchScore: matches[0].score,
                        daysDiff: matches[0].daysDiff.toFixed(1),
                        totalMatches: matches.length
                    });
                }

                // EDGE CASE: Track unmatched reviews for manual review
                // This helps identify reviews that couldn't be linked to customers/orders
                const matchStatus = wooOrderId ? 'matched' : 'unmatched';
                if (!wooCustomerId && reviewerEmail) {
                    Logger.debug('[ReviewSync] Orphaned review - no customer match', {
                        accountId,
                        syncId,
                        reviewId: r.id,
                        reviewerEmail,
                        reviewerName: r.reviewer,
                        productId: r.product_id,
                        productName: r.product_name
                    });
                }

                await prisma.wooReview.upsert({
                    where: { accountId_wooId: { accountId, wooId: r.id } },
                    update: {
                        status: r.status,
                        content: r.review,
                        rating: r.rating,
                        rawData: r as any,
                        reviewerEmail: reviewerEmail || null,
                        wooCustomerId,
                        wooOrderId,
                        matchStatus // Track match status for filtering
                    },
                    create: {
                        accountId,
                        wooId: r.id,
                        productId: r.product_id,
                        productName: r.product_name,
                        reviewer: r.reviewer,
                        rating: r.rating,
                        content: r.review,
                        status: r.status,
                        // Use date_created_gmt for accurate UTC timestamp
                        dateCreated: new Date((r as any).date_created_gmt || r.date_created),
                        rawData: r as any,
                        reviewerEmail: reviewerEmail || null,
                        wooCustomerId,
                        wooOrderId,
                        matchStatus // Track match status for filtering
                    }
                });

                // Emit Event
                EventBus.emit(EVENTS.REVIEW.SYNCED, { accountId, review: r });

                // Detect "Review Left" for triggers
                const isRecent = (new Date().getTime() - reviewDate.getTime()) < 24 * 60 * 60 * 1000;

                if (isRecent && !existingWooIds.has(r.id)) {
                    EventBus.emit(EVENTS.REVIEW.LEFT, { accountId, review: r });
                }

                totalProcessed++;
            }

            // Bulk index all reviews in one ES call (like CustomerSync/OrderSync)
            try {
                await IndexingService.bulkIndexReviews(accountId, reviews);
            } catch (error: any) {
                Logger.warn('Bulk index reviews failed', { accountId, syncId, error: error.message });
            }

            Logger.info(`Synced batch of ${reviews.length} reviews`, { accountId, syncId, page, totalPages });
            // Use WooCommerce's x-wp-totalpages header instead of batch size
            // (batch size is unreliable when Zod validation skips records from a full page)
            if (page >= totalPages) hasMore = false;

            if (job) {
                const progress = totalPages > 0 ? Math.round((page / totalPages) * 100) : 100;
                await job.updateProgress(progress);
                if (!(await job.isActive())) throw new Error('Cancelled');
            }

            page++;

            // Throttle API pagination to avoid overwhelming the WooCommerce store
            if (hasMore) await new Promise(r => setTimeout(r, 500));
        }

        // Reconciliation: remove reviews not touched during this full sync.
        // Uses updatedAt timestamps instead of accumulating all IDs in memory.
        if (!incremental && totalProcessed > 0) {
            const staleCount = await prisma.wooReview.count({
                where: { accountId, updatedAt: { lt: syncStartedAt } }
            });

            if (staleCount > 0) {
                // Safety cap: abort if stale count exceeds 30% of total (likely API issue)
                const localTotal = await prisma.wooReview.count({ where: { accountId } });
                const maxDeletions = Math.max(10, Math.floor(localTotal * 0.3));

                if (staleCount > maxDeletions) {
                    Logger.warn(`Review reconciliation aborted: would delete ${staleCount}/${localTotal} (>30% cap)`, {
                        accountId, syncId, toDelete: staleCount, localTotal
                    });
                } else {
                    const result = await prisma.wooReview.deleteMany({
                        where: { accountId, updatedAt: { lt: syncStartedAt } }
                    });
                    totalDeleted = result.count;
                    Logger.info(`Reconciliation: Deleted ${totalDeleted} orphaned reviews`, { accountId, syncId });
                }
            }
        }

        return { itemsProcessed: totalProcessed, itemsDeleted: totalDeleted };
    }
}

