/**
 * Ad Optimization Tools
 * 
 * Orchestrates AI-powered optimization suggestions across ad platforms.
 * Delegates to domain-specific advisors for modular analysis.
 */

import { Logger } from '../../utils/logger';
import { GoogleAdsTools } from './GoogleAdsTools';
import { MetaAdsTools } from './MetaAdsTools';
import { getSeasonalContext, isBrandCampaign, getCampaignType, SeasonalContext } from './AdContext';

// Import domain advisors
import {
    processInventorySuggestions,
    processBudgetSuggestions,
    processTrendAnalysis,
    processCreativeFatigue,
    processProductAdMatch
} from './advisors';
import { processSearchSuggestions } from './advisors/SearchAdvisor';

// Import multi-period analyzer (AI Marketing Co-Pilot Phase 1)
// Import cross-channel and LTV analyzers (AI Marketing Co-Pilot Phase 2)
// Import funnel and audience analyzers (AI Marketing Co-Pilot Phase 3)
import {
    MultiPeriodAnalyzer,
    CrossChannelAnalyzer,
    LTVAnalyzer,
    FunnelAnalyzer,
    AudienceAnalyzer
} from './analyzers';

// Import knowledge base (AI Marketing Co-Pilot Phase 4)
import { RecommendationEngine, MarketingKnowledgeBase } from './knowledge';

export interface AdOptimizerOptions {
    userContext?: string;
    includeInventory?: boolean;
}

/**
 * Prioritized suggestion with urgency level.
 * Priority: 1=urgent, 2=important, 3=info
 */
export interface PrioritizedSuggestion {
    text: string;
    priority: 1 | 2 | 3;
    category: 'stock' | 'performance' | 'budget' | 'creative' | 'seasonal' | 'info';
}

export class AdOptimizer {

    /**
     * Infer priority from suggestion text based on emoji and keywords.
     */
    private static inferPriority(text: string): PrioritizedSuggestion {
        // Guard against null/undefined text from malformed suggestions
        if (!text) {
            return { text: '', priority: 3, category: 'info' };
        }

        // Urgent (priority 1): Stock alerts, performance drops, seasonal peaks
        if (text.includes('🚫') || text.includes('Stock Alert') ||
            text.includes('📉') || text.includes('Performance Drop') ||
            (text.includes('📅') && text.includes('Peak'))) {
            return {
                text,
                priority: 1,
                category: text.includes('Stock') ? 'stock' : text.includes('📅') ? 'seasonal' : 'performance'
            };
        }

        // Important (priority 2): Underperformers, budget opportunities, warnings
        if (text.includes('🔴') || text.includes('Underperforming') ||
            text.includes('💰') || text.includes('Budget') ||
            text.includes('⚠️') || text.includes('Warning') ||
            text.includes('🛒') || text.includes('🎨')) {
            return {
                text,
                priority: 2,
                category: text.includes('Budget') ? 'budget' : text.includes('🎨') ? 'creative' : 'performance'
            };
        }

        // Info (priority 3): Everything else
        return {
            text,
            priority: 3,
            category: text.includes('ℹ️') || text.includes('Brand') ? 'info' :
                text.includes('🟢') || text.includes('⭐') ? 'performance' : 'info'
        };
    }

    /**
     * Get AI-powered optimization suggestions for all ad campaigns.
     * Analyzes both Google and Meta Ads and provides actionable recommendations.
     * Returns suggestions sorted by priority (urgent first).
     */
    static async getAdOptimizationSuggestions(accountId: string, options?: AdOptimizerOptions) {
        try {
            const googleAnalysis = await GoogleAdsTools.analyzeGoogleAdsCampaigns(accountId, 30);
            const metaAnalysis = await MetaAdsTools.analyzeMetaAdsCampaigns(accountId, 30);

            const hasGoogle = typeof googleAnalysis !== 'string';
            const hasMeta = typeof metaAnalysis !== 'string';

            if (!hasGoogle && !hasMeta) {
                return { message: "No ad accounts connected. Connect your Google or Meta Ads account in Marketing > Ad Accounts." };
            }

            const suggestions: string[] = [];
            const combinedSummary: Record<string, unknown> = {};

            // Add seasonal context
            const seasonalContext = getSeasonalContext();
            if (seasonalContext) {
                combinedSummary.seasonal = seasonalContext;
                this.processSeasonalContext(seasonalContext, suggestions);
            }

            // Process inventory suggestions first (highest priority)
            const activeAdProductIds = hasGoogle ? googleAnalysis?.shopping_products?.active_ad_product_ids : undefined;
            if (options?.includeInventory !== false) {
                await processInventorySuggestions(accountId, suggestions, combinedSummary, activeAdProductIds);
            }

            // Budget optimization suggestions (delegated to BudgetAdvisor)
            if (hasGoogle) {
                processBudgetSuggestions(googleAnalysis, 'Google', suggestions);
            }
            if (hasMeta) {
                processBudgetSuggestions(metaAnalysis, 'Meta', suggestions);
            }

            // Multi-period analysis (AI Marketing Co-Pilot Phase 1)
            const multiPeriodAnalysis = await MultiPeriodAnalyzer.analyze(accountId);
            if (multiPeriodAnalysis.hasData) {
                combinedSummary.multiPeriod = {
                    periods: multiPeriodAnalysis.combined,
                    trends: multiPeriodAnalysis.trends,
                    anomalyCount: multiPeriodAnalysis.anomalies.length
                };
                // Add multi-period suggestions (these come pre-prioritized)
                for (const suggestion of multiPeriodAnalysis.suggestions) {
                    suggestions.push(suggestion);
                }
            }

            // Cross-channel analysis (AI Marketing Co-Pilot Phase 2)
            const crossChannelAnalysis = await CrossChannelAnalyzer.analyze(accountId);
            if (crossChannelAnalysis.hasData) {
                combinedSummary.crossChannel = {
                    channelPerformance: crossChannelAnalysis.channelPerformance,
                    assistedConversions: crossChannelAnalysis.assistedConversions,
                    budgetRecommendation: crossChannelAnalysis.budgetRecommendation
                };
                for (const suggestion of crossChannelAnalysis.suggestions) {
                    suggestions.push(suggestion);
                }
            }

            // LTV analysis (AI Marketing Co-Pilot Phase 2)
            const ltvAnalysis = await LTVAnalyzer.analyze(accountId);
            if (ltvAnalysis.hasData) {
                combinedSummary.ltv = {
                    overall: ltvAnalysis.overall,
                    channelLtv: ltvAnalysis.channelLtv,
                    highValueSegments: ltvAnalysis.highValueSegments
                };
                for (const suggestion of ltvAnalysis.suggestions) {
                    suggestions.push(suggestion);
                }
            }

            // Funnel analysis (AI Marketing Co-Pilot Phase 3)
            const funnelAnalysis = await FunnelAnalyzer.analyze(accountId);
            if (funnelAnalysis.hasData) {
                combinedSummary.funnel = {
                    byStageSummary: funnelAnalysis.byStageSummary,
                    funnelHealth: funnelAnalysis.funnelHealth,
                    misjudgedCount: funnelAnalysis.misjudgedCampaigns.length
                };
                for (const suggestion of funnelAnalysis.suggestions) {
                    suggestions.push(suggestion);
                }
            }

            // Audience analysis (AI Marketing Co-Pilot Phase 3)
            const audienceAnalysis = await AudienceAnalyzer.analyze(accountId);
            if (audienceAnalysis.hasData) {
                combinedSummary.audience = {
                    devicePerformance: audienceAnalysis.devicePerformance,
                    geoPerformance: audienceAnalysis.geoPerformance.slice(0, 5),
                    bidAdjustments: audienceAnalysis.bidAdjustments
                };
                for (const suggestion of audienceAnalysis.suggestions) {
                    suggestions.push(suggestion);
                }
            }

            // Knowledge-base recommendations (AI Marketing Co-Pilot Phase 4)
            const trends = multiPeriodAnalysis.hasData ? {
                roas: multiPeriodAnalysis.trends.performance_trajectory === 'improving' ? 'improving' as const :
                    multiPeriodAnalysis.trends.performance_trajectory === 'declining' ? 'declining' as const : 'stable' as const,
                ctr: 'stable' as const
            } : undefined;

            if (hasGoogle && googleAnalysis.campaign_insights) {
                const kbRecs = RecommendationEngine.generateFromCampaigns(
                    googleAnalysis.campaign_insights as any, 'google', trends
                );
                for (const rec of kbRecs.slice(0, 3)) {
                    suggestions.push(rec.text);
                }
                combinedSummary.knowledgeBase = {
                    googleRecommendations: kbRecs.length,
                    topConfidence: kbRecs[0]?.confidence.score || 0
                };
            }

            if (hasMeta && metaAnalysis.campaign_insights) {
                const kbRecs = RecommendationEngine.generateFromCampaigns(
                    metaAnalysis.campaign_insights as any, 'meta', trends
                );
                for (const rec of kbRecs.slice(0, 3)) {
                    suggestions.push(rec.text);
                }
                if (combinedSummary.knowledgeBase) {
                    (combinedSummary.knowledgeBase as any).metaRecommendations = kbRecs.length;
                }
            }

            // Legacy trend analysis (kept for week-over-week CTR alerts)
            await processTrendAnalysis(accountId, suggestions, combinedSummary);

            // Product-Ad cross-reference (delegated to ProductAdMatcher)
            if (hasGoogle && googleAnalysis.shopping_products) {
                await processProductAdMatch(accountId, googleAnalysis.shopping_products, suggestions);
            }

            // Creative fatigue detection (delegated to CreativeFatigueAdvisor)
            if (hasMeta) {
                await processCreativeFatigue(accountId, suggestions);
            }

            // Standard campaign suggestions (inline - simple enough to keep here)
            if (hasGoogle) {
                this.processGoogleSuggestions(googleAnalysis, suggestions, combinedSummary, seasonalContext);
                if (googleAnalysis.search_analysis) {
                    processSearchSuggestions(googleAnalysis as any, suggestions);
                }
            }
            if (hasMeta) {
                this.processMetaSuggestions(metaAnalysis, suggestions, combinedSummary, seasonalContext);
            }

            if (hasGoogle && hasMeta) {
                this.addCrossPlatformSuggestion(googleAnalysis, metaAnalysis, suggestions);
            }

            // User context note (last)
            if (options?.userContext) {
                this.addUserContextNote(options.userContext, suggestions, combinedSummary);
            }

            if (suggestions.length === 0) {
                suggestions.push(
                    `✅ **Overall Performance**: Your ad campaigns appear to be performing well. ` +
                    `Continue monitoring and make incremental optimizations as data accumulates.`
                );
            }

            // Convert to prioritized format and sort
            const prioritized = suggestions.map(s => this.inferPriority(s));
            prioritized.sort((a, b) => a.priority - b.priority);

            // Legacy format uses sorted order
            const sortedSuggestions = prioritized.map(s => s.text);

            return {
                suggestions: sortedSuggestions,
                prioritized,
                summary: combinedSummary,
                action_items: prioritized
                    .filter(s => s.priority <= 2)
                    .slice(0, 3)
                    .map((s, i) => `${i + 1}. ${s.text.split(':')[0].replace(/[\p{Extended_Pictographic}\u{FE0F}]/gu, '').trim()}`)
            };

        } catch (error) {
            Logger.error('Tool Error (getAdOptimizationSuggestions)', { error });
            return { message: "Failed to generate optimization suggestions." };
        }
    }

    // ─────────────────────────────────────────────────────────────
    // SEASONAL CONTEXT
    // ─────────────────────────────────────────────────────────────

    private static processSeasonalContext(seasonal: SeasonalContext, suggestions: string[]) {
        if (seasonal.isPeakSeason) {
            suggestions.unshift(
                `📅 **${seasonal.period}**: Peak advertising season is active. ` +
                `CPMs may be ~${seasonal.expectedCpmIncrease}% higher than normal. ${seasonal.notes}`
            );
        } else {
            suggestions.push(
                `📅 **Seasonal Note**: ${seasonal.period} period. ${seasonal.notes}`
            );
        }
    }

    private static addUserContextNote(context: string, suggestions: string[], summary: Record<string, unknown>) {
        summary.user_context = context;
        suggestions.push(
            `📝 **Your Notes**: "${context.slice(0, 100)}${context.length > 100 ? '...' : ''}" - ` +
            `Consider this context when reviewing the recommendations above.`
        );
    }

    // ─────────────────────────────────────────────────────────────
    // STANDARD CAMPAIGN ANALYSIS (kept inline - simple logic)
    // ─────────────────────────────────────────────────────────────

    private static processGoogleSuggestions(
        analysis: { underperformers?: { campaign: string }[]; high_performers?: { campaign: string }[]; shopping_products?: { total_products_analyzed?: number; campaigns_with_products?: number; underperforming_products?: { product: string; spend: string; roas: string }[]; high_click_low_conversion?: { product: string; clicks: number }[]; top_products?: { product: string; roas: string }[] }; summary?: unknown },
        suggestions: string[],
        summary: Record<string, unknown>,
        seasonalContext: SeasonalContext | null
    ) {
        if (analysis.underperformers?.length) {
            const nonBrandUnderperformers = analysis.underperformers.filter(c => !isBrandCampaign(c.campaign));
            const brandUnderperformers = analysis.underperformers.filter(c => isBrandCampaign(c.campaign));

            if (nonBrandUnderperformers.length > 0) {
                const note = seasonalContext?.isPeakSeason ? ` (Note: CPMs are elevated during ${seasonalContext.period})` : '';
                suggestions.push(
                    `🔴 **Google Ads - Underperforming Campaigns**: ${nonBrandUnderperformers.length} campaign(s) have ROAS below 1x${note}. ` +
                    `Consider pausing or reducing budget for: ${nonBrandUnderperformers.map(c => c.campaign).join(', ')}.`
                );
            }

            if (brandUnderperformers.length > 0) {
                suggestions.push(
                    `ℹ️ **Google Ads - Brand Campaigns**: ${brandUnderperformers.length} brand campaign(s) have low ROAS - ` +
                    `this is expected as brand campaigns prioritize visibility over direct returns.`
                );
            }
        }

        if (analysis.high_performers?.length) {
            suggestions.push(
                `🟢 **Google Ads - High Performers**: ${analysis.high_performers.length} campaign(s) have ROAS above 3x. ` +
                `Consider increasing budget for: ${analysis.high_performers.map(c => c.campaign).join(', ')}.`
            );
        }

        if (analysis.shopping_products) {
            this.processShoppingSuggestions(analysis.shopping_products, suggestions);
        }

        summary.google = analysis.summary;
        if (analysis.shopping_products) {
            summary.shopping_analysis = {
                products_analyzed: analysis.shopping_products.total_products_analyzed,
                campaigns_with_products: analysis.shopping_products.campaigns_with_products
            };
        }
    }

    private static processShoppingSuggestions(
        shopping: { underperforming_products?: { product: string; spend: string; roas: string }[]; high_click_low_conversion?: { product: string; clicks: number }[]; top_products?: { product: string; roas: string }[] },
        suggestions: string[]
    ) {
        if (shopping.underperforming_products?.length) {
            const topWasters = shopping.underperforming_products.slice(0, 3);
            suggestions.push(
                `🛒 **Shopping - Underperforming Products**: ${shopping.underperforming_products.length} product(s) have very low ROAS. ` +
                `Consider excluding: ${topWasters.map(p => `"${p.product}" (${p.spend}, ${p.roas} ROAS)`).join('; ')}.`
            );
        }

        if (shopping.high_click_low_conversion?.length) {
            const problematic = shopping.high_click_low_conversion.slice(0, 3);
            suggestions.push(
                `🔍 **Shopping - Landing Page Issues**: ${shopping.high_click_low_conversion.length} product(s) get clicks but no sales. ` +
                `Review pricing/stock for: ${problematic.map(p => `"${p.product}" (${p.clicks} clicks, 0 conversions)`).join('; ')}.`
            );
        }

        if (shopping.top_products?.length) {
            const topPerformers = shopping.top_products.slice(0, 3);
            suggestions.push(
                `⭐ **Shopping - Top Performers**: Your best products are: ${topPerformers.map(p => `"${p.product}" (${p.roas} ROAS)`).join(', ')}. ` +
                `Consider increasing bids on these.`
            );
        }
    }

    private static processMetaSuggestions(
        analysis: { underperformers?: { campaign: string }[]; high_performers?: { campaign: string }[]; summary?: unknown },
        suggestions: string[],
        summary: Record<string, unknown>,
        seasonalContext: SeasonalContext | null
    ) {
        if (analysis.underperformers?.length) {
            const directResponseUnderperformers = analysis.underperformers.filter(
                c => !isBrandCampaign(c.campaign) && getCampaignType(c.campaign) !== 'awareness'
            );
            const brandOrAwarenessCount = analysis.underperformers.length - directResponseUnderperformers.length;

            if (directResponseUnderperformers.length > 0) {
                const note = seasonalContext?.isPeakSeason ? ` (Note: CPMs are elevated during ${seasonalContext.period})` : '';
                suggestions.push(
                    `🔴 **Meta Ads - Underperforming Campaigns**: ${directResponseUnderperformers.length} campaign(s) have ROAS below 1x${note}. ` +
                    `Consider pausing or reducing budget for: ${directResponseUnderperformers.map(c => c.campaign).join(', ')}.`
                );
            }

            if (brandOrAwarenessCount > 0) {
                suggestions.push(
                    `ℹ️ **Meta Ads - Brand/Awareness Campaigns**: ${brandOrAwarenessCount} campaign(s) have low ROAS - ` +
                    `this is expected for brand awareness campaigns which prioritize reach over conversions.`
                );
            }
        }

        if (analysis.high_performers?.length) {
            suggestions.push(
                `🟢 **Meta Ads - High Performers**: ${analysis.high_performers.length} campaign(s) have ROAS above 3x. ` +
                `Consider increasing budget for: ${analysis.high_performers.map(c => c.campaign).join(', ')}.`
            );
        }

        summary.meta = analysis.summary;
    }

    private static addCrossPlatformSuggestion(
        googleAnalysis: { summary: { overall_roas: string } },
        metaAnalysis: { summary: { overall_roas: string } },
        suggestions: string[]
    ) {
        const googleRoas = parseFloat(googleAnalysis.summary.overall_roas) || 0;
        const metaRoas = parseFloat(metaAnalysis.summary.overall_roas) || 0;

        if (googleRoas > metaRoas * 1.5) {
            suggestions.push(
                `📊 **Platform Comparison**: Google Ads (${googleAnalysis.summary.overall_roas}) is significantly outperforming Meta Ads (${metaAnalysis.summary.overall_roas}). ` +
                `Consider shifting more budget to Google.`
            );
        } else if (metaRoas > googleRoas * 1.5) {
            suggestions.push(
                `📊 **Platform Comparison**: Meta Ads (${metaAnalysis.summary.overall_roas}) is significantly outperforming Google Ads (${googleAnalysis.summary.overall_roas}). ` +
                `Consider shifting more budget to Meta.`
            );
        }
    }
}

import { AnalyticsService } from '../AnalyticsService';
import { prisma, Prisma } from '../../utils/prisma';
import { Logger } from '../../utils/logger';

export class AnalyticsTools {

    static async getVisitorTraffic(accountId: string) {
        try {
            const result = await AnalyticsService.getVisitorLog(accountId, 1, 10, true); // liveMode=true
            if (result.data.length === 0) return "No active visitors on the site right now.";

            return result.data.map((s: any) => ({
                location: `${s.city || 'Unknown'}, ${s.country || ''}`,
                device: `${s.browser} on ${s.os}`,
                current_page: s.currentPath,
                customer: s.customer ? `${s.customer.firstName} (${s.customer.email})` : 'Guest'
            }));
        } catch (error) {
            Logger.error('Tool Error (getVisitorTraffic)', { error });
            return "Failed to fetch live visitor data.";
        }
    }

    static async getSearchInsights(accountId: string) {
        try {
            const terms = await AnalyticsService.getSearchTerms(accountId);
            if (terms.length === 0) return "No recent search terms recorded.";
            return terms;
        } catch (error) {
            Logger.error('Tool Error (getSearchInsights)', { error });
            return "Failed to fetch search insights.";
        }
    }

    static async getProfitability(accountId: string, period: string) {
        try {
            const now = new Date();
            let startDate = new Date();

            // Default to 'this_month' if undefined, simple mapping
            if (period === 'last_7_days') startDate.setDate(now.getDate() - 7);
            else if (period === 'last_30_days') startDate.setDate(now.getDate() - 30);
            else startDate.setDate(1); // this_month or default

            const report = await AnalyticsService.getProfitabilityReport(accountId, startDate, now);
            return {
                summary: report.summary,
                top_items_by_margin: report.breakdown.slice(0, 5).map((i: any) => ({
                    name: i.name,
                    margin: `${i.margin.toFixed(1)}%`,
                    profit: i.profit.toFixed(2)
                }))
            };
        } catch (error) {
            Logger.error('Tool Error (getProfitability)', { error });
            return "Failed to calculate profitability.";
        }
    }

    static async forecastSales(accountId: string) {
        try {
            // Simple linear projection based on last 30 days
            const thirtyDaysAgo = new Date();
            thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

            const dailySales = await prisma.wooOrder.groupBy({
                by: ['dateCreated'],
                where: {
                    accountId,
                    status: 'completed',
                    dateCreated: { gte: thirtyDaysAgo }
                },
                _sum: { total: true },
            });

            // Aggregate by day string to smooth out timestamps
            const salesByDay: Record<string, number> = {};
            dailySales.forEach(s => {
                if (!s.dateCreated) return;
                const day = s.dateCreated.toISOString().split('T')[0];
                salesByDay[day] = (salesByDay[day] || 0) + Number(s._sum.total || 0);
            });

            const values = Object.values(salesByDay);
            if (values.length < 5) return "Not enough data to forecast sales (need at least 5 days of history).";

            // Calculate average daily sales
            const total = values.reduce((a, b) => a + b, 0);
            const avgDaily = total / values.length;

            // Simple trend (growth rate) check - comparing last 5 days vs first 5 days
            const recentAvg = values.slice(-5).reduce((a, b) => a + b, 0) / 5;
            const pastAvg = values.slice(0, 5).reduce((a, b) => a + b, 0) / 5;
            const growthFactor = pastAvg > 0 ? recentAvg / pastAvg : 1;

            const nextWeekTotal = avgDaily * 7 * growthFactor;

            return {
                forecast_next_7_days: nextWeekTotal.toFixed(2),
                trend: growthFactor > 1.05 ? "Growing" : growthFactor < 0.95 ? "Declining" : "Stable",
                confidence: "Moderate (Simple Linear Projection)"
            };

        } catch (error) {
            Logger.error('Tool Error (forecastSales)', { error });
            return "Failed to generate forecast.";
        }
    }

    static async analyzeCustomerSegments(accountId: string, segment: 'at_risk' | 'whales' | 'new') {
        try {
            const ninetyDaysAgo = new Date();
            ninetyDaysAgo.setDate(ninetyDaysAgo.getDate() - 90);

            if (segment === 'at_risk') {
                // High spenders who haven't bought in 90 days
                // Note: lastOrderDate not in schema, returning based on high spend only
                const customers = await prisma.wooCustomer.findMany({
                    where: {
                        accountId,
                        totalSpent: { gt: 500 } // Arbitrary 'High Value' threshold
                    },
                    take: 10,
                    orderBy: { totalSpent: 'desc' },
                    select: { firstName: true, email: true, totalSpent: true }
                });
                return customers.length ? customers : "No 'At Risk' high-value customers found.";
            }

            if (segment === 'whales') {
                // Top spenders all time
                const customers = await prisma.wooCustomer.findMany({
                    where: { accountId },
                    take: 10,
                    orderBy: { totalSpent: 'desc' },
                    select: { firstName: true, email: true, totalSpent: true, ordersCount: true }
                });
                return customers;
            }

            return "Segment not supported.";

        } catch (error) {
            Logger.error('Tool Error (analyzeCustomerSegments)', { error });
            return "Failed to analyze segments.";
        }
    }
}

/**
 * Google Ads Campaign Analysis Tools
 * 
 * Extracted from AdsTools for modularity.
 * Provides detailed Google Ads campaign analysis for AI tools.
 */

import { prisma } from '../../utils/prisma';
import { Logger } from '../../utils/logger';
import { AdsService } from '../ads';

export class GoogleAdsTools {

    /**
     * Analyze Google Ads campaigns with detailed performance breakdown.
     * Returns campaign-level metrics and identifies opportunities.
     * For Shopping campaigns, includes product-level performance data.
     */
    static async analyzeGoogleAdsCampaigns(accountId: string, days: number = 30) {
        try {
            const adAccounts = await prisma.adAccount.findMany({
                where: { accountId, platform: 'GOOGLE' },
                select: { id: true, name: true, externalId: true }
            });

            if (adAccounts.length === 0) {
                return "No Google Ads accounts connected. Connect your Google Ads account in Marketing > Ad Accounts.";
            }

            const allCampaigns: any[] = [];
            const allProducts: any[] = [];
            const allKeywords: any[] = [];

            for (const adAccount of adAccounts) {
                try {
                    const campaigns = await AdsService.getGoogleCampaignInsights(adAccount.id, days);
                    campaigns.forEach((c: any) => {
                        allCampaigns.push({
                            account: adAccount.name || adAccount.externalId,
                            ...c
                        });
                    });

                    // Also fetch shopping product data
                    try {
                        const products = await AdsService.getGoogleShoppingProducts(adAccount.id, days, 100);
                        products.forEach((p: any) => {
                            allProducts.push({
                                account: adAccount.name || adAccount.externalId,
                                ...p
                            });
                        });
                    } catch (err) {
                        Logger.debug(`No shopping data for ${adAccount.id}`, { error: (err as Error).message });
                    }

                    // Also fetch search keyword data
                    try {
                        const keywords = await AdsService.getGoogleSearchKeywords(adAccount.id, days, 500);
                        keywords.forEach((k: any) => {
                            allKeywords.push({
                                account: adAccount.name || adAccount.externalId,
                                ...k
                            });
                        });
                    } catch (err) {
                        Logger.debug(`No keyword data for ${adAccount.id}`, { error: (err as Error).message });
                    }
                } catch (err) {
                    Logger.warn(`Failed to fetch campaigns for ${adAccount.id}`, { error: (err as Error).message });
                }
            }

            if (allCampaigns.length === 0) {
                return "No campaign data available. Please check your Google Ads connection.";
            }

            const totals = this.calculateTotals(allCampaigns);
            const bySpend = [...allCampaigns].sort((a, b) => b.spend - a.spend);
            const byRoas = [...allCampaigns].filter(c => c.spend > 0).sort((a, b) => b.roas - a.roas);

            const underperformers = allCampaigns
                .filter(c => c.spend > totals.spend * 0.05 && c.roas < 1)
                .sort((a, b) => b.spend - a.spend)
                .slice(0, 3);

            const highPerformers = allCampaigns
                .filter(c => c.roas >= 3)
                .sort((a, b) => b.conversionsValue - a.conversionsValue)
                .slice(0, 3);

            const shoppingAnalysis = this.analyzeShoppingProducts(allProducts, totals);
            const searchAnalysis = this.analyzeSearchKeywords(allKeywords);

            return {
                summary: {
                    total_campaigns: allCampaigns.length,
                    total_spend: `$${totals.spend.toFixed(2)}`,
                    total_clicks: totals.clicks,
                    total_impressions: totals.impressions,
                    total_conversions: totals.conversions.toFixed(0),
                    overall_roas: totals.spend > 0 ? `${(totals.conversionsValue / totals.spend).toFixed(2)}x` : 'N/A',
                    overall_ctr: totals.impressions > 0 ? `${((totals.clicks / totals.impressions) * 100).toFixed(2)}%` : 'N/A',
                    period: `Last ${days} days`
                },
                top_spenders: bySpend.slice(0, 5).map(c => ({
                    campaign: c.campaignName,
                    spend: `$${c.spend.toFixed(2)}`,
                    roas: `${c.roas.toFixed(2)}x`,
                    status: c.status
                })),
                highest_roas: byRoas.slice(0, 5).map(c => ({
                    campaign: c.campaignName,
                    roas: `${c.roas.toFixed(2)}x`,
                    spend: `$${c.spend.toFixed(2)}`,
                    conversions: c.conversions.toFixed(0)
                })),
                underperformers: underperformers.map(c => ({
                    campaign: c.campaignName,
                    spend: `$${c.spend.toFixed(2)}`,
                    roas: `${c.roas.toFixed(2)}x`,
                    issue: c.roas < 0.5 ? 'Very low ROAS - consider pausing' : 'Below breakeven - needs optimization'
                })),
                high_performers: highPerformers.map(c => ({
                    campaign: c.campaignName,
                    roas: `${c.roas.toFixed(2)}x`,
                    revenue: `$${c.conversionsValue.toFixed(2)}`,
                    suggestion: 'Consider increasing budget'
                })),
                shopping_products: shoppingAnalysis,
                search_analysis: searchAnalysis,
                // Raw campaign data for knowledge base recommendations
                campaign_insights: allCampaigns.map(c => ({
                    campaignId: c.campaignId || c.id || `${c.campaignName}-${c.account}`,
                    campaignName: c.campaignName,
                    platform: 'google' as const,
                    spend: c.spend,
                    revenue: c.conversionsValue || 0,
                    roas: c.roas,
                    ctr: c.ctr || (c.impressions > 0 ? (c.clicks / c.impressions) * 100 : 0),
                    cpc: c.cpc || (c.clicks > 0 ? c.spend / c.clicks : 0),
                    cpa: c.cpa || (c.conversions > 0 ? c.spend / c.conversions : 0),
                    conversions: c.conversions,
                    impressions: c.impressions,
                    clicks: c.clicks
                }))
            };

        } catch (error) {
            Logger.error('Tool Error (analyzeGoogleAdsCampaigns)', { error });
            return "Failed to analyze Google Ads campaigns.";
        }
    }

    private static calculateTotals(campaigns: any[]) {
        return campaigns.reduce((acc, c) => ({
            spend: acc.spend + c.spend,
            clicks: acc.clicks + c.clicks,
            impressions: acc.impressions + c.impressions,
            conversions: acc.conversions + c.conversions,
            conversionsValue: acc.conversionsValue + c.conversionsValue
        }), { spend: 0, clicks: 0, impressions: 0, conversions: 0, conversionsValue: 0 });
    }

    private static analyzeShoppingProducts(allProducts: any[], totals: any) {
        if (allProducts.length === 0) return null;

        const productTotals = allProducts.reduce((acc, p) => ({
            spend: acc.spend + p.spend,
            conversionsValue: acc.conversionsValue + p.conversionsValue
        }), { spend: 0, conversionsValue: 0 });

        const topProducts = [...allProducts]
            .filter(p => p.spend > 0)
            .sort((a, b) => b.roas - a.roas)
            .slice(0, 5);

        const underperformingProducts = [...allProducts]
            .filter(p => p.spend > productTotals.spend * 0.02 && p.roas < 0.5)
            .sort((a, b) => b.spend - a.spend)
            .slice(0, 5);

        const highClickLowConversion = [...allProducts]
            .filter(p => p.clicks > 20 && p.conversions < 1)
            .sort((a, b) => b.clicks - a.clicks)
            .slice(0, 5);

        const productsByCampaign = allProducts.reduce((acc: Record<string, any[]>, p) => {
            if (!acc[p.campaignName]) acc[p.campaignName] = [];
            acc[p.campaignName].push(p);
            return acc;
        }, {});

        return {
            total_products_analyzed: allProducts.length,
            top_products: topProducts.map(p => ({
                product: p.productTitle,
                product_id: p.productId,
                campaign: p.campaignName,
                roas: `${p.roas.toFixed(2)}x`,
                spend: `$${p.spend.toFixed(2)}`,
                conversions: p.conversions.toFixed(0)
            })),
            underperforming_products: underperformingProducts.map(p => ({
                product: p.productTitle,
                product_id: p.productId,
                campaign: p.campaignName,
                roas: `${p.roas.toFixed(2)}x`,
                spend: `$${p.spend.toFixed(2)}`,
                issue: p.conversions === 0 ? 'No conversions - consider excluding' : 'Very low ROAS - review pricing/landing page'
            })),
            high_click_low_conversion: highClickLowConversion.map(p => ({
                product: p.productTitle,
                product_id: p.productId,
                campaign: p.campaignName,
                clicks: p.clicks,
                conversions: p.conversions.toFixed(0),
                issue: 'High traffic but no sales - check landing page, price, or stock'
            })),
            campaigns_with_products: Object.keys(productsByCampaign).length,
            // Return raw set of active product IDs (SKUs or IDs depending on feed setup)
            active_ad_product_ids: Array.from(new Set(allProducts.map(p => p.productId ? String(p.productId) : '')))
        };
    }

    private static analyzeSearchKeywords(allKeywords: any[]) {
        if (allKeywords.length === 0) return null;

        const keywordTotals = allKeywords.reduce((acc, k) => ({
            spend: acc.spend + k.spend,
            conversionsValue: acc.conversionsValue + k.conversionsValue
        }), { spend: 0, conversionsValue: 0 });

        const topKeywords = [...allKeywords]
            .filter(k => k.spend > 0)
            .sort((a, b) => b.roas - a.roas)
            .slice(0, 5);

        const negativeOpportunities = [...allKeywords]
            .filter(k => k.spend > 20 && k.conversions === 0)
            .sort((a, b) => b.spend - a.spend)
            .slice(0, 5);

        const highSpendLowCtr = [...allKeywords]
            .filter(k => k.impressions > 1000 && k.ctr < 1 && k.spend > 10)
            .sort((a, b) => b.spend - a.spend)
            .slice(0, 5);

        return {
            total_keywords_analyzed: allKeywords.length,
            top_keywords: topKeywords.map(k => ({
                keyword: k.keywordText,
                campaign: k.campaignName,
                match_type: k.matchType,
                roas: `${k.roas.toFixed(2)}x`,
                spend: `$${k.spend.toFixed(2)}`,
                conversions: k.conversions.toFixed(0)
            })),
            negative_opportunities: negativeOpportunities.map(k => ({
                keyword: k.keywordText,
                campaign: k.campaignName,
                match_type: k.matchType,
                spend: `$${k.spend.toFixed(2)}`,
                clicks: k.clicks,
                issue: 'High spend with zero conversions - consider adding as negative keyword'
            })),
            low_ctr_keywords: highSpendLowCtr.map(k => ({
                keyword: k.keywordText,
                campaign: k.campaignName,
                ctr: `${k.ctr.toFixed(2)}%`,
                impressions: k.impressions,
                issue: 'Low CTR - ad copy or keyword relevance may need review'
            }))
        };
    }
}

/**
 * Marketing Strategy Advisor
 * 
 * Provides executive-level marketing intelligence beyond campaign-level optimization.
 * Thinks like a CMO, not just a campaign manager.
 * 
 * Part of AI Marketing Co-Pilot Phase 4: Strategic Intelligence Layer.
 */

import { Logger } from '../../../utils/logger';
import { prisma } from '../../../utils/prisma';
import { getSeasonalContext, SeasonalContext } from '../AdContext';
import { ActionableRecommendation, BudgetAction } from '../types/ActionableTypes';
import { REVENUE_STATUSES } from '../../../constants/orderStatus';


interface StrategyAnalysisResult {
    hasData: boolean;
    recommendations: ActionableRecommendation[];
    summary: {
        strategicFocus: string;
        seasonalPhase: string;
        portfolioHealth: 'healthy' | 'attention' | 'critical';
    };
}

interface ChannelMetrics {
    platform: 'google' | 'meta';
    spend: number;
    revenue: number;
    roas: number;
    conversions: number;
}


export class MarketingStrategyAdvisor {

    /**
     * Analyze overall marketing posture and recommend strategic shifts.
     * Unlike tactical analyzers, this thinks in terms of:
     * - Seasonal portfolio adjustments
     * - Cross-channel budget allocation
     * - Customer acquisition vs retention balance
     * - Margin-aware scaling decisions
     */
    static async analyze(accountId: string): Promise<StrategyAnalysisResult> {
        const result: StrategyAnalysisResult = {
            hasData: false,
            recommendations: [],
            summary: {
                strategicFocus: 'optimization',
                seasonalPhase: 'normal',
                portfolioHealth: 'healthy'
            }
        };

        try {
            // Gather strategic inputs
            const [seasonal, channelMetrics, revenueData, marginData] = await Promise.all([
                Promise.resolve(getSeasonalContext()),
                this.getChannelMetrics(accountId),
                this.getRevenueMetrics(accountId),
                this.getMarginData(accountId)
            ]);

            // Need some data to provide strategy
            if (channelMetrics.length === 0 && revenueData.totalRevenue === 0) {
                return result;
            }

            result.hasData = true;

            // 1. Seasonal Strategy Recommendations
            if (seasonal) {
                const seasonalRecs = this.getSeasonalRecommendations(seasonal, channelMetrics);
                result.recommendations.push(...seasonalRecs);
                result.summary.seasonalPhase = seasonal.period;
            }

            // 2. Portfolio Rebalancing (Cross-Channel)
            if (channelMetrics.length >= 2) {
                const portfolioRecs = this.getPortfolioRecommendations(channelMetrics);
                result.recommendations.push(...portfolioRecs);
            }

            // 3. Margin-Aware Scaling
            if (marginData.avgMargin > 0) {
                const marginRecs = this.getMarginBasedRecommendations(marginData, channelMetrics);
                result.recommendations.push(...marginRecs);
            }

            // 4. New Customer Acquisition Strategy
            const acquisitionRecs = this.getAcquisitionRecommendations(revenueData, channelMetrics);
            result.recommendations.push(...acquisitionRecs);

            // Determine portfolio health
            const avgRoas = channelMetrics.length > 0
                ? channelMetrics.reduce((sum, c) => sum + c.roas, 0) / channelMetrics.length
                : 0;

            if (avgRoas >= 2.5) result.summary.portfolioHealth = 'healthy';
            else if (avgRoas >= 1.5) result.summary.portfolioHealth = 'attention';
            else result.summary.portfolioHealth = 'critical';

            // Determine strategic focus
            if (seasonal?.isPeakSeason) {
                result.summary.strategicFocus = 'scaling';
            } else if (avgRoas < 1.5) {
                result.summary.strategicFocus = 'efficiency';
            } else {
                result.summary.strategicFocus = 'growth';
            }

        } catch (error) {
            Logger.error('MarketingStrategyAdvisor failed', { error, accountId });
        }

        return result;
    }

    /**
     * Get channel-level metrics for portfolio analysis.
     */
    private static async getChannelMetrics(accountId: string): Promise<ChannelMetrics[]> {
        const metrics: ChannelMetrics[] = [];

        try {
            const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);

            // Get ad accounts and their metrics from snapshots
            const adAccounts = await prisma.adAccount.findMany({
                where: { accountId },
                select: { id: true, platform: true, name: true }
            });

            for (const acc of adAccounts) {
                // Use AdPerformanceSnapshot for metrics
                const snapshots = await prisma.adPerformanceSnapshot.findMany({
                    where: {
                        adAccountId: acc.id,
                        date: { gte: thirtyDaysAgo }
                    },
                    select: { spend: true, revenue: true, conversions: true }
                });

                if (snapshots.length === 0) continue;

                const spend = snapshots.reduce((s, snap) => s + (snap.spend || 0), 0);
                const revenue = snapshots.reduce((s, snap) => s + (snap.revenue || 0), 0);
                const conversions = snapshots.reduce((s, snap) => s + (snap.conversions || 0), 0);

                if (spend > 0) {
                    metrics.push({
                        platform: acc.platform.toLowerCase() as 'google' | 'meta',
                        spend,
                        revenue,
                        roas: revenue / spend,
                        conversions
                    });
                }
            }
        } catch (error) {
            Logger.warn('Failed to get channel metrics', { error });
        }

        return metrics;
    }

    /**
     * Get overall revenue metrics for strategic analysis.
     */
    private static async getRevenueMetrics(accountId: string): Promise<{
        totalRevenue: number;
        repeatRate: number;
        avgOrderValue: number;
    }> {
        try {
            const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);

            const orders = await prisma.wooOrder.aggregate({
                where: {
                    accountId,
                    status: { in: REVENUE_STATUSES },
                    dateCreated: { gte: thirtyDaysAgo }
                },
                _sum: { total: true },
                _count: { id: true }
            });

            const totalRevenue = Number(orders._sum.total) || 0;
            const orderCount = orders._count.id || 0;
            const avgOrderValue = orderCount > 0 ? totalRevenue / orderCount : 0;

            // Simplified repeat rate calculation using customer data
            // Note: Full repeat rate calculation requires joining order->customer data
            // For now, estimate based on customer count vs order count in 30d
            const repeatRate = orderCount > 0 ? Math.min(30, (orderCount / Math.max(orderCount / 1.5, 1)) * 10) : 0;

            return { totalRevenue, repeatRate, avgOrderValue };
        } catch {
            return { totalRevenue: 0, repeatRate: 0, avgOrderValue: 0 };
        }
    }

    /**
     * Get product margin data for scaling decisions.
     */
    private static async getMarginData(accountId: string): Promise<{
        avgMargin: number;
        highMarginProductCount: number;
    }> {
        try {
            const products = await prisma.wooProduct.findMany({
                where: {
                    accountId,
                    cogs: { not: null },
                    price: { not: null }
                },
                select: { price: true, cogs: true }
            });

            if (products.length === 0) {
                return { avgMargin: 0, highMarginProductCount: 0 };
            }

            let totalMargin = 0;
            let highMarginCount = 0;

            for (const p of products) {
                const price = parseFloat(String(p.price)) || 0;
                const cogs = parseFloat(String(p.cogs)) || 0;
                if (price > 0) {
                    const margin = ((price - cogs) / price) * 100;
                    totalMargin += margin;
                    if (margin >= 40) highMarginCount++;
                }
            }

            return {
                avgMargin: totalMargin / products.length,
                highMarginProductCount: highMarginCount
            };
        } catch {
            return { avgMargin: 0, highMarginProductCount: 0 };
        }
    }

    /**
     * Generate seasonal strategy recommendations.
     */
    private static getSeasonalRecommendations(
        seasonal: SeasonalContext,
        channels: ChannelMetrics[]
    ): ActionableRecommendation[] {
        const recs: ActionableRecommendation[] = [];

        if (seasonal.isPeakSeason) {
            const totalSpend = channels.reduce((s, c) => s + c.spend, 0);
            const suggestedIncrease = Math.round(totalSpend * 0.3);

            recs.push({
                id: `strategy_seasonal_${Date.now()}`,
                priority: 1,
                category: 'budget',
                headline: `🎯 ${seasonal.period} Strategy: Scale retargeting by 30%`,
                explanation: `Peak season is active with CPMs expected to rise ${seasonal.expectedCpmIncrease}% above normal. ` +
                    `Focus additional budget on retargeting warm audiences who are more likely to convert during high-intent periods. ` +
                    `${seasonal.notes}`,
                dataPoints: [
                    `Current total spend: $${totalSpend.toFixed(0)}/30d`,
                    `Suggested increase: +$${suggestedIncrease}/30d`,
                    `Expected CPM increase: +${seasonal.expectedCpmIncrease}%`,
                    `Strategy: Prioritize retargeting over cold prospecting`
                ],
                action: {
                    actionType: 'budget_increase',
                    campaignId: 'portfolio',
                    campaignName: 'All Retargeting Campaigns',
                    platform: 'both',
                    currentBudget: totalSpend,
                    suggestedBudget: totalSpend + suggestedIncrease,
                    changeAmount: suggestedIncrease,
                    changePercent: 30,
                    reason: `${seasonal.period} peak season scaling`
                } as BudgetAction,
                confidence: 75,
                estimatedImpact: {
                    revenueChange: suggestedIncrease * 2.5, // Assume 2.5x ROAS on retargeting
                    spendChange: suggestedIncrease,
                    timeframe: '30d'
                },
                platform: 'both',
                source: 'MarketingStrategyAdvisor',
                tags: ['seasonal', 'scaling', 'retargeting']
            });
        } else if (seasonal.period.includes('Post')) {
            // Post-peak period - focus on efficiency
            recs.push({
                id: `strategy_postpeak_${Date.now()}`,
                priority: 2,
                category: 'optimization',
                headline: `📊 Post-Peak Strategy: Shift to efficiency mode`,
                explanation: `${seasonal.period} is typically a slower period. Focus on maintaining ROAS ` +
                    `while reducing overall spend. Re-engage holiday buyers for repeat purchases.`,
                dataPoints: [
                    `Phase: ${seasonal.period}`,
                    `Strategy: Reduce prospecting, maintain retargeting`,
                    `Focus: Customer retention over acquisition`
                ],
                action: {
                    actionType: 'budget_decrease',
                    campaignId: 'portfolio',
                    campaignName: 'Cold Prospecting Campaigns',
                    platform: 'both',
                    currentBudget: 0,
                    suggestedBudget: 0,
                    changeAmount: 0,
                    changePercent: -20,
                    reason: 'Post-peak efficiency shift'
                } as BudgetAction,
                confidence: 70,
                platform: 'both',
                source: 'MarketingStrategyAdvisor',
                tags: ['seasonal', 'efficiency', 'retention']
            });
        }

        return recs;
    }

    /**
     * Generate portfolio rebalancing recommendations.
     */
    private static getPortfolioRecommendations(channels: ChannelMetrics[]): ActionableRecommendation[] {
        const recs: ActionableRecommendation[] = [];

        // Find best and worst performing channels
        const sorted = [...channels].sort((a, b) => b.roas - a.roas);
        const best = sorted[0];
        const worst = sorted[sorted.length - 1];

        // Only recommend rebalancing if there's a significant difference
        if (best && worst && best.roas > worst.roas * 1.5 && worst.spend > 100) {
            const shiftAmount = Math.round(worst.spend * 0.25);

            recs.push({
                id: `strategy_rebalance_${Date.now()}`,
                priority: 2,
                category: 'budget',
                headline: `📈 Portfolio Rebalance: Shift $${shiftAmount}/mo from ${worst.platform} to ${best.platform}`,
                explanation: `${best.platform.charAt(0).toUpperCase() + best.platform.slice(1)} is significantly outperforming ` +
                    `${worst.platform} (${best.roas.toFixed(2)}x vs ${worst.roas.toFixed(2)}x ROAS). ` +
                    `Reallocating 25% of underperforming channel budget could improve overall portfolio returns.`,
                dataPoints: [
                    `${best.platform}: ${best.roas.toFixed(2)}x ROAS, $${best.spend.toFixed(0)} spend`,
                    `${worst.platform}: ${worst.roas.toFixed(2)}x ROAS, $${worst.spend.toFixed(0)} spend`,
                    `Suggested shift: $${shiftAmount}/month`,
                    `Expected ROAS lift: +${((best.roas - worst.roas) * 0.25 * 100 / worst.roas).toFixed(0)}%`
                ],
                action: {
                    actionType: 'budget_decrease',
                    campaignId: 'portfolio',
                    campaignName: `${worst.platform} Portfolio`,
                    platform: worst.platform,
                    currentBudget: worst.spend,
                    suggestedBudget: worst.spend - shiftAmount,
                    changeAmount: -shiftAmount,
                    changePercent: -25,
                    reason: 'Cross-channel rebalancing for efficiency'
                } as BudgetAction,
                confidence: 70,
                estimatedImpact: {
                    roasChange: (best.roas - worst.roas) * 0.25,
                    spendChange: 0, // Net neutral
                    timeframe: '30d'
                },
                platform: 'both',
                source: 'MarketingStrategyAdvisor',
                tags: ['portfolio', 'rebalancing', 'cross-channel']
            });
        }

        return recs;
    }

    /**
     * Generate margin-based scaling recommendations.
     */
    private static getMarginBasedRecommendations(
        marginData: { avgMargin: number; highMarginProductCount: number },
        channels: ChannelMetrics[]
    ): ActionableRecommendation[] {
        const recs: ActionableRecommendation[] = [];

        if (marginData.avgMargin >= 40 && marginData.highMarginProductCount >= 5) {
            const totalSpend = channels.reduce((s, c) => s + c.spend, 0);
            const increaseAmount = Math.round(totalSpend * 0.2);

            recs.push({
                id: `strategy_margin_${Date.now()}`,
                priority: 2,
                category: 'optimization',
                headline: `💎 High Margins = Room to Scale: Increase ad spend by 20%`,
                explanation: `Your average product margin of ${marginData.avgMargin.toFixed(0)}% is healthy. ` +
                    `With ${marginData.highMarginProductCount} high-margin products (40%+ margin), ` +
                    `you can afford to bid more aggressively for traffic and still maintain profitability.`,
                dataPoints: [
                    `Avg margin: ${marginData.avgMargin.toFixed(0)}%`,
                    `High-margin products: ${marginData.highMarginProductCount}`,
                    `Current spend: $${totalSpend.toFixed(0)}/mo`,
                    `Suggested increase: +$${increaseAmount}/mo`
                ],
                action: {
                    actionType: 'budget_increase',
                    campaignId: 'portfolio',
                    campaignName: 'High-Margin Product Campaigns',
                    platform: 'both',
                    currentBudget: totalSpend,
                    suggestedBudget: totalSpend + increaseAmount,
                    changeAmount: increaseAmount,
                    changePercent: 20,
                    reason: 'Margin-enabled scaling opportunity'
                } as BudgetAction,
                confidence: 65,
                estimatedImpact: {
                    revenueChange: increaseAmount * 2, // Conservative 2x ROAS estimate
                    spendChange: increaseAmount,
                    timeframe: '30d'
                },
                platform: 'both',
                source: 'MarketingStrategyAdvisor',
                tags: ['margin', 'scaling', 'profitability']
            });
        }

        return recs;
    }

    /**
     * Generate customer acquisition strategy recommendations.
     */
    private static getAcquisitionRecommendations(
        revenueData: { totalRevenue: number; repeatRate: number; avgOrderValue: number },
        channels: ChannelMetrics[]
    ): ActionableRecommendation[] {
        const recs: ActionableRecommendation[] = [];

        // If repeat rate is low, focus on retention over acquisition
        if (revenueData.repeatRate < 15 && revenueData.totalRevenue > 1000) {
            recs.push({
                id: `strategy_retention_${Date.now()}`,
                priority: 2,
                category: 'optimization',
                headline: `🔄 Low Repeat Rate (${revenueData.repeatRate.toFixed(0)}%): Invest in retention`,
                explanation: `Your repeat purchase rate of ${revenueData.repeatRate.toFixed(0)}% is below the 20% benchmark. ` +
                    `Consider shifting 10-15% of prospecting budget to email/SMS retention campaigns. ` +
                    `Existing customers have higher conversion rates and lower acquisition costs.`,
                dataPoints: [
                    `Current repeat rate: ${revenueData.repeatRate.toFixed(0)}%`,
                    `Industry benchmark: 20-30%`,
                    `Avg order value: $${revenueData.avgOrderValue.toFixed(0)}`,
                    `Strategy: Email flows, loyalty programs, post-purchase sequences`
                ],
                action: {
                    actionType: 'budget_decrease',
                    campaignId: 'portfolio',
                    campaignName: 'Cold Prospecting',
                    platform: 'both',
                    currentBudget: 0,
                    suggestedBudget: 0,
                    changeAmount: 0,
                    changePercent: -15,
                    reason: 'Rebalance to retention-focused marketing'
                } as BudgetAction,
                confidence: 60,
                platform: 'both',
                source: 'MarketingStrategyAdvisor',
                tags: ['retention', 'ltv', 'efficiency']
            });
        }

        // If AOV is high, can afford higher CPA
        if (revenueData.avgOrderValue > 100) {
            const affordableCpa = revenueData.avgOrderValue * 0.25; // 25% of AOV
            recs.push({
                id: `strategy_aov_${Date.now()}`,
                priority: 3,
                category: 'optimization',
                headline: `📦 High AOV ($${revenueData.avgOrderValue.toFixed(0)}): You can afford $${affordableCpa.toFixed(0)} CPA`,
                explanation: `With an average order value of $${revenueData.avgOrderValue.toFixed(0)}, ` +
                    `you can profitably acquire customers at up to $${affordableCpa.toFixed(0)} CPA (25% of AOV). ` +
                    `Use this as your target CPA bidding cap.`,
                dataPoints: [
                    `AOV: $${revenueData.avgOrderValue.toFixed(0)}`,
                    `Max profitable CPA: $${affordableCpa.toFixed(0)}`,
                    `Assumption: 25% of AOV to acquisition`
                ],
                action: {
                    actionType: 'budget_increase',
                    campaignId: 'portfolio',
                    campaignName: 'Prospecting Campaigns',
                    platform: 'both',
                    currentBudget: 0,
                    suggestedBudget: 0,
                    changeAmount: 0,
                    changePercent: 0,
                    reason: 'AOV enables aggressive CPA bidding'
                } as BudgetAction,
                confidence: 55,
                platform: 'both',
                source: 'MarketingStrategyAdvisor',
                tags: ['aov', 'cpa', 'bidding']
            });
        }

        return recs;
    }
}

/**
 * Product Ad Matcher
 * 
 * Matches shopping ad products to WooCommerce inventory for margin analysis.
 * Extracted from AdOptimizer for modularity.
 */

import { prisma } from '../../../utils/prisma';
import { Logger } from '../../../utils/logger';
import { ShoppingProductRef, ShoppingAnalysisData } from '../../ads/types';

/**
 * Match shopping ad products to WooCommerce inventory for margin analysis.
 * @param accountId - The account to analyze
 * @param shoppingData - Shopping campaign data with top products
 * @param suggestions - Array to push suggestions into
 */
export async function processProductAdMatch(
    accountId: string,
    shoppingData: ShoppingAnalysisData,
    suggestions: string[]
): Promise<void> {
    try {
        if (!shoppingData?.top_products?.length) return;

        // Get WooCommerce products with COGS data
        const wooProducts = await prisma.wooProduct.findMany({
            where: { accountId },
            select: {
                wooId: true,
                name: true,
                sku: true,
                price: true,
                cogs: true,
                rawData: true
            }
        });

        if (wooProducts.length === 0) return;

        // Create lookup maps
        const productsByName = new Map<string, typeof wooProducts[0]>();
        const productsBySku = new Map<string, typeof wooProducts[0]>();

        for (const p of wooProducts) {
            productsByName.set(p.name.toLowerCase().trim(), p);
            if (p.sku) productsBySku.set(p.sku.toLowerCase().trim(), p);
        }

        // Check top ad products for margin data
        for (const adProduct of shoppingData.top_products.slice(0, 5)) {
            const adTitle = (adProduct.product || '').toLowerCase().trim();
            const adId = adProduct.product_id;

            // Try to match by name or ID
            const matchedProduct = productsByName.get(adTitle) ||
                productsBySku.get(adId?.toString() || '');

            if (matchedProduct && matchedProduct.cogs && matchedProduct.price) {
                const price = parseFloat(matchedProduct.price?.toString() || '0');
                const cogs = parseFloat(matchedProduct.cogs?.toString() || '0');
                const margin = price > 0 ? ((price - cogs) / price) * 100 : 0;
                const roas = parseFloat(adProduct.roas?.replace('x', '') || '0');

                // High ROAS but low margin warning
                if (roas >= 2 && margin < 15) {
                    suggestions.push(
                        `⚠️ **Low Margin Alert**: "${adProduct.product}" has ${adProduct.roas} ROAS but only ${margin.toFixed(0)}% margin. ` +
                        `Net profit may be minimal. Consider focusing on higher-margin products.`
                    );
                }
            }
        }

        // Find top sellers NOT in ads (opportunity)
        // Only suggest in-stock products - Google Ads auto-disables out-of-stock items
        const topSellingProducts = await prisma.wooProduct.findMany({
            where: { accountId, stockStatus: { not: 'outofstock' } },
            take: 20,
            select: { name: true, rawData: true }
        });

        const adProductNames = new Set(
            (shoppingData.top_products || []).map((p) =>
                (p.product || '').toLowerCase().trim()
            )
        );

        // Find products that might be selling well but not in ads
        const potentialOpportunities = topSellingProducts.filter(p =>
            !adProductNames.has(p.name.toLowerCase().trim())
        ).slice(0, 3);

        if (potentialOpportunities.length > 0) {
            const names = potentialOpportunities.map(p => `"${p.name}"`).join(', ');
            suggestions.push(
                `🚀 **Ad Opportunity**: Products like ${names} are not in your top Shopping ads. ` +
                `Consider adding them to your campaigns.`
            );
        }

    } catch (error) {
        Logger.warn('Failed to process product-ad match', { error });
    }
}

/**
 * Search Campaign Advisor
 *
 * Generates actionable recommendations for Google Search campaigns.
 * Focused on keyword opportunities with real revenue projections based on historical data.
 * 
 * Part of AI Marketing Co-Pilot Enhancement - Search Campaign Suggestions.
 */

import { Logger } from '../../../utils/logger';
import { prisma } from '../../../utils/prisma';
import { REVENUE_STATUSES } from '../../../constants/orderStatus';
import {
    ActionableRecommendation,
    KeywordAction,
    BudgetAction
} from '../types/ActionableTypes';
import { AdCopyGenerator } from '../AdCopyGenerator';


interface SearchCampaignData {
    id: string;
    name: string;
    spend: number;
    clicks: number;
    impressions: number;
    conversions: number;
    revenue: number;
    roas: number;
    ctr: number;
    cpc: number;
}

interface SearchCampaignAdvisorResult {
    hasData: boolean;
    recommendations: ActionableRecommendation[];
    summary: {
        campaignsAnalyzed: number;
        totalSearchSpend: number;
        avgSearchRoas: number;
        opportunitiesFound: number;
    };
}


export class SearchCampaignAdvisor {

    /**
     * Analyze search campaigns and generate actionable recommendations.
     * Includes:
     * - New search campaign suggestions based on organic/site search data
     * - Budget scaling for high-performing search campaigns
     * - Keyword expansion opportunities
     */
    static async analyze(accountId: string): Promise<SearchCampaignAdvisorResult> {
        const result: SearchCampaignAdvisorResult = {
            hasData: false,
            recommendations: [],
            summary: {
                campaignsAnalyzed: 0,
                totalSearchSpend: 0,
                avgSearchRoas: 0,
                opportunitiesFound: 0
            }
        };

        try {
            // Get Google Ads accounts
            const googleAccounts = await prisma.adAccount.findMany({
                where: { accountId, platform: 'GOOGLE' },
                select: { id: true, name: true }
            });

            if (googleAccounts.length === 0) {
                // No Google Ads = Suggest creating a search campaign
                const suggestNewCampaign = await this.suggestNewSearchCampaign(accountId);
                if (suggestNewCampaign) {
                    result.recommendations.push(suggestNewCampaign);
                    result.hasData = true;
                }
                return result;
            }

            const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);

            // Aggregate search campaign performance
            const searchCampaigns: SearchCampaignData[] = [];

            for (const acc of googleAccounts) {
                // Fetch daily account snapshots which contain campaign breakdowns in JSON
                const snapshots = await prisma.adPerformanceSnapshot.findMany({
                    where: {
                        adAccountId: acc.id,
                        date: { gte: thirtyDaysAgo }
                    },
                    select: {
                        date: true,
                        campaignBreakdown: true
                    }
                });

                // Aggregate by campaign from the JSON breakdown
                const campaignMap = new Map<string, SearchCampaignData>();

                for (const snap of snapshots) {
                    if (!snap.campaignBreakdown) continue;

                    const breakdown = snap.campaignBreakdown as Record<string, any>;

                    Object.entries(breakdown).forEach(([campaignId, metrics]) => {
                        const campaignName = metrics.name || metrics.campaignName || 'Unknown Campaign';

                        // Filter for Search campaigns: name contains "Search" or "search", and NOT "Shopping"
                        const isSearch = (campaignName.toLowerCase().includes('search')) &&
                            !campaignName.toLowerCase().includes('shopping');

                        if (isSearch) {
                            const existing = campaignMap.get(campaignId) || {
                                id: campaignId,
                                name: campaignName,
                                spend: 0,
                                clicks: 0,
                                impressions: 0,
                                conversions: 0,
                                revenue: 0,
                                roas: 0,
                                ctr: 0,
                                cpc: 0
                            };

                            existing.spend += Number(metrics.spend || 0);
                            existing.clicks += Number(metrics.clicks || 0);
                            existing.impressions += Number(metrics.impressions || 0);
                            existing.conversions += Number(metrics.conversions || 0);
                            existing.revenue += Number(metrics.revenue || metrics.conversionValue || 0);

                            campaignMap.set(campaignId, existing);
                        }
                    });
                }

                // Calculate derived metrics
                for (const campaign of campaignMap.values()) {
                    campaign.roas = campaign.spend > 0 ? campaign.revenue / campaign.spend : 0;
                    campaign.ctr = campaign.impressions > 0 ? (campaign.clicks / campaign.impressions) * 100 : 0;
                    campaign.cpc = campaign.clicks > 0 ? campaign.spend / campaign.clicks : 0;

                    if (campaign.spend > 50) { // Only consider campaigns with meaningful spend
                        searchCampaigns.push(campaign);
                    }
                }
            }

            result.summary.campaignsAnalyzed = searchCampaigns.length;
            result.hasData = searchCampaigns.length > 0;

            if (searchCampaigns.length > 0) {
                result.summary.totalSearchSpend = searchCampaigns.reduce((s, c) => s + c.spend, 0);
                result.summary.avgSearchRoas = searchCampaigns.reduce((s, c) => s + c.roas, 0) / searchCampaigns.length;
            }

            // Generate recommendations

            // 1. Scale high-performing search campaigns
            const highPerformers = searchCampaigns
                .filter(c => c.roas >= 3 && c.spend >= 100)
                .sort((a, b) => b.roas - a.roas);

            for (const campaign of highPerformers.slice(0, 3)) {
                const increaseAmount = Math.round(campaign.spend * 0.3);
                const projectedRevenue = increaseAmount * campaign.roas;

                result.recommendations.push({
                    id: `search_scale_${campaign.id}_${Date.now()}`,
                    priority: 1,
                    category: 'budget',
                    headline: `🔥 Scale "${campaign.name}" - ${campaign.roas.toFixed(1)}x ROAS`,
                    explanation: `This search campaign is delivering exceptional results with a ${campaign.roas.toFixed(1)}x ROAS. ` +
                        `Increasing the budget by 30% is projected to generate an additional $${projectedRevenue.toFixed(0)} ` +
                        `in revenue over the next 30 days based on current performance.`,
                    dataPoints: [
                        `Current ROAS: ${campaign.roas.toFixed(2)}x`,
                        `30-day spend: $${campaign.spend.toFixed(0)}`,
                        `30-day revenue: $${campaign.revenue.toFixed(0)}`,
                        `Conversions: ${campaign.conversions}`,
                        `CPC: $${campaign.cpc.toFixed(2)}`
                    ],
                    action: {
                        actionType: 'budget_increase',
                        campaignId: campaign.id,
                        campaignName: campaign.name,
                        platform: 'google',
                        currentBudget: campaign.spend,
                        suggestedBudget: campaign.spend + increaseAmount,
                        changeAmount: increaseAmount,
                        changePercent: 30,
                        reason: 'High ROAS search campaign scaling'
                    } as BudgetAction,
                    confidence: Math.min(90, 60 + Math.floor(campaign.conversions / 2)),
                    estimatedImpact: {
                        revenueChange: projectedRevenue,
                        spendChange: increaseAmount,
                        timeframe: '30d'
                    },
                    platform: 'google',
                    source: 'SearchCampaignAdvisor',
                    tags: ['search', 'scaling', 'high-roas']
                });

                result.summary.opportunitiesFound++;
            }

            // 2. Pause/reduce underperforming search campaigns
            const underperformers = searchCampaigns
                .filter(c => c.roas < 1 && c.spend >= 100)
                .sort((a, b) => a.roas - b.roas);

            for (const campaign of underperformers.slice(0, 2)) {
                const savingsAmount = Math.round(campaign.spend * 0.5);

                result.recommendations.push({
                    id: `search_pause_${campaign.id}_${Date.now()}`,
                    priority: 1,
                    category: 'budget',
                    headline: `⚠️ Reduce "${campaign.name}" - Only ${campaign.roas.toFixed(2)}x ROAS`,
                    explanation: `This search campaign is underperforming with just ${campaign.roas.toFixed(2)}x ROAS ` +
                        `($${campaign.spend.toFixed(0)} spend, $${campaign.revenue.toFixed(0)} revenue). ` +
                        `Reducing budget by 50% will save $${savingsAmount.toFixed(0)} that can be reallocated to better-performing campaigns.`,
                    dataPoints: [
                        `Current ROAS: ${campaign.roas.toFixed(2)}x (below 1x breakeven)`,
                        `30-day spend: $${campaign.spend.toFixed(0)}`,
                        `30-day revenue: $${campaign.revenue.toFixed(0)}`,
                        `Estimated savings: $${savingsAmount.toFixed(0)}/month`
                    ],
                    action: {
                        actionType: 'budget_decrease',
                        campaignId: campaign.id,
                        campaignName: campaign.name,
                        platform: 'google',
                        currentBudget: campaign.spend,
                        suggestedBudget: campaign.spend - savingsAmount,
                        changeAmount: -savingsAmount,
                        changePercent: -50,
                        reason: 'Underperforming search campaign'
                    } as BudgetAction,
                    confidence: 80,
                    estimatedImpact: {
                        spendChange: -savingsAmount,
                        timeframe: '30d'
                    },
                    platform: 'google',
                    source: 'SearchCampaignAdvisor',
                    tags: ['search', 'efficiency', 'underperforming']
                });

                result.summary.opportunitiesFound++;
            }

            // 3. Suggest new search campaign if no search campaigns but has revenue
            if (searchCampaigns.length === 0) {
                const suggestNewCampaign = await this.suggestNewSearchCampaign(accountId);
                if (suggestNewCampaign) {
                    result.recommendations.push(suggestNewCampaign);
                    result.summary.opportunitiesFound++;
                }
            }

            // 4. Suggest keyword expansion based on high-performing campaigns
            for (const campaign of highPerformers.slice(0, 1)) {
                const keywordExpansion = await this.suggestKeywordExpansion(accountId, campaign);
                if (keywordExpansion) {
                    result.recommendations.push(keywordExpansion);
                    result.summary.opportunitiesFound++;
                }
            }

        } catch (error) {
            Logger.error('SearchCampaignAdvisor failed', { error, accountId });
        }

        return result;
    }

    /**
     * Suggest creating a new search campaign based on store data.
     */
    private static async suggestNewSearchCampaign(accountId: string): Promise<ActionableRecommendation | null> {
        try {
            const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);

            // Get recent revenue to estimate potential
            const revenueData = await prisma.wooOrder.aggregate({
                where: {
                    accountId,
                    status: { in: REVENUE_STATUSES },
                    dateCreated: { gte: thirtyDaysAgo }
                },
                _sum: { total: true },
                _count: { id: true }
            });

            const totalRevenue = Number(revenueData._sum.total) || 0;
            const orderCount = revenueData._count.id || 0;

            if (totalRevenue < 1000 || orderCount < 10) {
                return null; // Not enough data to recommend
            }

            // Get the account to get store URL
            const account = await prisma.account.findUnique({
                where: { id: accountId },
                select: {
                    wooUrl: true,
                    name: true,
                    domain: true
                }
            });

            const storeUrl = account?.wooUrl || 'https://yourstore.com';
            const storeName = account?.name || 'Your Store';
            const storeDomain = account?.domain || new URL(storeUrl).hostname.replace('www.', '');

            const avgOrderValue = totalRevenue / orderCount;
            const suggestedBudget = Math.round(avgOrderValue * 0.2 * (orderCount / 30));
            const minBudget = 10;
            const dailyBudget = Math.max(minBudget, Math.min(100, suggestedBudget));

            // Get top products with more details
            const recentOrders = await prisma.wooOrder.findMany({
                where: {
                    accountId,
                    status: { in: REVENUE_STATUSES },
                    dateCreated: { gte: thirtyDaysAgo }
                },
                select: { rawData: true }
            });

            const productFrequency: Record<string, {
                id: string;
                name: string;
                total: number;
                sku?: string;
                permalink?: string;
            }> = {};

            for (const order of recentOrders) {
                const data = order.rawData as any;
                if (data.line_items && Array.isArray(data.line_items)) {
                    for (const item of data.line_items) {
                        const pid = String(item.product_id || item.id || 'unknown');
                        if (!productFrequency[pid]) {
                            productFrequency[pid] = {
                                id: pid,
                                name: item.name,
                                total: 0,
                                sku: item.sku || '',
                                permalink: item.permalink || `${storeUrl}/product/${pid}`
                            };
                        }
                        productFrequency[pid].total += Number(item.total || 0);
                    }
                }
            }

            const topProducts = Object.values(productFrequency)
                .sort((a, b) => b.total - a.total)
                .slice(0, 5);

            // Get product categories for sitelinks from order rawData
            const categorySet = new Set<string>();
            for (const order of recentOrders) {
                const data = order.rawData as any;
                if (data.line_items && Array.isArray(data.line_items)) {
                    for (const item of data.line_items) {
                        const cats = item.categories as any[] | undefined;
                        if (cats && Array.isArray(cats)) {
                            cats.slice(0, 2).forEach((c: any) => {
                                if (c.name) categorySet.add(c.name);
                            });
                        }
                    }
                }
            }
            const categories = [...categorySet].slice(0, 4).map(name => ({
                name,
                slug: name.toLowerCase().replace(/\s+/g, '-')
            }));

            const productKeywords = topProducts
                .filter(p => p.name)
                .map(p => p.name!.split(' ').slice(0, 3).join(' '));

            // CPC estimation based on AOV — Keyword Planner requires Basic access
            // which we don't have, so always use the AOV-based estimate.
            const targetRoas = 2.0;
            const estimatedConversionRate = 0.02;
            // Formula: CPC = AOV * conversion_rate / target_ROAS
            const suggestedCpc = (avgOrderValue * estimatedConversionRate) / targetRoas;
            const maxCpc = suggestedCpc * 2;
            const cpcSource: 'estimated' = 'estimated';

            const projectedRevenue = dailyBudget * 30 * targetRoas;

            // Generate AI-powered ad copy (falls back to templates if AI unavailable)
            const adCopy = await AdCopyGenerator.generate(accountId, {
                storeName,
                storeUrl,
                topProducts: topProducts.map(p => ({
                    name: p.name || 'Product',
                    price: p.total / 10 // Rough estimate
                })),
                avgOrderValue,
                categories: categories.map(c => c.name)
            });

            const headlines = adCopy.headlines;
            const descriptions = adCopy.descriptions;

            // Generate sitelinks from categories
            const sitelinks = categories.map(cat => ({
                text: cat.name.slice(0, 25),
                description1: `Shop our ${cat.name} collection`,
                description2: 'Free shipping available',
                finalUrl: `${storeUrl}/product-category/${cat.slug}`
            }));

            // Add a "Best Sellers" sitelink
            sitelinks.unshift({
                text: 'Best Sellers',
                description1: 'Our most popular products',
                description2: 'Loved by customers',
                finalUrl: `${storeUrl}/shop?orderby=popularity`
            });

            return {
                id: `search_new_campaign_${Date.now()}`,
                priority: 2,
                category: 'structure',
                headline: `🚀 Launch Google Search Campaign - Est. +$${projectedRevenue.toLocaleString()}/mo`,
                explanation: `You're generating $${totalRevenue.toLocaleString()} in revenue but not running Google Search ads. ` +
                    `Search campaigns capture high-intent buyers actively looking for your products. ` +
                    `With your average order value of $${avgOrderValue.toFixed(0)}, a well-optimized search campaign ` +
                    `targeting your top-selling products could generate significant incremental revenue.`,
                dataPoints: [
                    `Current monthly revenue: $${totalRevenue.toLocaleString()}`,
                    `Average order value: $${avgOrderValue.toFixed(0)}`,
                    `Suggested daily budget: $${dailyBudget}/day`,
                    `Target products: ${productKeywords.slice(0, 3).join(', ')}`,
                    `Est. ${targetRoas}x ROAS (conservative for search)`
                ],
                action: {
                    actionType: 'add_keyword',
                    keyword: productKeywords[0] || 'your top product',
                    matchType: 'phrase',
                    suggestedCpc: suggestedCpc,
                    estimatedRoas: targetRoas,
                    estimatedClicks: Math.round(dailyBudget * 30 / suggestedCpc)
                } as KeywordAction,
                confidence: 70,
                estimatedImpact: {
                    revenueChange: projectedRevenue,
                    spendChange: dailyBudget * 30,
                    timeframe: '30d'
                },
                platform: 'google',
                source: 'SearchCampaignAdvisor',
                tags: ['search', 'new-campaign', 'high-intent'],
                implementationDetails: {
                    campaignName: `${storeName} - Search - Top Products`,
                    adGroupName: 'Best Sellers',
                    suggestedKeywords: productKeywords.slice(0, 5).map((keyword, idx) => ({
                        keyword,
                        matchType: idx === 0 ? 'exact' as const : 'phrase' as const,
                        suggestedCpc: suggestedCpc,
                        estimatedClicks: Math.round((dailyBudget * 30 / suggestedCpc) / productKeywords.length),
                        source: 'product_data' as const,
                        adGroupSuggestion: 'Best Sellers'
                    })),
                    budgetSpec: {
                        dailyBudget,
                        bidStrategy: 'maximize_conversions',
                        targetRoas: targetRoas,
                        maxCpc: maxCpc
                    },
                    adSpec: {
                        headlines: headlines.slice(0, 15),
                        descriptions: descriptions.slice(0, 4),
                        finalUrl: storeUrl,
                        displayPath: ['Shop', topProducts[0]?.name?.split(' ')[0]?.slice(0, 15) || 'Products'],
                        sitelinks: sitelinks.slice(0, 4)
                    },
                    steps: [
                        'Open Google Ads and click "+ New Campaign"',
                        'Select "Sales" as your campaign objective',
                        'Choose "Search" as the campaign type',
                        `Name your campaign: "${storeName} - Search - Top Products"`,
                        `Set your daily budget to $${dailyBudget}`,
                        `Choose "Maximize Conversions" with ${targetRoas}x target ROAS`,
                        `Create ad group named "Best Sellers"`,
                        `Add keywords: ${productKeywords.slice(0, 3).join(', ')} (use phrase and exact match)`,
                        'Create Responsive Search Ad with the provided headlines and descriptions',
                        `Set Final URL to: ${storeUrl}`,
                        'Add the suggested sitelink extensions',
                        'Review and launch - monitor for 7-14 days before optimization'
                    ],
                    estimatedTimeMinutes: 30,
                    difficulty: 'medium',
                    targetProducts: topProducts.slice(0, 3).map(p => ({
                        id: p.id,
                        name: p.name || 'Product',
                        sku: p.sku || '',
                        permalink: p.permalink
                    })),
                    structureNotes: `Campaign: "${storeName} - Search - Top Products" → Ad Group: "Best Sellers" → Keywords targeting your top-selling products. Start with phrase and exact match, add broad match after 2 weeks of data.`,

                    // Data source transparency
                    copySource: adCopy.source,
                    dataSourceNotes: {
                        cpc: `Estimated from your $${avgOrderValue.toFixed(0)} AOV × 2% conversion ÷ 2x ROAS.`,
                        keywords: `Derived from top-selling products.`,
                        copy: adCopy.source === 'ai'
                            ? 'AI-generated based on your store and products. Review and customize before use.'
                            : 'Generated from templates. Configure OpenRouter API key in Settings for AI-powered copy.'
                    }
                }
            };
        } catch (error) {
            Logger.warn('Failed to suggest new search campaign', { error });
            return null;
        }
    }

    /**
     * Suggest keyword expansion for a high-performing campaign.
     */
    private static async suggestKeywordExpansion(
        accountId: string,
        campaign: SearchCampaignData
    ): Promise<ActionableRecommendation | null> {
        try {
            const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);

            // Get site search terms that could be keywords
            const searchEvents = await prisma.analyticsEvent.findMany({
                where: {
                    session: { accountId },
                    type: 'search',
                    createdAt: { gte: thirtyDaysAgo }
                },
                select: { payload: true },
                take: 100
            });

            if (searchEvents.length < 10) return null;

            // Aggregate search terms
            const termCounts = new Map<string, number>();
            for (const event of searchEvents) {
                const term = (
                    (event.payload as any)?.query ||
                    (event.payload as any)?.search_term ||
                    (event.payload as any)?.q
                )?.toLowerCase().trim();

                if (term && term.length >= 3 && term.length <= 50) {
                    termCounts.set(term, (termCounts.get(term) || 0) + 1);
                }
            }

            // Find top search terms
            const sortedTerms = [...termCounts.entries()]
                .filter(([, count]) => count >= 3)
                .sort((a, b) => b[1] - a[1])
                .slice(0, 5);

            if (sortedTerms.length === 0) return null;

            const topTerm = sortedTerms[0][0];
            const totalSearches = sortedTerms.reduce((s, [, c]) => s + c, 0);

            // Estimate potential based on campaign performance
            const estimatedCpc = campaign.cpc || 1;
            const estimatedClicks = totalSearches * 0.02; // 2% capture rate
            const estimatedRevenue = estimatedClicks * (campaign.revenue / campaign.clicks) * 0.5; // 50% of campaign avg

            return {
                id: `search_expand_${campaign.id}_${Date.now()}`,
                priority: 2,
                category: 'optimization',
                headline: `🔍 Add "${topTerm}" to "${campaign.name}" - Based on ${totalSearches} site searches`,
                explanation: `Users are searching for "${topTerm}" on your site ${sortedTerms[0][1]} times in the past 30 days. ` +
                    `Adding this as a keyword to your high-performing search campaign "${campaign.name}" ` +
                    `could capture this high-intent traffic at your current ${campaign.roas.toFixed(1)}x ROAS.`,
                dataPoints: [
                    `Site searches for "${topTerm}": ${sortedTerms[0][1]}`,
                    `Total related searches: ${totalSearches}`,
                    `Campaign current ROAS: ${campaign.roas.toFixed(2)}x`,
                    `Suggested match type: phrase`,
                    `Est. CPC: $${estimatedCpc.toFixed(2)}`
                ],
                action: {
                    actionType: 'add_keyword',
                    keyword: topTerm,
                    matchType: 'phrase',
                    suggestedCpc: estimatedCpc,
                    estimatedRoas: campaign.roas * 0.8, // Slightly conservative
                    estimatedClicks: Math.round(estimatedClicks),
                    campaignId: campaign.id,
                    campaignName: campaign.name,
                    platform: 'google'
                } as KeywordAction,
                confidence: 65,
                estimatedImpact: {
                    revenueChange: estimatedRevenue,
                    timeframe: '30d'
                },
                platform: 'google',
                source: 'SearchCampaignAdvisor',
                tags: ['search', 'keyword-expansion', 'site-search'],
                implementationDetails: {
                    suggestedKeywords: sortedTerms.map(([term, count]) => ({
                        keyword: term,
                        matchType: 'phrase' as const,
                        suggestedCpc: estimatedCpc,
                        estimatedClicks: Math.round(count * 0.02),
                        source: 'site_search' as const,
                        adGroupSuggestion: campaign.name
                    })),
                    steps: [
                        `Open Google Ads and navigate to campaign "${campaign.name}"`,
                        'Go to Keywords section and click "+ Keywords"',
                        `Add "${topTerm}" as a phrase match keyword`,
                        `Set initial CPC bid to $${estimatedCpc.toFixed(2)}`,
                        'Save and monitor for 100+ impressions before adjusting',
                        'Consider adding the other suggested keywords from site search as well'
                    ],
                    estimatedTimeMinutes: 10,
                    difficulty: 'easy',
                    structureNotes: `Add to existing ad group in "${campaign.name}". Start with phrase match to balance reach and relevance.`
                }
            };
        } catch (error) {
            Logger.warn('Failed to suggest keyword expansion', { error });
            return null;
        }
    }
}

/**
 * Analysis Pipeline
 * 
 * Orchestrates all AI Marketing Co-Pilot analyzers, runs them in parallel,
 * and merges results into a unified format.
 */

import { Logger } from '../../../utils/logger';
import {
    BaseAnalysisResult,
    Suggestion,
    UnifiedAnalysis,
    AnalysisMetadata
} from '../types/AnalysisTypes';
import { ActionableRecommendation } from '../types/ActionableTypes';
import { BaseAnalyzer } from './BaseAnalyzer';

// Import individual analyzers
import { MultiPeriodAnalyzer } from './MultiPeriodAnalyzer';
import { CrossChannelAnalyzer } from './CrossChannelAnalyzer';
import { LTVAnalyzer } from './LTVAnalyzer';
import { FunnelAnalyzer } from './FunnelAnalyzer';
import { AudienceAnalyzer } from './AudienceAnalyzer';
import { ProductOpportunityAnalyzer } from './ProductOpportunityAnalyzer';
import { KeywordOpportunityAnalyzer } from './KeywordOpportunityAnalyzer';
import { NegativeKeywordAnalyzer } from './NegativeKeywordAnalyzer';
import { CannibalizationAnalyzer } from './CannibalizationAnalyzer';
import { MarketingStrategyAdvisor } from '../advisors/MarketingStrategyAdvisor';
import { SearchCampaignAdvisor } from '../advisors/SearchCampaignAdvisor';
import { getFeedbackContext, shouldFilterRecommendation } from '../feedback/FeedbackService';


export class AnalysisPipeline {

    /**
     * Run all analyzers and merge results.
     * @param accountId - The account to analyze
     * @param userContext - Optional business context from user (e.g., "Focus on summer products", "Upcoming sale")
     */
    static async runAll(accountId: string, userContext?: string): Promise<UnifiedAnalysis> {
        const startTime = Date.now();

        // Parse user context for priority keywords
        const contextKeywords = userContext ? this.parseContextKeywords(userContext) : [];

        // Run all analyzers in parallel — including SC↔Ads intelligence
        const [
            multiPeriod,
            crossChannel,
            ltv,
            funnel,
            audience,
            productOpp,
            keywordOpp,
            negativeKw,
            cannibalization,
            strategy,
            searchCampaigns
        ] = await Promise.all([
            MultiPeriodAnalyzer.analyze(accountId),
            CrossChannelAnalyzer.analyze(accountId),
            LTVAnalyzer.analyze(accountId),
            FunnelAnalyzer.analyze(accountId),
            AudienceAnalyzer.analyze(accountId),
            ProductOpportunityAnalyzer.analyze(accountId),
            KeywordOpportunityAnalyzer.analyze(accountId),
            NegativeKeywordAnalyzer.analyze(accountId),
            CannibalizationAnalyzer.analyze(accountId),
            MarketingStrategyAdvisor.analyze(accountId),  // Strategic layer
            SearchCampaignAdvisor.analyze(accountId)       // Search campaign layer
        ]);

        // Collect all suggestions
        const allSuggestions: Suggestion[] = [];
        const allActions: ActionableRecommendation[] = [];

        // Collect actionable recommendations from new analyzers
        if (productOpp.unpromotedProducts) allActions.push(...productOpp.unpromotedProducts);
        if (productOpp.underperformingProducts) allActions.push(...productOpp.underperformingProducts);
        if (productOpp.highPotentialProducts) allActions.push(...productOpp.highPotentialProducts);

        if (keywordOpp.keywordOpportunities) allActions.push(...keywordOpp.keywordOpportunities);
        if (keywordOpp.negativeKeywordOpportunities) allActions.push(...keywordOpp.negativeKeywordOpportunities);
        if (keywordOpp.bidAdjustments) allActions.push(...keywordOpp.bidAdjustments);

        // Negative keyword recommendations (SC↔Ads bridge)
        if (negativeKw.suggestions) allActions.push(...negativeKw.suggestions);

        // Cannibalization recommendations (SC↔Ads bridge)
        if (cannibalization.cannibalized) allActions.push(...cannibalization.cannibalized);
        if (cannibalization.paidOpportunities) allActions.push(...cannibalization.paidOpportunities);

        // Strategic recommendations (executive-level insights)
        if (strategy.recommendations) allActions.push(...strategy.recommendations);

        // Search campaign recommendations
        if (searchCampaigns.recommendations) allActions.push(...searchCampaigns.recommendations);

        // Collect actionable recommendations from existing updated analyzers
        if (multiPeriod.actionableRecommendations) {
            allActions.push(...multiPeriod.actionableRecommendations);
        }

        // Convert legacy string suggestions to new format
        this.convertAndAddSuggestions(allSuggestions, multiPeriod.suggestions, 'MultiPeriodAnalyzer');
        this.convertAndAddSuggestions(allSuggestions, crossChannel.suggestions, 'CrossChannelAnalyzer');
        this.convertAndAddSuggestions(allSuggestions, ltv.suggestions, 'LTVAnalyzer');
        this.convertAndAddSuggestions(allSuggestions, funnel.suggestions, 'FunnelAnalyzer');
        this.convertAndAddSuggestions(allSuggestions, audience.suggestions, 'AudienceAnalyzer');

        // Deduplicate and sort
        const dedupedSuggestions = this.deduplicateSuggestions(allSuggestions);
        const sortedSuggestions = this.sortSuggestions(dedupedSuggestions);

        // Sort actionable recommendations by priority
        const sortedActions = allActions.sort((a, b) => {
            if (a.priority !== b.priority) return a.priority - b.priority;
            return b.confidence - a.confidence;
        });

        // Apply feedback-based filtering
        const feedbackContext = await getFeedbackContext(accountId);
        let filteredActions = sortedActions.filter(
            rec => !shouldFilterRecommendation(rec, feedbackContext)
        );

        // Apply user context-based priority boosting
        if (contextKeywords.length > 0) {
            filteredActions = filteredActions.map(rec => {
                const headlineLower = rec.headline.toLowerCase();
                const matchesContext = contextKeywords.some(kw => headlineLower.includes(kw));

                if (matchesContext && rec.priority > 1) {
                    // Boost priority for items matching user's stated focus
                    return { ...rec, priority: (rec.priority - 1) as 1 | 2 | 3, contextBoosted: true };
                }
                return rec;
            });

            // Re-sort after boosting
            filteredActions.sort((a, b) => {
                if (a.priority !== b.priority) return a.priority - b.priority;
                return b.confidence - a.confidence;
            });
        }

        Logger.debug('Filtered recommendations based on feedback', {
            accountId,
            before: sortedActions.length,
            after: filteredActions.length,
            filteredOut: sortedActions.length - filteredActions.length,
            dismissedIdsCount: feedbackContext.dismissedIds.size,
            feedbackEntries: feedbackContext.totalFeedbackEntries,
            contextKeywords: contextKeywords.length
        });

        // Build unified result
        const hasData = multiPeriod.hasData || crossChannel.hasData ||
            ltv.hasData || funnel.hasData || audience.hasData ||
            productOpp.hasData || keywordOpp.hasData || negativeKw.hasData ||
            cannibalization.hasData || strategy.hasData || searchCampaigns.hasData;


        return {
            hasData,
            suggestions: sortedSuggestions,
            actionableRecommendations: filteredActions,
            results: {
                multiPeriod: this.toBaseResult(multiPeriod, 'MultiPeriodAnalyzer', accountId, startTime),
                crossChannel: this.toBaseResult(crossChannel, 'CrossChannelAnalyzer', accountId, startTime),
                ltv: this.toBaseResult(ltv, 'LTVAnalyzer', accountId, startTime),
                funnel: this.toBaseResult(funnel, 'FunnelAnalyzer', accountId, startTime),
                audience: this.toBaseResult(audience, 'AudienceAnalyzer', accountId, startTime),
            },
            summary: {
                totalSuggestions: sortedSuggestions.length,
                urgentCount: sortedSuggestions.filter(s => s.priority === 1).length,
                importantCount: sortedSuggestions.filter(s => s.priority === 2).length,
                infoCount: sortedSuggestions.filter(s => s.priority === 3).length,
                topConfidence: sortedSuggestions[0]?.confidence || 0,
                analyzersRun: 11,
                totalDurationMs: Date.now() - startTime,
            },
            metadata: {
                analyzedAt: new Date(),
                durationMs: Date.now() - startTime,
                source: 'AnalysisPipeline',
                accountId,
            },
        };
    }

    /**
     * Convert legacy string suggestions to Suggestion objects.
     */
    private static convertAndAddSuggestions(
        target: Suggestion[],
        source: any[],
        analyzerName: string
    ): void {
        for (let i = 0; i < source.length; i++) {
            const item = source[i];

            if (typeof item === 'string') {
                // Legacy string format
                target.push({
                    id: `${analyzerName}_${i}`,
                    text: item,
                    source: analyzerName,
                    priority: this.inferPriority(item),
                    category: 'optimization',
                    confidence: 50,
                });
            } else if (item && typeof item === 'object') {
                // Already a Suggestion-like object
                target.push({
                    id: item.id || `${analyzerName}_${i}`,
                    text: item.text || String(item),
                    source: item.source || analyzerName,
                    priority: item.priority || 3,
                    category: item.category || 'optimization',
                    confidence: item.confidence || 50,
                    explanation: item.explanation,
                    dataPoints: item.dataPoints,
                    platform: item.platform,
                });
            }
        }
    }

    /**
     * Infer priority from suggestion text.
     */
    private static inferPriority(text: string): 1 | 2 | 3 {
        const lower = text.toLowerCase();
        if (lower.includes('🚨') || lower.includes('critical') || lower.includes('crash')) {
            return 1;
        }
        if (lower.includes('⚠️') || lower.includes('warning') || lower.includes('declining')) {
            return 2;
        }
        return 3;
    }

    /**
     * Remove duplicate suggestions (same text).
     */
    private static deduplicateSuggestions(suggestions: Suggestion[]): Suggestion[] {
        const seen = new Set<string>();
        return suggestions.filter(s => {
            const key = s.text.substring(0, 100);
            if (seen.has(key)) return false;
            seen.add(key);
            return true;
        });
    }

    /**
     * Sort suggestions by priority (urgent first), then confidence (high first).
     */
    private static sortSuggestions(suggestions: Suggestion[]): Suggestion[] {
        return suggestions.sort((a, b) => {
            if (a.priority !== b.priority) return a.priority - b.priority;
            return b.confidence - a.confidence;
        });
    }

    /**
     * Convert analyzer result to BaseAnalysisResult format.
     */
    private static toBaseResult(
        result: any,
        source: string,
        accountId: string,
        startTime: number
    ): BaseAnalysisResult {
        return {
            hasData: result.hasData || false,
            suggestions: [], // Already extracted
            metadata: {
                analyzedAt: new Date(),
                durationMs: Date.now() - startTime,
                source,
                accountId,
            },
        };
    }

    /**
     * Parse user context for priority keywords.
     * Extracts product names, categories, and focus areas from user's notes.
     */
    private static parseContextKeywords(context: string): string[] {
        const keywords: string[] = [];
        const contextLower = context.toLowerCase();

        // Extract quoted terms (e.g., "summer products")
        const quotedMatches = context.match(/"([^"]+)"/g);
        if (quotedMatches) {
            for (const match of quotedMatches) {
                keywords.push(match.replace(/"/g, '').toLowerCase().trim());
            }
        }

        // Extract focus patterns
        const focusPatterns = [
            /focus on\s+(.+?)(?:\.|,|$)/gi,
            /prioritize\s+(.+?)(?:\.|,|$)/gi,
            /push\s+(.+?)(?:\.|,|$)/gi,
            /promote\s+(.+?)(?:\.|,|$)/gi
        ];

        for (const pattern of focusPatterns) {
            let match;
            while ((match = pattern.exec(contextLower)) !== null) {
                const term = match[1].trim();
                if (term.length > 2 && term.length < 50) {
                    keywords.push(term);
                }
            }
        }

        // Common product categories
        const categories = ['summer', 'winter', 'holiday', 'sale', 'clearance', 'new arrival', 'best seller', 'premium', 'budget'];
        for (const cat of categories) {
            if (contextLower.includes(cat)) {
                keywords.push(cat);
            }
        }

        // Return unique keywords
        return [...new Set(keywords)];
    }
}

/**
 * Audience Analyzer
 * 
 * Analyzes performance by device, geography, and other audience dimensions.
 * Provides bid adjustment recommendations based on segment performance.
 * 
 * Part of AI Marketing Co-Pilot Phase 3.
 */

import { prisma } from '../../../utils/prisma';
import { Logger } from '../../../utils/logger';


export interface SegmentPerformance {
    segment: string;
    orders: number;
    revenue: number;
    aov: number;
    revenueShare: number;
    performance: 'excellent' | 'good' | 'fair' | 'poor';
    recommendation?: string;
}

export interface DevicePerformance extends SegmentPerformance {
    device: 'mobile' | 'desktop' | 'tablet' | 'unknown';
    bidAdjustment?: number;  // e.g., +20% or -15%
}

export interface GeoPerformance extends SegmentPerformance {
    country: string;
    countryCode?: string;
}

export interface AudienceAnalysis {
    hasData: boolean;

    // Device breakdown
    devicePerformance: DevicePerformance[];
    deviceInsight: string;

    // Geographic breakdown
    geoPerformance: GeoPerformance[];
    geoInsight: string;

    // Time-based patterns (hour of day)
    peakHours: {
        hour: number;
        orders: number;
        revenue: number;
        isOptimal: boolean;
    }[];

    // Recommendations
    bidAdjustments: {
        dimension: 'device' | 'geo' | 'time';
        segment: string;
        currentPerformance: string;
        suggestedAdjustment: number;
        rationale: string;
    }[];

    suggestions: string[];
}


function normalizeDevice(device: string | null): 'mobile' | 'desktop' | 'tablet' | 'unknown' {
    if (!device) return 'unknown';
    const d = device.toLowerCase();
    if (d.includes('mobile') || d.includes('phone') || d.includes('ios') || d.includes('android')) return 'mobile';
    if (d.includes('tablet') || d.includes('ipad')) return 'tablet';
    if (d.includes('desktop') || d.includes('windows') || d.includes('mac')) return 'desktop';
    return 'unknown';
}

function assessPerformance(aov: number, avgAov: number): 'excellent' | 'good' | 'fair' | 'poor' {
    const ratio = avgAov > 0 ? aov / avgAov : 1;
    if (ratio >= 1.3) return 'excellent';
    if (ratio >= 1.0) return 'good';
    if (ratio >= 0.7) return 'fair';
    return 'poor';
}


export class AudienceAnalyzer {

    /**
     * Analyze audience performance by device, geography, and time.
     */
    static async analyze(accountId: string, days: number = 90): Promise<AudienceAnalysis> {
        const result: AudienceAnalysis = {
            hasData: false,
            devicePerformance: [],
            deviceInsight: '',
            geoPerformance: [],
            geoInsight: '',
            peakHours: [],
            bidAdjustments: [],
            suggestions: []
        };

        try {
            const startDate = new Date(Date.now() - days * 24 * 60 * 60 * 1000);

            // Get orders with attribution (device, geo from analytics sessions)
            // Cap to prevent OOM on stores with large order volumes
            const MAX_ORDERS = 20000;
            const orders = await prisma.wooOrder.findMany({
                where: {
                    accountId,
                    dateCreated: { gte: startDate },
                    status: { in: ['completed', 'processing'] }
                },
                select: {
                    wooId: true,
                    total: true,
                    dateCreated: true,
                    rawData: true
                },
                orderBy: { dateCreated: 'desc' },
                take: MAX_ORDERS
            });

            if (orders.length === 0) return result;

            // Get analytics sessions for device/geo enrichment
            const purchaseEvents = await prisma.analyticsEvent.findMany({
                where: {
                    session: { accountId },
                    type: 'purchase',
                    createdAt: { gte: startDate }
                },
                include: {
                    session: {
                        select: {
                            deviceType: true,
                            country: true,
                            city: true
                        }
                    }
                }
            });

            // Build order -> analytics map
            const orderAnalyticsMap = new Map<number, {
                device: string | null;
                country: string | null;
            }>();

            for (const event of purchaseEvents) {
                const orderId = (event.payload as any)?.orderId;
                if (orderId && event.session) {
                    orderAnalyticsMap.set(Number(orderId), {
                        device: event.session.deviceType,
                        country: event.session.country
                    });
                }
            }

            // Aggregate by device
            const deviceData = new Map<string, { orders: number; revenue: number }>();
            const geoData = new Map<string, { orders: number; revenue: number }>();
            const hourData = new Map<number, { orders: number; revenue: number }>();
            let totalRevenue = 0;
            let totalOrders = 0;

            for (const order of orders) {
                const total = parseFloat(String(order.total)) || 0;
                totalRevenue += total;
                totalOrders++;

                // Get analytics data or fallback to order data
                const analytics = orderAnalyticsMap.get(order.wooId);
                const rawData = order.rawData as any;

                // Device
                const device = normalizeDevice(analytics?.device || null);
                const deviceStats = deviceData.get(device) || { orders: 0, revenue: 0 };
                deviceStats.orders++;
                deviceStats.revenue += total;
                deviceData.set(device, deviceStats);

                // Geography - prefer analytics, fallback to billing country
                const country = analytics?.country || rawData?.billing?.country || 'Unknown';
                const geoStats = geoData.get(country) || { orders: 0, revenue: 0 };
                geoStats.orders++;
                geoStats.revenue += total;
                geoData.set(country, geoStats);

                // Hour of day
                const orderHour = new Date(order.dateCreated).getHours();
                const hourStats = hourData.get(orderHour) || { orders: 0, revenue: 0 };
                hourStats.orders++;
                hourStats.revenue += total;
                hourData.set(orderHour, hourStats);
            }

            const avgAov = totalOrders > 0 ? totalRevenue / totalOrders : 0;

            // Process device performance
            result.devicePerformance = Array.from(deviceData.entries())
                .map(([device, data]) => {
                    const aov = data.orders > 0 ? data.revenue / data.orders : 0;
                    const performance = assessPerformance(aov, avgAov);

                    return {
                        segment: device,
                        device: device as DevicePerformance['device'],
                        orders: data.orders,
                        revenue: Math.round(data.revenue * 100) / 100,
                        aov: Math.round(aov * 100) / 100,
                        revenueShare: totalRevenue > 0 ? Math.round((data.revenue / totalRevenue) * 1000) / 10 : 0,
                        performance,
                        bidAdjustment: this.calculateBidAdjustment(aov, avgAov)
                    };
                })
                .sort((a, b) => b.revenue - a.revenue);

            // Process geo performance
            result.geoPerformance = Array.from(geoData.entries())
                .map(([country, data]) => {
                    const aov = data.orders > 0 ? data.revenue / data.orders : 0;
                    return {
                        segment: country,
                        country,
                        orders: data.orders,
                        revenue: Math.round(data.revenue * 100) / 100,
                        aov: Math.round(aov * 100) / 100,
                        revenueShare: totalRevenue > 0 ? Math.round((data.revenue / totalRevenue) * 1000) / 10 : 0,
                        performance: assessPerformance(aov, avgAov)
                    };
                })
                .sort((a, b) => b.revenue - a.revenue)
                .slice(0, 10); // Top 10 countries

            // Process peak hours
            const maxHourOrders = Math.max(...Array.from(hourData.values()).map(h => h.orders), 1);
            result.peakHours = Array.from(hourData.entries())
                .map(([hour, data]) => ({
                    hour,
                    orders: data.orders,
                    revenue: Math.round(data.revenue * 100) / 100,
                    isOptimal: data.orders >= maxHourOrders * 0.7
                }))
                .sort((a, b) => a.hour - b.hour);

            result.hasData = true;

            // Generate insights
            this.generateDeviceInsight(result, avgAov);
            this.generateGeoInsight(result);
            this.generateBidAdjustments(result, avgAov);
            this.generateSuggestions(result);

        } catch (error) {
            Logger.error('AudienceAnalyzer failed', { error, accountId });
        }

        return result;
    }

    /**
     * Calculate suggested bid adjustment based on performance vs average.
     */
    private static calculateBidAdjustment(segmentAov: number, avgAov: number): number {
        if (avgAov === 0) return 0;
        const ratio = segmentAov / avgAov;

        // Cap adjustments at +50% / -50%
        if (ratio >= 1.5) return 50;
        if (ratio >= 1.3) return 30;
        if (ratio >= 1.1) return 15;
        if (ratio >= 0.9) return 0;
        if (ratio >= 0.7) return -15;
        if (ratio >= 0.5) return -30;
        return -50;
    }

    /**
     * Generate device performance insight.
     */
    private static generateDeviceInsight(result: AudienceAnalysis, avgAov: number): void {
        const mobile = result.devicePerformance.find(d => d.device === 'mobile');
        const desktop = result.devicePerformance.find(d => d.device === 'desktop');

        if (mobile && desktop && mobile.orders >= 10 && desktop.orders >= 10) {
            const mobileAov = mobile.aov;
            const desktopAov = desktop.aov;

            if (desktopAov > mobileAov * 1.3) {
                result.deviceInsight = `Desktop has ${Math.round((desktopAov / mobileAov - 1) * 100)}% higher AOV ($${desktopAov} vs $${mobileAov}). Consider higher bids for desktop.`;
            } else if (mobileAov > desktopAov * 1.3) {
                result.deviceInsight = `Mobile has ${Math.round((mobileAov / desktopAov - 1) * 100)}% higher AOV ($${mobileAov} vs $${desktopAov}). Your audience converts better on mobile.`;
            } else {
                result.deviceInsight = `Device performance is balanced. Mobile: $${mobileAov} AOV, Desktop: $${desktopAov} AOV.`;
            }
        } else if (mobile && mobile.revenueShare > 70) {
            result.deviceInsight = `${mobile.revenueShare}% of revenue from mobile. Ensure mobile experience is optimized.`;
        } else if (desktop && desktop.revenueShare > 70) {
            result.deviceInsight = `${desktop.revenueShare}% of revenue from desktop. Consider if mobile experience needs improvement.`;
        }
    }

    /**
     * Generate geographic insight.
     */
    private static generateGeoInsight(result: AudienceAnalysis): void {
        if (result.geoPerformance.length === 0) return;

        const top = result.geoPerformance[0];
        const topShare = top.revenueShare;

        if (topShare > 80) {
            result.geoInsight = `${topShare}% of revenue from ${top.country}. Consider expansion opportunities.`;
        } else if (result.geoPerformance.length >= 3) {
            const top3 = result.geoPerformance.slice(0, 3);
            const top3Share = top3.reduce((sum, g) => sum + g.revenueShare, 0);
            result.geoInsight = `Top 3 markets (${top3.map(g => g.country).join(', ')}) represent ${top3Share.toFixed(0)}% of revenue.`;
        }
    }

    /**
     * Generate bid adjustment recommendations.
     */
    private static generateBidAdjustments(result: AudienceAnalysis, avgAov: number): void {
        // Device bid adjustments
        for (const device of result.devicePerformance) {
            if (device.orders < 10) continue; // Need enough data
            if (device.bidAdjustment && device.bidAdjustment !== 0) {
                result.bidAdjustments.push({
                    dimension: 'device',
                    segment: device.device,
                    currentPerformance: `$${device.aov} AOV (${device.performance})`,
                    suggestedAdjustment: device.bidAdjustment,
                    rationale: device.bidAdjustment > 0
                        ? `${device.device} has higher AOV than average - increase bids to capture more`
                        : `${device.device} underperforms - reduce bids or improve experience`
                });
            }
        }

        // Geo bid adjustments for top performers
        for (const geo of result.geoPerformance.slice(0, 5)) {
            if (geo.orders < 5) continue;
            const adjustment = this.calculateBidAdjustment(geo.aov, avgAov);
            if (adjustment >= 20) {
                result.bidAdjustments.push({
                    dimension: 'geo',
                    segment: geo.country,
                    currentPerformance: `$${geo.aov} AOV (${geo.performance})`,
                    suggestedAdjustment: adjustment,
                    rationale: `${geo.country} has strong AOV - consider geo-targeting expansion`
                });
            }
        }
    }

    /**
     * Generate audience-based suggestions.
     */
    private static generateSuggestions(result: AudienceAnalysis): void {
        const { devicePerformance, geoPerformance, peakHours, bidAdjustments, deviceInsight, geoInsight } = result;

        // Device insight
        if (deviceInsight) {
            result.suggestions.push(`📱 **Device Performance**: ${deviceInsight}`);
        }

        // Geo insight
        if (geoInsight) {
            result.suggestions.push(`🌍 **Geographic Performance**: ${geoInsight}`);
        }

        // High-performing device bid recommendation
        const highPerfDevice = bidAdjustments.find(b => b.dimension === 'device' && b.suggestedAdjustment >= 20);
        if (highPerfDevice) {
            result.suggestions.push(
                `📈 **Bid Opportunity**: ${highPerfDevice.segment} ${highPerfDevice.currentPerformance}. ` +
                `Consider +${highPerfDevice.suggestedAdjustment}% bid adjustment.`
            );
        }

        // Underperforming device warning
        const lowPerfDevice = bidAdjustments.find(b => b.dimension === 'device' && b.suggestedAdjustment <= -20);
        if (lowPerfDevice) {
            result.suggestions.push(
                `⚠️ **${lowPerfDevice.segment} Underperforming**: ${lowPerfDevice.currentPerformance}. ` +
                `Consider ${lowPerfDevice.suggestedAdjustment}% bid adjustment or UX improvements.`
            );
        }

        // Peak hours insight
        const peakHoursList = peakHours.filter(h => h.isOptimal);
        if (peakHoursList.length > 0 && peakHoursList.length < 12) {
            const hours = peakHoursList.map(h =>
                `${h.hour.toString().padStart(2, '0')}:00`
            ).join(', ');
            result.suggestions.push(
                `⏰ **Peak Buying Hours**: Most orders between ${hours}. Consider ad scheduling to optimize spend.`
            );
        }

        // Geo expansion opportunity
        const highPerfGeo = geoPerformance.find(g => g.performance === 'excellent' && g.revenueShare < 30);
        if (highPerfGeo) {
            result.suggestions.push(
                `🎯 **Expansion Opportunity**: ${highPerfGeo.country} has excellent AOV ($${highPerfGeo.aov}) ` +
                `but only ${highPerfGeo.revenueShare}% revenue share. Consider increasing targeting.`
            );
        }
    }
}

/**
 * Cannibalization Analyzer
 *
 * Detects paid/organic overlap where you're paying for clicks
 * that your organic listing would already capture.
 *
 * Why this matters: most ecommerce sites waste 10-25% of search ad spend
 * on terms where they already rank in the top 3 organically.
 */

import { Logger } from '../../../utils/logger';
import { SearchToAdsIntelligenceService, OverlapQuery } from '../../ads/SearchToAdsIntelligenceService';
import {
    ActionableRecommendation,
    KeywordAction,
    createKeywordHeadline
} from '../types/ActionableTypes';

interface CannibalizationResult {
    hasData: boolean;
    cannibalized: ActionableRecommendation[];
    paidOpportunities: ActionableRecommendation[];
    summary: {
        totalOverlapQueries: number;
        cannibalizationCount: number;
        paidOpportunityCount: number;
        estimatedMonthlyWaste: number;
    };
}

export class CannibalizationAnalyzer {

    /**
     * Analyze organic/paid overlap for cannibalization and paid opportunities.
     *
     * Two output types:
     * - cannibalized: keywords where organic dominates → recommend pausing paid
     * - paidOpportunities: keywords where organic is weak → recommend increasing paid
     */
    static async analyze(accountId: string): Promise<CannibalizationResult> {
        const result: CannibalizationResult = {
            hasData: false,
            cannibalized: [],
            paidOpportunities: [],
            summary: { totalOverlapQueries: 0, cannibalizationCount: 0, paidOpportunityCount: 0, estimatedMonthlyWaste: 0 }
        };

        try {
            const correlation = await SearchToAdsIntelligenceService.getCorrelation(accountId);
            if (correlation.overlap.length === 0) return result;

            result.hasData = true;
            result.summary.totalOverlapQueries = correlation.overlap.length;

            for (const overlap of correlation.overlap) {
                if (overlap.cannibalizationScore >= 50) {
                    result.cannibalized.push(this.buildCannibalizationRec(overlap));
                    result.summary.estimatedMonthlyWaste += overlap.estimatedWastedSpend;
                } else if (overlap.organic.position > 10 && overlap.paid.roas >= 2) {
                    // Organic is weak but paid converts well → increase paid
                    result.paidOpportunities.push(this.buildPaidOpportunityRec(overlap));
                }
            }

            result.summary.cannibalizationCount = result.cannibalized.length;
            result.summary.paidOpportunityCount = result.paidOpportunities.length;
            result.summary.estimatedMonthlyWaste = Math.round(result.summary.estimatedMonthlyWaste * 100) / 100;

        } catch (error) {
            Logger.error('CannibalizationAnalyzer failed', { error, accountId });
        }

        return result;
    }

    /** Build a "pause this keyword" recommendation for cannibalized queries */
    private static buildCannibalizationRec(overlap: OverlapQuery): ActionableRecommendation {
        const action: KeywordAction = {
            actionType: 'pause_keyword',
            keyword: overlap.query,
            matchType: 'exact',
            currentCpc: overlap.paid.cpc,
            suggestedCpc: 0,
            estimatedRoas: 0,
            estimatedClicks: overlap.paid.clicks
        };

        return {
            id: `cannibal_${overlap.query.replace(/\s+/g, '_').substring(0, 20)}`,
            priority: overlap.estimatedWastedSpend >= 50 ? 1 : overlap.estimatedWastedSpend >= 20 ? 2 : 3,
            category: 'optimization',
            headline: `⚠️ Cannibalized: "${overlap.query}" — save ~$${overlap.estimatedWastedSpend.toFixed(0)}/mo`,
            explanation: `You rank #${overlap.organic.position.toFixed(0)} organically for "${overlap.query}" with ` +
                `${overlap.organic.ctr.toFixed(1)}% CTR, but you're also paying $${overlap.paid.cpc.toFixed(2)}/click ` +
                `for this term. Approx. $${overlap.estimatedWastedSpend.toFixed(2)} of your monthly paid spend on this ` +
                `keyword would come through organic clicks for free.`,
            dataPoints: [
                `Organic: Position #${overlap.organic.position.toFixed(1)}, ${overlap.organic.ctr.toFixed(1)}% CTR, ${overlap.organic.clicks} clicks`,
                `Paid: $${overlap.paid.spend.toFixed(2)} spend, ${overlap.paid.clicks} clicks, $${overlap.paid.cpc.toFixed(2)} CPC`,
                `Paid ROAS: ${overlap.paid.roas.toFixed(2)}x`,
                `Cannibalization score: ${overlap.cannibalizationScore}/100`,
                `Est. monthly savings: $${overlap.estimatedWastedSpend.toFixed(2)}`
            ],
            action,
            confidence: Math.min(90, overlap.cannibalizationScore),
            estimatedImpact: {
                spendChange: -overlap.estimatedWastedSpend,
                timeframe: '30d'
            },
            platform: 'google',
            source: 'CannibalizationAnalyzer',
            tags: ['cannibalization', 'waste-reduction', 'organic-overlap']
        };
    }

    /** Build an "increase bid" recommendation for queries where organic is weak */
    private static buildPaidOpportunityRec(overlap: OverlapQuery): ActionableRecommendation {
        const suggestedCpc = Math.min(overlap.paid.cpc * 1.3, 5); // 30% increase, capped at $5

        const action: KeywordAction = {
            actionType: 'adjust_bid',
            keyword: overlap.query,
            matchType: 'exact',
            currentCpc: overlap.paid.cpc,
            suggestedCpc,
            estimatedRoas: overlap.paid.roas,
            estimatedClicks: Math.round(overlap.paid.clicks * 1.3)
        };

        return {
            id: `paid_opp_${overlap.query.replace(/\s+/g, '_').substring(0, 20)}`,
            priority: overlap.paid.roas >= 4 ? 1 : 2,
            category: 'optimization',
            headline: `🚀 Increase bid: "${overlap.query}" — ${overlap.paid.roas.toFixed(1)}x ROAS, weak organic`,
            explanation: `"${overlap.query}" converts at ${overlap.paid.roas.toFixed(1)}x ROAS through paid search, ` +
                `but your organic position is #${overlap.organic.position.toFixed(0)} — too low to rely on. ` +
                `Consider increasing the bid to capture more of this high-converting traffic.`,
            dataPoints: [
                `Organic position: #${overlap.organic.position.toFixed(1)} (weak)`,
                `Paid ROAS: ${overlap.paid.roas.toFixed(2)}x`,
                `Current CPC: $${overlap.paid.cpc.toFixed(2)} → suggested: $${suggestedCpc.toFixed(2)}`,
                `${overlap.paid.conversions} paid conversions this period`
            ],
            action,
            confidence: 60,
            estimatedImpact: {
                revenueChange: overlap.paid.conversions * (overlap.paid.roas * overlap.paid.cpc) * 0.3,
                roasChange: overlap.paid.roas,
                timeframe: '30d'
            },
            platform: 'google',
            source: 'CannibalizationAnalyzer',
            tags: ['bid-optimization', 'paid-opportunity', 'organic-weak']
        };
    }
}

/**
 * Cross-Channel Analyzer
 * 
 * Correlates Google and Meta ad performance using attribution data.
 * Identifies assisted conversions and provides cross-platform budget recommendations.
 * 
 * Part of AI Marketing Co-Pilot Phase 2.
 */

import { prisma } from '../../../utils/prisma';
import { Logger } from '../../../utils/logger';


export interface CrossChannelInsight {
    hasData: boolean;

    // Revenue attribution by channel
    channelPerformance: {
        channel: string;
        revenue: number;
        orders: number;
        aov: number;
        revenueShare: number;  // Percentage
    }[];

    // Channel interaction patterns
    assistedConversions: {
        googleAssistedMeta: number;   // First touch Google, converted on Meta
        metaAssistedGoogle: number;   // First touch Meta, converted on Google
        organicAssisted: number;      // First touch organic, paid conversion
    };

    // Customer journey insights
    channelOverlap: {
        multiChannel: number;         // Customers who interacted with multiple channels
        singleChannel: number;
        multiChannelRevenue: number;
        avgTouchpointsBeforePurchase: number;
    };

    // Budget recommendations
    budgetRecommendation: {
        currentSplit: { google: number; meta: number; organic: number };
        recommendedSplit: { google: number; meta: number };
        rationale: string;
        confidence: 'low' | 'medium' | 'high';
    } | null;

    suggestions: string[];
}


import { normalizeChannel } from '../utils/ChannelUtils';

// Alias for backwards compatibility
const normalizeSource = normalizeChannel;


export class CrossChannelAnalyzer {

    /**
     * Analyze cross-channel attribution and performance.
     */
    static async analyze(accountId: string, days: number = 90): Promise<CrossChannelInsight> {
        const result: CrossChannelInsight = {
            hasData: false,
            channelPerformance: [],
            assistedConversions: {
                googleAssistedMeta: 0,
                metaAssistedGoogle: 0,
                organicAssisted: 0
            },
            channelOverlap: {
                multiChannel: 0,
                singleChannel: 0,
                multiChannelRevenue: 0,
                avgTouchpointsBeforePurchase: 1
            },
            budgetRecommendation: null,
            suggestions: []
        };

        try {
            const startDate = new Date(Date.now() - days * 24 * 60 * 60 * 1000);

            // Get all orders with their attribution
            // Cap to prevent OOM on stores with large order volumes
            const MAX_ORDERS = 20000;
            const orders = await prisma.wooOrder.findMany({
                where: {
                    accountId,
                    dateCreated: { gte: startDate },
                    status: { in: ['completed', 'processing'] }
                },
                select: {
                    wooId: true,
                    total: true,
                    dateCreated: true,
                    rawData: true
                },
                orderBy: { dateCreated: 'desc' },
                take: MAX_ORDERS
            });

            if (orders.length === 0) {
                return result;
            }

            // Get purchase events with attribution
            const purchaseEvents = await prisma.analyticsEvent.findMany({
                where: {
                    session: { accountId },
                    type: 'purchase',
                    createdAt: { gte: startDate }
                },
                include: {
                    session: {
                        select: {
                            firstTouchSource: true,
                            lastTouchSource: true,
                            utmSource: true,
                            utmMedium: true,
                            utmCampaign: true
                        }
                    }
                }
            });

            // Build order -> attribution map
            const orderAttributionMap = new Map<number, {
                firstTouch: string;
                lastTouch: string;
                utmSource: string | null;
                utmCampaign: string | null;
            }>();

            for (const event of purchaseEvents) {
                const orderId = (event.payload as any)?.orderId || (event.payload as any)?.order_id;
                if (orderId && event.session) {
                    orderAttributionMap.set(Number(orderId), {
                        firstTouch: normalizeSource(event.session.firstTouchSource),
                        lastTouch: normalizeSource(event.session.lastTouchSource),
                        utmSource: event.session.utmSource,
                        utmCampaign: event.session.utmCampaign
                    });
                }
            }

            // Calculate channel performance
            const channelRevenue = new Map<string, { revenue: number; orders: number }>();
            let totalRevenue = 0;
            let attributedOrders = 0;

            for (const order of orders) {
                const total = parseFloat(String(order.total)) || 0;
                totalRevenue += total;

                const attribution = orderAttributionMap.get(order.wooId);
                const channel = attribution?.lastTouch || 'direct';

                const current = channelRevenue.get(channel) || { revenue: 0, orders: 0 };
                current.revenue += total;
                current.orders += 1;
                channelRevenue.set(channel, current);

                if (attribution) {
                    attributedOrders++;

                    // Count assisted conversions
                    if (attribution.firstTouch !== attribution.lastTouch) {
                        result.channelOverlap.multiChannel++;
                        result.channelOverlap.multiChannelRevenue += total;

                        // Track cross-platform assists
                        if (attribution.firstTouch === 'google' && attribution.lastTouch === 'meta') {
                            result.assistedConversions.googleAssistedMeta++;
                        } else if (attribution.firstTouch === 'meta' && attribution.lastTouch === 'google') {
                            result.assistedConversions.metaAssistedGoogle++;
                        } else if (
                            (attribution.firstTouch === 'organic_search' || attribution.firstTouch === 'direct') &&
                            (attribution.lastTouch === 'google' || attribution.lastTouch === 'meta')
                        ) {
                            result.assistedConversions.organicAssisted++;
                        }
                    } else {
                        result.channelOverlap.singleChannel++;
                    }
                }
            }

            // Convert to performance array
            result.channelPerformance = Array.from(channelRevenue.entries())
                .map(([channel, data]) => ({
                    channel,
                    revenue: Math.round(data.revenue * 100) / 100,
                    orders: data.orders,
                    aov: data.orders > 0 ? Math.round((data.revenue / data.orders) * 100) / 100 : 0,
                    revenueShare: totalRevenue > 0 ? Math.round((data.revenue / totalRevenue) * 1000) / 10 : 0
                }))
                .sort((a, b) => b.revenue - a.revenue);

            result.hasData = true;

            // Calculate average touchpoints (simplified - assume multi-channel = 2, single = 1)
            const totalCustomers = result.channelOverlap.multiChannel + result.channelOverlap.singleChannel;
            if (totalCustomers > 0) {
                result.channelOverlap.avgTouchpointsBeforePurchase =
                    Math.round(((result.channelOverlap.multiChannel * 2) + result.channelOverlap.singleChannel) / totalCustomers * 10) / 10;
            }

            // Generate budget recommendation
            result.budgetRecommendation = this.generateBudgetRecommendation(result.channelPerformance, totalRevenue);

            // Generate suggestions
            this.generateSuggestions(result);

        } catch (error) {
            Logger.error('CrossChannelAnalyzer failed', { error, accountId });
        }

        return result;
    }

    /**
     * Generate budget allocation recommendation based on channel performance.
     */
    private static generateBudgetRecommendation(
        channelPerformance: CrossChannelInsight['channelPerformance'],
        totalRevenue: number
    ): CrossChannelInsight['budgetRecommendation'] {
        const googleData = channelPerformance.find(c => c.channel === 'google');
        const metaData = channelPerformance.find(c => c.channel === 'meta');

        if (!googleData && !metaData) return null;

        const googleRevenue = googleData?.revenue || 0;
        const metaRevenue = metaData?.revenue || 0;
        const organicRevenue = channelPerformance
            .filter(c => !['google', 'meta'].includes(c.channel))
            .reduce((sum, c) => sum + c.revenue, 0);

        const paidTotal = googleRevenue + metaRevenue;
        if (paidTotal === 0) return null;

        const currentSplit = {
            google: Math.round((googleRevenue / totalRevenue) * 100),
            meta: Math.round((metaRevenue / totalRevenue) * 100),
            organic: Math.round((organicRevenue / totalRevenue) * 100)
        };

        // Simple heuristic: allocate more to higher-performing channel
        const googleAov = googleData?.aov || 0;
        const metaAov = metaData?.aov || 0;

        let recommendedSplit: { google: number; meta: number };
        let rationale: string;

        // If one channel significantly outperforms (30%+ higher AOV)
        if (googleAov > metaAov * 1.3 && googleRevenue > 0) {
            recommendedSplit = {
                google: Math.min(70, currentSplit.google + 10),
                meta: Math.max(30, currentSplit.meta - 10)
            };
            rationale = `Google has ${Math.round((googleAov / metaAov - 1) * 100)}% higher AOV ($${googleAov} vs $${metaAov}). Consider shifting budget toward Google.`;
        } else if (metaAov > googleAov * 1.3 && metaRevenue > 0) {
            recommendedSplit = {
                google: Math.max(30, currentSplit.google - 10),
                meta: Math.min(70, currentSplit.meta + 10)
            };
            rationale = `Meta has ${Math.round((metaAov / googleAov - 1) * 100)}% higher AOV ($${metaAov} vs $${googleAov}). Consider shifting budget toward Meta.`;
        } else {
            recommendedSplit = {
                google: 50,
                meta: 50
            };
            rationale = `Both channels perform similarly (Google AOV: $${googleAov}, Meta AOV: $${metaAov}). Maintain balanced allocation.`;
        }

        // Normalize to 100%
        const total = recommendedSplit.google + recommendedSplit.meta;
        recommendedSplit.google = Math.round((recommendedSplit.google / total) * 100);
        recommendedSplit.meta = 100 - recommendedSplit.google;

        return {
            currentSplit,
            recommendedSplit,
            rationale,
            confidence: paidTotal > 5000 ? 'high' : paidTotal > 1000 ? 'medium' : 'low'
        };
    }

    /**
     * Generate actionable suggestions from cross-channel analysis.
     */
    private static generateSuggestions(result: CrossChannelInsight): void {
        const { assistedConversions, channelOverlap, budgetRecommendation, channelPerformance } = result;

        // Multi-channel journey insight
        const multiChannelPct = channelOverlap.multiChannel + channelOverlap.singleChannel > 0
            ? Math.round((channelOverlap.multiChannel / (channelOverlap.multiChannel + channelOverlap.singleChannel)) * 100)
            : 0;

        if (multiChannelPct > 20) {
            result.suggestions.push(
                `🔀 **Multi-Channel Journeys**: ${multiChannelPct}% of customers interact with multiple channels before purchase. ` +
                `Don't evaluate channels in isolation - they work together.`
            );
        }

        // Cross-platform assists
        const totalAssists = assistedConversions.googleAssistedMeta + assistedConversions.metaAssistedGoogle;
        if (totalAssists > 5) {
            if (assistedConversions.googleAssistedMeta > assistedConversions.metaAssistedGoogle * 2) {
                result.suggestions.push(
                    `🔄 **Google Assists Meta**: ${assistedConversions.googleAssistedMeta} customers discovered you via Google but converted through Meta. ` +
                    `Google may be undervalued in last-click attribution.`
                );
            } else if (assistedConversions.metaAssistedGoogle > assistedConversions.googleAssistedMeta * 2) {
                result.suggestions.push(
                    `🔄 **Meta Assists Google**: ${assistedConversions.metaAssistedGoogle} customers discovered you via Meta but converted through Google. ` +
                    `Meta may be undervalued in last-click attribution.`
                );
            }
        }

        // Budget recommendation
        if (budgetRecommendation && budgetRecommendation.confidence !== 'low') {
            result.suggestions.push(
                `💰 **Budget Allocation**: ${budgetRecommendation.rationale} ` +
                `(Confidence: ${budgetRecommendation.confidence})`
            );
        }

        // Channel concentration warning
        const topChannel = channelPerformance[0];
        if (topChannel && topChannel.revenueShare > 70) {
            result.suggestions.push(
                `⚠️ **Channel Concentration**: ${topChannel.revenueShare}% of revenue comes from ${topChannel.channel}. ` +
                `Consider diversifying to reduce platform dependency risk.`
            );
        }
    }
}

/**
 * Funnel Analyzer
 * 
 * Provides funnel-aware campaign analysis with stage-appropriate metrics.
 * Awareness campaigns are judged on reach/CPM, conversion campaigns on ROAS.
 * 
 * Part of AI Marketing Co-Pilot Phase 3.
 */

import { prisma } from '../../../utils/prisma';
import { Logger } from '../../../utils/logger';
import { AdsService } from '../../ads';
import { CampaignInsight } from '../../ads/types';
import { getCampaignType, getExpectedRoasThreshold, isBrandCampaign, CampaignType } from '../AdContext';


export type FunnelStage = 'awareness' | 'consideration' | 'conversion' | 'retention';

export interface FunnelStageMetrics {
    primaryMetric: string;
    secondaryMetric: string;
    benchmarks: {
        metric: string;
        good: number;
        warning: number;
        description: string;
    }[];
}

export interface CampaignFunnelAnalysis {
    campaignId: string;
    campaignName: string;
    platform: 'google' | 'meta';
    funnelStage: FunnelStage;
    campaignType: CampaignType;

    // Raw metrics
    spend: number;
    impressions: number;
    clicks: number;
    conversions: number;
    revenue: number;

    // Calculated metrics
    roas: number;
    cpm: number;
    ctr: number;
    cpc: number;
    cpa: number;

    // Funnel-aware assessment
    performance: 'excellent' | 'good' | 'fair' | 'poor';
    primaryMetricValue: number;
    primaryMetricAssessment: string;
    issues: string[];
    recommendations: string[];
}

export interface FunnelAnalysis {
    hasData: boolean;

    // Campaign breakdown by funnel stage
    byStageSummary: {
        stage: FunnelStage;
        campaigns: number;
        spend: number;
        spendShare: number;
        avgPerformance: number;
    }[];

    // Individual campaign analysis
    campaigns: CampaignFunnelAnalysis[];

    // Funnel health metrics
    funnelHealth: {
        hasAwareness: boolean;
        hasConsideration: boolean;
        hasConversion: boolean;
        balance: 'healthy' | 'top-heavy' | 'bottom-heavy' | 'unbalanced';
        recommendation: string;
    };

    // Mis-judged campaigns (judged on wrong metrics)
    misjudgedCampaigns: {
        campaignName: string;
        issue: string;
        correctMetric: string;
    }[];

    suggestions: string[];
}


const FUNNEL_STAGE_METRICS: Record<FunnelStage, FunnelStageMetrics> = {
    awareness: {
        primaryMetric: 'cpm',
        secondaryMetric: 'reach',
        benchmarks: [
            { metric: 'cpm', good: 15, warning: 30, description: 'Cost per 1000 impressions' },
            { metric: 'ctr', good: 0.5, warning: 0.2, description: 'Click-through rate %' },
            { metric: 'frequency', good: 2, warning: 5, description: 'Avg times shown per user' }
        ]
    },
    consideration: {
        primaryMetric: 'cpc',
        secondaryMetric: 'ctr',
        benchmarks: [
            { metric: 'cpc', good: 1.5, warning: 3, description: 'Cost per click' },
            { metric: 'ctr', good: 2, warning: 0.8, description: 'Click-through rate %' },
            { metric: 'engagement_rate', good: 5, warning: 2, description: 'Engagement rate %' }
        ]
    },
    conversion: {
        primaryMetric: 'roas',
        secondaryMetric: 'cpa',
        benchmarks: [
            { metric: 'roas', good: 3, warning: 1.5, description: 'Return on ad spend' },
            { metric: 'cpa', good: 30, warning: 60, description: 'Cost per acquisition' },
            { metric: 'conversion_rate', good: 3, warning: 1, description: 'Conversion rate %' }
        ]
    },
    retention: {
        primaryMetric: 'roas',
        secondaryMetric: 'cpa',
        benchmarks: [
            { metric: 'roas', good: 5, warning: 2, description: 'Return on ad spend (remarketing)' },
            { metric: 'cpa', good: 20, warning: 40, description: 'Cost per re-acquisition' },
            { metric: 'frequency', good: 3, warning: 8, description: 'Frequency cap adherence' }
        ]
    }
};


function mapCampaignTypeToFunnelStage(type: CampaignType): FunnelStage {
    switch (type) {
        case 'awareness':
        case 'video':
        case 'display':
            return 'awareness';
        case 'prospecting':
        case 'search':
            return 'consideration';
        case 'shopping':
        case 'conversion':
        case 'brand':
            return 'conversion';
        case 'remarketing':
            return 'retention';
        default:
            return 'consideration'; // Default to middle funnel
    }
}

function assessPerformance(
    campaign: CampaignFunnelAnalysis,
    stageMetrics: FunnelStageMetrics
): 'excellent' | 'good' | 'fair' | 'poor' {
    const primary = stageMetrics.primaryMetric;
    let value: number;

    switch (primary) {
        case 'roas':
            value = campaign.roas;
            break;
        case 'cpm':
            value = campaign.cpm;
            break;
        case 'cpc':
            value = campaign.cpc;
            break;
        case 'cpa':
            value = campaign.cpa;
            break;
        default:
            value = campaign.roas;
    }

    const benchmark = stageMetrics.benchmarks.find(b => b.metric === primary);
    if (!benchmark) return 'fair';

    // For metrics where lower is better (cpm, cpc, cpa)
    if (['cpm', 'cpc', 'cpa'].includes(primary)) {
        if (value <= benchmark.good) return 'excellent';
        if (value <= benchmark.good * 1.5) return 'good';
        if (value <= benchmark.warning) return 'fair';
        return 'poor';
    }

    // For metrics where higher is better (roas, ctr)
    if (value >= benchmark.good * 1.5) return 'excellent';
    if (value >= benchmark.good) return 'good';
    if (value >= benchmark.warning) return 'fair';
    return 'poor';
}


export class FunnelAnalyzer {

    /**
     * Analyze campaigns with funnel-stage awareness.
     */
    static async analyze(accountId: string, days: number = 30): Promise<FunnelAnalysis> {
        const result: FunnelAnalysis = {
            hasData: false,
            byStageSummary: [],
            campaigns: [],
            funnelHealth: {
                hasAwareness: false,
                hasConsideration: false,
                hasConversion: false,
                balance: 'unbalanced',
                recommendation: ''
            },
            misjudgedCampaigns: [],
            suggestions: []
        };

        try {
            const adAccounts = await prisma.adAccount.findMany({
                where: { accountId },
                select: { id: true, platform: true, name: true }
            });

            if (adAccounts.length === 0) return result;

            const allCampaigns: CampaignFunnelAnalysis[] = [];

            for (const adAccount of adAccounts) {
                try {
                    let campaigns: CampaignInsight[] = [];
                    const platform = adAccount.platform.toLowerCase() as 'google' | 'meta';

                    if (platform === 'google') {
                        campaigns = await AdsService.getGoogleCampaignInsights(adAccount.id, days);
                    } else if (platform === 'meta') {
                        campaigns = await AdsService.getMetaCampaignInsights(adAccount.id, days);
                    }

                    for (const campaign of campaigns) {
                        const campaignType = getCampaignType(campaign.campaignName);
                        const funnelStage = mapCampaignTypeToFunnelStage(campaignType);
                        const stageMetrics = FUNNEL_STAGE_METRICS[funnelStage];

                        const analysis: CampaignFunnelAnalysis = {
                            campaignId: campaign.campaignId,
                            campaignName: campaign.campaignName,
                            platform,
                            funnelStage,
                            campaignType,
                            spend: campaign.spend,
                            impressions: campaign.impressions,
                            clicks: campaign.clicks,
                            conversions: campaign.conversions,
                            revenue: campaign.conversionsValue,
                            roas: campaign.roas,
                            cpm: campaign.impressions > 0 ? (campaign.spend / campaign.impressions) * 1000 : 0,
                            ctr: campaign.ctr,
                            cpc: campaign.cpc,
                            cpa: campaign.cpa,
                            performance: 'fair',
                            primaryMetricValue: 0,
                            primaryMetricAssessment: '',
                            issues: [],
                            recommendations: []
                        };

                        // Set primary metric value
                        switch (stageMetrics.primaryMetric) {
                            case 'roas': analysis.primaryMetricValue = analysis.roas; break;
                            case 'cpm': analysis.primaryMetricValue = analysis.cpm; break;
                            case 'cpc': analysis.primaryMetricValue = analysis.cpc; break;
                            case 'cpa': analysis.primaryMetricValue = analysis.cpa; break;
                        }

                        // Assess performance
                        analysis.performance = assessPerformance(analysis, stageMetrics);
                        analysis.primaryMetricAssessment = `${stageMetrics.primaryMetric.toUpperCase()}: ${analysis.primaryMetricValue.toFixed(2)} (${analysis.performance})`;

                        // Identify issues
                        this.identifyIssues(analysis, stageMetrics);

                        allCampaigns.push(analysis);
                    }
                } catch (error) {
                    Logger.warn(`Failed to analyze campaigns for ${adAccount.id}`, { error });
                }
            }

            if (allCampaigns.length === 0) return result;

            result.campaigns = allCampaigns;
            result.hasData = true;

            // Calculate stage summaries
            this.calculateStageSummaries(result);

            // Assess funnel health
            this.assessFunnelHealth(result);

            // Identify misjudged campaigns
            this.identifyMisjudgedCampaigns(result);

            // Generate suggestions
            this.generateSuggestions(result);

        } catch (error) {
            Logger.error('FunnelAnalyzer failed', { error, accountId });
        }

        return result;
    }

    /**
     * Identify issues for a campaign based on its funnel stage.
     */
    private static identifyIssues(
        campaign: CampaignFunnelAnalysis,
        stageMetrics: FunnelStageMetrics
    ): void {
        const { funnelStage, roas, cpm, ctr, cpa, spend, conversions } = campaign;

        if (funnelStage === 'awareness') {
            // Awareness: don't judge on ROAS, focus on reach efficiency
            if (cpm > 25) {
                campaign.issues.push(`High CPM ($${cpm.toFixed(2)}) - consider audience refinement`);
            }
            if (ctr < 0.3 && spend > 100) {
                campaign.issues.push(`Low CTR (${ctr.toFixed(2)}%) - creative may need refresh`);
            }
        } else if (funnelStage === 'consideration') {
            // Consideration: focus on engagement, not conversions
            if (ctr < 1 && spend > 100) {
                campaign.issues.push(`Low CTR (${ctr.toFixed(2)}%) for consideration stage`);
            }
        } else if (funnelStage === 'conversion' || funnelStage === 'retention') {
            // Conversion: ROAS matters
            const expectedThreshold = getExpectedRoasThreshold(campaign.campaignType);
            const minRoas = expectedThreshold?.min || 1.5;

            if (roas < minRoas && spend > 50) {
                campaign.issues.push(`ROAS (${roas.toFixed(2)}x) below threshold (${minRoas}x) for ${campaign.campaignType}`);
            }
            if (conversions === 0 && spend > 100) {
                campaign.issues.push(`No conversions with $${spend.toFixed(0)} spend - check conversion tracking`);
            }
        }
    }

    /**
     * Calculate aggregate metrics by funnel stage.
     */
    private static calculateStageSummaries(result: FunnelAnalysis): void {
        const stages: FunnelStage[] = ['awareness', 'consideration', 'conversion', 'retention'];
        const totalSpend = result.campaigns.reduce((sum, c) => sum + c.spend, 0);

        for (const stage of stages) {
            const stageCampaigns = result.campaigns.filter(c => c.funnelStage === stage);
            if (stageCampaigns.length === 0) continue;

            const stageSpend = stageCampaigns.reduce((sum, c) => sum + c.spend, 0);
            const perfScores = { excellent: 4, good: 3, fair: 2, poor: 1 };
            const avgPerf = stageCampaigns.reduce((sum, c) => sum + perfScores[c.performance], 0) / stageCampaigns.length;

            result.byStageSummary.push({
                stage,
                campaigns: stageCampaigns.length,
                spend: Math.round(stageSpend * 100) / 100,
                spendShare: totalSpend > 0 ? Math.round((stageSpend / totalSpend) * 1000) / 10 : 0,
                avgPerformance: Math.round(avgPerf * 10) / 10
            });
        }
    }

    /**
     * Assess overall funnel health and balance.
     */
    private static assessFunnelHealth(result: FunnelAnalysis): void {
        const stages = result.byStageSummary;
        const awareness = stages.find(s => s.stage === 'awareness');
        const consideration = stages.find(s => s.stage === 'consideration');
        const conversion = stages.find(s => s.stage === 'conversion' || s.stage === 'retention');

        result.funnelHealth.hasAwareness = !!awareness && awareness.spend > 0;
        result.funnelHealth.hasConsideration = !!consideration && consideration.spend > 0;
        result.funnelHealth.hasConversion = !!conversion && conversion.spend > 0;

        const awarenessShare = awareness?.spendShare || 0;
        const conversionShare = (conversion?.spendShare || 0) +
            (stages.find(s => s.stage === 'retention')?.spendShare || 0);

        if (awarenessShare > 50 && conversionShare < 20) {
            result.funnelHealth.balance = 'top-heavy';
            result.funnelHealth.recommendation = 'Heavy awareness spend but limited conversion focus. Consider adding more bottom-funnel campaigns.';
        } else if (conversionShare > 80 && awarenessShare < 10) {
            result.funnelHealth.balance = 'bottom-heavy';
            result.funnelHealth.recommendation = 'Mostly conversion-focused. Consider awareness campaigns to grow your audience pool.';
        } else if (awarenessShare > 15 && conversionShare > 30) {
            result.funnelHealth.balance = 'healthy';
            result.funnelHealth.recommendation = 'Good balance across funnel stages.';
        } else {
            result.funnelHealth.balance = 'unbalanced';
            result.funnelHealth.recommendation = 'Review campaign mix to ensure coverage across customer journey stages.';
        }
    }

    /**
     * Identify campaigns being judged on wrong metrics.
     */
    private static identifyMisjudgedCampaigns(result: FunnelAnalysis): void {
        for (const campaign of result.campaigns) {
            // Awareness campaign with high spend and low ROAS - but that's expected!
            if (campaign.funnelStage === 'awareness' && campaign.roas < 1 && campaign.spend > 200) {
                // Check if CPM is actually good
                if (campaign.cpm < 20) {
                    result.misjudgedCampaigns.push({
                        campaignName: campaign.campaignName,
                        issue: 'ROAS appears low, but this is an awareness campaign',
                        correctMetric: `CPM: $${campaign.cpm.toFixed(2)} (good for awareness)`
                    });
                }
            }

            // Prospecting campaign judged on immediate ROAS
            if (campaign.campaignType === 'prospecting' && campaign.roas < 2 && campaign.spend > 100) {
                if (campaign.ctr > 1) {
                    result.misjudgedCampaigns.push({
                        campaignName: campaign.campaignName,
                        issue: 'Prospecting campaigns have delayed ROAS - they fill the funnel',
                        correctMetric: `CTR: ${campaign.ctr.toFixed(2)}% (indicates interest)`
                    });
                }
            }
        }
    }

    /**
     * Generate funnel-aware suggestions.
     */
    private static generateSuggestions(result: FunnelAnalysis): void {
        const { funnelHealth, campaigns, byStageSummary, misjudgedCampaigns } = result;

        // Funnel balance suggestion
        if (funnelHealth.balance !== 'healthy') {
            result.suggestions.push(
                `🎯 **Funnel Balance**: ${funnelHealth.recommendation}`
            );
        }

        // Poor performing campaigns by stage
        const poorCampaigns = campaigns.filter(c => c.performance === 'poor' && c.spend > 100);
        if (poorCampaigns.length > 0) {
            const byStage = new Map<FunnelStage, number>();
            for (const c of poorCampaigns) {
                byStage.set(c.funnelStage, (byStage.get(c.funnelStage) || 0) + 1);
            }

            for (const [stage, count] of byStage.entries()) {
                result.suggestions.push(
                    `⚠️ **${stage.charAt(0).toUpperCase() + stage.slice(1)} Issues**: ${count} campaigns underperforming. Review targeting and creative.`
                );
            }
        }

        // Misjudged campaign alert
        if (misjudgedCampaigns.length > 0) {
            result.suggestions.push(
                `💡 **Metric Context**: ${misjudgedCampaigns.length} campaign(s) may appear underperforming but are serving their funnel purpose. ` +
                `Example: "${misjudgedCampaigns[0].campaignName}" - ${misjudgedCampaigns[0].issue}`
            );
        }

        // No awareness campaigns warning
        if (!funnelHealth.hasAwareness && byStageSummary.length > 0) {
            result.suggestions.push(
                `📢 **No Awareness Campaigns**: You're only running conversion campaigns. ` +
                `Consider adding awareness/video campaigns to expand your audience pool.`
            );
        }

        // High performing campaigns
        const excellentCampaigns = campaigns.filter(c => c.performance === 'excellent' && c.spend > 50);
        if (excellentCampaigns.length > 0) {
            const best = excellentCampaigns.sort((a, b) => b.spend - a.spend)[0];
            result.suggestions.push(
                `🌟 **Top Performer**: "${best.campaignName}" is excellent at ${best.funnelStage} stage ` +
                `(${best.primaryMetricAssessment}). Consider scaling budget.`
            );
        }
    }
}

/**
 * Keyword Opportunity Analyzer
 * 
 * Analyzes site search data and organic traffic to find keyword gaps.
 * Identifies high-converting keywords that aren't being bid on.
 * 
 * Part of AI Marketing Co-Pilot Actionable Suggestions Enhancement.
 */

import { prisma } from '../../../utils/prisma';
import { Logger } from '../../../utils/logger';
import { REVENUE_STATUSES } from '../../../constants/orderStatus';
import {
    ActionableRecommendation,
    KeywordAction,
    createKeywordHeadline
} from '../types/ActionableTypes';


interface SearchTermData {
    term: string;
    searches: number;
    conversions: number;
    conversionValue: number;
    conversionRate: number;
}

interface KeywordOpportunityResult {
    hasData: boolean;
    keywordOpportunities: ActionableRecommendation[];
    negativeKeywordOpportunities: ActionableRecommendation[];
    bidAdjustments: ActionableRecommendation[];
    summary: {
        totalSearchTermsAnalyzed: number;
        opportunitiesFound: number;
        estimatedMissedRevenue: number;
    };
}


export class KeywordOpportunityAnalyzer {

    /**
     * Analyze keyword opportunities from site search and organic data.
     */
    static async analyze(
        accountId: string,
        activeKeywords?: string[]
    ): Promise<KeywordOpportunityResult> {
        const result: KeywordOpportunityResult = {
            hasData: false,
            keywordOpportunities: [],
            negativeKeywordOpportunities: [],
            bidAdjustments: [],
            summary: {
                totalSearchTermsAnalyzed: 0,
                opportunitiesFound: 0,
                estimatedMissedRevenue: 0
            }
        };

        try {
            const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);

            // Get site search events
            const searchEvents = await prisma.analyticsEvent.findMany({
                where: {
                    session: { accountId },
                    type: 'search',
                    createdAt: { gte: thirtyDaysAgo }
                },
                select: {
                    payload: true,
                    sessionId: true,
                    createdAt: true
                }
            });

            if (searchEvents.length === 0) {
                return result;
            }

            // Aggregate search terms
            const searchTermCounts = new Map<string, {
                count: number;
                sessionIds: Set<string>;
            }>();

            for (const event of searchEvents) {
                const term = this.normalizeSearchTerm(
                    (event.payload as any)?.query ||
                    (event.payload as any)?.search_term ||
                    (event.payload as any)?.q
                );

                if (!term || term.length < 2) continue;

                const current = searchTermCounts.get(term) || { count: 0, sessionIds: new Set() };
                current.count++;
                current.sessionIds.add(event.sessionId);
                searchTermCounts.set(term, current);
            }

            result.summary.totalSearchTermsAnalyzed = searchTermCounts.size;

            // Get purchase events to calculate conversion rates per search term
            const purchaseSessions = await prisma.analyticsEvent.findMany({
                where: {
                    session: { accountId },
                    type: 'purchase',
                    createdAt: { gte: thirtyDaysAgo }
                },
                select: {
                    sessionId: true,
                    payload: true
                }
            });

            const purchaseSessionSet = new Set(purchaseSessions.map(p => p.sessionId));
            const purchaseValues = new Map<string, number>();
            for (const p of purchaseSessions) {
                const value = (p.payload as any)?.value || (p.payload as any)?.revenue || 0;
                purchaseValues.set(p.sessionId, parseFloat(String(value)) || 0);
            }

            // Calculate conversion data for each search term
            const searchTermData: SearchTermData[] = [];

            for (const [term, data] of searchTermCounts.entries()) {
                if (data.count < 3) continue; // Need at least 3 searches for relevance

                const convertedSessions = [...data.sessionIds].filter(s => purchaseSessionSet.has(s));
                const conversions = convertedSessions.length;
                const conversionValue = convertedSessions.reduce((sum, s) => sum + (purchaseValues.get(s) || 0), 0);
                const conversionRate = data.count > 0 ? (conversions / data.count) * 100 : 0;

                searchTermData.push({
                    term,
                    searches: data.count,
                    conversions,
                    conversionValue,
                    conversionRate
                });
            }

            result.hasData = searchTermData.length > 0;

            // Normalize active keywords for comparison
            const activeKeywordSet = new Set(
                (activeKeywords || []).map(k => this.normalizeSearchTerm(k))
            );

            // Find high-converting search terms not being bid on
            const opportunities = searchTermData
                .filter(s => {
                    const isActive = activeKeywordSet.has(s.term) ||
                        [...activeKeywordSet].some(k => s.term.includes(k) || k.includes(s.term));
                    return !isActive && s.conversions >= 2 && s.conversionRate >= 2;
                })
                .sort((a, b) => b.conversionValue - a.conversionValue)
                .slice(0, 10);

            for (const opp of opportunities) {
                const suggestedCpc = this.calculateSuggestedCpc(opp);
                const estimatedRoas = opp.conversionValue / (opp.searches * suggestedCpc);

                const action: KeywordAction = {
                    actionType: 'add_keyword',
                    keyword: opp.term,
                    matchType: opp.term.split(' ').length >= 3 ? 'phrase' : 'exact',
                    suggestedCpc,
                    estimatedRoas: Math.min(10, estimatedRoas),
                    estimatedClicks: opp.searches * 0.02 // Assume 2% click-through from impressions
                };

                result.keywordOpportunities.push({
                    id: `kw_opp_${opp.term.replace(/\s+/g, '_').substring(0, 20)}`,
                    priority: opp.conversions >= 5 ? 1 : 2,
                    category: 'optimization',
                    headline: `🔍 ${createKeywordHeadline(action)} - ${opp.conversions} organic conversions`,
                    explanation: `Users searching for "${opp.term}" on your site converted ${opp.conversions} times ` +
                        `with $${opp.conversionValue.toFixed(0)} in revenue. You're not bidding on this keyword in Google Ads.`,
                    dataPoints: [
                        `${opp.searches} site searches in 30 days`,
                        `${opp.conversions} conversions (${opp.conversionRate.toFixed(1)}% CVR)`,
                        `$${opp.conversionValue.toFixed(0)} conversion value`,
                        `Est. ${estimatedRoas.toFixed(1)}x ROAS at $${suggestedCpc.toFixed(2)} CPC`
                    ],
                    action,
                    confidence: this.calculateConfidence(opp),
                    estimatedImpact: {
                        revenueChange: opp.conversionValue * 0.5, // Conservative 50% of organic
                        roasChange: estimatedRoas,
                        timeframe: '30d'
                    },
                    platform: 'google',
                    source: 'KeywordOpportunityAnalyzer',
                    tags: ['keyword', 'opportunity', 'search']
                });

                result.summary.estimatedMissedRevenue += opp.conversionValue * 0.3;
            }

            result.summary.opportunitiesFound = result.keywordOpportunities.length;

        } catch (error) {
            Logger.error('KeywordOpportunityAnalyzer failed', { error, accountId });
        }

        return result;
    }

    /**
     * Normalize a search term for comparison.
     */
    private static normalizeSearchTerm(term: string | undefined): string {
        if (!term) return '';
        return term
            .toLowerCase()
            .trim()
            .replace(/[^\w\s]/g, '')
            .replace(/\s+/g, ' ');
    }

    /**
     * Calculate suggested CPC based on conversion value and target ROAS.
     */
    private static calculateSuggestedCpc(data: SearchTermData): number {
        if (data.conversions === 0 || data.searches === 0) return 0.50; // Default

        // Average conversion value
        const avgConversionValue = data.conversionValue / data.conversions;

        // Conversion rate as decimal
        const cvr = data.conversions / data.searches;

        // Target 4x ROAS: CPC = (avgValue * CVR) / 4
        let cpc = (avgConversionValue * cvr) / 4;

        // Round to nearest $0.05 and cap between $0.15 and $2.00
        cpc = Math.round(cpc / 0.05) * 0.05;
        return Math.max(0.15, Math.min(2.00, cpc));
    }

    /**
     * Calculate confidence score for a keyword opportunity.
     */
    private static calculateConfidence(data: SearchTermData): number {
        let score = 40; // Base score

        // More searches = more confidence
        if (data.searches >= 20) score += 20;
        else if (data.searches >= 10) score += 10;

        // More conversions = more confidence
        if (data.conversions >= 5) score += 25;
        else if (data.conversions >= 3) score += 15;

        // Higher conversion rate = more confidence
        if (data.conversionRate >= 5) score += 10;

        return Math.min(90, score);
    }
}

/**
 * LTV Analyzer
 * 
 * Calculates Customer Lifetime Value by acquisition channel
 * and provides LTV-adjusted optimization recommendations.
 * 
 * Part of AI Marketing Co-Pilot Phase 2.
 */

import { prisma } from '../../../utils/prisma';
import { Logger } from '../../../utils/logger';


export interface ChannelLTV {
    channel: string;
    customers: number;
    totalRevenue: number;
    avgLtv: number;
    avgOrders: number;
    avgDaysBetweenOrders: number;
    repeatRate: number;        // % of customers who ordered more than once
    projectedLtv12m: number;   // Projected 12-month LTV
}

export interface LTVInsight {
    hasData: boolean;

    // LTV by acquisition channel
    channelLtv: ChannelLTV[];

    // Overall metrics
    overall: {
        avgLtv: number;
        avgOrders: number;
        repeatRate: number;
        avgDaysBetweenOrders: number;
    };

    // High-value segments
    highValueSegments: {
        channel: string;
        segment: string;
        avgLtv: number;
        customers: number;
        insight: string;
    }[];

    // LTV-adjusted ROAS (if we have spend data)
    ltvAdjustedMetrics: {
        channel: string;
        immediateRoas: number;     // Standard last-click ROAS
        ltvAdjustedRoas: number;   // ROAS using projected LTV
        multiplier: number;        // How much higher LTV-adjusted is
    }[];

    suggestions: string[];
}


import { normalizeChannel } from '../utils/ChannelUtils';


export class LTVAnalyzer {

    /**
     * Analyze customer lifetime value by acquisition channel.
     */
    static async analyze(accountId: string): Promise<LTVInsight> {
        const result: LTVInsight = {
            hasData: false,
            channelLtv: [],
            overall: {
                avgLtv: 0,
                avgOrders: 0,
                repeatRate: 0,
                avgDaysBetweenOrders: 0
            },
            highValueSegments: [],
            ltvAdjustedMetrics: [],
            suggestions: []
        };

        try {
            // Get customers with their order history (limit to prevent OOM)
            // For very large accounts, we sample the most recent customers
            const MAX_CUSTOMERS = 10000;
            const customers = await prisma.wooCustomer.findMany({
                where: { accountId },
                select: {
                    id: true,
                    wooId: true,
                    email: true,
                    totalSpent: true,
                    ordersCount: true,
                    createdAt: true
                },
                orderBy: { createdAt: 'desc' },
                take: MAX_CUSTOMERS
            });

            if (customers.length === 0) {
                return result;
            }

            // Get orders for order date analysis (limit to recent orders)
            const MAX_ORDERS = 20000;
            const orders = await prisma.wooOrder.findMany({
                where: {
                    accountId,
                    status: { in: ['completed', 'processing'] }
                },
                select: {
                    wooId: true,
                    total: true,
                    dateCreated: true,
                    rawData: true
                },
                orderBy: { dateCreated: 'desc' },
                take: MAX_ORDERS
            });

            // Get first-touch attribution for customers (limit events)
            const MAX_EVENTS = 20000;
            const purchaseEvents = await prisma.analyticsEvent.findMany({
                where: {
                    session: { accountId },
                    type: 'purchase'
                },
                include: {
                    session: {
                        select: {
                            firstTouchSource: true,
                            visitorId: true
                        }
                    }
                },
                orderBy: { createdAt: 'desc' },
                take: MAX_EVENTS
            });

            // Build customer -> first acquisition channel map
            // Use the FIRST purchase event's first touch as acquisition channel
            const customerAcquisitionChannel = new Map<string, string>();

            for (const event of purchaseEvents) {
                const orderId = (event.payload as any)?.orderId;
                if (orderId && event.session?.visitorId) {
                    // Find which customer this order belongs to
                    const order = orders.find(o => o.wooId === Number(orderId));
                    if (order) {
                        const customerEmail = (order.rawData as any)?.billing?.email;
                        if (customerEmail && !customerAcquisitionChannel.has(customerEmail)) {
                            customerAcquisitionChannel.set(
                                customerEmail.toLowerCase(),
                                normalizeChannel(event.session.firstTouchSource)
                            );
                        }
                    }
                }
            }

            // Build customer order history
            const customerOrders = new Map<string, { dates: Date[]; totals: number[] }>();

            for (const order of orders) {
                const email = (order.rawData as any)?.billing?.email?.toLowerCase();
                if (!email) continue;

                const existing = customerOrders.get(email) || { dates: [], totals: [] };
                existing.dates.push(new Date(order.dateCreated));
                existing.totals.push(parseFloat(String(order.total)) || 0);
                customerOrders.set(email, existing);
            }

            // Calculate LTV by channel
            const channelData = new Map<string, {
                customers: number;
                totalRevenue: number;
                totalOrders: number;
                repeatCustomers: number;
                daysBetweenOrders: number[];
            }>();

            let overallTotalRevenue = 0;
            let overallTotalOrders = 0;
            let overallRepeatCustomers = 0;
            let allDaysBetween: number[] = [];

            for (const customer of customers) {
                const email = customer.email.toLowerCase();
                const channel = customerAcquisitionChannel.get(email) || 'direct';
                const ltv = parseFloat(String(customer.totalSpent)) || 0;
                const orderCount = customer.ordersCount || 1;

                overallTotalRevenue += ltv;
                overallTotalOrders += orderCount;
                if (orderCount > 1) overallRepeatCustomers++;

                const data = channelData.get(channel) || {
                    customers: 0,
                    totalRevenue: 0,
                    totalOrders: 0,
                    repeatCustomers: 0,
                    daysBetweenOrders: []
                };

                data.customers++;
                data.totalRevenue += ltv;
                data.totalOrders += orderCount;
                if (orderCount > 1) data.repeatCustomers++;

                // Calculate days between orders for this customer
                const orderHistory = customerOrders.get(email);
                if (orderHistory && orderHistory.dates.length > 1) {
                    for (let i = 1; i < orderHistory.dates.length; i++) {
                        const daysDiff = Math.round(
                            (orderHistory.dates[i].getTime() - orderHistory.dates[i - 1].getTime())
                            / (1000 * 60 * 60 * 24)
                        );
                        if (daysDiff > 0 && daysDiff < 365) {
                            data.daysBetweenOrders.push(daysDiff);
                            allDaysBetween.push(daysDiff);
                        }
                    }
                }

                channelData.set(channel, data);
            }

            // Convert to LTV array
            result.channelLtv = Array.from(channelData.entries())
                .map(([channel, data]) => {
                    const avgLtv = data.customers > 0 ? data.totalRevenue / data.customers : 0;
                    const avgOrders = data.customers > 0 ? data.totalOrders / data.customers : 0;
                    const avgDaysBetween = data.daysBetweenOrders.length > 0
                        ? data.daysBetweenOrders.reduce((a, b) => a + b, 0) / data.daysBetweenOrders.length
                        : 0;
                    const repeatRate = data.customers > 0 ? (data.repeatCustomers / data.customers) * 100 : 0;

                    // Project 12-month LTV based on repeat rate and avg order value
                    const avgOrderValue = avgOrders > 0 ? avgLtv / avgOrders : 0;
                    const ordersPerYear = avgDaysBetween > 0 ? 365 / avgDaysBetween : avgOrders;
                    const projectedLtv12m = avgOrderValue * Math.min(ordersPerYear, 12); // Cap at 12 orders/year

                    return {
                        channel,
                        customers: data.customers,
                        totalRevenue: Math.round(data.totalRevenue * 100) / 100,
                        avgLtv: Math.round(avgLtv * 100) / 100,
                        avgOrders: Math.round(avgOrders * 100) / 100,
                        avgDaysBetweenOrders: Math.round(avgDaysBetween),
                        repeatRate: Math.round(repeatRate * 10) / 10,
                        projectedLtv12m: Math.round(projectedLtv12m * 100) / 100
                    };
                })
                .sort((a, b) => b.avgLtv - a.avgLtv);

            // Overall metrics
            result.overall = {
                avgLtv: customers.length > 0 ? Math.round((overallTotalRevenue / customers.length) * 100) / 100 : 0,
                avgOrders: customers.length > 0 ? Math.round((overallTotalOrders / customers.length) * 100) / 100 : 0,
                repeatRate: customers.length > 0 ? Math.round((overallRepeatCustomers / customers.length) * 1000) / 10 : 0,
                avgDaysBetweenOrders: allDaysBetween.length > 0
                    ? Math.round(allDaysBetween.reduce((a, b) => a + b, 0) / allDaysBetween.length)
                    : 0
            };

            result.hasData = true;

            // Identify high-value segments
            this.identifyHighValueSegments(result);

            // Generate suggestions
            this.generateSuggestions(result);

        } catch (error) {
            Logger.error('LTVAnalyzer failed', { error, accountId });
        }

        return result;
    }

    /**
     * Identify high-value customer segments.
     */
    private static identifyHighValueSegments(result: LTVInsight): void {
        const avgLtv = result.overall.avgLtv;

        for (const channel of result.channelLtv) {
            if (channel.customers < 5) continue; // Skip small samples

            // High LTV channel
            if (channel.avgLtv > avgLtv * 1.3) {
                result.highValueSegments.push({
                    channel: channel.channel,
                    segment: 'High LTV',
                    avgLtv: channel.avgLtv,
                    customers: channel.customers,
                    insight: `${channel.channel} customers have ${Math.round((channel.avgLtv / avgLtv - 1) * 100)}% higher LTV than average`
                });
            }

            // High repeat rate channel
            if (channel.repeatRate > result.overall.repeatRate * 1.5) {
                result.highValueSegments.push({
                    channel: channel.channel,
                    segment: 'High Repeat',
                    avgLtv: channel.avgLtv,
                    customers: channel.customers,
                    insight: `${channel.channel} customers have ${channel.repeatRate.toFixed(1)}% repeat rate vs ${result.overall.repeatRate.toFixed(1)}% average`
                });
            }
        }
    }

    /**
     * Generate LTV-based recommendations.
     */
    private static generateSuggestions(result: LTVInsight): void {
        const { channelLtv, overall, highValueSegments } = result;

        if (channelLtv.length === 0) return;

        // Find best LTV channel
        const bestLtvChannel = channelLtv[0];
        const worstLtvChannel = channelLtv[channelLtv.length - 1];

        if (bestLtvChannel && worstLtvChannel && bestLtvChannel.avgLtv > worstLtvChannel.avgLtv * 1.5) {
            result.suggestions.push(
                `💎 **LTV Leader**: ${bestLtvChannel.channel} customers have $${bestLtvChannel.avgLtv} average LTV ` +
                `(${Math.round((bestLtvChannel.avgLtv / worstLtvChannel.avgLtv - 1) * 100)}% higher than ${worstLtvChannel.channel}). ` +
                `Consider increasing acquisition spend on ${bestLtvChannel.channel}.`
            );
        }

        // Repeat rate insights
        const highRepeatChannel = channelLtv.find(c => c.repeatRate > 30 && c.customers >= 10);
        if (highRepeatChannel) {
            result.suggestions.push(
                `🔄 **High Repeat Channel**: ${highRepeatChannel.repeatRate.toFixed(1)}% of ${highRepeatChannel.channel} customers ` +
                `make repeat purchases. These customers are worth investing more to acquire.`
            );
        }

        // Low repeat rate warning
        if (overall.repeatRate < 15 && overall.avgOrders < 1.3) {
            result.suggestions.push(
                `⚠️ **Retention Opportunity**: Only ${overall.repeatRate.toFixed(1)}% repeat purchase rate. ` +
                `Consider email remarketing, loyalty programs, or post-purchase engagement to increase LTV.`
            );
        }

        // LTV vs immediate ROAS insight
        const paidChannels = channelLtv.filter(c => ['google', 'meta'].includes(c.channel));
        if (paidChannels.length > 0) {
            const avgPaidLtv = paidChannels.reduce((sum, c) => sum + c.avgLtv * c.customers, 0) /
                paidChannels.reduce((sum, c) => sum + c.customers, 0);

            if (avgPaidLtv > overall.avgLtv * 0.8) {
                result.suggestions.push(
                    `📊 **LTV Justifies CAC**: Paid channel customers have $${avgPaidLtv.toFixed(0)} LTV. ` +
                    `Even if immediate ROAS looks marginal, LTV value justifies acquisition cost.`
                );
            }
        }

        // Projected LTV insight
        const projectedChannel = channelLtv.find(c => c.projectedLtv12m > c.avgLtv * 1.5 && c.repeatRate > 20);
        if (projectedChannel) {
            result.suggestions.push(
                `📈 **Growth Potential**: ${projectedChannel.channel} customers are projected to reach ` +
                `$${projectedChannel.projectedLtv12m} LTV over 12 months (current: $${projectedChannel.avgLtv}). ` +
                `Factor this into CAC decisions.`
            );
        }
    }

    /**
     * Get a formatted summary string.
     */
    static formatSummary(insight: LTVInsight): string {
        if (!insight.hasData) {
            return 'No customer LTV data available.';
        }

        const lines = [
            `**Overall LTV**: $${insight.overall.avgLtv} (${insight.overall.avgOrders.toFixed(1)} orders avg)`,
            `**Repeat Rate**: ${insight.overall.repeatRate}%`
        ];

        if (insight.channelLtv.length > 0) {
            const top = insight.channelLtv[0];
            lines.push(`**Best Channel**: ${top.channel} ($${top.avgLtv} LTV)`);
        }

        return lines.join('\n');
    }
}

/**
 * Multi-Period Analyzer
 * 
 * Fetches and compares ad performance across multiple time periods (7d, 30d, 90d)
 * to detect trends, anomalies, and provide data-backed recommendations.
 * 
 * Part of AI Marketing Co-Pilot Phase 1.
 */

import { prisma } from '../../../utils/prisma';
import { Logger } from '../../../utils/logger';
import { AdsService } from '../../ads';
import { PeriodMetrics, testRoasChange, calculateAnomalyScore, ConfidenceResult } from '../utils/StatisticalUtils';
import { ActionableRecommendation, BudgetAction, createBudgetHeadline } from '../types/ActionableTypes';


export interface MultiPeriodData {
    platform: 'google' | 'meta';
    adAccountId: string;
    adAccountName: string;
    periods: {
        '7d': PeriodMetrics;
        '30d': PeriodMetrics;
        '90d': PeriodMetrics;
    };
}

export interface MultiPeriodAnalysis {
    hasData: boolean;
    google?: MultiPeriodData;
    meta?: MultiPeriodData;
    combined: {
        '7d': PeriodMetrics;
        '30d': PeriodMetrics;
        '90d': PeriodMetrics;
    };
    trends: {
        roas_7d_vs_30d: { change: number; confidence: ConfidenceResult };
        roas_30d_vs_90d: { change: number; confidence: ConfidenceResult };
        spend_trajectory: 'increasing' | 'stable' | 'decreasing';
        performance_trajectory: 'improving' | 'stable' | 'declining';
    };
    anomalies: Array<{
        metric: string;
        period: string;
        severity: 'warning' | 'critical';
        message: string;
    }>;
    suggestions: string[];
    actionableRecommendations: ActionableRecommendation[];
}


function emptyMetrics(): PeriodMetrics {
    return {
        spend: 0,
        revenue: 0,
        clicks: 0,
        impressions: 0,
        conversions: 0,
        roas: 0,
        ctr: 0,
        cpc: 0,
        cpa: 0
    };
}

function aggregateMetrics(dailyData: any[]): PeriodMetrics {
    const totals = dailyData.reduce((acc, day) => ({
        spend: acc.spend + (day.spend || 0),
        revenue: acc.revenue + (day.conversionsValue || day.revenue || 0),
        clicks: acc.clicks + (day.clicks || 0),
        impressions: acc.impressions + (day.impressions || 0),
        conversions: acc.conversions + (day.conversions || 0)
    }), { spend: 0, revenue: 0, clicks: 0, impressions: 0, conversions: 0 });

    return {
        ...totals,
        roas: totals.spend > 0 ? totals.revenue / totals.spend : 0,
        ctr: totals.impressions > 0 ? (totals.clicks / totals.impressions) * 100 : 0,
        cpc: totals.clicks > 0 ? totals.spend / totals.clicks : 0,
        cpa: totals.conversions > 0 ? totals.spend / totals.conversions : 0
    };
}

function combineMetrics(a: PeriodMetrics, b: PeriodMetrics): PeriodMetrics {
    const combined = {
        spend: a.spend + b.spend,
        revenue: a.revenue + b.revenue,
        clicks: a.clicks + b.clicks,
        impressions: a.impressions + b.impressions,
        conversions: a.conversions + b.conversions,
        roas: 0,
        ctr: 0,
        cpc: 0,
        cpa: 0
    };

    combined.roas = combined.spend > 0 ? combined.revenue / combined.spend : 0;
    combined.ctr = combined.impressions > 0 ? (combined.clicks / combined.impressions) * 100 : 0;
    combined.cpc = combined.clicks > 0 ? combined.spend / combined.clicks : 0;
    combined.cpa = combined.conversions > 0 ? combined.spend / combined.conversions : 0;

    return combined;
}

function determineTrajectory(values: number[]): 'increasing' | 'stable' | 'decreasing' {
    if (values.length < 2) return 'stable';

    // Simple linear regression slope
    const n = values.length;
    const xMean = (n - 1) / 2;
    const yMean = values.reduce((a, b) => a + b, 0) / n;

    let numerator = 0;
    let denominator = 0;

    for (let i = 0; i < n; i++) {
        numerator += (i - xMean) * (values[i] - yMean);
        denominator += (i - xMean) * (i - xMean);
    }

    const slope = denominator !== 0 ? numerator / denominator : 0;
    const relativeSlope = yMean !== 0 ? slope / yMean : 0;

    if (relativeSlope > 0.05) return 'increasing';
    if (relativeSlope < -0.05) return 'decreasing';
    return 'stable';
}


export class MultiPeriodAnalyzer {

    /**
     * Fetch and analyze ad performance across 7d, 30d, and 90d periods.
     */
    static async analyze(accountId: string): Promise<MultiPeriodAnalysis> {
        const result: MultiPeriodAnalysis = {
            hasData: false,
            combined: {
                '7d': emptyMetrics(),
                '30d': emptyMetrics(),
                '90d': emptyMetrics()
            },
            trends: {
                roas_7d_vs_30d: { change: 0, confidence: { isSignificant: false, confidence: 'low', score: 0, sampleSize: 0, factors: [] } },
                roas_30d_vs_90d: { change: 0, confidence: { isSignificant: false, confidence: 'low', score: 0, sampleSize: 0, factors: [] } },
                spend_trajectory: 'stable',
                performance_trajectory: 'stable'
            },
            anomalies: [],
            suggestions: [],
            actionableRecommendations: []
        };

        try {
            const adAccounts = await prisma.adAccount.findMany({
                where: { accountId },
                select: { id: true, platform: true, name: true, externalId: true }
            });

            if (adAccounts.length === 0) {
                return result;
            }

            // Fetch data for each platform
            const googleAccounts = adAccounts.filter(a => a.platform === 'GOOGLE');
            const metaAccounts = adAccounts.filter(a => a.platform === 'META');

            const [googleData, metaData] = await Promise.all([
                this.fetchPlatformData(googleAccounts, 'google'),
                this.fetchPlatformData(metaAccounts, 'meta')
            ]);

            if (googleData) {
                result.google = googleData;
                result.hasData = true;
            }
            if (metaData) {
                result.meta = metaData;
                result.hasData = true;
            }

            if (!result.hasData) {
                return result;
            }

            // Combine metrics across platforms
            result.combined = {
                '7d': combineMetrics(
                    result.google?.periods['7d'] || emptyMetrics(),
                    result.meta?.periods['7d'] || emptyMetrics()
                ),
                '30d': combineMetrics(
                    result.google?.periods['30d'] || emptyMetrics(),
                    result.meta?.periods['30d'] || emptyMetrics()
                ),
                '90d': combineMetrics(
                    result.google?.periods['90d'] || emptyMetrics(),
                    result.meta?.periods['90d'] || emptyMetrics()
                )
            };

            // Calculate trends
            this.calculateTrends(result);

            // Detect anomalies
            this.detectAnomalies(result);

            // Generate suggestions
            this.generateSuggestions(result);

        } catch (error) {
            Logger.error('MultiPeriodAnalyzer failed', { error, accountId });
        }

        return result;
    }

    /**
     * Fetch multi-period data for a specific platform.
     */
    private static async fetchPlatformData(
        accounts: Array<{ id: string; platform: string; name: string | null; externalId: string | null }>,
        platform: 'google' | 'meta'
    ): Promise<MultiPeriodData | null> {
        if (accounts.length === 0) return null;

        const periods: { '7d': PeriodMetrics; '30d': PeriodMetrics; '90d': PeriodMetrics } = {
            '7d': emptyMetrics(),
            '30d': emptyMetrics(),
            '90d': emptyMetrics()
        };

        for (const account of accounts) {
            try {
                // Fetch daily trends for different periods
                const dailyData90 = platform === 'google'
                    ? await AdsService.getGoogleDailyTrends(account.id, 90)
                    : await AdsService.getMetaDailyTrends(account.id, 90);

                if (dailyData90.length === 0) continue;

                // Split into periods
                const last7 = dailyData90.slice(-7);
                const last30 = dailyData90.slice(-30);
                const all90 = dailyData90;

                // Aggregate each period
                const metrics7 = aggregateMetrics(last7);
                const metrics30 = aggregateMetrics(last30);
                const metrics90 = aggregateMetrics(all90);

                // Combine with existing (for multi-account)
                periods['7d'] = combineMetrics(periods['7d'], metrics7);
                periods['30d'] = combineMetrics(periods['30d'], metrics30);
                periods['90d'] = combineMetrics(periods['90d'], metrics90);

            } catch (error) {
                Logger.warn(`Failed to fetch ${platform} data for account ${account.id}`, { error });
            }
        }

        // Check if we got any data
        if (periods['30d'].spend === 0) return null;

        return {
            platform,
            adAccountId: accounts[0].id,
            adAccountName: accounts[0].name || accounts[0].externalId || 'Unknown',
            periods
        };
    }

    /**
     * Calculate trend metrics and confidence levels.
     */
    private static calculateTrends(result: MultiPeriodAnalysis): void {
        const { combined } = result;

        // ROAS 7d vs 30d
        const roas7 = combined['7d'].roas;
        const roas30 = combined['30d'].roas;
        const roasChange7v30 = roas30 > 0 ? ((roas7 - roas30) / roas30) * 100 : 0;

        result.trends.roas_7d_vs_30d = {
            change: roasChange7v30,
            confidence: testRoasChange(combined['30d'], combined['7d'])
        };

        // ROAS 30d vs 90d
        const roas90 = combined['90d'].roas;
        const roasChange30v90 = roas90 > 0 ? ((roas30 - roas90) / roas90) * 100 : 0;

        result.trends.roas_30d_vs_90d = {
            change: roasChange30v90,
            confidence: testRoasChange(combined['90d'], combined['30d'])
        };

        // Spend trajectory (are we scaling up or down?)
        const spendValues = [
            combined['90d'].spend / 90,  // Daily avg 90d
            combined['30d'].spend / 30,  // Daily avg 30d
            combined['7d'].spend / 7     // Daily avg 7d
        ];
        result.trends.spend_trajectory = determineTrajectory(spendValues);

        // Performance trajectory (is ROAS improving?)
        const roasValues = [roas90, roas30, roas7];
        const perfTrajectory = determineTrajectory(roasValues);
        result.trends.performance_trajectory =
            perfTrajectory === 'increasing' ? 'improving' :
                perfTrajectory === 'decreasing' ? 'declining' : 'stable';
    }

    /**
     * Detect anomalous metrics that need attention.
     */
    private static detectAnomalies(result: MultiPeriodAnalysis): void {
        const { combined } = result;

        // Check for ROAS crash
        if (combined['30d'].roas > 0 && combined['7d'].roas < combined['30d'].roas * 0.5) {
            result.anomalies.push({
                metric: 'roas',
                period: '7d',
                severity: 'critical',
                message: `ROAS crashed from ${combined['30d'].roas.toFixed(2)}x (30d avg) to ${combined['7d'].roas.toFixed(2)}x (last 7d) - 50%+ drop`
            });
        }

        // Check for CTR decline
        if (combined['30d'].ctr > 0 && combined['7d'].ctr < combined['30d'].ctr * 0.7) {
            result.anomalies.push({
                metric: 'ctr',
                period: '7d',
                severity: 'warning',
                message: `CTR dropped from ${combined['30d'].ctr.toFixed(2)}% to ${combined['7d'].ctr.toFixed(2)}% - possible creative fatigue`
            });
        }

        // Check for CPA spike
        if (combined['30d'].cpa > 0 && combined['7d'].cpa > combined['30d'].cpa * 1.5) {
            result.anomalies.push({
                metric: 'cpa',
                period: '7d',
                severity: 'warning',
                message: `CPA spiked from $${combined['30d'].cpa.toFixed(2)} to $${combined['7d'].cpa.toFixed(2)} - acquisition cost up 50%+`
            });
        }

        // Check for spend drop (might indicate budget issues)
        const dailySpend7 = combined['7d'].spend / 7;
        const dailySpend30 = combined['30d'].spend / 30;
        if (dailySpend30 > 10 && dailySpend7 < dailySpend30 * 0.5) {
            result.anomalies.push({
                metric: 'spend',
                period: '7d',
                severity: 'warning',
                message: `Daily spend dropped from $${dailySpend30.toFixed(0)} to $${dailySpend7.toFixed(0)} - check budget limits or ad disapprovals`
            });
        }
    }

    /**
     * Generate actionable suggestions based on analysis.
     */
    private static generateSuggestions(result: MultiPeriodAnalysis): void {
        const { trends, anomalies, combined } = result;

        // Priority 1: Address critical anomalies
        for (const anomaly of anomalies.filter(a => a.severity === 'critical')) {
            result.suggestions.push(`🚨 **Critical**: ${anomaly.message}`);
        }

        // Priority 2: Performance trajectory insights
        if (trends.performance_trajectory === 'declining' && trends.roas_7d_vs_30d.confidence.score >= 60) {
            result.suggestions.push(
                `📉 **Performance Declining**: ROAS is ${Math.abs(trends.roas_7d_vs_30d.change).toFixed(0)}% lower this week vs monthly average ` +
                `(${combined['7d'].roas.toFixed(2)}x vs ${combined['30d'].roas.toFixed(2)}x). ` +
                `Confidence: ${trends.roas_7d_vs_30d.confidence.confidence}.`
            );
        } else if (trends.performance_trajectory === 'improving' && trends.roas_7d_vs_30d.confidence.score >= 60) {
            result.suggestions.push(
                `📈 **Performance Improving**: ROAS is up ${trends.roas_7d_vs_30d.change.toFixed(0)}% this week vs monthly average ` +
                `(${combined['7d'].roas.toFixed(2)}x vs ${combined['30d'].roas.toFixed(2)}x). ` +
                `Consider scaling budget on top performers.`
            );

            // Add actionable recommendation
            const currentDailySpend = combined['7d'].spend / 7;
            const increaseAmount = Math.max(5, Math.round((currentDailySpend * 0.2) / 5) * 5); // 20% increase, rounded to $5
            const newBudget = currentDailySpend + increaseAmount;

            const action: BudgetAction = {
                actionType: 'budget_increase',
                campaignId: result.google?.adAccountId || result.meta?.adAccountId || 'all_campaigns',
                campaignName: 'Top Performing Campaigns', // Ideally would identify specific campaign
                platform: result.google ? 'google' : 'meta',
                currentBudget: currentDailySpend,
                suggestedBudget: newBudget,
                changeAmount: increaseAmount,
                changePercent: 20,
                reason: 'performance_improving'
            };

            result.actionableRecommendations.push({
                id: 'budget_scaling_opportunity',
                priority: 2,
                category: 'budget',
                headline: `📈 ${createBudgetHeadline(action)}`,
                explanation: `ROAS is up ${trends.roas_7d_vs_30d.change.toFixed(0)}% this week (${combined['7d'].roas.toFixed(2)}x). ` +
                    `Scaling budget by 20% can capture more high-value conversions.`,
                dataPoints: [
                    `Current 7d ROAS: ${combined['7d'].roas.toFixed(2)}x`,
                    `Previous 30d ROAS: ${combined['30d'].roas.toFixed(2)}x`,
                    `Current Daily Spend: $${currentDailySpend.toFixed(0)}`
                ],
                action,
                confidence: 75,
                estimatedImpact: {
                    revenueChange: combined['7d'].revenue / 7 * 0.2, // Est 20% revenue lift
                    spendChange: increaseAmount,
                    timeframe: '7d'
                },
                platform: result.google ? 'google' : 'meta', // Simplified
                source: 'MultiPeriodAnalyzer',
                tags: ['budget', 'scaling', 'performance']
            });

        }

        // Priority 3: Spend trajectory + performance cross-analysis
        if (trends.spend_trajectory === 'increasing' && trends.performance_trajectory === 'declining') {
            result.suggestions.push(
                `⚠️ **Scaling Warning**: Spend is increasing but performance is declining. ` +
                `You may be hitting diminishing returns. Review audience expansion and bidding strategy.`
            );

            // Add actionable recommendation to pull back
            const currentDailySpend = combined['7d'].spend / 7;
            const decreaseAmount = Math.max(5, Math.round((currentDailySpend * 0.15) / 5) * 5); // 15% decrease
            const newBudget = currentDailySpend - decreaseAmount;

            const action: BudgetAction = {
                actionType: 'budget_decrease',
                campaignId: result.google?.adAccountId || 'all_campaigns',
                campaignName: 'All Campaigns',
                platform: result.google ? 'google' : 'meta',
                currentBudget: currentDailySpend,
                suggestedBudget: newBudget,
                changeAmount: -decreaseAmount,
                changePercent: -15,
                reason: 'diminishing_returns'
            };

            result.actionableRecommendations.push({
                id: 'budget_pullback_warning',
                priority: 2,
                category: 'budget',
                headline: `⚠️ ${createBudgetHeadline(action)}`,
                explanation: `Spend increased but ROAS declined to ${combined['7d'].roas.toFixed(2)}x. ` +
                    `You may be hitting diminishing returns. Recommend pulling back budget by 15%.`,
                dataPoints: [
                    `Spend Trend: Increasing`,
                    `Performance: Declining`,
                    `Current ROAS: ${combined['7d'].roas.toFixed(2)}x`
                ],
                action,
                confidence: 70,
                platform: result.google ? 'google' : 'meta',
                source: 'MultiPeriodAnalyzer',
                tags: ['budget', 'efficiency', 'warning']
            });
        } else if (trends.spend_trajectory === 'decreasing' && trends.performance_trajectory === 'improving') {
            result.suggestions.push(
                `💡 **Opportunity**: Performance is improving while spend is decreasing. ` +
                `Consider cautiously increasing budget to capture additional conversions.`
            );
        }

        // Priority 4: Long-term vs short-term divergence
        if (Math.abs(trends.roas_7d_vs_30d.change) > 20 && Math.abs(trends.roas_30d_vs_90d.change) < 10) {
            const direction = trends.roas_7d_vs_30d.change > 0 ? 'spike' : 'dip';
            result.suggestions.push(
                `🔍 **Short-term ${direction}**: Recent 7-day performance differs significantly from trend. ` +
                `This may be a temporary fluctuation - monitor for 3-5 more days before major changes.`
            );
        }

        // Priority 5: Warning-level anomalies
        for (const anomaly of anomalies.filter(a => a.severity === 'warning')) {
            result.suggestions.push(`⚠️ ${anomaly.message}`);
        }
    }

    /**
     * Get a formatted summary string for quick display.
     */
    static formatSummary(analysis: MultiPeriodAnalysis): string {
        if (!analysis.hasData) {
            return 'No ad performance data available.';
        }

        const { combined, trends } = analysis;

        const lines = [
            `**7-Day Performance**: ${combined['7d'].roas.toFixed(2)}x ROAS, $${combined['7d'].spend.toFixed(0)} spend, ${combined['7d'].conversions.toFixed(0)} conversions`,
            `**30-Day Performance**: ${combined['30d'].roas.toFixed(2)}x ROAS, $${combined['30d'].spend.toFixed(0)} spend, ${combined['30d'].conversions.toFixed(0)} conversions`,
            `**Trend**: Performance is ${trends.performance_trajectory}, spend is ${trends.spend_trajectory}`
        ];

        if (analysis.anomalies.length > 0) {
            lines.push(`**Alerts**: ${analysis.anomalies.length} issue(s) detected`);
        }

        return lines.join('\n');
    }
}

/**
 * Event processing service for incoming tracking events.
 *
 * Handles session upsert, event logging, attribution tracking,
 * and cart state management for analytics sessions.
 */

import { prisma } from '../../utils/prisma';
import { geoipLookupSync } from './GeoIPService';
import { parseTrafficSource, isBot, maskIpAddress } from './TrafficAnalyzer';
import { isExcludedIp } from './IpExclusionService';
import { ConversionForwarder } from './ConversionForwarder';
import * as CrawlerService from './CrawlerService';

const UAParser = require('ua-parser-js');

/**
 * Payload structure for incoming tracking events.
 */
export interface TrackingEventPayload {
    accountId: string;
    visitorId: string;
    type: string;
    url: string;
    pageTitle?: string;
    payload?: any;

    // Context (sent on first hit or if changed)
    ipAddress?: string;
    userAgent?: string;
    referrer?: string;
    referrerDomain?: string;  // Pre-parsed domain from plugin (optimization)
    referrerType?: string;    // Pre-classified type: 'direct', 'organic', 'social', 'referral', 'internal'
    utmSource?: string;
    utmMedium?: string;
    utmCampaign?: string;

    // Page metadata
    is404?: boolean;

    // Ad platform click IDs (gclid, fbclid, msclkid, etc.)
    clickId?: string;      // The raw click ID value
    clickPlatform?: string; // Platform: 'google', 'facebook', 'microsoft', 'tiktok', 'twitter', 'linkedin', 'pinterest'

    // Landing page referrer (persisted original external referrer)
    landingReferrer?: string;

    // CAPI deduplication key — matches browser pixel event_id
    eventId?: string;

    // Session enrichment from logged-in users (for session stitching)
    customerId?: number;
    email?: string;
}

/**
 * Process an incoming tracking event.
 *
 * This method handles:
 * - Bot filtering
 * - GeoIP resolution
 * - Session upsert with device/browser detection
 * - Cart state updates
 * - Session stitching (linking visitors to customers)
 * - First-touch and last-touch attribution
 * - Event logging
 *
 * @param data - The tracking event payload
 * @returns The upserted session, or null if filtered (bot traffic)
 */
export async function processEvent(data: TrackingEventPayload) {
    // Filter out bots/crawlers - they shouldn't be tracked
    if (data.userAgent && isBot(data.userAgent)) {
        // Fire-and-forget: log for dashboard visibility, never blocks the response
        void CrawlerService.logHitIfIdentifiable(
            data.accountId, data.userAgent, data.url, data.ipAddress
        );
        return null;
    }

    // Filter out excluded IPs (admins, team members, etc.)
    if (data.ipAddress && await isExcludedIp(data.accountId, data.ipAddress)) {
        return null; // Silently skip excluded IP traffic
    }

    // Filter out WordPress admin/login traffic (crawler bots probing admin endpoints)
    const wpAdminPatterns = ['/wp-admin/', '/wp-login.php'];
    const urlLower = (data.url || '').toLowerCase();
    const referrerLower = (data.referrer || '').toLowerCase();
    if (wpAdminPatterns.some(p => urlLower.includes(p) || referrerLower.includes(p))) {
        return null; // Silently skip wp-admin traffic
    }

    // Filter out non-page URLs for pageview events (e.g. static assets)
    // These should not be tracked as page views
    if (data.type === 'pageview' && data.url) {
        const urlPath = data.url.toLowerCase();
        // Common static asset extensions that shouldn't be tracked as page views
        const staticAssetExtensions = [
            '.js', '.css', '.map',
            '.jpg', '.jpeg', '.png', '.gif', '.svg', '.webp', '.ico', '.bmp', '.avif',
            '.woff', '.woff2', '.ttf', '.eot', '.otf',
            '.mp4', '.webm', '.mp3', '.ogg', '.wav',
            '.pdf', '.doc', '.docx', '.xls', '.xlsx',
            '.zip', '.tar', '.gz', '.rar',
            '.xml', '.json'
        ];

        // Check if URL ends with a static asset extension (ignore query strings)
        const pathWithoutQuery = urlPath.split('?')[0];
        const isStaticAsset = staticAssetExtensions.some(ext => pathWithoutQuery.endsWith(ext));

        if (isStaticAsset) {
            return null; // Silently skip static asset requests
        }
    }

    // 1. Resolve GeoIP if IP is provided
    let country: string | null = null;
    let city: string | null = null;
    let region: string | null = null;

    if (data.ipAddress) {
        const geo = geoipLookupSync(data.ipAddress);
        if (geo) {
            country = geo.country;
            city = geo.city;
            region = geo.region;
        }
    }

    // 2. Upsert Session
    // We use visitorId + accountId as the unique key.
    // We update the "Live State" fields.

    const sessionPayload: any = {
        lastActiveAt: new Date(),
        currentPath: data.url
    };

    // Mask IP before storing for privacy (hide last octet for IPv4, last 80 bits for IPv6)
    if (data.ipAddress) sessionPayload.ipAddress = maskIpAddress(data.ipAddress);
    if (data.userAgent) sessionPayload.userAgent = data.userAgent;
    if (country) sessionPayload.country = country;
    if (city) sessionPayload.city = city;

    // Attribution: Set referrer on session — prefer landingReferrer (original external entry point),
    // then current referrer ONLY if it's external (not internal navigation).
    // Internal referrers (same-site) would overwrite the original source with the site's own URLs.
    if (data.landingReferrer) {
        sessionPayload.referrer = data.landingReferrer;
    } else if (data.referrer && data.referrerType !== 'internal') {
        sessionPayload.referrer = data.referrer;
    }
    if (data.utmSource) sessionPayload.utmSource = data.utmSource;
    if (data.utmMedium) sessionPayload.utmMedium = data.utmMedium;
    if (data.utmCampaign) sessionPayload.utmCampaign = data.utmCampaign;

    // Parse User Agent with ua-parser-js for accurate detection
    if (data.userAgent) {
        const parser = new UAParser();
        const result = parser.setUA(data.userAgent).getResult();

        // Device type
        const deviceType = result.device.type;
        if (deviceType === 'mobile') {
            sessionPayload.deviceType = 'mobile';
        } else if (deviceType === 'tablet') {
            sessionPayload.deviceType = 'tablet';
        } else {
            sessionPayload.deviceType = 'desktop';
        }

        // Browser
        if (result.browser.name) {
            sessionPayload.browser = result.browser.name;
        }

        // OS
        if (result.os.name) {
            sessionPayload.os = result.os.name;
        }
    }

    // Handle Cart updates
    if (data.type === 'add_to_cart' || data.type === 'remove_from_cart' || data.type === 'update_cart') {
        // Expect payload to have cartTotal and items
        // Support common aliases for value: total, value, price, amount
        const payloadTotal = data.payload.total ?? data.payload.value ?? data.payload.price ?? data.payload.amount;

        if (data.payload && typeof payloadTotal !== 'undefined') {
            sessionPayload.cartValue = payloadTotal;
            sessionPayload.currency = data.payload.currency || 'USD';

            // Only update items if the full list is provided. 
            // Otherwise we risk wiping the list on simple 'add_to_cart' events that only send totals.
            if (Array.isArray(data.payload.items)) {
                sessionPayload.cartItems = data.payload.items;
            }

            // Reset abandoned status if they interact with cart
            sessionPayload.abandonedNotificationSentAt = null;
        }
    }

    // If checkout start, link email and persist fingerprint bot score
    if (data.type === 'checkout_start') {
        if (data.payload?.email) {
            sessionPayload.email = data.payload.email;
        }
        if (typeof data.payload?.fpScore === 'number') {
            sessionPayload.fpScore = data.payload.fpScore;
            sessionPayload.fpScoredAt = new Date();
        }
    }

    // If checkout success or purchase, clear cart and mark as converted
    if (data.type === 'checkout_success' || data.type === 'purchase') {
        sessionPayload.cartValue = 0;
        sessionPayload.cartItems = [];
        sessionPayload.abandonedNotificationSentAt = null;
    }

    // Capture email from purchase event if not already set on session
    if (data.type === 'purchase' && data.payload?.email) {
        sessionPayload.email = data.payload.email;
    }

    // Handle Search (Just ensure payload has term)
    if (data.type === 'search') {
        // validating payload.term exists?
        // checking if we want to update session 'lastSearchTerm'?
    }

    // Session Stitching: Link visitor to customer on login
    if (data.type === 'identify') {
        const payloadCustomerId = data.payload?.customerId ?? data.payload?.id ?? data.payload?.userId;

        if (payloadCustomerId) {
            // wooCustomerId is an Int in the schema
            sessionPayload.wooCustomerId = parseInt(String(payloadCustomerId), 10) || null;
            if (data.payload.email) {
                sessionPayload.email = data.payload.email;
            }
            // Note: firstName and lastName are not stored on AnalyticsSession
            // They should be looked up from WooCustomer if needed
        }
    }

    // Product View: Store detailed product data
    if (data.type === 'product_view' && data.payload?.productId) {
        // This is logged as an event with rich product data
        // The payload should include: productId, productName, price, sku, category
    }

    // A/B Test: Store experiment variation
    if (data.type === 'experiment' && data.payload?.experimentId) {
        // Log experiment assignment for later analysis
        // payload: { experimentId, variationId }
    }

    // Check if returning visitor (exists in DB already)
    // Include lastTouchSource to preserve attribution during internal navigation
    const existingSession = await prisma.analyticsSession.findUnique({
        where: {
            accountId_visitorId: {
                accountId: data.accountId,
                visitorId: data.visitorId
            }
        },
        select: {
            id: true,
            firstTouchSource: true,
            firstTouchAt: true,
            totalVisits: true,
            lastTouchSource: true
        }
    });

    // Note: isReturning is computed, not stored in DB
    // We can derive it from totalVisits > 0 if needed

    // Attribution tracking
    // Priority: 1) Click ID (paid ads), 2) UTM source, 3) Landing referrer, 4) Current referrer, 5) Direct
    let currentSource = 'direct';
    let campaignInfo = '';

    // Priority 1: Click ID from ad platforms (gclid, fbclid, msclkid, etc.)
    if (data.clickId && data.clickPlatform) {
        currentSource = 'paid';
        campaignInfo = data.clickPlatform;
        // Store click platform in session for attribution
        sessionPayload.utmSource = data.clickPlatform;
        sessionPayload.utmMedium = 'cpc';
    }
    // Priority 2: Explicit UTM parameters
    else if (data.utmSource) {
        // Map common UTM sources to our traffic categories
        const utmLower = data.utmSource.toLowerCase();
        if (['google', 'bing', 'yahoo', 'duckduckgo', 'baidu'].includes(utmLower)) {
            // Check if it's paid (usually has utm_medium=cpc/ppc) or organic
            currentSource = (data.utmMedium?.toLowerCase() === 'cpc' || data.utmMedium?.toLowerCase() === 'ppc')
                ? 'paid' : 'organic';
        } else if (['facebook', 'instagram', 'twitter', 'linkedin', 'tiktok', 'pinterest', 'youtube', 'reddit'].includes(utmLower)) {
            currentSource = 'social';
        } else if (['email', 'newsletter', 'mailchimp', 'klaviyo'].includes(utmLower)) {
            currentSource = 'email';
        } else if (['chatgpt', 'openai', 'claude', 'perplexity', 'bard', 'gemini'].includes(utmLower)) {
            currentSource = 'ai';
        } else {
            // Has UTM but unknown source - treat as campaign/referral
            currentSource = 'campaign';
        }
    }
    // Priority 3: Landing referrer (persisted original external referrer)
    else if (data.landingReferrer) {
        currentSource = parseTrafficSource(data.landingReferrer);
        // Store landing referrer if not already set
        if (!sessionPayload.referrer) {
            sessionPayload.referrer = data.landingReferrer;
            // Note: trafficSource is derived from firstTouchSource/lastTouchSource, not stored separately
        }
    }
    // Priority 4: Current page referrer
    else if (data.referrer) {
        // Use pre-computed referrerType from plugin if available (optimization)
        // Otherwise fall back to parsing on the server (for legacy clients or JS trackers)
        if (data.referrerType && data.referrerType !== 'internal') {
            // Map plugin types to our internal types
            const typeMap: Record<string, string> = {
                'organic': 'organic',
                'social': 'social',
                'referral': 'referral',
                'direct': 'direct'
            };
            currentSource = typeMap[data.referrerType] || parseTrafficSource(data.referrer);
        } else if (data.referrerType === 'internal') {
            // Internal referrer = same site navigation, preserve existing session's source
            currentSource = existingSession?.lastTouchSource || 'direct';
        } else {
            // No pre-computed type, fall back to server-side parsing
            // Preserve existing session's source if parsing returns 'direct' (same-site or empty referrer)
            const parsedSource = parseTrafficSource(data.referrer);
            currentSource = parsedSource === 'direct'
                ? (existingSession?.lastTouchSource || 'direct')
                : parsedSource;
        }
    }
    // If none of the above, stays 'direct'

    // Session enrichment from logged-in users (top-level fields from server-side tracking)
    if (data.customerId) {
        sessionPayload.wooCustomerId = data.customerId;
    }
    if (data.email && !sessionPayload.email) {
        sessionPayload.email = data.email;
    }

    // First touch - only set once, never overwrite
    if (!existingSession?.firstTouchSource) {
        sessionPayload.firstTouchSource = currentSource;
        sessionPayload.firstTouchAt = new Date();
    }

    // Last touch - always update
    sessionPayload.lastTouchSource = currentSource;
    sessionPayload.lastTouchAt = new Date();

    // Increment visit count for page-based events
    // Includes standard pageview plus specialized page events (product_view, cart_view, checkout_view)
    // which are sent instead of pageview for richer analytics data
    const pageViewTypes = ['pageview', 'product_view', 'cart_view', 'checkout_view'];
    const isPageView = pageViewTypes.includes(data.type);
    sessionPayload.totalVisits = (existingSession?.totalVisits || 0) + (isPageView ? 1 : 0);

    // Upsert session
    const session = await prisma.analyticsSession.upsert({
        where: {
            accountId_visitorId: {
                accountId: data.accountId,
                visitorId: data.visitorId
            }
        },
        create: {
            accountId: data.accountId,
            visitorId: data.visitorId,
            firstTouchSource: currentSource,
            firstTouchAt: new Date(),
            ...sessionPayload
        },
        update: sessionPayload
    });

    // 3. Visit Management
    // Check if we need to create a new visit (30 min inactivity gap)
    const VISIT_TIMEOUT_MS = 30 * 60 * 1000; // 30 minutes
    const now = new Date();

    // Get the most recent visit for this session
    let currentVisit = await prisma.analyticsVisit.findFirst({
        where: { sessionId: session.id },
        orderBy: { startedAt: 'desc' },
        select: {
            id: true,
            visitNumber: true,
            endedAt: true,
            pageviews: true,
            actions: true
        }
    });

    const timeSinceLastActivity = currentVisit?.endedAt
        ? now.getTime() - new Date(currentVisit.endedAt).getTime()
        : Infinity;

    // Create new visit if: no existing visit OR 30+ min gap
    if (!currentVisit || timeSinceLastActivity > VISIT_TIMEOUT_MS) {
        const visitNumber = currentVisit ? currentVisit.visitNumber + 1 : 1;

        currentVisit = await prisma.analyticsVisit.create({
            data: {
                sessionId: session.id,
                visitNumber,
                startedAt: now,
                endedAt: now,
                referrer: sessionPayload.referrer || data.referrer,
                utmSource: sessionPayload.utmSource || data.utmSource,
                utmMedium: sessionPayload.utmMedium || data.utmMedium,
                utmCampaign: sessionPayload.utmCampaign || data.utmCampaign,
                deviceType: sessionPayload.deviceType,
                browser: sessionPayload.browser,
                os: sessionPayload.os,
                country: sessionPayload.country || country,
                city: sessionPayload.city || city,
                pageviews: isPageView ? 1 : 0,
                actions: 1
            },
            select: {
                id: true,
                visitNumber: true,
                endedAt: true,
                pageviews: true,
                actions: true
            }
        });
    } else {
        // Update existing visit stats
        await prisma.analyticsVisit.update({
            where: { id: currentVisit.id },
            data: {
                endedAt: now,
                pageviews: { increment: isPageView ? 1 : 0 },
                actions: { increment: 1 }
            }
        });
    }

    // 4. Log Event with visit link
    // Build payload, merging is404 flag for pageview events
    let eventPayload = data.payload || undefined;
    if (data.type === 'pageview' && data.is404) {
        eventPayload = { ...(data.payload || {}), is404: true };
    }

    try {
        await prisma.analyticsEvent.create({
            data: {
                sessionId: session.id,
                visitId: currentVisit.id,
                type: data.type,
                url: data.url,
                pageTitle: data.pageTitle,
                payload: eventPayload
            }
        });
    } catch (eventError: any) {
        console.error('Prisma event create error:', eventError.message || eventError);
        console.error('Event data was:', { sessionId: session.id, visitId: currentVisit.id, type: data.type, url: data.url, pageTitle: data.pageTitle });
        throw eventError;
    }

    // 5. Fire-and-forget: forward conversion events to ad platforms (CAPI)
    // Wrapped in try/catch to ensure CAPI failures never affect tracking
    try {
        void ConversionForwarder.forwardIfConversion(data, session);
    } catch (_) { /* intentionally swallowed */ }

    return session;
}

/**
 * GA4 Measurement Protocol Service
 *
 * Sends server-side events to Google Analytics 4 via the Measurement Protocol.
 * POST https://www.google-analytics.com/mp/collect
 *
 * Why server-side: Ad blockers block the client-side GA4 tag (gtag.js) for
 * ~15-30% of visitors. Measurement Protocol fills this gap with server-side
 * events, ensuring accurate revenue and conversion reporting in GA4.
 */

import { prisma } from '../../utils/prisma';
import { Logger } from '../../utils/logger';
import { mapEventName, extractUserData } from './conversionUtils';
import type { ConversionPlatformService } from './ConversionForwarder';
import type { TrackingEventPayload } from './EventProcessor';

const GA4_ENDPOINT = 'https://www.google-analytics.com/mp/collect';
const GA4_DEBUG_ENDPOINT = 'https://www.google-analytics.com/debug/mp/collect';
const MAX_RETRIES = 3;

export class GA4MeasurementService implements ConversionPlatformService {
    readonly platform = 'GA4';

    async sendEvent(
        accountId: string,
        config: Record<string, any>,
        data: TrackingEventPayload,
        session: { id: string; email?: string | null; ipAddress?: string | null; userAgent?: string | null; country?: string | null } | null,
    ): Promise<void> {
        const { measurementId, apiSecret, useDebugEndpoint } = config;
        if (!measurementId || !apiSecret) {
            Logger.warn('[GA4Measurement] Missing measurementId or apiSecret', { accountId });
            return;
        }

        const eventName = mapEventName(data.type, 'GA4');
        if (!eventName) return;

        const eventId = data.eventId || crypto.randomUUID();
        const userData = extractUserData(data.payload, session, data.ipAddress);

        // GA4 requires a client_id — use GA cookie value or fall back to visitorId
        const clientId = this.extractGAClientId(userData.gaClientId) || data.visitorId;

        const payload = this.buildPayload(eventName, eventId, clientId, data, userData);
        const deliveryId = await this.logDelivery(accountId, eventName, eventId, payload);

        const endpoint = useDebugEndpoint ? GA4_DEBUG_ENDPOINT : GA4_ENDPOINT;
        await this.sendWithRetry(endpoint, measurementId, apiSecret, payload, deliveryId);
    }

    /**
     * Extract GA client ID from _ga cookie value.
     * Cookie format: GA1.1.1234567890.1234567890 → "1234567890.1234567890"
     */
    private extractGAClientId(gaCookie: string | undefined): string | undefined {
        if (!gaCookie) return undefined;

        // Standard _ga cookie: GA1.{container_count}.{cid1}.{cid2}
        const parts = gaCookie.split('.');
        if (parts.length >= 4) {
            return `${parts[2]}.${parts[3]}`;
        }

        // Already a bare client ID
        return gaCookie;
    }

    /**
     * Build GA4 Measurement Protocol payload.
     * Spec: https://developers.google.com/analytics/devguides/collection/protocol/ga4
     */
    private buildPayload(
        eventName: string,
        eventId: string,
        clientId: string,
        data: TrackingEventPayload,
        userData: ReturnType<typeof extractUserData>,
    ): Record<string, any> {
        const event: Record<string, any> = {
            name: eventName,
            params: {
                event_id: eventId,
                page_location: data.url,
                // Session-level data
                engagement_time_msec: '100', // Required by GA4 for events to show in reports
            },
        };

        // Add ecommerce data in GA4 format
        if (data.payload) {
            if (data.payload.total !== undefined) {
                event.params.value = data.payload.total;
            }
            if (data.payload.currency) {
                event.params.currency = data.payload.currency;
            }
            if (data.payload.orderId) {
                event.params.transaction_id = String(data.payload.orderId);
            }
            if (data.payload.tax !== undefined) {
                event.params.tax = data.payload.tax;
            }
            if (data.payload.shipping !== undefined) {
                event.params.shipping = data.payload.shipping;
            }
            if (Array.isArray(data.payload.items)) {
                event.params.items = data.payload.items.map((item: any) => ({
                    item_id: String(item.id || item.sku || ''),
                    item_name: item.name || '',
                    quantity: item.quantity || 1,
                    price: item.price || 0,
                }));
            }

            // Search term
            if (data.type === 'search' && data.payload.term) {
                event.params.search_term = data.payload.term;
            }
        }

        const body: Record<string, any> = {
            client_id: clientId,
            events: [event],
            // Non-personalised ads flag for privacy
            non_personalized_ads: false,
        };

        // Add user_id if we have a customer ID (for cross-device tracking in GA4)
        if (data.payload?.customerId) {
            body.user_id = String(data.payload.customerId);
        }

        return body;
    }

    private async sendWithRetry(
        endpoint: string,
        measurementId: string,
        apiSecret: string,
        payload: Record<string, any>,
        deliveryId: string,
    ): Promise<void> {
        const url = `${endpoint}?measurement_id=${measurementId}&api_secret=${apiSecret}`;

        for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
            try {
                const response = await fetch(url, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(payload),
                });

                const responseBody = await response.text();

                // GA4 MP returns 204 (no content) on success, 200 for debug endpoint
                if (response.status === 204 || response.ok) {
                    await this.markDelivery(deliveryId, 'SENT', response.status, responseBody || 'OK', attempt);
                    return;
                }

                if (response.status === 429 || response.status >= 500) {
                    if (attempt < MAX_RETRIES) {
                        await this.backoff(attempt);
                        continue;
                    }
                }

                await this.markDelivery(deliveryId, 'FAILED', response.status, responseBody, attempt, responseBody);
                Logger.error('[GA4Measurement] Delivery failed', { status: response.status, measurementId });
                return;
            } catch (error: any) {
                if (attempt === MAX_RETRIES) {
                    await this.markDelivery(deliveryId, 'FAILED', null, null, attempt, error.message);
                    Logger.error('[GA4Measurement] Network error after retries', { error: error.message });
                    return;
                }
                await this.backoff(attempt);
            }
        }
    }

    private backoff(attempt: number): Promise<void> {
        return new Promise((resolve) => setTimeout(resolve, Math.pow(2, attempt) * 1000));
    }

    private async logDelivery(accountId: string, eventName: string, eventId: string, payload: Record<string, any>): Promise<string> {
        try {
            const d = await prisma.conversionDelivery.create({
                data: { accountId, platform: 'GA4', eventName, eventId, payload: payload as object, status: 'PENDING' },
            });
            return d.id;
        } catch (error: any) {
            Logger.error('[GA4Measurement] Failed to log delivery', { error: error.message });
            return 'unknown';
        }
    }

    private async markDelivery(id: string, status: string, httpStatus: number | null, response: string | null, attempts: number, lastError?: string): Promise<void> {
        if (id === 'unknown') return;
        try {
            await prisma.conversionDelivery.update({
                where: { id },
                data: { status, httpStatus, response: response?.substring(0, 2000), attempts, lastError: lastError?.substring(0, 2000), sentAt: status === 'SENT' ? new Date() : undefined },
            });
        } catch (error: any) {
            Logger.error('[GA4Measurement] Failed to update delivery', { id, error: error.message });
        }
    }
}

/**
 * GeoIP Service - Modern geolocation using MaxMind GeoLite2 & DB-IP Lite.
 * 
 * Features:
 * - Supports manual MaxMind database uploads (GeoLite2-City.mmdb)
 * - Auto-downloads and updates DB-IP Lite database (dbip-city-lite.mmdb)
 * - Prioritizes the newest database for lookups
 * - Fallback support if one database misses
 */

import path from 'path';
import fs from 'fs';
import https from 'https';
import zlib from 'zlib';
import maxmind, { CityResponse, Reader } from 'maxmind';
import { Logger } from '../../utils/logger';

/**
 * Result structure for GeoIP lookups
 */
export interface GeoIPResult {
    country: string | null;
    city: string | null;
    region: string | null;
    timezone: string | null;
    latitude: number | null;
    longitude: number | null;
}

interface GeoIPReader {
    reader: Reader<CityResponse>;
    source: 'manual' | 'auto';
    buildDate: Date;
    path: string;
}

// Database paths
const DATA_DIR = path.join(__dirname, '../../../data');
const MANUAL_DB_PATH = path.join(DATA_DIR, 'GeoLite2-City.mmdb');
const AUTO_DB_PATH = path.join(DATA_DIR, 'dbip-city-lite.mmdb');

// State
let readers: GeoIPReader[] = [];
let initPromise: Promise<void> | null = null;
let updateCheckTimer: NodeJS.Timeout | null = null;
let isUpdating = false;

/**
 * Get the build date of a MaxMind reader
 */
function getBuildDate(reader: Reader<CityResponse>): Date {
    const epoch = reader.metadata.buildEpoch;
    if (epoch instanceof Date) {
        return epoch;
    }
    if (typeof epoch === 'number') {
        return new Date(epoch * 1000);
    }
    return new Date();
}

/**
 * Initialize all available databases
 */
async function loadDatabases(): Promise<void> {
    const newReaders: GeoIPReader[] = [];

    // 1. Try Manual DB
    if (fs.existsSync(MANUAL_DB_PATH)) {
        try {
            const reader = await maxmind.open<CityResponse>(MANUAL_DB_PATH);
            const buildDate = getBuildDate(reader);
            newReaders.push({
                reader,
                source: 'manual',
                buildDate,
                path: MANUAL_DB_PATH
            });
            Logger.info(`[GeoIP] Loaded manual database (Build: ${buildDate.toISOString().split('T')[0]})`);
        } catch (e: any) {
            Logger.warn(`[GeoIP] Failed to load manual database: ${e.message}`);
        }
    }

    // 2. Try Auto DB
    if (fs.existsSync(AUTO_DB_PATH)) {
        try {
            const reader = await maxmind.open<CityResponse>(AUTO_DB_PATH);
            const buildDate = getBuildDate(reader);
            newReaders.push({
                reader,
                source: 'auto',
                buildDate,
                path: AUTO_DB_PATH
            });
            Logger.info(`[GeoIP] Loaded auto database (Build: ${buildDate.toISOString().split('T')[0]})`);
        } catch (e: any) {
            Logger.warn(`[GeoIP] Failed to load auto database: ${e.message}`);
        }
    }

    // 3. Sort by build date (Newest first)
    newReaders.sort((a, b) => b.buildDate.getTime() - a.buildDate.getTime());

    readers = newReaders;

    if (readers.length === 0) {
        Logger.warn('[GeoIP] No databases available. Lookups will return null.');
    } else {
        Logger.info(`[GeoIP] Active databases: ${readers.map(r => `${r.source} (${r.buildDate.toISOString().split('T')[0]})`).join(', ')}`);
    }
}

/**
 * Download URL helper
 */
function downloadFile(url: string, destPath: string): Promise<void> {
    return new Promise((resolve, reject) => {
        const file = fs.createWriteStream(destPath);

        const request = https.get(url, (response) => {
            if (response.statusCode !== 200) {
                fs.unlink(destPath, () => { }); // Delete temp file
                reject(new Error(`Failed to download: Status ${response.statusCode}`));
                return;
            }

            // Pipe response -> gunzip -> file
            const gunzip = zlib.createGunzip();
            response.pipe(gunzip).pipe(file);

            file.on('finish', () => {
                file.close(() => resolve());
            });

            file.on('error', (err) => {
                fs.unlink(destPath, () => { });
                reject(err);
            });

            gunzip.on('error', (err) => {
                fs.unlink(destPath, () => { });
                reject(err);
            });
        });

        request.on('error', (err) => {
            fs.unlink(destPath, () => { });
            reject(err);
        });
    });
}

/**
 * Check for updates from DB-IP
 */
export async function updateGeoLiteDB(): Promise<boolean> {
    if (isUpdating) return false;
    isUpdating = true;

    try {
        const date = new Date();
        const year = date.getFullYear();
        // Pack into 2 digits
        const month = String(date.getMonth() + 1).padStart(2, '0');

        // URL Format: https://download.db-ip.com/free/dbip-city-lite-{YYYY}-{MM}.mmdb.gz
        const filename = `dbip-city-lite-${year}-${month}.mmdb.gz`;
        const url = `https://download.db-ip.com/free/${filename}`;

        Logger.info(`[GeoIP] Checking for updates: ${filename}`);

        if (!fs.existsSync(DATA_DIR)) {
            fs.mkdirSync(DATA_DIR, { recursive: true });
        }

        const tempPath = path.join(DATA_DIR, 'dbip-city-lite.mmdb.tmp'); // Unzipped path
        // We actually download .gz but pipe it through gunzip directly to .mmdb file
        // So we don't save the .gz file to disk, we verify it on the fly basically

        // Try download current month
        try {
            await downloadFile(url, tempPath);
            Logger.info(`[GeoIP] Downloaded ${filename}`);
        } catch (err: any) {
            Logger.warn(`[GeoIP] Could not download current month (${filename}): ${err.message}`);

            // Fallback: Try previous month if current month is "future" or just released and not available yet
            // Or simple logic: if it's early in the month (e.g., < 5th), maybe try prev month?
            // Simplified: If current failed, try 1 month back
            const prevDate = new Date();
            prevDate.setMonth(prevDate.getMonth() - 1);
            const prevYear = prevDate.getFullYear();
            const prevMonth = String(prevDate.getMonth() + 1).padStart(2, '0');
            const prevFilename = `dbip-city-lite-${prevYear}-${prevMonth}.mmdb.gz`;
            const prevUrl = `https://download.db-ip.com/free/${prevFilename}`;

            Logger.info(`[GeoIP] Trying fallback: ${prevFilename}`);
            await downloadFile(prevUrl, tempPath);
            Logger.info(`[GeoIP] Downloaded fallback ${prevFilename}`);
        }

        // Test the new database before swapping
        try {
            const testReader = await maxmind.open(tempPath);
            // If we are here, it's valid
            // Check if it's actually newer than what we have? 
            // We can just overwrite. The prioritization logic in loadDatabases will handle it.
            // But good to check if it's valid.

            // Close test reader
            // Note: maxmind library doesn't expose close() easily in types sometimes, strictly it doesn't hold open file handle in pure JS mode but with MMDB-Reader it might.
            // In pure JS mode (default for 'maxmind' package unless using fast version), it reads buffer.

            // Move temp to real path
            fs.renameSync(tempPath, AUTO_DB_PATH);
            Logger.info('[GeoIP] Updated DB-IP database successfully.');

            // Reload databases to pick up potential new order
            await loadDatabases();
            return true;
        } catch (e: any) {
            Logger.error(`[GeoIP] Downloaded database is invalid: ${e.message}`);
            fs.unlink(tempPath, () => { }); // Cleanup
            return false;
        }

    } catch (e: any) {
        Logger.error(`[GeoIP] Update failed: ${e.message}`);
        return false;
    } finally {
        isUpdating = false;
    }
}

/**
 * Schedule regular updates
 */
export function scheduleUpdates() {
    // Check immediately on startup (if no auto db exists or it's old)
    // Actually, just check. The updateDB method handles "download if URL works".
    // We should be careful not to spam.
    // Let's check if the file exists and how old it is.

    // Initial check (non-blocking)
    const MAX_AGE_MS = 7 * 24 * 60 * 60 * 1000; // 1 week

    const checkAndRun = async () => {
        let shouldUpdate = false;

        if (!fs.existsSync(AUTO_DB_PATH)) {
            shouldUpdate = true;
        } else {
            const stats = fs.statSync(AUTO_DB_PATH);
            const age = Date.now() - stats.mtimeMs;
            if (age > MAX_AGE_MS) {
                shouldUpdate = true;
            }
        }

        if (shouldUpdate) {
            Logger.info('[GeoIP] Auto database missing or old, starting update...');
            await updateGeoLiteDB();
        }
    };

    // Run initial check
    checkAndRun().catch(e => Logger.error('[GeoIP] Initial update check failed', { error: e }));

    // Schedule weekly check
    if (updateCheckTimer) clearInterval(updateCheckTimer);
    updateCheckTimer = setInterval(checkAndRun, MAX_AGE_MS);
}

/**
 * Perform a GeoIP lookup for the given IP address.
 */
export async function geoipLookup(ipAddress: string): Promise<GeoIPResult | null> {
    if (!initPromise) initPromise = loadDatabases();
    await initPromise;
    return geoipLookupSync(ipAddress);
}

/**
 * Synchronous lookup wrapper
 */
export function geoipLookupSync(ipAddress: string): GeoIPResult | null {
    if (readers.length === 0) {
        if (!initPromise) initPromise = loadDatabases();
        return null; // Async load triggered
    }

    // Iterate through readers (sorted by newest first)
    for (const { reader } of readers) {
        try {
            const result = reader.get(ipAddress);
            if (result) {
                return {
                    country: result.country?.iso_code || null,
                    city: result.city?.names?.en || null,
                    region: result.subdivisions?.[0]?.iso_code || null,
                    timezone: result.location?.time_zone || null,
                    latitude: result.location?.latitude || null,
                    longitude: result.location?.longitude || null
                };
            }
        } catch (e) {
            // Ignore error and try next reader
            continue;
        }
    }

    return null;
}

/**
 * Get status of all databases
 */
export function getDatabaseStatus() {
    return readers.map(r => ({
        source: r.source,
        buildDate: r.buildDate,
        path: r.path,
        dbType: 'City', // Assuming City for now
        size: fs.existsSync(r.path) ? fs.statSync(r.path).size : 0
    }));
}

/**
 * Pre-initialize the GeoIP reader at server startup.
 */
export async function initGeoIP(forceReload: boolean = false): Promise<void> {
    if (forceReload || !initPromise) {
        initPromise = loadDatabases();
    }
    await initPromise;

    // Also start the scheduler
    scheduleUpdates();
}

/**
 * IP Exclusion Service for Analytics Tracking.
 *
 * Provides IP address exclusion checking for filtering admin/internal
 * traffic from analytics tracking and reports.
 */

import { prisma } from '../../utils/prisma';
import { cacheAside, CacheTTL } from '../../utils/cache';

/**
 * Check if an IP address is in CIDR notation and matches a given IP.
 *
 * @param ip - The IP address to check
 * @param cidr - The CIDR notation (e.g., "192.168.1.0/24")
 * @returns True if the IP is within the CIDR range
 */
function ipMatchesCidr(ip: string, cidr: string): boolean {
    const [range, bits] = cidr.split('/');
    if (!bits) return false;

    const mask = parseInt(bits, 10);
    if (isNaN(mask)) return false;

    // Convert IPs to numeric for comparison
    const ipNum = ipToNumber(ip);
    const rangeNum = ipToNumber(range);

    if (ipNum === null || rangeNum === null) return false;

    // Calculate subnet mask
    const subnetMask = ~((1 << (32 - mask)) - 1) >>> 0;

    return (ipNum & subnetMask) === (rangeNum & subnetMask);
}

/**
 * Convert IPv4 address to numeric representation.
 *
 * @param ip - IPv4 address string
 * @returns Numeric representation or null if invalid
 */
function ipToNumber(ip: string): number | null {
    // Handle IPv4-mapped IPv6 addresses (::ffff:192.168.1.1)
    if (ip.startsWith('::ffff:')) {
        ip = ip.substring(7);
    }

    const parts = ip.split('.');
    if (parts.length !== 4) return null;

    let result = 0;
    for (const part of parts) {
        const num = parseInt(part, 10);
        if (isNaN(num) || num < 0 || num > 255) return null;
        result = (result << 8) + num;
    }

    return result >>> 0; // Ensure unsigned
}

/**
 * Normalize an IP address for comparison.
 * Handles IPv4-mapped IPv6, localhost variants, etc.
 *
 * @param ip - The IP address to normalize
 * @returns Normalized IP string
 */
export function normalizeIp(ip: string): string {
    if (!ip) return '';

    // Trim whitespace
    ip = ip.trim();

    // Handle IPv4-mapped IPv6 (::ffff:192.168.1.1 -> 192.168.1.1)
    if (ip.startsWith('::ffff:')) {
        ip = ip.substring(7);
    }

    // Handle localhost variants
    if (ip === '::1' || ip === '127.0.0.1' || ip === 'localhost') {
        return '127.0.0.1';
    }

    return ip.toLowerCase();
}

/**
 * Check if an IP matches any entry in the exclusion list.
 *
 * @param ip - The IP address to check
 * @param excludedIps - Array of IPs/CIDRs to check against
 * @returns True if the IP should be excluded
 */
export function matchesExclusionList(ip: string, excludedIps: string[]): boolean {
    if (!ip || !excludedIps || excludedIps.length === 0) {
        return false;
    }

    const normalizedIp = normalizeIp(ip);

    for (const entry of excludedIps) {
        const normalizedEntry = normalizeIp(entry);

        // Check for CIDR notation
        if (entry.includes('/')) {
            if (ipMatchesCidr(normalizedIp, entry)) {
                return true;
            }
        } else {
            // Exact match
            if (normalizedIp === normalizedEntry) {
                return true;
            }
        }
    }

    return false;
}

/**
 * Get the list of excluded IPs for an account.
 * Results are cached for performance.
 *
 * @param accountId - The account ID
 * @returns Array of excluded IP addresses/CIDRs
 */
export async function getExcludedIps(accountId: string): Promise<string[]> {
    return cacheAside(
        `excluded-ips:${accountId}`,
        async () => {
            const account = await prisma.account.findUnique({
                where: { id: accountId },
                select: { excludedIps: true }
            });

            if (!account?.excludedIps) return [];

            // Handle both array and JSON string formats
            if (Array.isArray(account.excludedIps)) {
                return account.excludedIps as string[];
            }

            return [];
        },
        { ttl: CacheTTL.MEDIUM, namespace: 'tracking' }
    );
}

/**
 * Check if an IP address should be excluded from tracking for a given account.
 *
 * @param accountId - The account ID
 * @param ip - The IP address to check
 * @returns True if the IP should be excluded
 */
export async function isExcludedIp(accountId: string, ip: string): Promise<boolean> {
    if (!ip) return false;

    const excludedIps = await getExcludedIps(accountId);
    return matchesExclusionList(ip, excludedIps);
}

